INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207279F$$, $$Isolated Personnel Survivability and Recovery$$, $$rdte_af_ba5$$, $$dw_mda$$, 2026, 99248000, 54271000, 10020000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0207279F"}$$::jsonb, $$This Program Element contains two projects that provide Air Force aircrew survival equipment to assist in personnel recovery in the event they become Isolated Personnel (IP). Project 65412B (Isolated Personnel): This project is for the Isolated Personnel Survival and Flight Equipment (IPSAFE) program which develops, test and fields aircrew survival components to support climate specific equipment and aims to increase the ability for IP to evade and survive in operational environments where rapid extraction is not possible. Project 654522 (CSAR EMD): This project is for the Next Generation Survival Radio (NGSR) program; an Air Force led development effort to replace the aging legacy Combat Survivor Evader Locator (CSEL) handheld radio (HHR) for the entire Joint Force. The NGSR will deliver communications capability supporting the Joint Personnel Recovery Agency (JPRA) Combat Search and Rescue (CSAR) mission to locate, authenticate, and communicate with Joint forces who become isolated. The NGSR program will replace legacy satellite communication and encryption methods to deliver secured end-to-end communication and locate and recover downed aircrew/special operations personnel. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. In FY 2025 $0.319 million was expended for civilian pay expenses in this program element, and in FY2026 $0.947 million is forecasted for civilian pay expenses in this program element. The total cost of the Middle Tier of Acquisition effort is $222.400 million. The NGSR RP program is fully funded across the Future Years Defense Program. The FY 2026 cost of the Combat Survivor Evader Locator Next Generation Survival Radio Rapid Prototyping Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0207279F / Isolated Personnel Survivability and Recovery Development & Demonstration (SDD)$$, NULL, 39662000, 29671000, 23541000, NULL, NULL, 109, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 9757000, 53948000, 16001000, 16001000, 0, 16001000, 24286000, $$This Program Element contains two projects that provide Air Force aircrew survival equipment to assist in personnel recovery in the event they become Isolated Personnel (IP). Project 65412B (Isolated Personnel): This project is for the Isolated Personnel Survival and Flight Equipment (IPSAFE) program which develops, test and fields aircrew survival components to support climate specific equipment and aims to increase the ability for IP to evade and survive in operational environments where rapid extraction is not possible. Project 654522 (CSAR EMD): This project is for the Next Generation Survival Radio (NGSR) program; an Air Force led development effort to replace the aging legacy Combat Survivor Evader Locator (CSEL) handheld radio (HHR) for the entire Joint Force. The NGSR will deliver communications capability supporting the Joint Personnel Recovery Agency (JPRA) Combat Search and Rescue (CSAR) mission to locate, authenticate, and communicate with Joint forces who become isolated. The NGSR program will replace legacy satellite communication and encryption methods to deliver secured end-to-end communication and locate and recover downed aircrew/special operations personnel. The total cost of the Next Generation Survival Radio (NGSR) Program Middle Tier of Acquisition effort is $182.913 million, including RDT&E and procurement of prototype units. The NGSR program is fully funded across the Future Years Defense Program. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0207279F / Isolated Personnel Survivability and Recovery Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101221N$$, $$Strategic Sub & Wpns Sys Supt$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 807099000, 326254000, 335294000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0101221N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 1190144000, 1307016000, 1287844000, NULL, NULL, NULL, NULL, NULL, FALSE, 326596000, 828337000, 1051736000, 1051736000, NULL, 1051736000, 1313601000, $$The Strategic Submarine & Weapon Systems Support program element directly supports the Navy's deterrence mission, specifically the Submarine Launched Ballistic Missile (SLBM). The SLBM is comprised of several key sub-systems, including launcher, navigation, missile, guidance, fire control, re-entry, platform integration, and instrumentation components. Nuclear Weapons Surety is also a critical element to safeguarding nuclear weapons within the Department of War. The SLBM accounts for approximately 70 percent of the deployable nuclear inventory, is the most survivable leg of the triad and foundational to the nation's deterrence strategy. Nuclear deterrence underwrites every U.S. military operation and capability on the globe and serves as the backstop for both our national defense and the defense of our allies. The nation's nuclear triad serves as the bedrock of our ability to deter aggression, assure our allies and partners, achieve U.S. objectives should deterrence fail, and hedge against an uncertain future.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
