INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0901202F$$, $$Joint Personnel Recovery Agency$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 2080000, 2158000, 2320000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0901202F"}$$::jsonb, $$Funding supports development of innovative capabilities to address Personnel Recovery in Large Scale Combat Operations, Multi-Domain Operations and anti-access/ area denial environments for Combatant Commanders and the Services. Joint personnel Recovery Agency [JPRA] developmental efforts address Personnel Recovery capability gaps and shortfalls identified in the Personnel Recovery Initial Capabilities Document approved by the Joint Requirements Oversight Council memorandum 120-12 on 8 Aug 2012, and subsequent supporting documents approved in the Joint Capabilities Integration Development System. Activities include funding for research and development, support equipment, contract services and all associated costs specifically identified to support the JPRA headquarters Ft. Belvoir, VA and other agency operating locations. Development and transition to sustainment of an enterprise level information data system [Personnel Recovery Information Data System [PRIDS] to enable DoD data management, analysis and collaboration. Funds also provide USAF Platform One/Cloud One housing for PRIDS. DODI 3002.1 directed JPRA capability. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.0M was expended for civilian pay expenses in this program element and in FY25 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0901202F / Joint Personnel Recovery Agency Operational Systems Development$$, NULL, 2140000, 2192000, 2235000, NULL, NULL, 286, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 2235000, 2051000, 2035000, 2035000, 0, 2035000, 2281000, $$Funding supports development of innovative capabilities to address Personnel Recovery in Large Scale Combat Operations, Multi-Domain Operations and anti-access/ area denial environments for Combatant Commanders and the Services. Joint personnel Recovery Agency [JPRA] developmental efforts address Personnel Recovery capability gaps and shortfalls identified in the Personnel Recovery Initial Capabilities Document approved by the Joint Requirements Oversight Council memorandum 120-12 on 8 Aug 2012, and subsequent supporting documents approved in the Joint Capabilities Integration Development System. Activities include funding for research and development, support equipment, contract services and all associated costs specifically identified to support the JPRA headquarters Ft. Belvoir, VA and other agency operating locations. Development and transition to sustainment of an enterprise level information data system [Personnel Recovery Information Data System [PRIDS] to enable DoD data management, analysis and collaboration. Funds also provide USAF Platform One/Cloud One housing for PRIDS. DODI 3002.1 directed JPRA capability. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.0M was expended for civilian pay expenses in this program element and in FY26 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0901202F / Joint Personnel Recovery Agency Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101226N$$, $$Submarine Acoustic War Dev$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 111401000, 95931000, 100667000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0101226N", "page_header": "Department of the Navy", "fy26_v182_disc_K": 47701, "fy26_v182_supp_K": 63700, "fy26_v182_total_K": 111401, "fy26_v182_note_name": "Submarine Acoustic Warfare Development Program", "fy26_v182_source_file": "RDTEN_BA7-8_Book.txt", "fy26_v182_source_line": 13472}$$::jsonb, NULL, NULL, 114817000, 103691000, 99806000, NULL, NULL, NULL, NULL, NULL, FALSE, 99201000, 111401000, 114279000, 114279000, NULL, 114279000, 102386000, $$The Submarine Acoustic Warfare (SAWS) Development Program develops acoustic countermeasures, submarine defense capabilities, external launch systems and all acoustic augmentation systems for the U.S. Navy submarines. The SAWS Development Program is comprised of Submarine Torpedo Defensive Systems (SubTDS) (MK 5 and MK 6), Submarine Tethered Expendable Buoy (STEB), Compact Rapid Attack Weapon (CRAW), Non-Traditional Acoustic Communications (NTAC), and Submarine Launched Unmanned Aerial System (SLUAS). The FY 2026 spend plan amount for Submarine Acoustic Warfare Development Program includes $47,701 thousand of discretionary and $63,700 thousand of mandatory (reconciliation) for a total of $111,401 thousand. Project 1265 Sub Defensive Warfare The Submarine Torpedo Defense System (SubTDS) program delivers advanced acoustic countermeasures to protect submarines against enemy torpedo threats through a phased development approach. ADC MK5: The primary focus is delivering full Internal Countermeasure Launcher (ICL) functionality fleet-wide through the Acoustic Device Countermeasure (ADC) MK5. This developmental contract, awarded in September 2018, is currently in Engineering and Manufacturing Development (E&MD) phase. The development follows a phased approach, beginning with Engineering Development Models (EDMs) before transitioning to fully functional test units for Developmental Testing (DT) and Operational Testing (OT). Upon successful completion of DT and OT, the program will proceed to Low-Rate Initial Production (LRIP). The ADC MK5 incorporates new adaptive technologies in a three-inch diameter form factor and will evolve through software/hardware upgrades, improved mobility, combat control system integration via ICL, and enhanced functionality to counter advancing torpedo threats. ADC MK6: Development of a six-inch acoustic countermeasure for External Countermeasure Launcher (ECL) deployment. The ADC MK6 will build upon the technological advancements developed by the ADC MK5 program. The MK6 Other Transaction Agreement (OTA) initiated development and prototyping efforts continuing through the Future Years Defense Program (FYDP). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                  Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational         PE 0101226N / Submarine Acoustic War Dev Systems Development PMS415 STEB effort supports development of power and communication capability to the internal countermeasure launcher via a stand-alone Temporary Alteration (TEMPALT). Project 1267 CRAW The FY 2027 budget supports development and delivery of a new very-lightweight torpedo to the submarine Force via the CRAW Technology Insertion 1 (TI-1) and Technology Insertion 2 (TI-2) acquisition programs. CRAW provides enhanced Anti-Submarine Warfare (ASW) and Anti-Torpedo Torpedo (ATT) mission capabilities. The CRAW TI-1 program rapidly delivers fieldable prototypes by modifying existing legacy hardware. This legacy hardware is no longer manufacturable, so the CRAW TI-2 program addresses obsolescence issues to establish an updated design baseline that is manufacturable by industry. Two incremental hardware Technology Insertions, TI-1 and TI-2, will be used to deliver developmental prototypes to support Engineering, Development, and Operational Testing. The ASW and ATT capabilities will be delivered via two Advanced Processor Build (APB) software spirals. The ASW capability will be part of APB-1 and the ATT capability will be included in APB-2. The CRAW TI-1 effort is being executed as a Middle Tier of Acquisition (MTA) effort and will rapidly develop fieldable prototypes to demonstrate the new very-lightweight torpedo ASW capabilities in an operational environment. Due to obsolescence there is a limited inventory of TI-1 systems. The TI-2 effort will update the TI-1 baseline to address obsolescence and improve producibility and supportability to enable production of additional inventory so that the CRAW capability can be fielded broadly across the submarine force. The TI-2 program is a post-Milestone B (MS-B) ACAT III Major Capability Acquisition Program. The TI-2 program is being phased with the TI-1 effort so that the TI-2 program can fully leverage the TI-1 prototypes as proof of design hardware. This will reduce overall cost of the TI-2 program as the TI-2 program will move into development of proof of manufacturing prototypes to support Development Testing. Low-Rate Initial Production (LRIP) units to support Operational Testing will also be delivered as part of TI-2. The CRAW program also includes development of submarine launcher system modifications to allow for launch capabilities from vertical and horizontal launch tubes. This will include the development of the Revolver horizontal launcher system that enables launch of multiple very- lightweight torpedoes from standard submarine torpedo tubes. The TI-1 program includes safety qualification testing, submarine integration, operational testing via Quick Reaction Assessment (QRA), and delivery of TI-1 Warshot prototypes. The FY27 budget also supports delivery of the initial TI-2 prototypes, TI-2 qualification testing, planning, development of the Anti-Torpedo Torpedo (ATT) software, development of modeling and simulation capabilities, and ordering material for Proof of Design units to support in-water engineering testing. Project 1268 NTAC NTAC provides advanced undersea acoustic communications across multiple platforms within the Navy. This program builds upon the baseline NTAC software capability and integrates the software components into existing hardware to expand the effectiveness and reliability of the capability. Additional details are available at the classified level. SLUAS extends the sensor range of the submarine. SLUAS sub-systems include the unmanned aerial vehicle (UAV), UAV encapsulating canister, UAV command and control capabilities, and onboard stowage. Funding supports development and testing of capability improvements that will be part of the next variant AUR. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0101226N / Submarine Acoustic War Dev Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604331J$$, $$Rapid Prototyping Program$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 0, 5665000, 7710000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 72, "original_pe": "0604331J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101316F$$, $$Worldwide Joint Strategic Communications$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 24081000, 23522000, 13690000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101316F"}$$::jsonb, $$Worldwide Joint Strategic Communication efforts include Nuclear Command, Control, and Communications (NC3) systems to include the Defense Injection Reception Emergency Action Message (EAM) C2 Terminals (DIRECT) and the Strategic Automated Command and Control System (SACCS). Funding may be used to modernize these, and other, NC3 systems. Funding may also be used for research, testing, validation, certification, configuration management, and assessment of the Air Force NC3 Weapon System. SACCS is a dedicated, high speed, multi-level secure, data transmission, processing, and display system. SACCS provides the primary non-survivable command and control capability for receiving and disseminating secure Emergency Action Messages (EAM), Force Direction Messages (FDM), Force Status Reporting (FSR), and exchanging information type messages from USSTRATCOM. SACCS provides messages for effective deployment of strategic bombers, reconnaissance aircraft, mobilization aircraft, tanker support aircraft, and the Intercontinental Ballistic Missile (ICBM) force to include Minuteman III (MM III) and Sentinel. SACCS has equipment that has reached its end of life and is no longer repairable due to diminished manufacturing sources and parts obsolescence. This jeopardizes Air Force Global Strike Command's (AFGSC) ability to meet mission requirements as required by Chairman Joint Chiefs of Staff Nuclear Technical Performance Criteria and Operational Standards (CJCSI 6811.01). In order to mitigate the risk of SACCS inability to operate once the current spares are completely diminished and ensure the system remains secure against modern/future threats, the Air Force is developing a replacement system (SACCS-R). SACCS-R is currently pursuing Technology Maturation and Risk Reduction (TMRR) efforts to transition from Time-Division Multiplexing (TDM) to Internet Protocol (IP) architecture, monitor and secure the new IP- based network, and provide requisite support to Sentinel fielding plans. This program element may include necessary civilian pay expenses required to manage, execute, and deliver SACCS capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101316F / Worldwide Joint Strategic Communications Operational Systems Development$$, NULL, 81270000, 75670000, 70300000, NULL, NULL, 165, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 13268000, 13364000, 44424000, 44424000, 0, 44424000, 56000000, $$Worldwide Joint Strategic Communication efforts include Nuclear Command, Control, and Communications (NC3) systems to include the Defense Injection Reception Emergency Action Message (EAM) C2 Terminals (DIRECT) and the Strategic Automated Command and Control System (SACCS). Funding may be used to modernize these, and other, NC3 systems. Funding may also be used for research, testing, validation, certification, configuration management, and assessment of the Air Force NC3 Weapon System. SACCS is a dedicated, high speed, multi-level secure, data transmission, processing, and display system. SACCS provides the primary non-survivable command and control capability for receiving and disseminating secure EAM, Force Direction Messages (FDM), Force Status Reporting (FSR), and exchanging information type messages from USSTRATCOM. SACCS provides messages for effective deployment of strategic bombers, reconnaissance aircraft, mobilization aircraft, tanker support aircraft, and the Intercontinental Ballistic Missile (ICBM) force to include Minuteman III (MM III) and Sentinel. SACCS has equipment that has reached its end of life and is no longer repairable due to diminished manufacturing sources and parts obsolescence. This jeopardizes Air Force Global Strike Command's (AFGSC) ability to meet mission requirements as required by Chairman Joint Chiefs of Staff Nuclear Technical Performance Criteria and Operational Standards (CJCSI 6811.01). In order to mitigate the risk of SACCS inability to operate once the current spares are completely diminished and ensure the system remains secure against modern/future threats, the Air Force is developing a replacement system (SACCS-R). SACCS-R is leveraging the Software Acquisition Pathway (SWP) to modernize its architecture through an agile and iterative approach. Key efforts include transitioning from Time-Division Multiplexing (TDM) to Internet Protocol (IP), implementing robust monitoring and security for the new network, and supporting the Sentinel fielding plans. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0101316F / Worldwide Joint Strategic Communications Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101318F$$, $$Service Support to STRATCOM - Global Strike$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 6928000, 7562000, 7330000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101318F"}$$::jsonb, $$The mission of USSTRATCOM is to deter strategic attack through a safe, secure, effective, and credible, global combat capability and, when directed, is ready to prevail in conflict. The command enables Joint Force operations and is the combatant command responsible for Strategic Deterrence, Nuclear Operations, Nuclear Command, Control, and Communications (NC3) Enterprise Operations, Joint Electromagnetic Spectrum Operations, Global Strike, Analysis and Targeting, and Missile Threat Assessment. USSTRATCOM integrates and coordinates the necessary command and control capability to provide support with the most accurate and timely information for the President, the Secretary of Defense, other national leadership and combatant commanders. The Nation's strategic C2 sensors, and mission planning programs cannot rapidly exchange information across multiple missions creating ambiguity that delays time critical national C2 decision making processes. GDI developed and established a unified schema that integrates disparate Missile Warning/Missile Defense (MW/MD), Technical Intelligence (TI) and other data into a single, exposed data set, providing redundant and unambiguous Situational Awareness data to national leadership. GDI also enables existing radars and sensors to provide data in net-centric formats consumable by other authorized systems and mission areas, thus reducing the need to acquire more systems. Activities also include studies and analysis to support current program planning, execution, and future program planning. GDI directly supports USSTRATCOM and other Combatant Command and MAJCOM mission sets. GDI meshes together selected systems and sensors (from tactical to strategic), including the Nation's most modern and capable assets, taking advantage of their larger numbers, improved algorithms, mobility, and forward deployment to provide earlier cross-cueing and expanded decision space when every second counts. Repurposing these traditionally stove-piped systems and sensors, GDI enables the warfighter in several ways. GDI enables creation of a User Defined Operating Picture (UDOP) to provide a single, unambiguous missile event picture allowing real- time collaboration for nuclear C2 and improved senior leader situational awareness (SA) for effective decision-making. GDI also improves Space Situational Awareness (SSA) by tapping additional sensor capability and provides this data for the larger space order of battle capabilities. GDI dramatically improves the ingestion of non- traditional, but readily available, non-US government and commercial data to the United States Space Force (USSF) satellite catalog. GDI addresses NORTHCOM/ STRATCOM's signed Joint Emergent Operational Need (JEON) ST-0010 request for uninterrupted traditional and non-traditional sensor data integration and the Global Threat Characterization Assessment (GTCA) Operational Planning Team report. Finally, GDI provides Data Analysis functions to optimize and operate situational awareness in the field, including units operating in Denied-Disconnected, Intermittent, Limited (D-DIL) and emissions controlled (EMCON) conditions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0101318F / Service Support to STRATCOM - Global Strike Operational Systems Development Leveraging the appropriate acquisition authorities and contract mechanisms to deliver capability sooner, USSTRATCOM will strategically execute experimentation, prototyping, risk reduction, and other efforts to develop new or repurpose capabilities. GDI may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability but the civilian pay is expended from program element 0101890F. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 7356000, 7495000, 7638000, NULL, NULL, 166, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 7062000, 6833000, 56203000, 56203000, 0, 56203000, 7793000, $$The mission of USSTRATCOM is to deter strategic attack through a safe, secure, effective, and credible, global combat capability and, when directed, is ready to prevail in conflict. The command enables Joint Force operations and is the combatant command responsible for Strategic Deterrence, Nuclear Operations, Nuclear Command, Control, and Communications (NC3) Enterprise Operations, Joint Electromagnetic Spectrum Operations, Global Strike, Analysis and Targeting, and Missile Threat Assessment. USSTRATCOM integrates and coordinates the necessary command and control capability to provide support with the most accurate and timely information for the President, the Secretary of War, other national leadership and combatant commanders. The Nation's strategic C2 sensors, and mission planning programs cannot rapidly exchange information across multiple missions creating ambiguity that delays time critical national C2 decision making processes. GDI developed and established a unified schema that integrates disparate Missile Warning/Missile Defense (MW/MD), Technical Intelligence (TI) and other data into a single, exposed data set, providing redundant and unambiguous Situational Awareness data to national leadership. GDI also enables existing radars and sensors to provide data in net-centric formats consumable by other authorized systems and mission areas, thus reducing the need to acquire more systems. Activities also include studies and analysis to support current program planning, execution, and future program planning. GDI directly supports USSTRATCOM and other Combatant Command and MAJCOM mission sets. GDI meshes together selected systems and sensors (from tactical to strategic), including the Nation's most modern and capable assets, taking advantage of their larger numbers, improved algorithms, mobility, and forward deployment to provide earlier cross-cueing and expanded decision space when every second counts. Re-purposing these traditionally stove-piped systems and sensors, GDI enables the warfighter in several ways. GDI enables creation of a User Defined Operating Picture (UDOP) to provide a single, unambiguous missile event picture allowing real- time collaboration for nuclear C2 and improved senior leader situational awareness (SA) for effective decision-making. GDI also improves Space Domain Awareness (SSA) by tapping additional sensor capability and provides this data for the larger space order of battle capabilities. GDI dramatically improves the ingestion of non- traditional, but readily available, non-US government and commercial data to the United States Space Force (USSF) satellite catalog. GDI addresses NORTHCOM/ STRATCOM's signed Joint Emergent Operational Need (JEON) ST-0010 request for uninterrupted traditional and non-traditional sensor data integration and the Global Threat Characterization Assessment (GTCA) Operational Planning Team report. Finally, GDI provides Data Analysis and fusion functions to optimize and operate situational awareness in the field, including units operating in Denied-Disconnected, Intermittent, Limited (D-DIL) and emissions controlled (EMCON) conditions. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0101318F / Service Support to STRATCOM - Global Strike Operational Systems Development Leveraging the appropriate acquisition authorities and contract mechanisms to deliver capability sooner, USSTRATCOM will strategically execute experimentation, prototyping, risk reduction, and other efforts to develop new or repurpose capabilities. GDI may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability but the civilian pay is expended from program element 0101890F. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101328F$$, $$ICBM Reentry Vehicles$$, $$rdte_af_ba7$$, $$afnwc_nd$$, 2026, 359605000, 452306000, 392423000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0101328F"}$$::jsonb, $$The Intercontinental Ballistic Missile (ICBM) Reentry Vehicles (RVs) activity will design, develop, produce, and deploy advanced countermeasures and integrated RV systems capable of delivering the W87-1 warhead and future warheads when released from ICBM weapon systems. The Mk21A program will meet the requirements laid out in the LGM-35A Sentinel weapon system Capability Development Document (CDD) as directed by Air Force Global Strike Command and will provide needed performance and security enhancements over the Mk21 RV to meet the upgraded requirements for the Department of Energy (DOE)/ National Nuclear Security Administration (NNSA) W87-1 warhead. The Mk21A RV includes: shape-stable nose tip; high-impulse transducer; arming and fuzing subsystem (AFS); aeroshell forward section, body section, and rear cover; radio frequency subsystem with antennas; RV spin subsystem; in-flight disconnect cable; and other electrical cables. The Next Generation Reentry Capabilities (NGRC) program will ensure ICBM weapon systems continue to meet reentry performance requirements in an evolving threat landscape by leveraging advanced technologies matured by the Research & Development (R&D) and ICBM Demonstration/Validation communities in support of the Air Force's Reentry Vehicle Strategy. Future NGRC solutions will include acquisition and integration of complementary advanced countermeasures and Next Generation Reentry Vehicle (NGRV). The FY 2026 request for ICBM Reentry Vehicles includes 259,605 thousand of discretionary and 100,000 thousand of mandatory (reconciliation) for a total of 359,605 thousand. The mandatory funds continue advancing major RV acquisition activities. Further information for this reconciliation request is provided in Section 20008 (Nuclear) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 1.249M was expended for civilian pay expenses in this program element, and in FY 2025 5.104M is forecasted for civilian pay expenses in this program element. All FY 2024 and 2025 civilian pay expenses will be executed in BPAC 675920 - Next Generation Reentry Capabilities. This program element utilized FY24 4.325M for a Rapid Acquisition Authority requirement. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0101328F / ICBM Reentry Vehicles Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 1053256000, 1152009000, 1484146000, NULL, NULL, 167, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 378983000, 256758000, 733182000, 733182000, 0, 733182000, 1362846000, $$The Intercontinental Ballistic Missile (ICBM) Reentry Vehicles (RVs) activity will design, develop, produce, and deploy advanced countermeasures and integrated RV systems capable of delivering the W87-1 warhead and future warheads when released from ICBM weapon systems. The Mk21A program will meet the requirements laid out in the LGM-35A Sentinel weapon system Capability Development Document (CDD) as directed by Air Force Global Strike Command and will provide needed performance and security enhancements over the Mk21 RV to meet the upgraded requirements for the Department of Energy (DOE)/ National Nuclear Security Administration (NNSA) W87-1 warhead. The Mk21A RV includes: shape-stable nose tip; high-impulse transducer; arming and fuzing subsystem (AFS); aeroshell forward section, body section, and rear cover; radio frequency subsystem with antennas; RV spin subsystem; in-flight disconnect cable; and other electrical cables. In FY2026, BPAC 675920, Next Generation Reentry Capabilities (NGRC) encompassed efforts to design, develop, produce, and deploy new payload system suites (reentry vehicles and/or capabilities) In FY2027, BPAC 675920 was renamed Advanced Capability for Missile Enhancement (ACME), along with the creation of BPAC 675921 Next Generation Reentry Vehicle (NGRV), providing visibility of these major thrusts. NGRC funding stayed within BPAC 675920. NGRV will ensure ICBM weapon systems continue to meet reentry performance requirements in an evolving threat landscape by leveraging advanced technologies matured by the Research & Development (R&D) and ICBM Demonstration/Validation communities in support of the Air Force's Reentry Vehicle Strategy. Future NGRV solutions will include acquisition and integration of advanced reentry capabilities and complementary countermeasures. ACME supports enhancements to ICBM operations. More information is available at higher classification levels. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:         PE 0101328F / ICBM Reentry Vehicles Operational Systems Development The FY 2026 spend plan amount for Research, Development, Test & Evaluation includes $256,758 thousand of discretionary and $100,000 thousand of mandatory (reconciliation) for a total of $356,758 thousand. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205675N$$, $$Operational Nuclear Power Systems$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 209200000, 150790000, 167098000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0205675N", "page_header": "Department of the Navy", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, 252893000, 252893000, NULL, 252893000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
