INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101402N$$, $$Navy Strategic Comms$$, $$rdte_navy_ba7$$, $$dw_osd$$, 2026, 52404000, 49362000, 29743000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0101402N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 65071000, 51732000, 37194000, NULL, NULL, NULL, NULL, NULL, FALSE, 28915000, 52404000, 88572000, 88572000, NULL, 88572000, 37982000, $$The details of program element 0101402N Project 1083 are classified and are submitted to Congress in the classified budget justification books. Special Handling Statement: This exhibit contains NC3-N material within it and shall be developed, stored, and transmitted on classified networks in accordance with SPAWAR ltr 5510 Ser 00/245 19 April 2018. Project 3002:The E-6 is a manned airborne platform that provides survivable, endurable and reliable Command, Control and Communications capability in support of the President, Secretary of Defense and United States strategic and non-strategic forces. In order to respond effectively to emerging capability requirements, continued effort is needed to perform technical evaluations, modeling and simulation, investigative ground and flight testing, enhanced software modifications and development of configuration modifications. Funding is for operational mission analysis and hardware/software engineering required to optimize E-6 systems for cyber security and interoperability in a strategic environment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
