INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L063$$, $$DTRA Cyber Activities$$, $$proc_dw_0300_ba1$$, $$dw_dtra$$, 2026, 12023000, 12787000, 8783000, NULL, $${"page": 167, "ba_num": "01", "source": "p1_fy26", "ba_name": "Major equipment", "line_no": "63", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "01", "p1_li": 42}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 42, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 1800, "fy26_supp_K": 0, "fy26_total_K": 1800, "name_partial": "DTRA Cyber Activities"}, "fy26t_qty": null, "fy26d_cost": 12023000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 1800000, 900000, 900000, 0, 900000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_DTRA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0102110F$$, $$MH-139A$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 5982000, 25464000, 15000000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0102110F"}$$::jsonb, $$The MH-139A Grey Wolf will replace the Air Force fleet of UH-1N aircraft, and offers a significant capability increase in areas of speed, range, endurance, payload, and survivability. Funding provides replacement aircraft with vertical airlift and supports requirements for Air Force Global Strike Command (AFGSC) and Air Force Reserve Command (AFRC). AFGSC is the Air Force lead command and operational capability requirements sponsor. The MH-139A Grey Wolf program is an element of the Air Force's nuclear enterprise reform initiatives. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, $2.750 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0102110F / MH-139A Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 169, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 14679000, 5900000, 7046000, 7046000, 0, 7046000, 0, $$The MH-139A Grey Wolf will replace the Air Force fleet of UH-1N aircraft, and offers a significant capability increase in areas of speed, range, endurance, payload, and survivability. Funding provides replacement aircraft with vertical airlift and supports requirements for Air Force Global Strike Command (AFGSC) and Air Force Reserve Command (AFRC). AFGSC is the Air Force lead command and operational capability requirements sponsor. The MH-139A Grey Wolf program is an element of the Air Force's nuclear enterprise reform initiatives. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0102326F$$, $$Region/Sector Operation Control Center Modernization Program$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 726000, 831000, 852000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0102326F"}$$::jsonb, $$The Regional/Sector Operation Center Modernization program supports the North American Aerospace Defense Command (NORAD)/ US Northern Command (USNORTHCOM) homeland defense and air sovereignty mission for fixed Air Defense Sectors. BATTLE CONTROL SYSTEM-FIXED (BCS-F): BCS-F is a bi-national development program with Canada. The BCS-F Program is a USAF Homeland Defense battle management command and control system with the capability to integrate data from existing and future civil and military defense surveillance systems into a comprehensive air picture. BCS-F provides tactical communications and data link capabilities with other military and civil systems responsible for planning, directing, coordinating and controlling forces for air surveillance, air defense, and control of sovereign US air space. This integrated air picture enhances the capability to conduct peacetime air sovereignty operations and transition to active air defense operations in the event of aggression. BATTLE CONTROL SYSTEM-FIXED MODIFICATION ONE (BCS-F Modification 1): BCS-F Modification 1 effort will support the implementation of Earth Center Earth Fixed (ECEF). The BCS-F Modification 1 effort is executed as a Cooperative Development Program between the US and Canada. This program aligns with Air Battle Management System (ABMS) Cloud-Based Command and Control (CBC2) (0604003F), which is planned to replace BCS-F as the Air Defense Sectors' C2 system of record. Activities in this FY are planned overlap with ABMS CBC2 to minimize operational risk during the transition. NATIONAL CAPITOL REGION - INTEGRATED AIR DEFENSE SYSTEM (NCR-IADS): NCR-IADS is a post-September 11, 2001 rapidly fielded capability that provides ground-based air defense of the NCR airspace by delivering an integrated air picture, air defense weapons, enhanced regional situational awareness, and forensic data collection capabilities. Life cycle replacement will be required to prevent system obsolescence, account for new cyber security requirements, and posture the program to seamlessly integrate future capabilities. Reduces contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.000M was expended for civilian pay expenses in this program element and in FY26 $0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0102326F / Region/Sector Operation Control Center Modernization Program Operational Systems Development This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute and deliver Battle Control Systems-Fixed Modification 1. The use of such programs would be in addition to the civilian pay expenses budgeted in program element 0102326F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 735000, 749000, 762000, NULL, NULL, 170, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 839000, 722000, 709000, 709000, 0, 709000, 778000, $$The Regional/Sector Operation Center Modernization program supports the North American Aerospace Defense Command (NORAD)/ US Northern Command (USNORTHCOM) homeland defense and air sovereignty mission for fixed Air Defense Sectors. BATTLE CONTROL SYSTEM-FIXED (BCS-F): BCS-F is a bi-national development program with Canada. The BCS-F Program is a USAF Homeland Defense battle management command and control system with the capability to integrate data from existing and future civil and military defense surveillance systems into a comprehensive air picture. BCS-F provides tactical communications and data link capabilities with other military and civil systems responsible for planning, directing, coordinating and controlling forces for air surveillance, air defense, and control of sovereign US air space. This integrated air picture enhances the capability to conduct peacetime air sovereignty operations and transition to active air defense operations in the event of aggression. BATTLE CONTROL SYSTEM-FIXED MODIFICATION ONE (BCS-F Modification 1): BCS-F Modification 1 effort will support the implementation of Automatic Dependent Surveillance Broadcast (ADS-B). The BCS-F Modification 1 effort is executed as a Cooperative Development Program between the US and Canada. This program aligns with Air Battle Management System (ABMS) Cloud-Based Command and Control (CBC2) (0604003F), which is planned to replace BCS-F as the Air Defense Sectors' C2 system of record. Activities in this FY are planned overlap with ABMS CBC2 to minimize operational risk during the transition. NATIONAL CAPITOL REGION - INTEGRATED AIR DEFENSE SYSTEM (NCR-IADS): NCR-IADS is a post-September 11, 2001 rapidly fielded capability that provides ground-based air defense of the NCR airspace by delivering an integrated air picture, air defense weapons, enhanced regional situational awareness, and forensic data collection capabilities. Life cycle replacement will be required to prevent system obsolescence, account for new cyber security requirements, and posture the program to seamlessly integrate future capabilities. Reduces contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0102326F / Region/Sector Operation Control Center Modernization Program Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0102417F_ba5$$, $$Over-the-Horizon Backscatter Radar$$, $$rdte_af_ba5$$, $$afrl_ry$$, 2026, 0, 471042000, 377394000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0102417F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0102417F_ba7$$, $$Over-the-Horizon Backscatter Radar$$, $$rdte_af_ba7$$, $$afrl_ry$$, 2026, 202697000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0102417F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605118OTE$$, $$Operational Test and Evaluation (OT&E)$$, $$rdte_ote_ba6$$, $$dw_dote$$, 2026, 133542000, 135847000, 136226000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 84, "original_pe": "0605118OTE", "page_header": "Defense-Wide"}$$::jsonb, $$The Office of the Director, Operational Test and Evaluation (DOT&E) was created by Congress in 1983. The Director is prescribed, by authority of the Secretary of Defense, policies and procedures for the conduct of operational test and evaluation (OT&E) in the Department of Defense (DoD). The Director provides guidance to and consults with the Secretary of Defense, the Under Secretary of Defense for Acquisition and Sustainment, and the Under Secretary of Defense for Research and Engineering, and the Service Secretaries with respect to OT&E. DOT&E's oversight list fluctuates, but generally has around 250 programs, including Major Defense Acquisition Programs (MDAP) and programs from across each of the six adaptive acquisition pathways. Programs identified as MDAPs for the purposes of test and evaluation may not proceed beyond low-rate initial production (BLRIP) until OT&E of the program is complete. DOT&E is involved early in the planning phase of each program to ensure adequate testing is planned and executed. Key elements of DOT&E's oversight authority include: - Approval of component Test and Evaluation Master Plans (TEMPs). - Approval of component OT&E test plans (TPs). - Oversight of military department preparation for and conduct of field operational tests; analysis and evaluation of the resultant test data; the assessment of the adequacy of the executed test and evaluation; and assessment of the operational effectiveness, suitability, and survivability of the defense business and weapon systems. - Reporting results of OT&E that support BLRIP decisions to the Secretary of Defense and Congress, and providing an annual report summarizing all OT&E activities and the adequacy of test resources within the DoD during the previous fiscal year. - Review of DoD budgets and financial matters related to OT&E, and recommendations to the Secretary of Defense on all matters relating to operational test facilities and equipment. DOT&E also oversees and resources OT&E community efforts to plan and execute joint cybersecurity assessments of fielded systems and networks during major combatant command (CCMD) and Service exercises, and reports the trends and findings in the annual report. DOT&E is also involved in assessing and increasing the capacity of realistically advanced cyber warfighting capabilities to keep pace with heightened demand, advancing technologies, and the growing cyber threat. DOT&E funded cyber assessments provide assistance for the remediation of mission-critical vulnerabilities as rapidly as possible. This Program Element includes funds to obtain Federally Funded Research and Development Center (FFRDC) support in performing the described tasks, travel funds to carry out oversight of the OT&E and cyber assessment programs, funds for Service teams performing information assurance and interoperability assessments during exercises, administrative support services, DFAS support, and engineering and technical support services. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Operational Test and Evaluation, Defense                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0460: Operational Test and Evaluation, Defense / BA 6: RDT&E Management      PE 0605118OTE / Operational Test and Evaluation (OT&E) Support$$, NULL, 127865000, 130512000, 133280000, NULL, NULL, 1, $$RDTE_OTE_PB_2026.pdf$$, $$OT&E$$, FALSE, 136226000, 151542000, 101365000, 101365000, NULL, 101365000, 136106000, $$The Office of the Director, Operational Test and Evaluation (DOT&E) was created by Congress in 1983. The Director is prescribed, by authority of the Secretary of War, policies and procedures for the conduct of operational test and evaluation (OT&E) in the Department of War (DoW). The Director provides guidance to and consults with the Secretary of War, the Under Secretary of War for Acquisition and Sustainment, the Under Secretary of War for Research and Engineering, and the Service Secretaries with respect to OT&E. DOT&E's provides oversight to a wide range of the Department’s acquisitions programs, including Major Defense Acquisition Programs (MDAPs) and programs from across each of the six adaptive acquisition pathways . Programs identified as MDAPs for the purposes of test and evaluation may not proceed beyond low-rate initial production (BLRIP) until initial OT&E of the program is complete. DOT&E is involved early in the planning phase of each program to ensure adequate testing is planned and executed. Key elements of DOT&E's oversight authority include: - Approval of component Test and Evaluation Master Plans (TEMPs). - Approval of component OT&E test plans (TPs). - Oversight of military department preparation for and conduct of field operational tests; analysis and evaluation of the resultant test data; the assessment of the adequacy of the executed test and evaluation; and assessment of the operational effectiveness, suitability, and survivability of the defense business and weapon systems. - Reporting results of OT&E that support BLRIP decisions to the Secretary of War and Congress, and providing an annual report summarizing all OT&E activities and the adequacy of test resources within the DoW during the previous fiscal year. - Review of DoW budgets and financial matters related to OT&E, and recommendations to the Secretary of War on all matters relating to operational test facilities and equipment. DOT&E also oversees and resources OT&E community efforts to plan and execute joint operational evaluations of information assurance (cyber survivability) and interoperability of fielded systems and networks during major Combatant Command (CCMD) and Service exercises. DOT&E reports the mission-focused trends and findings in the annual report and provides a mission risk assessment each fiscal year. DOT&E also supports efforts to increase the capacity for assessments of advanced cyber warfighting capabilities, to keep pace with heightened demand for those capabilities, advancing technologies, and the growing cyber threat. DOT&E- funded cyber assessments help with the remediation of mission-critical vulnerabilities as rapidly as possible. This Program Element includes funds to obtain Federally Funded Research and Development Center (FFRDC) support in performing the described tasks, travel funds to carry out oversight of the OT&E and cyber assessment programs, funds for Service teams performing information assurance and interoperability assessments during exercises, administrative support services, Defense Finance and Accounting Service support, and engineering and technical support services. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Operational Test and Evaluation, Defense                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0460: Operational Test and Evaluation, Defense / BA 6: RDT&E Management      PE 0605118OTE / Operational Test and Evaluation (OT&E) Support$$, $$Budget J-Books/FY27/Remaining/RDTE_OTE_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
