INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207423F$$, $$Advanced Communications Systems$$, $$rdte_af_ba4$$, $$aflcmc_hn$$, 2026, 5500000, 0, 0, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207423F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604122D8Z$$, $$JADC2 Development and Experimentation Activities$$, $$rdte_dw_ba6$$, $$dw_cdao$$, 2026, 297801000, 359056000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 74, "original_pe": "0604122D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 293597, "fy26_v182_supp_K": 275000, "fy26_v182_total_K": 568597, "fy26_v182_note_name": "JADC2 Development and Experimentation Activities", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 37854}$$::jsonb, $$The Chief Digital and Artificial Intelligence Officer (CDAO) mission is to accelerate DoD adoption of data, analytics, and artificial intelligence (AI) to enable decision advantage from the boardroom to the battlefield. This includes improving CJADC2 in support of the Joint Warfighting Concept through four lines of effort: -Open DAGIR: The CDAO created the Open DAGIR acquisition approach to secure government data rights, ensure open application programming interfaces (APIs), and implement open systems best practices in the acquisition of commercial software. CDAO applies Open DAGIR to the procurement of government-owned/ contractor-operated data stacks. This enables interoperability across data stacks, and allows third party application developers to build software that can access relevant mission data in and across those Joint interoperable data stacks. Open DAGIR is not a specific technical solution, but an acquisition approach CDAO applies to procurement of data, analytics, and AI capabilities across vendors. -Data Integration Layer (085): These efforts mature management of DoD operational data and deploy a tactical edge data mesh (EDM) to enable data integration among new and legacy systems. EDM is a resilient, interoperable data integration service connecting sensors, weapons, and other battlefield assets for enhanced situational awareness and coordination into a cloud environment. EDM leverages commercial software, a government-owned software development kit (SDK), and open application programming interfaces (APIs) to integrate government and vendor systems, facilitate tactical data sharing, and incorporate artificial intelligence/machine learning (AI/ Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                                  Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:          PE 0604122D8Z / JADC2 Development and Experimentation Activities RDT&E Management Support ML) capabilities at the edge. EDM supports multi-domain operations across echelons, including enhanced C2 and fires in contested environments by optimizing data exchange among Denied, Disrupted, Intermittent, and Limited (DDIL) communication paths. -Mission Command Applications (668): This effort integrates data, analytics, and AI in support of the seven Joint warfighting functions leveraging a common government owned/contractor operated data stack that adheres to Open DAGIR principles. Requested funding purchases licenses for Combatant Command (CCMD) and Joint Staff access to Maven Smart System (MSS) on multiple networks, engineering support to integrate new data sources and digitize workflows, maintenance of a DevSecOps pipeline to allow third party vendors to develop and field applications on MSS, funding for those third party vendors to close CJADC2 gaps, and cloud compute costs needed to run applications and workflows. -Global Experimentation (669): The Global Information Dominance Experimentation (GIDE) series is an iterative, metrics-based approach to experimentation with Combined Joint All-Domain Command and Control (CJADC2) capabilities and concepts. The experimentation series leverages CCMD and Service exercises, as well as smaller data integration sprints, to test new data integrations and digital workflows in the context of real mission use cases, on live networks, and with real data and users. Capabilities that prove successful in GIDE rapidly field to warfighters on the spot because they are software-based. GIDE workflows include cross-CCMD strategic and operational global integration, CCMD and Service workflows, and tactical-to-operational fires workflows in coordination with the Services. This line also supports funding to recruit, train, educate, and enable the DoD workforce to adopt digital CJADC2 capabilities, concepts, and workflows.$$, NULL, 2019011000, 2078776000, 2080984000, NULL, NULL, 164, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 271605000, 568597000, 2109895000, 2109895000, NULL, 2109895000, 2094017000, $$The Chief Digital and Artificial Intelligence Officer (CDAO) mission is to accelerate DoW adoption of data, analytics, and artificial intelligence (AI) to enable decision advantage from the boardroom to the battlefield. This includes improving CJADC2 in support of the Joint Warfighting Concept through three lines of effort: -Data Integration Layer: These efforts mature management of DoW operational data and deploy a tactical edge data mesh (EDM) to enable data integration among new and legacy systems. EDM is a resilient, interoperable data integration service connecting sensors, weapons, and other battlefield assets for enhanced situational awareness and coordination into a cloud environment. EDM leverages commercial software, a government-owned software development kit (SDK), and open application programming interfaces (APIs) to integrate government and vendor systems, facilitate tactical data sharing, and incorporate artificial intelligence/machine learning (AI/ ML) capabilities at the edge. EDM supports multi-domain operations across echelons, including enhanced C2 and fires in contested environments by optimizing data exchange among Denied, Disrupted, Intermittent, and Limited (DDIL) communication paths. -Mission Command Applications: This effort integrates data, analytics, and AI in support of the seven Joint warfighting functions leveraging a common government owned/contractor operated data stack that adheres to open architecture principles. Requested funding purchases licenses for access to Joint commercial software tools for Joint Force and Services on multiple networks, engineering support to integrate new data sources and digitize workflows, maintenance of a DevSecOps pipeline to allow third party vendors to develop and field applications on shared digital infrastructure, funding for those third party vendors to close CJADC2 gaps, and cloud compute costs needed to run applications and workflows. -Global Experimentation: This effort supports experimentation efforts for Joint Command and Control (C2) capabilities leveraging CCMD and Service exercises. Experiments evaluate data integrations and digital workflows in the context of real mission use cases, on live networks, and with real data and users. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                           R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:    PE 0604122D8Z / JADC2 Development and Experimentation Activities RDT&E Management Support The FY 2026 spend plan amount for JADC2 Development and Experimentation Activities includes $293,597 thousand of discretionary and $275,000 thousand of mandatory for a total of $568,597 thousand.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207605F$$, $$Wargaming and Simulation Centers$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 11894000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207605F"}$$::jsonb, $$In FY2026, no requirement. In FY2025, no requirement. In FY2024: The Distributed Mission Operations Center (DMOC) provides comprehensive Live, Virtual, and Constructive (LVC) simulation capabilities which prepare warfighters to conduct Joint All-Domain Command & Control (JADC2) operations in air, land, sea, space, and cyber domains for theater-level, full spectrum combat training for Air Force, joint service, and coalition partners. The DMOC training capabilities reach over 40 geographically separated Live, Virtual, and Constructive (LVC) locations across 17 time zones representing such assets as real-world weapon systems, operator-in-the-loop, and constructive or computer-driven simulations. DMOC is responsible for development and integration of scenarios, models, and databases and the integration of participating sites into Virtual Flag (VF) and other Distributed Mission Operations (DMO) training events via numerous network connections, DMOC-developed interoperability tools, and controlled interfaces in support of Air Force, joint, and coalition warfighter readiness. In addition, activities include DMO technology and capability studies/analyses which support both current and future program planning and execution by: 1. Distributed Mission Operations Capability/Battlespace Systems Development: The DMOC upgrades and enhances the capabilities of various systems, tools, and simulators to incorporate emerging technology and training requirements into DMO events, such as Virtual Flag (VF) and VF: Coalition (VF:C), to enhance the quality of warfighter training. Activities include Environment Generator development, DMO Tool Development, and Simulator Enhancement. DMOC is in partnership with the US Naval Air Warfare Center-Aircraft Division (NAWCAD) to enhance the capabilities of the Next Generation Threat System (NGTS). The NGTS is the primary environment generator for both Blue and Red Air in DMOC White Force. DMO Tool development includes: a) DMOC Replay Tool (DRT), which facilitates a more complete mission review and debrief capability of the exercises as more sites and systems are added to events; b) enhancement & improvement of the Distributed Interactive Simulation (DIS) Filter and the Doctor-J (Dr. J) tools to enable tactical datalinks to be communicated and translated between disparate simulator and operationally fielded (i.e. live aircraft) communication formats; c) Development of Intelligence, Surveillance, and Reconnaissance (ISR)/Battle Damage Assessment (BDA) to improve damage state models used by intelligence analysts in exercises; and d) development of solutions for integrating Contested Degraded Operations Gateway (CDOG, geographical and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0207605F / Wargaming and Simulation Centers Operational Systems Development communications jamming) into DMO events; and simulator enhancement efforts to incorporate Mission Package standards upgrades into the Control and Reporting Center (CRC) Simulation Package (CSP) to allow a real-world system to be used as a simulator when needed in DMO events. 2. Assessment & Authorization (A&A)/Software Certification: The DMOC supports cybersecurity requirements definition, integration/test support, analysis, systems engineering support, A&A of core systems, and support software certification. The DMOC implements cybersecurity requirements and complies with the application of the Risk Management Framework (RMF) and Continuous Monitoring. Efforts include Cross-Domain Information Sharing / Multi-national Information Sharing (CDIS/ MNIS) ruleset development, load sharing, and testing; integration and testing of various newly developed / updated systems such as the DMOC Replay Tool, Dr. J, DIS Filter, and the DMOC Battlespace; support of Air Force Network Integration Center (AFNIC) software certification. 3. Distributed Training Sites & Systems Integration: DMOC integrates over 40 geographically separated LVC training locations and 50+ systems into LVC DMO training events such as VF and VF:C by resolving interoperability issues between disparate systems and networks so that all exercise participants can interact in the DMO environment. New sites and systems are incorporated into LVC DMO events each year based on higher headquarters and Combatant Commander's (CCDRs) emerging requirements. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Joint Training Center (JTC): Adds training and test capability to 5th generation operation readiness, scales up the Joint Simulation Environment (JSE), and increases operational training capability at Elmendorf AFB. This is not a new start. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, NULL, NULL, NULL, NULL, NULL, 207, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208053A$$, $$Joint Tactical Ground System$$, $$rdte_army_ba7$$, $$asa_alt_alt$$, 2026, 0, 477000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0208053A", "page_header": "Department of the Army"}$$::jsonb, $$JTAGS transitioned to US Space Force in Fiscal Year 2024 (FY2024). The Joint Tactical Ground Station (JTAGS) is a post-production, Acquisition Category (ACAT) III program. JTAGS provides missile warning message data for the Air and Missile Defense (AMD) architecture and improves performance for Integrated Air and Missile Defense Fire Control Systems/Composite Army Air and Missile Defense Brigades. JTAGS disseminates near real time warning, alerting, and cueing information on ballistic missile launches and other tactical events of interest throughout the theater using existing communication networks, providing critical support to Combatant Commanders in their Areas of Responsibility (AOR). Four outside the continental United States (OCONUS) deployed JTAGS units, which are deployed in three theaters (United States Pacific Command (PACOM), United States Central Command (CENTCOM), United States European Command (EUCOM)), constitute DoD's only in-theater system providing space-based missile warning. The fifth CONUS system is used as an institutional trainer but is available as a deployable asset. JTAGS is designated as the in-theater element of the United States Strategic Command's Theater Event System (TES), supporting all Theater Missile Defense pillars, affording the shortest sensor-to-shooter connectivity. On 14 January 2016, the Army Acquisition Executive designated the JTAGS Pre-Planned Product Improvement (JTAGS P3I) program as a separate ACAT III modification program. The JTAGS Program Element (PE) supports development and testing of the JTAGS Block II Preplanned Product Improvements (P3I) program based on the JTAGS Operational Requirements Document (ORD), additive Joint Requirements Oversight Council - Memorandum (JROC-M) requirements, and the formal JTAGS Block II Capability Development Document (CDD) thresholds. P3I upgraded JTAGS to a Block II configuration for operation with the next generation of Space Based Infrared System (SBIRS) satellites, and improved warning tactical parameters and timeliness. The JTAGS Block II P3I program based on the 2009 JTAGS ORD is on contract as a two-phase development effort. JTAGS Block II P3I Phase 1 is complete. The final developmental efforts of JTAGS Block II P3I Phase 2 to achieve 2009 ORD requirements completed in FY2022. Follow-on Test and Evaluation (FOTE) completed in FY2022 with Materiel Release efforts to be conducted in FY2023. The JTAGS Block II CDD addresses evolving User-driven needs such as emerging threats and interface efforts that were not known at the time the JTAGS ORD was validated. There is no funding in this line in FY26. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational   PE 0208053A / Joint Tactical Ground System Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 226, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0104159D8Z$$, $$Golden Dome - Directed Energy System Development, Integration and Assessment$$, $$rdte_gd_ba3$$, $$afrl_rd$$, 2026, 0, 0, 0, NULL, $${"ba": "03", "line": 11, "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 142000, "fy27_disc": 0, "fy27_mand": 452000, "fy26_total": 142000, "fy27_total": 452000, "appropriation": "3007D"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 11, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, $$GDAF$$, FALSE, 0, 142000000, 0, 0, 452000000, 452000000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207159D8Z$$, $$Golden Dome for America - Air Force$$, $$rdte_gd_ba3$$, $$dw$$, 2026, 0, 0, 0, NULL, $${"ba": "03", "line": 13, "note": "AF-tagged but Golden Dome appr; BA-01/BA-02 lines also exist, captured here is RDT&E BA-03 only", "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 182800, "fy27_disc": 0, "fy27_mand": 615000, "fy26_total": 182800, "fy27_total": 615000, "appropriation": "3007D"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 13, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, $$GDAF$$, FALSE, 0, 182800000, 0, 0, 615000000, 615000000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0101113F$$, $$B-52 Squadrons$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 931164000, 880341000, 1051116000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "fy27_mand_k": 101100, "original_pe": "0101113F", "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Air Superiority"}$$::jsonb, $$The B-52 is a long-range bomber capable of delivering the widest variety of nuclear and conventional standoff and direct attack munitions in the Air Force. The Air Force plans to fly the B-52 to 2050. The B-52 modernization efforts are needed to perform current and future wartime missions and to ensure relevance, lethality and survivability. Additionally, modernization projects alleviate aircraft obsolescence issues due to Diminishing Manufacturing Sources and Material Shortages (DMSMS) while at the same time providing improved capabilities to the B-52 weapon system that require significant hardware and software development and testing. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0101113F / B-52 Squadrons Operational Systems Development B-52 funding also supports innovation activities including, but not limited to tech demonstrations, studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $23.786M was expended for civilian pay expenses in this program element, and in FY 2025 $26.783M is forecasted for civilian pay expenses in this program element. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 1664641000, 1263807000, 936562000, NULL, NULL, 160, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 1019125000, 888158000, 1478648000, 1478648000, 101100000, 1579748000, 849672000, $$The B-52 is a long-range bomber capable of delivering the widest variety of nuclear and conventional standoff and direct attack munitions in the Air Force. The Air Force plans to fly the B-52 to 2050. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0101113F / B-52 Squadrons Operational Systems Development The B-52 modernization efforts are needed to perform current and future wartime missions and to ensure relevance, lethality and survivability. Additionally, modernization projects alleviate aircraft obsolescence issues due to Diminishing Manufacturing Sources and Material Shortages (DMSMS) while at the same time providing improved capabilities to the B-52 weapon system that require significant hardware and software development and testing. B-52 funding also supports innovation activities including, but not limited to tech demonstrations, studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. The FY 2027 request for B-52 includes $1,478,648 thousands of discretionary and $101,100 thousands of mandatory for a total of $1,579,748 thousands. The mandatory funds B-52 for the Resilient Operation Capability (ROCS) effort to fully fund the program's first year of EMD efforts to include design reviews, and test asset hardware buys; Mission Employment Trainer (MET) funds will be used to develop B-52 training devices that will provide an interactive and immersive environment to provide proficiency-based and initial qualification training for full crew mission training and coordination, and related programmatic support; and CERP which allows B-52 to fully fund the development effort in Fiscal Year 2027. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604041F$$, $$Family of Affordable Mass Missiles (FAMM)$$, $$rdte_af_ba4$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${"fy27_mand_k": 51000, "fy27_mand_v157": "2026-05-08", "fy27_mand_source": "DoW_FY2027_Mandatory_Funding_Overview.txt Appendix B", "fy27_mand_section": "Munitions"}$$::jsonb, NULL, NULL, 724833000, 1009225000, 798004000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 525223000, 525223000, 51000000, 576223000, 851926000, $$The Adaptive Weapons program element (0604041F) modernizes the weapons acquisition process through the Modular Weapon Series (M-Series) paradigm using open and common hardware and software interface standards to increase acquisition agility, lower costs of weapon development and modification, and be rapidly upgradeable to respond to adversary actions. This program element will be utilized for additional classes of Adaptive Weapons as new Budget Program Activity Codes are incorporated into the PE. The first Adaptive Weapons class is the Family of Affordable Mass Missiles (FAMM)(BPAC 640411) which provides a low-cost, standoff cruise missile designed to provide long range affordable mass to overwhelm enemy defenses and deplete adversary defensive weapons inventories, operating as a complement to more complex and more expensive weapons. The first variant of FAMM missiles is a palletized baseline configuration and will be followed by a lugged variant both with weapon- weapon communications. Future increments will be defined based upon user demand and are likely to include a Beyond Line-of-Sight (BLOS), Extended Range (ER), Long-Range Kill Chain (LRKC) communications, different payloads, sub-systems or employment options, etc. This program element will be utilized to further execute component level development for modular implementation into future increments of FAMM. Increment 1 key warfighter requirements are 500nm+ range, Networked Collaborative Autonomous (NCA) capabilities, and palletized employment from cargo aircraft to provide capability to employ large swarms of missiles against slow moving maritime targets. Threshold launch platforms are the C-130 and C-17. Future employment methods may include launch from fighter/bomber racks, ground or surface launched. FAMM activities will include integration with the various employment platforms, to include risk-reduction, development, integration and testing if operationally available systems are not available. The Air Force Long Range Missile program develops a next-generation, air-launched precision strike weapon to provide standoff capability against high-value, time- sensitive targets. It leverages Government Reference Architectures (GRA), Weapons Open System Architecture (WOSA), Digital Infrastructure Products (DIPs), and Collaborative Test Groups (CTGs) to enable rapid upgrades and enhance lethality in contested environments. This approach ensures modular, scalable design for integration on bombers and fighters, with a focus on digital engineering and open architecture to counter evolving threats like advanced air defenses. Allows for Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio trade space studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0604041F / Family of Affordable Mass Missiles (FAMM) Component Development & Prototypes (ACD&P) higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging the Department of War (DoW) and the Department of the Air Force (DAF) enterprise IT solutions. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2027 request for FAMM includes $525,223 thousand, of discretionary funding and $51,000 thousand of mandatory funding for a total of $576,223. The FY 2027 mandatory funds continue efforts from FY 2026 to complete test & evaluation activities resulting in a fieldable baseline weapon system configuration, in addition to beginning development & integration of Increment 1 (BLOS) capability. The FY 2026 spend plan amount for the Family of Affordable Mass Missiles (FAMM) includes 0 discretionary and $285,000 thousand of mandatory (reconciliation) for a total of $285,000 thousand. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Remaining/DoW_FY2027_Mandatory_Funding_Overview.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0202057C$$, $$Safety Program Management$$, $$rdte_dw_ba4$$, $$dw_mda$$, 2026, 1806000, 2476000, 1771000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0202057C", "page_header": "Defense-Wide"}$$::jsonb, $$The Missile Defense Agency (MDA) Occupational Safety and Health (OSH) establishes the program plans, policy, responsibilities, and guidelines for compliance with statutory, regulatory, and Department of Defense (DoD) policy/program directives. It also establishes MDA OSH programs designed for the protection of human resources through accident prevention; protection of MDA systems, property, and equipment; and the compliance with appropriate statutes, regulations, Executive Orders, and DoD policies. OSH develops and ensures implementation of safety requirements, mitigates safety risks to the lowest practical level, and ensures a safe workplace for all MDA employees and contractors by implementing a Safety and Occupational Health program.$$, NULL, 2206000, 2282000, 2357000, NULL, NULL, 130, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 2118000, 1801000, 2146000, 2146000, NULL, 2146000, 2421000, $$The MDA OSH establishes the program plans, policy, responsibilities, and guidelines for compliance with statutory, regulatory, and Department of War (DoW) policy/ program directives. It also establishes the MDA OSH program designed for the protection of human resources through accident prevention; protection of MDA systems, property, and equipment; and the compliance with appropriate statutes, regulations, Executive Orders, and DoW policies. OSH develops and ensures implementation of safety requirements, mitigates safety risks to the lowest practical level, and ensures a safe workplace for all MDA employees and contractors.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0102417F$$, $$Over-the-Horizon Backscatter Radar$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 0, 0, 377394000, NULL, $${"source": "jbook_fy26", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, $$Efforts funded in this PE focus on development, testing, and fielding, of a long-range early detection capability for airborne and surface targets of interest. Each line of effort acquires and fields a land based, high-frequency (HF) ionospheric backscatter radar for over the horizon detection and tracking of airborne and surface targets over wide geographic areas. Fielding of this capability will enable detection, tracking and reporting of airborne and surface targets that may be obscured from conventional line of sight radar systems by the curvature of the earth. Specific lines of effort funded include, but are not limited to, Tactical Multi-Mission Over the Horizon Radar (TACMOR), Homeland Defense Over the Horizon Radar (HLD-OTHR) and support for a classified EUCOM requirement. TACMOR capability is being developed for employment in the Republic of Palau (RoP) to provide enhanced Air Domain Awareness in the USINDOPACOM area of responsibility. TACMOR will be located in the RoP and operated by the United States in agreement with the RoP. Development, test and evaluation, and acquisition of the system and associated components will provide warfighters with the capability to close gaps in surveillance coverage in key regions of the Pacific area of interest to the United States and its Allies. The total cost of the TACMOR Middle Tier of Acquisition effort is 243.4 million, including RDT&E and procurement of prototype units. TACMOR is not fully funded across the Future Years Defense Program. The Department of the Air Force is assessing all options to address the funding shortfalls for MTA programs including additional funding in a future budget request, performance trades based on technical maturity, or transition to alternative pathways. HLD-OTHR efforts focus on the development, testing, and fielding of capabilities to extend current NWS surveillance of long-range early warning for North America in response to emerging threats. The primary mission of the new HLD-OTHR systems will be to provide long-range sensor coverage of potential air and cruise missile threats to North America, with secondary and tertiary capability against complex targets of interest (i.e, High Altitude Balloons) and maritime surface vessels and additional tasking as required. The system will be comprised of four OTHR systems and an Operational Control Center. HLD-OTHR data will be distributed and integrated into existing air, missile and maritime defense early warning networks, as applicable. This project will continue to focus investments to enhance capability for the Air and Cruise Missile Defense of the Homeland mission. The FY 2025 funding request was reduced by 1.647 million to account for the availability of prior year execution balances. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in PE 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2023, 4.2M was expended for civilian pay expenses in this program element, and in FY2024, 4.3M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0102417F / Over-the-Horizon Backscatter Radar Development & Demonstration (SDD) FY26 PB $132.067M funding and budget justification has been submitted in PE 0102417F, Budget Activity 07 due to a database error. DAF will internally correct this error prior to submission of the FY27 PB and all OTHR efforts will continue in this updated exhibit executing in Budget Activity 05. No Congressional action is requested to correct this technical error. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 0, 0, 0, NULL, NULL, 105, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 130401000, 173975000, 173975000, 0, 173975000, 0, $$Efforts funded in this program focus on development, testing, and fielding, of a long-range early detection capability for airborne and surface targets of interest. Each line of effort acquires and fields a land based, high-frequency (HF) ionospheric, backscatter Over-the-Horizon RADAR (OTHR) for detection and tracking of airborne and surface targets over wide geographic areas. Fielding of this capability will enable detection, tracking and reporting of airborne and surface targets that may be obscured from conventional line of sight radar systems by the curvature of the earth. Tactical Multi-Mission Over the Horizon Radar(TACMOR) is a US Air Force remotely operated OTHR system being developed for deployment in the Republic of Palau (RoP). The system will provide enhanced Air Domain Awareness in key regions of USINDOPACOM's area of responsibility. This program may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F , In FY 2025 0.000 million was expended for civilian pay expenses in this program, in FY 2026 0.111 million is forecasted for civilian pay expenses in this program element. TACMOR FY 2026 funds were allocated to - Program 012417F Project 674865 (budget authority 7). FY 2027-FY 2031 corrects the budget authority from 7 to 5 to appropriately reflect program efforts. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0102417F / Over-the-Horizon Backscatter Radar Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
