INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401115F$$, $$C-130 Airlift Squadron$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 0, 21959000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401115F"}$$::jsonb, $$The C-130H is a medium sized tactical transport aircraft providing multi-purpose theater support throughout the globe. The C-130H fleet supports several diverse Air Force roles, including but not limited to tactical and inter-theater airlift and airdrop support, Arctic resupply, special operations support, aeromedical evacuation, aerial spraying, firefighting duties, and natural disaster and humanitarian relief missions. Previous funding provides weapon system modifications and upgrades to meet USAF mission requirements for the LC/C-130H fleets. C-130H AMP Increment 2 includes digital avionics upgrades (e.g. Flight Management System, improved navigation), cockpit modernization (e.g. digital flight displays) and resolves select obsolescence and Diminishing Manufacturing Source (DMS) issues. RDT&E efforts cover software development, design, integration, developmental and operational test, studies and risk reduction efforts, trial kit buy and installation, technical order development validation and verification, spares and peculiar support equipment in support of trial kit installs, Systems Integration Laboratory (SIL) development, type 1 training and C-130H aircrew and maintenance training systems and courseware development efforts, program office support and other efforts necessary to fulfill program requirements. Project 672030, MUOS/SATURN, is now included in project 675250, AMP Increment 2. The MUOS/SATURN radio addresses future DMS/integration issues and incorporates MUOS/SATURN capabilities. Milestone C (MS C) is now planned for June 2026. This change is due to flight testing taking longer than planned due to the development, installation, and testing of corrections required prior to MS C. This funding includes Rapid Global Mobility (RGM) platform related activities including but not limited to prototyping, capability development, process activities, planning analysis and systems engineering activities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0401115F / C-130 Airlift Squadron Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 275, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1506_L027$$, $$MQ-4 Triton$$, $$proc_navy_1506_ba4$$, $$peo_uw$$, 2026, 133139000, 416010000, 159226000, NULL, $${"page": 59, "ba_num": "04", "source": "p1_fy26", "ba_name": "Other aircraft", "line_no": "27", "service": "navy", "fy24_qty": 2, "fy25_qty": null, "fy27_v24": {"ba": "04", "appr": "APN", "title": "P-1 Line 16", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf + APN_BA5_Book.pdf + APN_BA6-7_Book.pdf", "fy27_base_K": 104326, "p1_line_num": 16, "fy27_total_K": 104326}, "appr_code": "1506", "appr_name": "Aircraft Procurement, Navy", "fy26_v179": {"disc_K": 123839, "li_num": 16, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/APN_BA1-4_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 133139000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 123839000, 104326000, 104326000, 0, 104326000, NULL, NULL, $$Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0202834F$$, $$Aviation Support Equipment - General$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 744000, 9474000, 6097000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0202834F"}$$::jsonb, $$Aviation Support Equipment Modernization provides funding for the modernization of organizational and intermediate level support equipment for out-of-production and emerging aircraft, munitions and external stowage to maximize commonality of equipment, improve aircraft readiness/availability and to reduce life cycle sustainment costs. These items, common (used on more than one weapon system) and peculiar (unique to one weapon system), directly support aircraft maintenance, servicing, and sortie generation requirements. To support aircraft generation requirements, support equipment may be studied, reviewed, modified and/or re-developed in order to maintain operational readiness. Examples of equipment under review and/or modernization includes, but not limited to, power generation, heating, ventilation, and air conditioning (HVAC), munition trailers/accessories, munition lifts/accessories, tow vehicles, munition test/maintenance stands, hydraulic equipment, and engine test stands. Any identified capability gaps may result in the design of a new system. Additionally, modernization is a continuous, deliberate effort and is key to complete lifecycle management. This program element also includes program administrative cost for the Support Equipment and Vehicles program office and funds the cost of studies and research to support the aviation support equipment fleet. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Aviation Support Modernization capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0202834F / Vehicles and Support Equipment - General Operational Systems Development$$, NULL, 12190000, 5910000, 6150000, NULL, NULL, 172, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 6097000, 10733000, 1028000, 1028000, 0, 1028000, 6274000, $$Aviation Support Equipment Modernization provides funding for the modernization of organizational and intermediate level support equipment for out-of-production and emerging aircraft, munitions and external stowage to maximize commonality of equipment, improve aircraft readiness/availability and to reduce life cycle sustainment costs. These items, common (used on more than one weapon system) and peculiar (unique to one weapon system), directly support aircraft maintenance, servicing, and sortie generation requirements. To support aircraft generation requirements, support equipment may be studied, reviewed, modified and/or re-developed in order to maintain operational readiness. Examples of equipment under review and/or modernization includes, but not limited to, power generation, heating, ventilation, and air conditioning (HVAC), munition trailers/accessories, munition lifts/accessories, tow vehicles, munition test/maintenance stands, hydraulic equipment, and engine test stands. Any identified capability gaps may result in the design of a new system. Additionally, modernization is a continuous, deliberate effort and is key to complete lifecycle management. This program element may include program administrative cost for the Support Equipment and Vehicles program office and funds the cost of studies and research to support the aviation support equipment fleet. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Aviation Support Modernization capability. This program includes a congressional add in FY26 for next generation advance munitions lift. In direct support of SecDef's direction to increase readiness across the DoD, efforts within this PEC will be prioritized based on the National Defense Authorization Act (NDAA), USAF Force Design, Agile Combat Employment (ACE), and the Defense Planning Guide (DPG). These efforts will support work and collaboration efforts across the Combat Readiness Directorate in PE's 78051F, 71212F, 72833F, 64706F, 65827F, 22834F, 52834F, 52844F, 28031F, 41135F and 27521F -- to increase readiness across the Air Force Enterprise This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0202834F / Aviation Support Equipment - General Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0203345F$$, $$Operations Security (OPSEC)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 67000000, 70400000, 73900000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 45000000, 45000000, 0, 45000000, 77600000, $$The DAF Operations Security (OPSEC) Program enables the effective and efficient execution of the OPSEC process. OPSEC is a Presidentially directed security discipline and operational function that denies adversaries the ability to collect, analyze, and exploit information that might provide an advantage against the United States by preventing the compromise of critical information through a process of continual assessment that identifies and analyzes critical information, vulnerabilities, risks, and external threats. OPSEC requires the continual implementation and modernization of measures and countermeasures, to include technical solutions, to mitigate operational risk. The Battering Ram project and associated efforts, may include but are not limited to, provide the automated classification governance, requirements management, and scaling across the Department of War (DoW) through the modernization of the information security classification and declassification processes which enhance critical OPSEC measures; thereby reducing risks to DOW and DAF capabilities and missions. The Battering Ram project is developing and implementing the information technology infrastructure that enables the modernization of existing information security capabilities to realize a uniform system for classifying, safeguarding, and declassifying national security information as prescribed in Executive Order 13526, Classified National Security Information. Battering Ram will enable the DoW to improve warfighter effectiveness by increasing the speed with which information can be exchanged by reducing complex and manual review processes and providing a secure multi-level information system and information technology infrastructure to support the execution and operation of the information security enterprise. Battering Ram will continue to operationalize capabilities that further the DoW's ability to centrally manage classification, such as but not limited to: - Digitizing, curating, and maintaining authoritative classification and declassification guidance across all classification levels (CUI through TS//SCI/SAR) - Automatically classifying and validating existing DoW documents and data using machine-readable guidance and Artificial Intelligence (AI)-enabled decision support - Providing software services to both connected and air-gapped DoW and cleared contractor information systems Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0203345F / Operations Security (OPSEC) Operational Systems Development - Enabling adjudication, governance, and continuous improvement of classification policy through a centralized digital infrastructure Battering Ram directly supports mission assurance, operational security, information advantage, and risk reduction by replacing fragmented, manual, and inconsistent classification processes with a standardized, auditable, and automated digital lifecycle. This program element may include all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expense budgeted in program elements 0605829F, 06050831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L025$$, $$Gray Eagle Mods2$$, $$proc_army_2031_ba2$$, $$peo_aviation$$, 2026, 0, 82959000, 23865000, NULL, $${"page": 12, "ba_num": "02", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "25", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 12351, "li_num": 16, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 12351000, 2556000, 2556000, 0, 2556000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0203743A$$, $$155mm Self-Propelled Howitzer Improvements$$, $$rdte_army_ba7$$, $$peo_gcs$$, 2026, 107826000, 22066000, 47870000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "original_pe": "0203743A", "page_header": "Department of the Army"}$$::jsonb, $$Self-Propelled Howitzer Modernization effort improves self-propelled howitzer lethality through increased range and increased rate of fire, using mature technology to improve mobility, survivability, reliability, supportability, and lethality. This effort will analyze and evaluate new cannon technology, including existing and future artillery systems as well as technology to improve mission cycle time and enable future platform autonomy. This effort will also inform requirements, release request for vendor proposals and evaluate vendor offerings. The FY 2026 request was reduced by $7.022 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, NULL, NULL, NULL, NULL, NULL, 219, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 39905000, 105410000, NULL, NULL, NULL, NULL, NULL, $$Self-Propelled Howitzer Modernization effort improves self-propelled howitzer lethality through increased range and increased rate of fire, using mature technology to improve mobility, survivability, reliability, supportability, and lethality. This effort will analyze and evaluate new cannon technology, including existing and future artillery systems as well as technology to improve mission cycle time and enable future platform autonomy. This effort will also inform requirements, release request for vendor proposals and evaluate vendor offerings.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0602142A$$, $$Army Applied Research$$, $$rdte_army_ba2$$, $$devcom$$, 2026, 0, 38072000, 0, NULL, $${"act": "02", "ba_raw": "6.2", "source": "r1_fy26", "service": "army", "page_num": 10, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0602142A", "page_header": "Department of the Army"}$$::jsonb, $$The Army Applied Research budget line includes systematic application of knowledge toward the production of useful materials, devices and systems or methods including the design, development and improvement of science and technology for Army applications. Efforts in this budget line include studies, investigations and non-system specific technology efforts leading to bread-board hardware or proof of principle analysis.$$, NULL, NULL, NULL, NULL, NULL, NULL, 11, $$RDTE - Vol 1 - Budget Activity 2.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0203801A$$, $$Missile/Air Defense Product Improvement Program$$, $$rdte_army_ba7$$, $$peo_cscss$$, 2026, 1338000, 4203000, 1511000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "original_pe": "0203801A", "page_header": "Department of the Army"}$$::jsonb, $$Avenger is a lightweight, ground-to-air missile and gun weapon system mounted on a High Mobility Multi-Purpose Wheeled Vehicle (HMMWV). The system protects against unmanned aircraft systems, cruise missiles, and fixed and rotary wing threats. Avenger provides day/night adverse weather operations, shoot on the move capability, rapid target engagement, and remote firing capability. It can be air dropped, lifted by helicopter and is air transportable. The system employs up to eight Stinger missiles to counter aerial threats and a .50 Caliber Machine Gun (M3P) for close-in ground and air threats. An Identification Friend or Foe (IFF) system aids in the identification of friendly aircraft in order to minimize the potential for fratricide. The Avenger fleet of 421 systems includes 169 systems that are equipped with a digital Slew-to-Cue (STC) capability to speed target detection and engagement. FY 2026 funding of $1.338 million continues system testing requirements and system improvements to address evolving threats. Avenger is part of the Army Transformation Initiative. The FY 2026 request was reduced by $0.171 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative."$$, NULL, 2097000, 2134000, 2182000, NULL, NULL, 222, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 1456000, 1338000, 2054000, 2054000, NULL, 2054000, 2224000, $$The Avenger is a lightweight, ground-to-air missile and gun weapon system mounted on a High Mobility Multi-Purpose Wheeled Vehicle (HMMWV). It is designed to protect against unmanned aircraft systems (UAS), cruise missiles, and fixed- and rotary-wing threats. The Avenger provides day/night and adverse weather operational capabilities, shoot-on-the-move functionality, rapid target engagement, and remote firing capability. It is highly mobile, capable of being air-dropped, helicopter-lifted, and air-transportable. The system employs up to eight Stinger missiles to counter aerial threats and is equipped with an M3P .50 Caliber Machine Gun for close-in ground and air defense. An Identification Friend or Foe (IFF) system is integrated to aid in identifying friendly aircraft, minimizing the risk of fratricide. The Avenger fleet consists of 421 systems, including 169 systems equipped with a digital Slew-to-Cue (STC) capability, which enhances target detection and engagement speed. The FY 2027 funding of $2.054 million is allocated to support ongoing system testing requirements and implement system improvements to address evolving threats.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0203802A$$, $$Other Missile Product Improvement Programs$$, $$rdte_army_ba7$$, $$peo_gcs$$, 2026, 0, 9677000, 26708000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 22, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0203802A", "page_header": "Department of the Army"}$$::jsonb, $$PE 0203802A VV2: TOW: TOW Weapon System includes the Improved Target Acquisition System (ITAS) and other TOW missile launchers, TOW missiles (BGM-71 series) and other missiles capable of being fired from TOW Missile launchers, and associated tactical training aids/devices. The TOW Weapon System provides long- range, lethal anti-armor and precision assault fires capability for Army Infantry Brigade Combat Teams (IBCT), Stryker Brigade Combat Teams (SBCT) and Armor Brigade Combat Teams (ABCT) within the Active, Reserve, and National Guard components. The United States Marine Corps (USMC) employs the TOW missile from its ITAS derived M41A7 Saber launchers and Anti-Tank Guided Missile (ATGM) vehicles. The TOW Weapon System improvement program integrates U.S. Army missile and launcher modifications to improve missile safety and reliability, increase system survivability and lethality, and enhance system network capabilities. These capability improvements support Multi-Domain Operations (MDO) as a part of Joint All Domain Operations (JADO) and the Functional Concept for Movement and Maneuver by providing precise lethal capabilities in multiple domains against armored threat systems. PE 0203802A VV2:TOW: has no FY 2026 funding requests. FY 2025 Program Change of $3.000 million for Congressional Add: Containerized Weapon System-APKWS (CWS-A).. CWS-A has demonstrated ability to defeat Group II through III UAS threats. It provides networked sensor to shooter interface enabling multiple stations remotely controlled by a single operator from a protected location. CWS-A increases stand-off situational awareness and security of Command Posts and other Critical Capabilities Assets and Activities (CCAA) and reduces the manpower required to protect semi-fixed locations enabling increased patrols for area security, movement corridors, and response force operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational   PE 0203802A / Other Missile Product Improvement Programs Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 223, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 25843000, 0, NULL, NULL, NULL, NULL, NULL, $$PE 0203802A VV2: TOW: TOW Weapon System includes the Improved Target Acquisition System (ITAS) and other TOW missile launchers, TOW missiles (BGM-71 series) and other missiles capable of being fired from TOW Missile launchers, and associated tactical training aids/devices. The TOW Weapon System provides long- range, lethal anti-armor and precision assault fires capability for Army Infantry Brigade Combat Teams (IBCT), Stryker Brigade Combat Teams (SBCT) and Armor Brigade Combat Teams (ABCT) within the Active, Reserve, and National Guard components. The United States Marine Corps (USMC) employs the TOW missile from its ITAS derived M41A7 Saber launchers and Anti-Tank Guided Missile (ATGM) vehicles. The TOW Weapon System improvement program integrates U.S. Army missile and launcher modifications to improve missile safety and reliability, increase system survivability and lethality, and enhance system network capabilities. These capability improvements support Multi-Domain Operations (MDO) as a part of Joint All Domain Operations (JADO) and the Functional Concept for Movement and Maneuver by providing precise lethal capabilities in multiple domains against armored threat systems. PE 0203802A VV2: TOW has no FY 2027 funding requests. FY 2025 Program Change of $3.000 million for Congressional Add: Containerized Weapon System-APKWS (CWS-A). CWS-A has demonstrated ability to defeat Group II through III UAS threats. It provides networked sensor to shooter interface enabling multiple stations remotely controlled by a single operator from a protected location. CWS-A increases stand-off situational awareness and security of Command Posts and other Critical Capabilities Assets and Activities (CCAA) and reduces the manpower required to protect semi-fixed locations enabling increased patrols for area security, movement corridors, and response force operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational   PE 0203802A / Other Missile Product Improvement Programs Systems Development$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
