INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2031_L052$$, $$Aircrew Integrated Systems$$, $$proc_army_2031_ba4$$, $$asa_alt_alt$$, 2026, 14986000, 22097000, 14478000, NULL, $${"page": 14, "ba_num": "04", "source": "p1_fy26", "ba_name": "Support equipment and facilities", "line_no": "52", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2031", "appr_name": "Aircraft Procurement, Army", "fy26_v178": {"disc_K": 24213, "li_num": 32, "source": "p40_fy26_v178", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Army/Aircraft_Procurement_Army.txt"}, "fy26t_qty": null, "fy26d_cost": 14986000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 24213000, 11044000, 11044000, 0, 11044000, NULL, NULL, $$Budget J-Books/FY27/Army/Aircraft_Procurement_Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0603216F$$, $$Aerospace Propulsion and Power$$, $$rdte_af_ba3$$, $$afrl_rq$$, 2026, 0, 92129000, 0, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0603216F"}$$::jsonb, $$This program develops and demonstrates technologies to achieve enabling and revolutionary advances in turbine, advanced-cycle, rocket, and space propulsion as well as electrical power, thermal management, and fuels. The program has five current projects, each focusing on technologies with a high potential to enhance the performance of existing and future Air Force weapon systems. The Aerospace Power Technology project develops and demonstrates adaptive power and thermal management components, controls, and systems for high-power payloads and aircraft as part of energy-optimized aircraft development. The Aircraft Propulsion Subsystems Integration project develops demonstrator engines by integrating the engine cores demonstrated in the Advanced Turbine Engine Gas Generator project with low-pressure components. The Advanced Aerospace Propulsion project develops the scramjet propulsion cycle to a technology readiness level appropriate for in- flight demonstration and for full integration with other engine cycles (including turbine and rocket based). The Advanced Turbine Engine Gas Generator project develops and demonstrates core turbine engine technologies for current and future aircraft propulsion systems. The Missile Rocket Propulsion project develops and demonstrates innovative rocket propulsion technologies, propellants, and manufacturing techniques. In FY 2025, the RDT&E Budget Activity 03 (BA03) Aerospace Propulsion and Power Technology efforts and activities under PE 0603216F, was transferred to PE 0603211F, Aerospace Technology Dev/Demo for increased integration between airframe, flight control, propulsion, electrical, power and thermal management. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 633035 Aerospace Power Technology, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634927 Flight Systems Control. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 634093 Missile Rocket Propulsion Integ & Demo, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634093 Missile Rocket Propulsion Integ & Demo. In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 634921 Aircraft Propulsion Subsystems Int, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634921 Aircraft Propulsion Subsystems Int. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0603216F / Aerospace Propulsion and Power Technology Technology Development (ATD) In FY 2025, the entirety of PE 0603216F, Aerospace Propulsion and Power Technology, Project 635098 Advanced Aerospace Propulsion, was transferred to PE 0603211F, Aerospace Technology Dev/Demo, Project 634926 High Speed Systems Integ & Demo. This program element may include necessary civilian pay expenses required to manage, execute, and deliver science & technology capabilities. The use of program funds in this program element would be in addition to the civilian pay expenses budgeted in program elements 0601102F, 0602020, 0602102F, 0602202F,0602203F, 0602204F, 0602602F, 0602605F, 0602788F, 0602298F, and 1206601SF. This program element may include necessary expenses to support the operation and maintenance of facilities to manage, execute, and deliver science and technology capabilities. Projects in this program have been coordinated through the Department of Defense (DoD) Science and Technology (S&T) Executive Committee process to harmonize efforts and eliminate duplication. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment.$$, NULL, NULL, NULL, NULL, NULL, NULL, 21, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604025M$$, $$Rapid Defense Experimentation Reserve$$, $$rdte_navy_ba4$$, $$asn_rda$$, 2026, 99000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 30, "original_pe": "0604025M", "page_header": "Department of the Navy"}$$::jsonb, $$This effort is critical for assessing integrated technologies, representative models, and prototype systems within a high-fidelity and realistic operational environment. The objective is to foster comprehensive evaluation, ensuring the efficacy, efficiency, and reliability of all systems involved.$$, NULL, NULL, NULL, NULL, NULL, NULL, 76, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1506_L018$$, $$Multi-Engine Training System (METS)$$, $$proc_navy_1506_ba3$$, $$peo_aasm$$, 2026, 0, 297141000, 301303000, NULL, $${"page": 58, "ba_num": "03", "source": "p1_fy26", "ba_name": "Trainer aircraft", "line_no": "18", "service": "navy", "fy24_qty": 26, "fy25_qty": 27, "fy27_v24": {"ba": "03", "appr": "APN", "title": "P-1 Line 14", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf + APN_BA5_Book.pdf + APN_BA6-7_Book.pdf", "fy27_base_K": 0, "p1_line_num": 14, "fy27_total_K": 0}, "appr_code": "1506", "appr_name": "Aircraft Procurement, Navy", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 705045000, NULL, NULL, NULL, FALSE, 301303000, 0, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2035_L013$$, $$Family Of Heavy Tactical Vehicles (FHTV)$$, $$proc_army_2035_ba1$$, $$peo_cscss$$, 2026, 39761000, 55340000, 36726000, NULL, $${"page": 35, "ba_num": "01", "source": "p1_fy26", "ba_name": "Tactical and support vehicles", "line_no": "13", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2035", "appr_name": "Other Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 39761000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 527407000, 202009000, 80187000, 80187000, 0, 80187000, NULL, NULL, $$Budget J-Books/FY27/Army/Other Procurement - BA1 - Tactical & Support Vehicles.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204136N$$, $$F/A-18 Squadrons$$, $$rdte_navy_ba7$$, $$peo_tacair$$, 2026, 369863000, 279537000, 348286000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0204136N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 277609000, 263396000, 241066000, NULL, NULL, NULL, NULL, NULL, FALSE, 328703000, 395927000, 271429000, 271429000, NULL, 271429000, 245242000, $$JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. The F/A-18 is a high performance, twin-engine, mid-wing, multi-mission tactical aircraft designed to provide strike and Fleet Air Defense in support of USN and USMC requirements. The F/A-18 is designed to meet current Navy and Marine Corps fighter escort and interdiction mission requirements, to maintain fleet air defense and close air support roles, as well as an increasing range of missions including Aerial Tanking and Long Range Fires. F/A-18E/F enhancements include increased range and improved carrier suitability required for the F/A-18 to continue its key strike fighter role against the advanced threats of the 21st century. This Program Element (PE) funds the development and improvement of the F/A-18 and EA-18G platform through its primary missions: Advanced Electronic Warfare (ADVEW) Automatic Ground Collision Avoidance System (AUTOGCAS) EFG Beyond Line of Sight (BLOS) Global Lightning (GL) capability Brizo Beacon Digital Video Map Computer-Upgrade (DVMC-U)/Advanced Crew Station (ACS) F/A-18 E/F and EA-18G "Flight Plan" spiral capability development Live Virtual Constructive (LVC) Multi-System Integration (MSI) F/A-18 E/F/G Network Cyber Defense Next Generation Naval Mission Planning System (NGNMPS) F/A-18 E/F/G Network Cyber Defense Stores Management Set (SMS) Stores Management Processor (SMP) Automatic Ground Collision Avoidance System (AUTOGCAS) USMC F/A-18 Radar Upgrade Physiological Episode (PE) Mitigation Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                          Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0204136N / F/A-18 Squadrons Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204202N$$, $$DDG-1000$$, $$rdte_navy_ba5$$, $$peo_ships$$, 2026, 58817000, 215762000, 224860000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0204202N", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element (PE) provides funds for the integration of Conventional Prompt Strike (CPS) into the Zumwalt class surface combatants. CPS integration is a top Chief of Naval Operations (CNO) priority that enhances the Zumwalt class's mission to provide credible independent forward presence/deterrence and operate as an integral part of Naval, Joint or Combined Maritime Forces. DDG 1000 will establish and maintain surface superiority, provide local air defense, and incorporate signature reduction to operate in all threat environments. DDG 1000 will have seamless Joint Interoperability to integrate all source information for battlespace awareness and weapons direction. Funding provided is for development activities necessary to integrate CPS into all three Zumwalt Class destroyers to perform the required systems engineering, analysis, modeling and simulation necessary to install the CPS capability on DDG 1000 during her first Build Yard Mod Period (BYMP). The funding provides a flexible, surface combatant launched long-range strike capability through the ships' remaining service life. When combined with the low observable characteristics of the Zumwalt platform, the ships provide a compelling strike capability from a platform designed to complicate an adversaries' targeting problem. Funding enables ship modifications for installation of a CPS cold launch system common to the future Virginia Payload Module.$$, NULL, 271247000, 146175000, 109757000, NULL, NULL, 177, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 216153000, 58817000, 50166000, 50166000, NULL, 50166000, 50619000, $$This Program Element (PE) provides funds for the integration of Conventional Prompt Strike (CPS) into the Zumwalt class surface combatants. CPS integration is a top Chief of Naval Operations (CNO) priority that enhances the Zumwalt class's mission to provide credible independent forward presence/deterrence and operate as an integral part of Naval, Joint or Combined Maritime Forces. DDG 1000 will establish and maintain surface superiority, provide local air defense, and incorporate signature reduction to operate in all threat environments. DDG 1000 will have seamless Joint Interoperability to integrate all source information for battlespace awareness and weapons direction. Funding provided is for development activities necessary to integrate CPS into all three Zumwalt Class destroyers to perform the required systems engineering, analysis, modeling and simulation necessary to install the CPS capability on DDG 1000 during her first Build Yard Mod Period (BYMP). The funding provides a flexible, surface combatant launched long-range strike capability through the ships' remaining service life. When combined with the low observable characteristics of the Zumwalt platform, the ships provide a compelling strike capability from a platform designed to complicate an adversaries' targeting problem. Funding enables ship modifications for installation of a CPS cold launch system common to the future Virginia Payload Module. DDG 1000 Class-specific ESSM missile inventory issues necessitate a transition to support ESSM Blk 2 missile type. Funding supports integration and shipboard live- fire testing. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 5: System           PE 0204202N / DDG-1000 Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204228N$$, $$(U)SURFACE SUPPORT$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 0, 9727000, 8420000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0204228N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 8419000, 0, 0, 0, NULL, 0, 0, $$Effective in FY 2026, Project 3311 Navigation Systems moved from PE 0204228N to PE 0607658N as part of the PE/BLI consolidation effort in the DoW Implementation Plan from the Commission on PPBE Reform Final Report. Through FY 2025, the focus of PE 0204228N (Surface Support) is for the research, design, development, integration testing, and documentation of the Inertial Navigation System (INS) AN/WSN-12 for all Navy ships and submarines. The INS provides mission critical ship position and attitude data to shipboard sensors (such as radars), combat and weapon systems. The INS uses data from the Global Positioning System (GPS) to periodically update (i.e., reset) its position and internal clock. The INS is the ship's primary position source in the absence of GPS, and it consists of an Inertial Sensor Module (ISM) and a Navigation Processing Module (NPM) that will provide a significant improvement with respect to attitude and velocity data over previous INS. RDT&E funding will support continued system design to create a baseline for Pre-Production Units (PPU), Low-Rate Initial Production (LRIP), and Full Rate Production (FRP). Military GPS User Equipment (MGUE) will provide assured Positioning, Navigation, and Timing (PNT) in a GPS degraded environment. Funding will be used for the development of interface and performance requirements, shipboard system architecture definition, and MGUE integration. Submarine Speed Sensors will provide investigation, development, testing and integration of new Own-Ship Speed sensors to address new capabilities, reduce detection, and improve reliability. Automated Celestial Navigation System (ACNS) funding will be used for the research, development, Engineering Development Model (EDM), documentation and integration testing of the celestial navigation solution for the NoGAPSS navigation implementation on the fleet. Efforts will leverage ONR celestial navigation research into a reproducible ruggedized system fully integrated into the navigation suite. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational   PE 0204228N / (U)SURFACE SUPPORT Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204229N$$, $$Tomahawk Mssn Planning Ctr$$, $$rdte_navy_ba7$$, $$peo_uw$$, 2026, 151177000, 119505000, 166150000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0204229N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 47701000, 47379000, 46667000, NULL, NULL, NULL, NULL, NULL, FALSE, 163035000, 134177000, 76653000, 76653000, NULL, 76653000, 39341000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. Funds support development of the Tomahawk Weapons System (TWS) encompassing Tactical Tomahawk upgrades including baseline improvements into the Block V missile All-Up Round (AUR), Tactical Tomahawk Weapons Controls System (TTWCS), Theater Mission Planning Center (TMPC) upgrades, and other missile system improvements to maintain pace with threats. The TWS provides a long range cruise missile attack capability against fixed, mobile, and maritime targets. Tomahawk is capable of being deployed from both submarines and surface ships and increases the total capability of joint forces. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under Operational Systems Development because it includes development efforts to upgrade systems that have been fielded or have received approval for Full Rate Production (FRP) and anticipate funding in the current or subsequent fiscal year. The FY 2026 request for Tomahawk Mission Planning Center includes $134,177K of discretionary and $80,175K of mandatory (reconciliation) for a total of $214,352K. FY2026 total funding supports Tomahawk capability and capacity increases. The discretionary funds provide for new capability development as described for each project unit. The mandatory funds provide for PU 4034 Maritime Strike Passive Sensor cost reduction and capacity increase along with PU 0545 Tomahawk GEU-R hardware redesign efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational      PE 0204229N / Tomahawk Mssn Planning Ctr Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204311N$$, $$Integrated Surveillance System$$, $$rdte_navy_ba7$$, $$dw_darpa$$, 2026, 71800000, 80232000, 72473000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0204311N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 81977000, 84568000, 84933000, NULL, NULL, NULL, NULL, NULL, FALSE, 71459000, 71800000, 71901000, 71901000, NULL, 71901000, 86554000, $$The Deployable Surveillance Systems (DSS) project (0344), complementing the Fixed Surveillance System (FSS) and Surveillance Towed Array Sensor System (SURTASS), provides flexible and responsive wide area surveillance to the Theater Undersea Warfare (TUSW) commanders worldwide. DSS will operate as adjunct systems to meet the established FSS and SURTASS missions and to meet additional missions as articulated in the OPNAV Top Level Requirements documents and follow-on Course of Action Analysis (COAA) and as dictated by TUSW commanders evolving and emergent operational requirements. DSS is comprised of the following systems: Deep Water Passive (DWP) and Deep Water Active (DWA). Informed by TUSW Offset operations and the tailored requirements process, the DSS Middle Tier Acquisition (MTA) Rapid Fielding Program focused initially on the DWP increment and associated spiral development updates. Spiral developments to meet the evolving submarine threat will leverage on-going Navy, Defense Advanced Research Projects Agency (DARPA), and small business research efforts including processing and sensor technology. The follow-on increment is on DWA where FY23-26 includes funds that will provide a rapidly deployable sustained surveillance capability in response to emergent Fleet Undersea Warfare (USW) coverage gaps to include mitigating array outages or platform shortages. FY27 includes funds for DWA that will provide a rapidly deployable sustained surveillance capability in response to emergent Fleet Undersea Warfare (USW) coverage gaps to include mitigating array outages or platform shortages. The FY 2027 cost of the DSS Middle Tier of Acquisition effort is $15.120 million, including RDT&E and procurement of prototype units. Project 0766 provides for Integrated Undersea Surveillance Systems (IUSS) Research and Development Projects under the Maritime Surveillance Systems (MSS) Program Office (PEO UWS PMS 485). IUSS provides the Navy with its primary means of submarine detection, both nuclear and diesel. A portion of project 0766 Fixed Surveillance System (FSS) is classified, with details available at a higher classification level. The Surveillance Towed Array Sensor System (SURTASS) project comprises the mobile, tactical arm of the Integrated Undersea Surveillance System (IUSS), providing long range detection and cueing for tactical weapons platforms against both diesel- and nuclear-powered submarines. SURTASS also provides the undersea surveillance necessary to support regional conflicts and sea-lane protection. SURTASS has recent passive and active success against diesel submarines operating in both shallow and deep ocean environments. SURTASS is leveraging existing developments and reducing costs by using Non-Developmental Items and commercial hardware, supporting common Navy Undersea Warfare processing and towed array developments, and increasing operator efficiency through computer-aided detection Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                              Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational         PE 0204311N / Integrated Surveillance System Systems Development and classification processing. SURTASS development efforts include Low Frequency Active (LFA)/Compact Low Frequency Active (CLFA) improvements, common IUSS processing, twin-line array development and processing, next generation array developments, improved detection and classification/passive automation to counter quieter threats, integrated active and passive operations, and improved Battle Group support. Project 1768 T-ARC(X) is a candidate replacement program for U.S. Navy's only organic undersea cable laying and repair ship, USNS ZEUS (T-ARC 7), which is approaching the end of her extended service life. The ship's main mission is to deploy, repair, and retrieve undersea cables and equipment, with a secondary mission of conducting acoustic, hydrographic and bathymetric surveys.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204313N$$, $$Ship-Towed Array Surveillance Systems$$, $$rdte_navy_ba7$$, $$msc$$, 2026, 1990000, 1103000, 1428000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0204313N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 963000, 5017000, 2408000, NULL, NULL, NULL, NULL, NULL, FALSE, 1428000, 1990000, 954000, 954000, NULL, 954000, 2406000, $$T-AGOS are Ocean surveillance ships that gather underwater acoustical data to support the Integrated Undersea Surveillance System (IUSS) mission by providing a ship platform capable of theater anti-submarine passive and active acoustic surveillance. T-AGOS ships are operated by Military Sealift Command (MSC) to support the anti-submarine warfare (ASW) mission of Atlantic and Pacific Fleet Commanders. Both classes of T-AGOS ships use the Surveillance Towed-Array Sensor System (SURTASS) to gather undersea acoustic data. They also carry electronic equipment to process and transmit that data via satellite to shore stations for evaluation. Funding in this budget will recapitalize Navy's Auxiliary General Ocean Surveillance (T-AGOS) ships (four T-AGOS 19 Class vessels & one T-AGOS 23 Class vessel) with a total of seven (7) T-AGOS 25 Class ships based on the 2016 N81 Force Structure Assessment (FSA).$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204413N$$, $$Amphibious Tactical Supt Units$$, $$rdte_navy_ba7$$, $$navfac$$, 2026, 1711000, 1983000, 2238000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 37, "original_pe": "0204413N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 1131000, 1146000, 1161000, NULL, NULL, NULL, NULL, NULL, FALSE, 2211000, 0, 1526000, 1526000, NULL, 1526000, 1183000, $$Landing Craft, Air Cushion (LCAC): Research and development efforts to transfer technologies into functional uses on the current LCACs. Current technology initiatives include sustainability/reliability/readiness/performance analyses, LCAC communication improvements, compliance with Cybersecurity policy regulations, and LCAC Total Ownership Costs (TOC) reduction initiatives. Landing Craft, Utility (LCU 1700): Replacement program for the current LCU 1610 class craft - a class of craft that has exceeded its 25-year planned service life by more than double, average age of craft is over 50-years-old. LCU 1700 will provide similar payload, range, speed, and interoperability. Detail design contract awarded Q2 FY18. NECC Additive Manufacturing: In accordance with the National Defense Strategy (NDS), A Design for Maintaining Maritime Superiority 2.0, and Navy Facility Command (NAVFAC) Strategic Design 2.0, this program provides the Navy with new capabilities to enable resilient and agile logistics thru additive manufacturing (AM). Investing in AM enhances the fleet's ability to conduct operational logistics in a contested environment and ensures logistics supportability across the austere distributed battlespace. AM technology results in increased operational availability, on demand production of critical systems, and supply chain cost savings. This effort will identify critical parts suitable for AM production in the field; identify AM systems appropriate to produce and certify critical parts in the field; analyze and identify AM system implications across doctrine, organization, training, materiel, leadership and education, personnel, facilities and policy (DOTMLPF-P); conduct end-user training, field experimentation, and fleet exercise technology insertion to validate AM system capability and systems integration issues. Funds were realigned to PE 0604286N starting in FY 2026. Note: The FY 2026 spend plan for LCAC/LCU 1700 included $0 thousand of discretionary and $1,679 thousand of mandatory (reconciliation for a total of $1,679 thousand. The mandatory funding supported test and evaluation requirements for the LCU 1700 class. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational     PE 0204413N / Amphibious Tactical Supt Units Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204460M$$, $$Ground/Air Task Oriented Radar (G/ATOR)$$, $$rdte_navy_ba7$$, $$mc$$, 2026, 32045000, 63427000, 41346000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 37, "original_pe": "0204460M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 30567000, 20335000, 18047000, NULL, NULL, NULL, NULL, NULL, FALSE, 39754000, 32045000, 66255000, 66255000, NULL, 66255000, 18732000, $$The Ground/Air Task Oriented Radar (G/ATOR) is a multi-role, ground-based, expeditionary 3D radar system employed by both the Air Combat Element and Ground Combat Element within the Marine Air Ground Task Force. It satisfies the Marine Air Command and Control System and the Ground Counter Fire/Counter Battery capabilities. G/ATOR provides mobile, multi-functional, three-dimensional surveillance of air breathing targets, detection of cruise missiles, unmanned aerial systems, rockets, artillery and mortars, and the cueing of air defense weapons. G/ATOR contributes to Littoral Operations in a Contested Environment and Expeditionary Advanced Base Operations by surveillance and detection of enemy air threats not seen by Navy sensors in the littorals and participating in a cooperative engagement network of sensors and shooters. G/ATOR enables integrated fire control (IFC) and provides engage/fire on remote capability. G/ATOR surveillance coverage with IFC will provide unprecedented reach, volume, and precision in the execution of Operational Maneuver from The Sea allowing Naval forces to project and sustain power deep inland. G/ATOR is the primary ground-based sensor for the United States Marine Corps and is the only air defense/air surveillance radar currently in the Marine Corps inventory.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204571J$$, $$Joint Staff Analytical Support$$, $$rdte_dw_ba6$$, $$dw_js$$, 2026, 8070000, 4737000, 7433000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0204571J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 4534000, 4342000, 3145000, NULL, NULL, NULL, NULL, NULL, FALSE, 7165000, 8013000, 5088000, 5088000, NULL, 5088000, 3209000, $$The Joint Staff Analytical Support (JSAS) family of programs provide defense analytical support capabilities for the Joint Staff and Combatant Commands (CCMDs). JSAS encompasses tools and infrastructure required to conduct analyses and formulate results that assist the Chairman in fulfilling his statutory responsibilities. A primary focus of this analysis is the development of the operational concepts that guide the evolution of the Joint Force. This effort is led by the threat-informed Joint Warfighting Concept (JWC), an overarching framework that is detailed through subordinate Concepts of Operation (CONOPS) and Concepts of Employment (CONEMPs). These integrated concepts describe how the force will fight and drive the identification of Concept-Required Capabilities (CRCs). This ensures that the entire JWC family of concepts provides direct, traceable input to the Joint Force Requirements Process (JFRP), aids senior leader decision-making, and implements timely, low-cost Joint Force development initiatives.$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0204571N$$, $$Consolidated Trng Sys Dev$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 199067000, 112735000, 159648000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0204571N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 148470000, 136077000, 113796000, NULL, NULL, NULL, NULL, NULL, FALSE, 156770000, 199067000, 115839000, 115839000, NULL, 115839000, 115840000, $$Project 0604 Training Range and Instrumentation Development (TRID) projects develop specialized instrumentations for fleet readiness training while minimizing life cycle costs. Projects are development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Project 1427, Surface Tactical Team Trainer (STTT) develops upgrades during the sustainment phase of the Battle Force Tactical Training (BFTT) system and its modernization into the Advanced Training Domain (ATD), forging ready warfighters for the Fleet. BFTT and ATD are the core systems used to integrate weapon system elements and combat system components, creating the Surface Combat System Training Environment (SCSTE) Total Ship Training Capability (TSTC), a cornerstone of the Foundry. BFTT and ATD continue to integrate and update at the speed of relevance as new tactical capabilities are introduced, enabling crew operator proficiency from basic through sustainment training events and from single-ship organic events through distributed strike group certification Fleet Synthetic Training (FST) events, including COMPTUEX FST at-sea integration into a Live, Virtual, and Constructive (LVC) environment. Development of the next generation of ATD will align with combat systems virtualization efforts and focus on increased fidelity to represent contested environments,a critical step in modernizing the fleet for decisive advantage. This is achieved by leveraging the high-fidelity simulations used in the Combined Integrated Air and Missile Defense (IAMD) and Anti-Submarine Warfare (ASW) Trainer (CIAT) to guarantee overmatch. Continued development is required to integrate new capabilities and interfaces to provide training for AEGIS and SSDS combat system upgrades, addressing the Fleet's LVC Fleet Training Wholeness (FTW) initiative to ensure full-spectrum readiness. This modernization directly supports the DoW Training Transformation Plan and the Chief of Naval Operations Fleet Response Plan (OFRP), ensuring we are building a lethal and resilient force. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                        Date: April 2026 Appropriation/Budget Activity                                                          R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational               PE 0204571N / Consolidated Trng Sys Dev Systems Development Project 1982 Airborne Adversary Mission Systems builds upon existing RedNet architecture to allow classified software development and classified hardware integration such as electronic attack, infrared search, Radio Frequency (RF) emulation with encrypted range training data links, such as Tactical Combat Training System (TCTS) and Link 16. This project will enable the aircrew to accurately emulate peer threat capabilities and provide a standalone Adversary Operational Flight Program (OFP), that can be deployed on any aircraft with RedNet Multi-Layered Obstructed Brokered Bus-Controller & Routing for Advanced Integrated Networks (MOB Brain) avionics architecture and an encrypted range training pod. Primary platforms for development include the F-5, F-16 and F-18 within existing Naval Adversary Squadrons. These systems combined with a classified electronic kneeboard, allows for the development, integration and deployment of adversary mission hardware and software systems without modification of aircraft's existing OFP. This effort will provide for the future ability to participate fully in the Live Virtual Constructive (LVC) environment as well as provide physics and effects-based threat replications for the mission essential training of deploying Fleet aircrews. Project 2124 Air Warfare Training Development (AWTD) provides for advanced technology development, risk mitigation, study and demonstration in support of naval aviation manned and unmanned platforms, operational flight trainers, maintenance trainers, training networks, distributed mission training, and Live Virtual Constructive (LVC) training applications. Supports the Navy Aviation Simulation Master Plan (NASMP) upgrade efforts and Type/Model/Series programs with advanced visual system display configurations requirements. Assesses trainee cognitive requirements and the development and incorporation of next generation LVC, UAS constructive and associated visualization component technologies. Additionally, AWTD provides for advanced virtual component fidelity improvements for LVC capability. LVC technologies will facilitate advanced, cost-effective weapons and tactics training and emerging capability requirements in the Air-Sea Battle Space and Naval Integrated Fire Control-Counter Air capabilities development. AWTD investigates training applications of emerging technologies such as Augmented Reality (AR), Virtual Reality (VR), and Mixed Reality (MR) Head Mounted Displays (HMD), haptic feedback devices, and cross domain solutions/ cybersecurity solutions. Project 2124 (cont.) Supports the development of advanced analytics tools for the Joint Simulation Environment (JSE) and high-fidelity modeling for the Next Generation Threat System (NGTS), enabling greater realism and operational value for JSE and other training systems. Technologies under development are evaluated and refined using testbeds that incorporate aviator feedback to ensure operational suitability and alignment with Fleet needs. Project 3093 Tactical Combat Training System (TCTS) Increment II will provide an improved environment for air combat training utilizing a secure air-to-air and air-to- ground data link and will provide range tethered and range less operation capability to CONUS ranges and Forward Deployed Naval Forces (FDNF). TCTS Increment II will provide encrypted instrumentation for multiple fixed and rotary wing platforms as well as an enhanced threat environment. Engineering Development Model (EDM) units in multiple form factors are being developed in FY19 through FY30 and will support Developmental Testing events. The EDMs will be specifically utilized for testing in the following areas: Environmental Qualification, Software, High Accelerated Lifecycle, Ground System Integration, Airborne Subsystem (AS) Air Worthiness and Performance, Internal Mount (IM), and JSF Airworthiness and Performance. TCTS Increment II provides the foundational encrypted airborne network for implementation of Aviation Live Virtual Constructive (LVC) training capabilities. Project 3093 (cont.) Aviation LVC Live Aircraft Integration (ALLAI) Phase 1 funds the integration of live aircraft into the Live, Virtual, Constructive (LVC), training environment to close the Great Powers Competition training capability gap for the high-end fight. Aviation LVC will establish an integrated System of Systems (SoS) training environment including "blue" and "red" air components integrating already-developed capabilities with new developmental efforts to form a cohesive architecture that accurately emulates the high-end fight for warfighter training. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational          PE 0204571N / Consolidated Trng Sys Dev Systems Development Project 3093 (cont.) Aviation Performance/Proficiency Analytics (APPA) will deliver scalable, common data collection, storage, analysis, and reporting capability to provide quantitative, high-fidelity feedback and proficiency assessments to meet real-world threats. APPA addresses current Training Analysis Project (TAP) constraints to include scalability, site limitations, and tactical SME manpower requirements. APPA will develop government-owned standards and architecture for aviation training data collection; deliver an AI-augmented debrief tool for data processing and analysis supported by tactical SMEs and data scientists; multilevel security databases; network capability; and intelligent, semi-automated assessments, reporting and visualization. An open systems architecture enables multi-domain integration. The system will enable rigorous and repeatable post-flight assessment of high-end Great Power Competition warfighting scenarios to produce individual performance "baseball cards", squadron reports, detailed strengths and weaknesses, and CVW reports measured against What-It-Takes-To-Win (WITTW) performance standards. Project 3093 (cont.) E-2D Internal Mount will develop and integrate a chassis mounted solution to provide encrypted Time, Space, Position Information (TSPI) in support of Live, Virtual Constructive training operations. Development will include an upgrade to the encryptor to be in compliance with Security Evaluation Requirements Document (SERD) 2.0 requirements, along with National Security Agency certification. E-2D Internal Mount will be an enabler to Synthetic Inject to Live (SITL) for the platform and is required for future untethered (removed from Tactical Training Ranges) operations. Project 3093 (cont.) LITL program will develop and integrate Link Inject to Live (LITL) into the F-35 and H-60. Additional platforms are pending. LITL will integrate Live, Virtual, Constructive (LVC) exercises for training purposes. LITL utilizes a synthetic scenario generation tool and integrates live game players into the synthetic environment by a message set communicated over Link-16. Synthetic entity information delivered over Link-16 will be injected into the existing platform training capability which will be modified to accommodate the LITL synthetic environment. Project 3356 High Fidelity Surface Trainers funds high fidelity Aegis Integrated Air and Missile Defense (IAMD) individual, instructor, strike group and team trainers for all Advanced Capability Build (ACB) and below Aegis baselines. This line provides funds for development of a High Fidelity Aegis Combined Integrated Air and Missile Defense (IAMD) and Anti-Submarine Warfare (ASW) Trainer (CIAT). Additionally, this line funds the development of the Surface Training and Readiness Management System (STRMS) and training scenario development for Integrated Tactical Trainers and Bridge Part Task Trainers. This line supports Surface Training Program (STP) (previously Surface Training Advanced Virtual Environment (STAVE)) methodology by researching and developing trainers that will create an immersive and interactive learning environment and support both Chief of Naval Operations (CNO) High Velocity Learning and Career Training Continuum (CTC) intent and developing advanced technology for collecting Sailor performance data to determine measured benefit of delivered training. JUSTIFICATON FOR BUDGET ACTIVITY: This program is funded under Operational Systems Development because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational        PE 0204571N / Consolidated Trng Sys Dev Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205159D8Z$$, $$Golden Dome for America - Army$$, $$rdte_gd_ba3$$, $$dw$$, 2026, 0, 0, 0, NULL, $${"ba": "03", "line": 12, "note": "Army-tagged but Golden Dome appr; BA-01/BA-02 lines also exist (O&M and Procurement classes), captured here is RDT&E BA-03 only", "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 839000, "fy27_disc": 0, "fy27_mand": 427000, "fy26_total": 839000, "fy27_total": 427000, "appropriation": "3007D"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 12, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, $$GDAF$$, FALSE, 0, 839000000, 0, 0, 3219517000, 3219517000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205159D8Z_ba1$$, $$Golden Dome for America - Army$$, $$om_gd_ba1$$, $$dw$$, 2026, 0, 0, 0, NULL, $${"ba": "01", "line": 2, "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 135000, "fy27_disc": 0, "fy27_mand": 7050, "fy26_total": 135000, "fy27_total": 7050, "appropriation": "3007D", "fy27_mand_v158": true}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, NULL, FALSE, NULL, 135000000, 0, 0, 112734000, 112734000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205219F$$, $$MQ-9 UAV$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 26689000, 82393000, 7074000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0205219F"}$$::jsonb, $$The MQ-9 Reaper system is a modular and adaptable system comprised of the Aircraft, sensors, Ground Control Station (GCS), communications equipment, weapon kits, support equipment, simulator and training devices, Readiness Spares Packages (RSP), technical data/training, and required personnel to operate, maintain, and sustain the system. Mission-specific equipment is employed to allow specific aircraft and GCS configurations to be tailored to fit mission needs. Current President's Budget request supports 56 Combat Lines to meet DoD force offering requirements to combat threats. The three key development programs in this Program Element are: MQ-9 System Lifecycle Agile Modernization (SLAM) enabling rapid fielding of new software, hardware, and integration; Squadron Operations Centers (SOC) for development and fielding of standardized operations centers necessary for remote split operations, to provide mission data and tasking information to aircrew, and to disseminate and/or exchange mission data with the intelligence community; and MQ-9 Upgrade for improving existing systems. The Air Force established the MQ-9 Multi-Domain Operations (M2DO) configuration with enhancements consisting of Anti-Jamming GPS, Enhanced Power, Link 16, Open Mission System (OMS) (to include Stellar Relay and Intelligent Electronics Unit (iEU)), and Command and Control (C2) Resiliency to maintain its viability in modern conflict. The FY 2026 request was reduced by -$1.026M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024 .759M was expended for civilian pay expenses in this program element and in FY2025 0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                              Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0205219F / MQ-9 UAV Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 173, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 6841000, 32600000, 16723000, 16723000, 0, 16723000, 0, $$The MQ-9 Reaper system is a modular and adaptable system comprised of the Aircraft, sensors, Ground Control Station (GCS), kill chain integration, communications equipment, weapon kits, support equipment, simulator and training devices, Readiness Spares Packages (RSP), technical data/training, and required personnel to operate, maintain, and sustain the system. Mission-specific equipment is employed to allow specific aircraft and GCS configurations to be tailored to fit mission needs. Current President's Budget request supports 56 Combat Lines to meet DoD force offering requirements to combat threats. The three key development programs in this Program Element are: MQ-9 System Lifecycle Agile Modernization (SLAM) enabling rapid fielding of new software, hardware, and integration; Squadron Operations Centers (SOC) for development and fielding of standardized operations centers necessary for remote split operations, to provide mission data and tasking information to aircrew, and to disseminate and/or exchange mission data with the intelligence community; and MQ-9 Upgrade for improving existing systems. The Air Force established the MQ-9 Multi-Domain Operations (M2DO) configuration, which includes Anti-Jamming GPS, Enhanced Power, Link 16, Open Mission System (OMS) (to include Stellar Relay and Intelligent Electronics Unit (iEU)), and Command and Control (C2) Resiliency to maintain its viability in modern conflict. This program element may include all necessary pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. In FY2026 0M was expended for civilian pay expenses in this program element and in FY2027 0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0205219F / MQ-9 UAV Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205401JCA$$, $$Counter - Small Unmanned Aircraft Systems$$, $$rdte_dw_ba5$$, $$dw_js$$, 2027, 0, 0, 0, NULL, $${"fy26_v182_disc_K": 0, "fy26_v182_supp_K": 6500, "fy26_v182_total_K": 6500, "fy26_v182_note_name": "Research, Development, Test & Evaluation (RDT&E) - Counter - Small Unmanned Aircraft Systems", "fy26_v182_source_file": "RDTE_TJS_PB_2027.txt", "fy26_v182_source_line": 1252}$$::jsonb, NULL, NULL, 580541000, 581310000, 101411000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 6500000, 580348000, 580348000, NULL, 580348000, 102425000, $$The FY 2026 spend plan amount for Research, Development, Test & Evaluation (RDT&E) - Counter - Small Unmanned Aircraft Systems includes $0 thousand of discretionary and $6,500 thousand of mandatory (reconciliation) for a total of $6,500 thousand. The Joint Interagency Task Force 401 (JIATF 401) is the Department of War (DoW) lead organization to counter small Unmanned Aerial Systems (C-sUAS). JIATF 401 synchronizes C-UAS efforts across the DoW to rapidly deliver joint capabilities at scale to defend the homeland, protect US and allied forces, defend critical infrastructure, and assist federal agencies. The task force has a global focus and is a multifaceted organization leading DoW C-sUAS activities at the nexus of the Office of the Secretary of War (OSW), the Joint Staff, Combatant Commands, and the Services. The JIATF 401 is innovative, scalable, and threat adaptive. We have one measure of effectiveness: quickly deliver state of the art C-sUAS capability to the warfighter at home and abroad. The Secretary of War (SecWar) designated the Secretary of the Army (SA) as the DoW’s Executive Agent (EA) for C-sUAS and aligned the JIATF 401 as a Chairmans Controlled Activity (CCA) in the Joint Staff. The EA holds the acquisition and procurement authority and oversight for the JIATF 401 efforts. The C-sUAS System Development and Demonstration efforts are focused on the rapid identification, development, testing, evaluation, and integration of advance prototyped technologies to defeat sUAS threats. The efforts, through operational assessments, provide warfighters the ability to comprehensively detect, track, identify, and defeat threat Group 1, 2 and 3 UAS platforms. These joint development efforts will provide rapidly integrated solutions to meet the needs of the Military Services and DoW Agencies against current and emerging threats.$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205412A$$, $$Environmental Quality Technology - Operational System Dev$$, $$rdte_army_ba7$$, $$asa_alt$$, 2026, 0, 271000, 269000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0205412A", "page_header": "Department of the Army"}$$::jsonb, $$The Environmental Information Technology Management (EITM) program includes support for the Defense Environment, Safety & Occupational Health Network Information Exchange (DENIX) defense business system, as well as its database and reporting application, the Knowledge Based Corporate Reporting System (KBCRS). This request for research, development, test and evaluation (RDTE) is to implement necessary enhancements to facilitate DENIX's Platform-as-a-Service capabilities, with additional modernizations that will improve the DoD's ESOH system of record and reporting tool set. This also includes upgrades to incorporate ongoing cybersecurity, cloud computing, and other information technology requirements.$$, NULL, NULL, NULL, NULL, NULL, NULL, 224, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 259000, 0, NULL, NULL, NULL, NULL, NULL, $$The Environmental Information Technology Management (EITM) program includes support for the Defense Environment, Safety & Occupational Health Network Information Exchange (DENIX) defense business system, as well as its database and reporting application, the Knowledge Based Corporate Reporting System (KBCRS). This request for research, development, test and evaluation (RDTE) is to implement necessary enhancements to facilitate DENIX's Platform-as-a-Service capabilities, with additional modernizations that will improve the DoW's ESOH system of record and reporting tool set. This also includes upgrades to incorporate ongoing cybersecurity, cloud computing, and other information technology requirements.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205601N$$, $$ANTI-RADIATION MISSILE IMPROVEMENT$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 33659000, 83564000, 22066000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0205601N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 45587000, 32668000, 19331000, NULL, NULL, NULL, NULL, NULL, FALSE, 21949000, 33659000, 80491000, 80491000, NULL, 80491000, 19679000, $$Research, Development, Test and Evaluation funding for the Joint Service Anti-Radiation Missile (ARM) program, which will include near and far term performance improvements, cost reduction, and studies that establish future development requirements. JUSTIFICATION FOR BUDGET ACTIVITY: These projects are funded under Operational Systems Development because they include development efforts to upgrade systems that have been fielded or have received approval for full-rate production and anticipate funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205620N$$, $$Surface ASW Cmbt Sys Integr$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 0, 28872000, 29887000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0205620N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 28793000, 0, 0, 0, NULL, 0, 0, $$The objective of this Program Element (PE) is to significantly improve existing AN/SQQ-89A(V)15 Surface Ship Anti-Submarine Warfare (ASW) sonar system capabilities through quick and affordable development and integration of emergent, transformational technologies in support of Surface Ship and Theater ASW (TASW) as required to pace the threat. Detection and classification play uniquely vital roles in the success of any ASW campaign. The Advanced Capability Build (ACB) spiral development process is the primary means by which these improvements are developed. ASW remains a Navy core competency in a dynamic and uncertain maritime environment. U.S. adversaries continue to develop asymmetric capabilities and capacities to deter, disrupt, or delay the entry of U.S. and allied naval forces, and pose a constant challenge as we implement the Maritime Strategy. Evolving submarine technologies offer enhanced stealth, speed, endurance, weapons, and operational proficiency, foretelling that the adversary submarine of the future will have a significantly larger sphere of influence, while presenting less vulnerability to U.S. forces. The effective offensive engagement range of the adversary submarine of the future will continue to match or outrange individual U.S. and multi-national platform sensors and weapons in many tactical environments. Submarines are an increasing threat to all Naval and Allied ships, particularly modern diesel subs and faster torpedoes. Not only can the presence of potential hostile submarines delay naval combatant action until they are located and neutralized, submarines can also disrupt all seaborne logistics supply for any ground campaign as well as maritime commerce. U.S. forces must be effective in all operating environments, ranging from the deep open ocean to the littorals, and are key to countering adversarial anti- access and area denial strategies. This PE takes advantage of the AN/SQQ-89A(V)15 Open System Architecture (OSA) and Acoustic Rapid Commercial-Off-The-Shelf (COTS) Insertion (ARCI) initiatives to integrate Torpedo Detection, Classification, and Localization (TDCL) and ASW sonar combat system capability improvements. The AN/SQQ-89A(V)15 COTS-based Surface Ship ASW Combat System is planned as a backfit program for all DDG51 class ships. The Open Architecture (OA) system enables the ACB process and provides budget flexibility to make COTS/OA technology solutions and ARCI-type initiatives affordable. Improvements are tested in the laboratory and at-sea. Undersea Warfare (USW) technology implementation will take advantage of improvements developed under the submarine Advanced Processing Build (APB) and Advanced Surveillance Build (ASB) programs and will in turn share unique improvements developed under this program with the submarine and surveillance USW communities. The ACB and APB programs are managed under a common development organization and process titled 'AxB'. While each platform retains its uniqueness Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational       PE 0205620N / Surface ASW Cmbt Sys Integr Systems Development and focus in functional domains essential to mission success, a premium is placed on development of common capabilities and modular architecture technologies to maximize commonality and cost effectiveness. This PE includes funding for the AN/SQQ-89A(V)15 Surface Ship ASW Test & Evaluation (T&E) program, which conducts testing and analysis to support certification of AN/SQQ-89A(V)15 Surface Ship ASW Combat System ACBs prior to fielding. Additionally, finalization of Test & Evaluation Master Plans (TEMPs) and AN/SQQ-89(V) Developmental Test (DT) and Operational Test (OT) events are conducted under this program. This PE includes funding for the AN/SQQ-89A(V)15 Surface Ship Engineering Measurement Program (SSEMP), which measures the performance of existing and new AN/SQQ-89A(V)15 Surface Ship ASW Combat System Technical Insertion (TI)/ACB baselines and enables data-based assessment of the capabilities and shortfalls in the performance of these systems in realistic scenarios. (Note about TI nomenclature: After TI-20, there will be a nomenclature shift for hardware baselines. Hypervisor Technology 0 (HT0) will replace what would have been TI-22. HT0 enables the deployment of virtualization technologies that create a logical separation between hardware and software, which can simplify future upgrades and accelerate software certification.) This PE includes funding to support cyber security initiatives to align future AN/SQQ-89A(V)15 Surface Ship ASW Combat System baselines with future AEGIS Integrated Combat Systems. This PE contributes to the development of the ASW component of the guided missile Frigate (CONSTELLATION Class, FFG 62) program.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205632N$$, $$MK-48 ADCAP$$, $$rdte_navy_ba7$$, $$peo_subs$$, 2026, 184338000, 202302000, 144935000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0205632N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 197861000, 195590000, 132389000, NULL, NULL, NULL, NULL, NULL, FALSE, 142331000, 53338000, 123011000, 123011000, NULL, 123011000, 135211000, $$The MK 48 ADCAP (Advanced Capability) Research, Development, Test and Evaluation (RDT&E) program executes incremental development of weapon performance improvements in two development product areas:(1) Advanced Processor Builds (APBs) (operational software), and (2) Torpedo Technology Insertions (TIs) (hardware). This Program Element (0205632N/0366) is tied to development programs that leverage a joint United States/Australia Armaments Cooperative Project (ACP) and develop MK 48 ADCAP technologies developed by the Office of Naval Research (ONR) and Strategic Capabilities Office (SCO). The Advanced Processor Builds (APBs) spiral engineering development process provides for continual performance improvements to the torpedo's operational software (OPSW). The Torpedo APB (TAPB) focused development testing and implementation within the APB process is being utilized to address shallow water as a critical operating area to counter near- peer adversaries and third world diesel electric submarines. In-water testing, in conjunction with laboratory simulation efforts, has shown that significant performance improvements can be made by implementing changes to weapon tactics and software algorithms. The TAPB program also leverages the Royal Australian Navy (RAN) joint torpedo program and technologies developed by ONR and SCO in the areas of torpedo broadband signal processing, tactics processing, and alertment. Torpedo Technology Insertions (TIs) will provide for significant torpedo hardware improvements and upgrades, including the transition and testing of advanced technologies from the R&D community. This approach will incorporate manufacturing development, integration and testing of transitioning technologies from ONR and SCO for ADCAP upgrades in the areas of torpedo sensors, energetics, propulsion, weapon/platform connectivity, and improved fusing. These efforts will continue torpedo development investment at a lower cost and shorter term than traditional torpedo programs. The MK 48 MOD 8 (APB 6/TI-1) Heavyweight Torpedo (HWT) program is an upgrade to the MK 48 MOD 7 HWT which will consist of an operational software upgrade referred to as APB 6 and a hardware upgrade referred to as TI-1. TI-1 will include a Guidance and Control (G&C) section upgrade including a new Sonar Assembly (higher density array, transmitter, receiver), and an Improved Post Launch Communications System (IPLCS). IPLCS will provide additional capability above the existing copper guidance wire with fiber optics. These improvements are needed for increased performance in the presence of advanced countermeasures, shallow water, low Doppler targets, Very Shallow Water (VSW), improve fusing, and Anti Surface Warfare (ASuW). TI-1 will also include features from three ONR Future Naval Capabilities (FNC) programs. The MK 48 MOD 9 (APB 7/TI-2) program provides extensive and important hardware and software capability improvements to the MK 48 MOD 7 and MOD 8 heavyweight torpedo (HWT). The capability improvements include a new propulsion system for increased range and advance sensing capabilities against surface and subsurface targets. The MK 48 MOD 9 (APB 7/TI-2) provides distinctly different capabilities than the MK 48 MOD 8 (APB 6/TI-1) and is intended for different operational Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational   PE 0205632N / MK-48 ADCAP Systems Development missions. The MK 48 MOD 9 software improvements consist of the APB 7 software and algorithm upgrades for advance sensing and processing capabilities. The MK 48 MOD 9 hardware improvements consist of TI-2 hardware upgrades replacing the legacy Otto fuel engine with the Stored Chemical Energy Propulsion System (SCEPS) for increased range. The MK48 Afterbody Upgrades program leverages other existing ONR efforts outside of the APB and TI programs to identify and implement updates including sensing, afterbody performance, and increased Otto fuel range across the MK 48 ADCAP family. MK-48 Heavyweight Warhead which provide and an opportunity to improve performance over Legacy MK107 Warheads against surface and submarine target sets through both warhead production restart and new capability development through improved sensing and UNDEX material improvements. The FY 2026 spend plan amount includes $53,338 thousand of discretionary and $180,000 thousand of mandatory (reconciliation) for a total of $233,338 thousand.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205633N$$, $$Aviation Improvements$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 127421000, 138457000, 136276000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0205633N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 128269000, 127190000, 122961000, NULL, NULL, NULL, NULL, NULL, FALSE, 134381000, 138522000, 108505000, 108505000, NULL, 108505000, 125149000, $$Project 0601 - Common Ground Equipment is a Naval Aviation Project to apply new technology to common support equipment due to obsolescence necessary to support multiple systems/aircraft within the Navy. Project 0852: Consolidated Automated Support System (CASS) Family of Testers (FoT) are standardized Automated Test Equipment (ATE) with computer assisted, multi-function capabilities to support the maintenance of aircraft weapons systems and missiles. Organizational Level (O-Level) testers are other types of standardized ATE with computer assisted, multi-function capabilities to support the maintenance of aircraft weapons systems. ATE host, and their Test Program Sets (TPS), along with associated ancillary are considered Automatic Test Systems (ATS). Project 1041 - Aircraft Equipment Reliability/Maintainability Improvement Program is the only Navy program that provides engineering support for in-service out-of- production aircraft equipment and provides increased readiness at reduced operational and support cost. Project 1355 - Aircraft Engine Component Improvement Program develops reliability and maintainability and safety enhancements for in-service Navy aircraft engines, transmissions, propellers, starters, auxiliary power units, electrical generating systems, fuel systems, fuels, and lubricants. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                    Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational            PE 0205633N / Aviation Improvements Systems Development Project 1356 - Corrosion Prevention Improvements funding will enable the NAE to establish a Center of Excellence for Corrosion and Finish (CoECF) Training focused on educating, training, and certifying qualified, proficient maintainers capable of performing: corrosion identification, corrosion inspection, corrosion prevention, corrosion repair and restoration. Qualified, proficient maintainers will improve material readiness through improved material condition, while also developing the knowledge & maintenance skills of Sailors and Marines. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0205671F$$, $$Joint Counter RCIED Electronic Warfare$$, $$rdte_af_ba7$$, $$afrl_ry$$, 2026, 3424000, 2303000, 3372000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0205671F"}$$::jsonb, $$Program funds Counter Radio-Controlled Improvised Explosive Device Electronic Warfare (CREW) Mounted, Dismounted, and Fixed systems. CREW devices are self- protection systems critical to Mine Resistant, Ambush Protected (MRAP) vehicle mounted, Joint Light Tactical Vehicle (JLTV) mounted, Explosive Ordinance Disposal and Tactical Air Control Party (TACP) dismounted and Security Forces (SF) Entry Control Point fixed operations. Includes integration of the devices into currently fielded systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.00M was expended for civilian pay expenses in this program element, and in FY25 $0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 2920000, 2977000, 3034000, NULL, NULL, 174, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 3325000, 3382000, 2816000, 2816000, 0, 2816000, 3095000, $$Program funds Counter Radio-Controlled Improvised Explosive Device Electronic Warfare (CREW) Mounted, Dismounted, and Fixed systems. CREW devices are self- protection systems critical to Mine Resistant, Ambush Protected (MRAP) vehicle mounted, Joint Light Tactical Vehicle (JLTV) mounted, Explosive Ordinance Disposal and Tactical Air Control Party (TACP) dismounted and Security Forces (SF) Entry Control Point fixed operations. Includes integration of the devices into currently fielded systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.00M was expended for civilian pay expenses in this program element, and in FY25 $0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0206335M$$, $$Common Aviation Command and Control Sys (CAC2S)$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 17813000, 12208000, 18332000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 38, "original_pe": "0206335M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 0, 1419000, 1448000, NULL, NULL, NULL, NULL, NULL, FALSE, 17626000, 17813000, 0, 0, NULL, 0, 769000, $$Common Aviation Command and Control System (CAC2S) is a Commandant of the Marine Corps Force Design program which provides the Aviation Combat Element with the necessary hardware, software, equipment, and facilities to effectively command, control, and coordinate aviation operations. CAC2S accomplishes the missions with a family of systems to support the Marine Air Ground Task Force (MAGTF), Naval forces, Joint Services, and Coalition Forces. CAC2S integrates the functions of aviation command and control (C2) into an interoperable system that supports the core competencies of all Marine Corps warfighting concepts. CAC2S, in conjunction with the Marine Air Command and Control System organic sensors, AN/TPS-80 Ground/Air Task Oriented Radar, and the weapon system Composite Tracking Network (CTN) provides enhanced air control, improved situational awareness, sensor integration, full Tactical Data Link integration, airspace and battle planning and command functionality, and sensor netting integration (CTN). CAC2S, with these organic MACCS programs, support the tenets of Expeditionary Maneuver Warfare and foster joint interoperability. CAC2S Increment I replaced legacy aviation command and control systems in the following Marine aviation agencies: Direct Air Support Center, Tactical Air Command Center, Tactical Air Operations Center, and Marine Air Traffic Control. In line with Force Design, CAC2S is to begin the development and prototyping of the Small Form Factor (SFF) variant in FY 2022. The SFF is a CAC2S variant required to meet the needs of Expeditionary Advance Base Operations and Force Design. The SFF variant will possess the same Tactical System, Data Link, and interface capabilities as the CAC2S Increment 1 system with the added benefits of being rapidly deployable, emitting at a lower signature, and reduced size and weight. The SFF's versatility will be a key enabling capability to support the task organization of the Marine Littoral Regiments as it meets the needs of Marine Corps Expeditionary Advance Base Operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational       PE 0206335M / Common Aviation Command and Control Sys (CAC2S) Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0206623M$$, $$MC Ground Cmbt Spt Arms Sys$$, $$rdte_navy_ba7$$, $$mcsc$$, 2026, 70139000, 92667000, 75377000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 38, "original_pe": "0206623M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 106108000, 99418000, 50378000, NULL, NULL, NULL, NULL, NULL, FALSE, 69049000, 72552000, 79031000, 79031000, NULL, 79031000, 51643000, $$This Program Element (PE) provides a collective of USMC Projects that represent a comprehensive effort to modernize and enhance the warfighting capabilities of the Marine Corps across various domains. They focus on equipping Marines with advanced combat systems, including modernized vehicles, improved infantry weapons Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational           PE 0206623M / MC Ground Cmbt Spt Arms Sys Systems Development and optics, enhanced ballistic protection, and advanced fire support capabilities like the LW155 howitzer and HIMARS. A recurring theme is the emphasis on leveraging technology to improve lethality, survivability, and situational awareness while also reducing logistical burdens and operational costs. Beyond direct combat enhancements, a significant portion of these projects supports the Marine Corps' ability to train effectively, operate in diverse environments, and sustain operations in contested areas. This includes the development of realistic training simulations, rigorous testing of amphibious and robotic systems, providing aerial resupply solutions, ensuring the availability of advanced munitions, improving mobility in distributed operations, and supporting specialized reconnaissance missions. The focus on low-cost, non-developmental items and coordination with other services highlights the commitment to efficient resource utilization and maximizing the impact of investments in Marine Corps readiness$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0206625M$$, $$USMC Intelligence/Electronics Warfare Sys$$, $$rdte_navy_ba7$$, $$mc$$, 2026, 34289000, 46762000, 37372000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 38, "original_pe": "0206625M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 69553000, 65202000, 70214000, NULL, NULL, NULL, NULL, NULL, FALSE, 37372000, 41789000, 149055000, 149055000, NULL, 149055000, 74751000, $$This Program Element (PE) for Intelligence Command and Control (C2) includes Military Intelligence Program (MIP) funds for Marine Corps Intelligence capabilities necessary to support the employment of intelligence, reconnaissance, surveillance (ISR), and target acquisition resources integral to delivering decision advantage at the speed of operational relevance. Marine Corps intelligence capabilities are divided into three functional areas organized along intelligence processes: Sensing (persistent ISR), Analysis (Distributed Common Ground/Surface System Marine Corps), and Dissemination (intelligence dissemination and utilization). This PE funds the Sensing and Dissemination portfolios while the Analysis portfolio is budgeted under DCGS-MC PE 0305208M.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L040$$, $$Large UUV$$, $$proc_navy_1810_ba1$$, $$dw_diu$$, 2026, 4079000, 3989000, 56667000, NULL, $${"page": 96, "ba_num": "01", "source": "p1_fy26", "ba_name": "Ships support equipment", "line_no": "40", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "01", "appr": "OPN", "title": "P-1 Line 37", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 240, "p1_line_num": 37, "fy27_total_K": 240}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 4079, "li_num": 37, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA1_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 4079000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 435410000, NULL, NULL, NULL, FALSE, 0, 0, 240000, 240000, 0, 240000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA1_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207040F$$, $$Multi-Platform Electronic Warfare Equipment$$, $$rdte_af_ba7$$, $$afrl_ry$$, 2026, 0, 14312000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207040F"}$$::jsonb, $$The Angry Kitten Combat System (AKCS) program has developed electronic attack capabilities supporting USAF fighter and attack platforms. The current 4th generation electronic warfare (EW) pods have diminishing manufacturing sources and require advanced capabilities. The AKCS program developed prototype EW systems for 4th/5th generation aircraft that improve threat detection techniques, incorporate open system architecture, and advance rapid reprogramming capabilities. Funds were utilized to leverage existing EW pod components and develop a relevant EW system supporting fighter and attack platforms. No funding required in FY26. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY23 0.0M was expended for civilian pay expenses in this program element. In FY24, FY25 & FY26 0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207040F / Multi-Platform Electronic Warfare Equipment Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 175, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 0, 7000000, 0, 0, 0, 0, 0, $$The Angry Kitten Combat System (AKCS) program has developed electronic attack capabilities supporting USAF fighter and attack platforms. The current 4th generation electronic warfare (EW) pods have diminishing manufacturing sources and require advanced capabilities. The AKCS program developed prototype EW systems for 4th/5th generation aircraft that improve threat detection techniques, incorporate open system architecture, and advance rapid reprogramming capabilities. Funds were utilized to leverage existing EW pod components and develop a relevant EW system supporting fighter and attack platforms. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207040F / Multi-Platform Electronic Warfare Equipment Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207133F$$, $$F-16 Squadrons$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 216638000, 119589000, 104252000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207133F"}$$::jsonb, $$The F-16 is a multi-role fighter that comprises roughly 40% of the USAF fighter fleet with over 830 aircraft supporting a variety of air-to-air and air-to-surface missions, such as offensive and defensive counter-air, close air support, forward air control, air interdiction (day/night and all-weather) and Suppression of Enemy Air Defenses (SEAD)/Destruction of Enemy Air Defenses (DEAD). F-16 posture and readiness combined with low operating costs deliver affordable capacity for the USAF and partner nations. Its capabilities continue to evolve, capitalizing upon advancements made in computers, avionics systems, engines, and structural technologies. These advancements meet emerging warfighter requirements to combat current and evolving enemy threats. Funding described in this document provides upgrades to the F-16 platform necessary for the delivery of joint lethality in the coming decades. These computer processing and avionics upgrades are critical to a modernized architecture compatible with current open, agile, and digital concepts that will maintain platform viability into the 2040s. Post-Block and Pre-Block F-16s have similar capabilities and are interoperable but require some independent modernization and sustainment of hardware, software, and training. The F-16 Foreign Military Sales (FMS) Program is one of the largest in DoD, providing assurance to 29 partners and growing. F-16 remains in production in South Carolina and additional nations continue to commit to new aircraft purchases. RDT&E efforts include, but are not limited to, enduring programs for Operational Flight Program (OFP) Software (SW) development, Integrated Test activities, Active Electronically Scanned Array (AESA) radar, Simulators/Trainers, Engineering Manufacturing and Design (EMD) Hardware/Advanced capability improvements, and Diminishing Manufacturing Sources (DMS). Programs ending funded development activities for Integrated Viper Electronic Warfare Suite (IVEWS) and M-Code. Programs complete or nearing full development completion for Modular Mission Computer (MMC) Upgrade/Programmable Display Generator (PDG) Upgrade, Advanced Identification Friend or Foe (AIFF-Mode 5) APX-127, and Data Bus Cybersecurity. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. In FY24, 7.067M is the estimate for civilian pay expenses in this program element, and in FY25 7.397M is forecasted for civilian pay expenses in this program element. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and delivery F-16 modifications for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to civilian pay expenses budgeted in program element 0605828F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207133F / F-16 Squadrons Operational Systems Development The FY 2026 request was reduced by $2.148 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 385075000, 303374000, 201385000, NULL, NULL, 176, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 107714000, 229857000, 527739000, 527739000, 0, 527739000, 176253000, $$The F-16 is a multi-role fighter that comprises roughly 40% of the USAF fighter fleet with 810 aircraft supporting a variety of air-to-air and air-to-surface missions, such as offensive and defensive counter-air, close air support, forward air control, air interdiction (day/night and all-weather), and Suppression of Enemy Air Defenses (SEAD)/Destruction of Enemy Air Defenses (DEAD). F-16 posture and readiness combined with low operating costs delivers affordable capacity for the USAF and partner nations. Its capabilities continue to evolve, capitalizing upon advancements made in computers, avionics systems, engines, and structural technologies. These advancements meet emerging warfighter requirements to combat current and evolving enemy threats. Funding described in this document provides upgrades to the F-16 platform necessary for the delivery of joint lethality in the coming decades. These computer processing and avionics upgrades are critical to a modernized architecture compatible with current open, agile, and digital concepts that will maintain platform viability into the 2040s. Post-Block (40/42/50/52) and Pre-Block (30) F-16s have similar capabilities and are interoperable but require some independent modernization and sustainment of hardware, software, and training. The F-16 Foreign Military Sales (FMS) Program is one of the largest in DoW, providing assurance to 29 partners and growing. F-16 remains in production in South Carolina and additional nations continue to commit to new aircraft purchases. RDT&E efforts include, but are not limited to, enduring programs for Operational Flight Program (OFP) Software (SW) development, Integrated Test activities, Active Electronically Scanned Array (AESA) radar, Simulators/Trainers, Integrated Viper Electronic Warfare Suite (IVEWS), Next Gen Mission Computer (NGMC)- New Start, Engineering Manufacturing and Design (EMD) Hardware/Advanced capability improvements, M-Code, and Diminishing Manufacturing Sources (DMS). Programs complete or nearing full development completion for Advanced Identification Friend or Foe (AIFF-Mode 5) APX-127, Data Bus Cybersecurity, and F-16 Electrical Test Equipment. The FY2026 spend plan amount for RDT&E includes $229,857 thousand of discretionary and $82,500 thousand of mandatory (reconciliation) for a total of $312,357 thousand. Mandatory funds are for the IVEWS program. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0207133F / F-16 Squadrons Operational Systems Development Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207134F$$, $$F-15E Squadrons$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 233018000, 40348000, 158603000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207134F"}$$::jsonb, $$The F-15C continues to provide air superiority with an undefeated and unmatched aerial combat record. The F-15E retains this air superiority capability and adds systems, such as conformal fuel tanks (CFTs), advanced imaging and targeting systems, to meet the requirement for all-weather, deep-penetration, and night/under-the- weather, air-to-surface attack. Upgrades to F-15 aircraft are critical to maintaining combat viability (lethality, survivability, and supportability) in support of the National Defense Strategy. With newer F-15E aircraft projected to remain in service past 2040, avionics modernization is key to long-term weapon system viability. Major avionics upgrades include radar modernization (both hardware and software) and capability enhancements via precision timing, data delivery and processing technology, precision registration systems, display optimization, instrumentation digitization and modernization, central computer processing power increases, digital mission event recording systems, and an infrared (IR)-based fire control system. The proliferation of fourth-generation enemy aircraft and sophisticated "double-digit" anti-aircraft missile systems pose a significant threat to F-15 survivability. A fully integrated electronic warfare suite holds the promise of providing improved survivability as well as expanded electronic attack capability. Nearly all new avionics or weapons capabilities require an Operational Flight Program (OFP) software update to fully employ the capability. OFP updates are directly linked to ACC prioritized capability needs which are continuously assessed and updated. OFP's agile development framework provides the ability to quickly change capability development focus to meet the time-based need to mitigate and defeat emerging threats. The OFP agile development framework integrates and deploys new capabilities on an annual basis to incorporate new technology/equipment or improvements for support equipment, mission planning systems, and training device upgrades which enhance performance, supportability, and aircrew training. Funds may be used to resolve issues among the F-15 fleet (e.g., emerging safety of flight issues and diminishing manufacturing sources), to accommodate technology insertion, and to fulfill Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This includes technical and acquisition-related studies to ensure F-15 lethality and survivability beyond 2040. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 1.794M was expended for civilian pay expenses in this program element, and in FY 2025 1.095M is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by 0.555 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207134F / F-15E Squadrons Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 149269000, 170063000, 171118000, NULL, NULL, 177, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 138345000, 229946000, 322889000, 322889000, 0, 322889000, 157118000, $$The F-15C continues to provide air superiority with an undefeated and unmatched aerial combat record. The F-15E retains this air superiority capability and adds systems, such as conformal fuel tanks (CFTs), advanced imaging and targeting systems, to meet the requirement for all-weather, deep-penetration, and night/under-the- weather, air-to-surface attack. Upgrades to F-15 aircraft are critical to maintaining combat viability (lethality, survivability, and supportability) in support of the National Defense Strategy. With newer F-15E aircraft projected to remain in service past 2040, avionics modernization is key to long-term weapon system viability. Major avionics upgrades include radar modernization (both hardware and software) and capability enhancements via precision timing, data delivery and processing technology, precision registration systems, display optimization, instrumentation digitization and modernization, central computer processing power increases, digital mission event recording systems, and an infrared (IR)-based fire control system. The proliferation of fourth-generation enemy aircraft and sophisticated "double-digit" anti-aircraft missile systems pose a significant threat to F-15 survivability. A fully integrated electronic warfare suite holds the promise of providing improved survivability as well as expanded electronic attack capability. Nearly all new avionics or weapons capabilities require an Operational Flight Program (OFP) software update to fully employ the capability. OFP updates are directly linked to ACC prioritized capability needs which are continuously assessed and updated. OFP's agile development framework provides the ability to quickly change capability development focus to meet the time-based need to mitigate and defeat emerging threats. The OFP agile development framework integrates and deploys new capabilities on an annual basis to incorporate new technology/equipment or improvements for support equipment, mission planning systems, and training device upgrades which enhance performance, supportability, and aircrew training. Funds may be used to resolve issues among the F-15 fleet (e.g., emerging safety of flight issues and diminishing manufacturing sources), to accommodate technology insertion, and to fulfill Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. This includes technical and acquisition-related studies to ensure F-15 lethality and survivability beyond 2040. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207134F / F-15E Squadrons Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207136F$$, $$Manned Destructive Suppression$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 17680000, 12871000, 13855000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207136F"}$$::jsonb, $$The FY 2026 request was reduced by .186 Million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The Manned Destructive Suppression (MDS) program funds the development and sustainment of the Air Force's Suppression of Enemy Air Defenses (SEAD) and Destruction of Enemy Air Defenses (DEAD) capabilities. The F-16 High-speed Anti-Radiation Missile (HARM) Targeting System (HTS) is currently the only programmed reactive SEAD/DEAD capability and enables targeting the HARM missile in its most lethal 'range known' mode. The program provides F-16 Block 50/52 and Block 40/42 aircraft with the ability to employ the AN/ASQ-213 targeting Pod. With the introduction of Pre-Planned Product Improvement (P3I) HTS Revision 7 in 2007, the AN/ASQ-213 Pod now has a precision geo-location capability to target Precision Guided Munitions (PGMs) to destroy fixed and mobile enemy air defense elements. Additionally, by relocating the AN/ASQ-213 HTS R7 Pod on the aircraft, the F-16 can simultaneously carry the HTS R7 Pod and an Advanced Targeting Pod (ATP). HTS R7 fielding is complete and represents the Air Force's near-term solution for reactive time-critical targeting for DEAD until this mission can be transferred to the F-35. HTS R7 derived precision targeting data can be provided to all Joint Forces via Link-16. This effort continues upgrades for the HTS and applies technologies similar to those demonstrated in the Advanced Tactical Targeting Technologies (AT3) program and HTS R7 development. Funds may be used to address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. HTS leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0.00M was expended for civilian pay expenses in this program element, and in FY2025 0.00M is forecasted for civilian pay expenses in this program. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207136F / Manned Destructive Suppression Operational Systems Development$$, NULL, 13132000, 13489000, 13839000, NULL, NULL, 178, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 12119000, 15309000, 8128000, 8128000, 0, 8128000, 19250000, $$The Manned Destructive Suppression (MDS) program funds the development and sustainment of the Air Force's Suppression of Enemy Air Defenses (SEAD) and Destruction of Enemy Air Defenses (DEAD) capabilities. The F-16 High-speed Anti-Radiation Missile (HARM) Targeting System (HTS) is currently the only programmed reactive SEAD/DEAD capability and enables targeting the HARM missile in its most lethal 'range known' mode. The program provides F-16 Block 50/52 and Block 40/42 aircraft with the ability to employ the AN/ASQ-213 targeting Pod. The AN/ASQ-213 Pod also has a precision geo-location capability to target Precision Guided Munitions (PGMs) to destroy fixed and mobile enemy air defense elements. Additionally, by relocating the AN/ASQ-213 HTS R7 Pod on the aircraft, the F-16 can simultaneously carry the HTS R7 Pod and an Advanced Targeting Pod (ATP). HTS R7 fielding is complete and represents the Air Force's near-term solution for reactive time-critical targeting for DEAD until this mission can be transferred to the F-35. HTS R7 derived precision targeting data can be provided to all Joint Forces via Link-16. This effort continues upgrades for the HTS and applies technologies similar to those demonstrated in the Advanced Tactical Targeting Technologies (AT3) program and HTS R7 development. Funds may be used to address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. HTS leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207136F / Manned Destructive Suppression Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207138F$$, $$F-22A Squadrons$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 852332000, 640109000, 758754000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207138F"}$$::jsonb, $$The F-22 Raptor is a multi-mission fighter aircraft that combines low observability, supercruise, maneuverability and integrated avionics providing air superiority to the Joint Force, access in highly contested environments, as well as homeland and cruise missile defense. To maintain operational relevance, the program continues planned, incremental modernization efforts that enhance both F-22 air superiority and strike capabilities. The F-22 modernization enterprise develops, tests, and fields hardware/software of the air vehicle, engine, Operational Flight Program (OFP), and training systems to improve F-22 weapons, communications, navigation, pilot- vehicle interface, and electronic warfare suite. Funds may be used to resolve emerging safety of flight and diminishing manufacturing sources issues, accommodate technology insertion and fulfill Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort F-22 is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024, 5.967M was expended for civilian pay expenses in this program element, and in FY2025, 7.311M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by 1.977 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207138F / F-22A Squadrons Operational Systems Development$$, NULL, 986192000, 840331000, 807847000, NULL, NULL, 179, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 733581000, 813987000, 950375000, 950375000, 0, 950375000, 768015000, $$The F-22 Raptor is a multi-mission fighter aircraft that combines low observability, supercruise, maneuverability and integrated avionics providing air superiority to the Joint Force, access in highly contested environments, as well as homeland and cruise missile defense. To maintain operational relevance, the program continues planned, incremental modernization efforts that enhance both F-22 air superiority and strike capabilities. The F-22 modernization enterprise develops, tests, and fields hardware/software of the air vehicle, engine, Operational Flight Program (OFP), and training systems to improve F-22 weapons, communications, navigation, pilot- vehicle interface, and electronic warfare suite. Funds may be used to resolve emerging safety of flight and diminishing manufacturing sources issues, accommodate technology insertion and fulfill Federal Aviation Administration (FAA) or other mandates necessary to ensure continued aircrew safety and mission effectiveness. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. In Oct 2025, the F-22 Software Pathway Acquisition Program was stood up. Programs that previously included OFP software requirements transitioned those requirements to the F-22 Software Pathway Program and major thrust Software Pathway for Enabling Expedited Deliveries (SPEED) beginning with FY2026 requirements. The total cost of the F-22 Sensor Enhancement Rapid Fielding (RF) Middle Tier of Acquisition (MTA) effort is $1,801.7 million, including RDT&E and procurement of prototype units. The F-22 Sensor Enhancement RF MTA program is fully funded across the Future Years Defense Program. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207138F / F-22A Squadrons Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207142F$$, $$F-35 Squadrons$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 48446000, 88991000, 47132000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207142F"}$$::jsonb, $$The F-35 Joint Strike Fighter (JSF) Program will develop and field an affordable, highly common family of next generation strike aircraft for the United States Air Force (USAF), United States Navy, United States Marine Corps and International Partners countries. There are three variants: the F-35A Conventional Takeoff and Landing (CTOL) variant; the F-35B Short Take Off and Vertical Landing (STOVL) variant; and the F-35C Carrier Variant (CV). Maximum commonality among the variants, consistent with National Disclosure Policy, will minimize total air system life cycle costs. PE 0207142F funding supports USAF-unique on-going SEEK EAGLE, Quick Reaction Instrumentation Package (QRIP), and Dual Capable Aircraft (DCA) requirements. These continuing efforts are not new starts. The Air Force SEEK EAGLE Office (AFSEO) delivers warfighting capability through aircraft/store compatibility testing and evaluation while providing accurate combat weapon delivery and mission planning software. Beginning in FY 2020, the USAF supported Flight Test Instrumentation (FTI) wiring and weapons integration tasks related to SEEK EAGLE requests. These tasks include, but are not limited to, envelope expansion, mixed loads testing, adding additional stores, and F-35A specific risk reduction efforts and studies. The QRIP/CSFD program enables the F-35 fleet to rapidly transport and leverage post-flight data—collected from both test and operational environments—to enhance Mission Data Files (MDF) and the onboard Software Data Load (SDL). The program aims to increase data-ingest capable systems and networks that will be utilized to support the processing, storage, and transmission of all F-35 generated CSFD sources. The program will also look to increase the operational viability of CSFD, including the use of data science teams, artificial intelligence (AI), and machine learning (ML) algorithms. The F-35 JSF Operational Requirements Document (ORD) calls for the F-35A to have the capabilities and provisions for DCA operations in the first post-System Development and Demonstration (SDD) block upgrade. DCA is a NATO and US priority which is a critical capability in our collective defense and credible deterrence. The USAF F-35A achieved operational certification on October 12, 2023, earlier than the need date of January 2024. DCA refers to the capability to carry and deliver conventional and non-conventional weapons. DCA operations for the F-35A is internal carriage of up to two B61-12s. Due to extensive certification requirements, the DCA capability planning and design, testing and certification will continue throughout Block 4. Funding in this PE will resource the following F-35A DCA activities: Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                              Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                     PE 0207142F / F-35 Squadrons Operational Systems Development development, analysis, test, integration, certification and risk-reduction activities necessary to field and maintain F-35A DCA capabilities throughout post-SDD block upgrades; assessment of DCA weapon integration and certification impacts on the F-35 aircraft; identification and mitigation of potential technical and cost risks; definition of integration and certification trade-space to field the DCA capability with the B61-12 weapon; follow-on risk reduction efforts to ensure future integration alignment with the earliest feasible post-SDD block upgrade; and full integration efforts pending Service decisions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.0M was expended for civilian pay expenses in this program element, and in FY 2025 0.0M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by 0.5M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 49303000, 50266000, 51221000, NULL, NULL, 180, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 45444000, 32203000, 47388000, 47388000, 0, 47388000, 52258000, $$The F-35 Joint Strike Fighter (JSF) Program will develop and field an affordable, highly common family of next generation strike aircraft for the United States Air Force (USAF), United States Navy, United States Marine Corps and International Partners countries. There are three variants: the F-35A Conventional Takeoff and Landing (CTOL) variant; the F-35B Short Take Off and Vertical Landing (STOVL) variant; and the F-35C Carrier Variant (CV). Maximum commonality among the variants, consistent with National Disclosure Policy, will minimize total air system life cycle costs. PE 0207142F funding supports USAF-unique on-going SEEK EAGLE, Quick Reaction Instrumentation Package (QRIP)/Crowd Sourced Flight Data (CSFD), and Dual Capable Aircraft (DCA) requirements. These continuing efforts are not new starts. The Air Force SEEK EAGLE Office (AFSEO) delivers warfighting capability through aircraft/store compatibility testing and evaluation while providing accurate combat weapon delivery and mission planning software. Beginning in FY2020, the USAF supported Flight Test Instrumentation (FTI) wiring and weapons integration tasks related to SEEK EAGLE requests. These tasks include, but are not limited to, envelope expansion, mixed loads testing, adding additional stores, and F-35A specific risk reduction efforts and studies. The QRIP/CSFD program enables the F-35 fleet to rapidly transport and leverage post-flight data—collected from both test and operational environments—to enhance Mission Data Files (MDF) and the onboard Software Data Load (SDL). The program aims to increase data-ingest capable systems and networks that will be utilized to support the processing, storage, and transmission of all F-35 generated CSFD sources. The program will also look to increase the operational viability of CSFD, including the use of data science teams, artificial intelligence (AI), and machine learning (ML) algorithms. The F-35 JSF Operational Requirements Document (ORD) calls for the F-35A to have the capabilities and provisions for DCA operations in the first post-System Development and Demonstration (SDD) block upgrade. DCA is a NATO and US priority which is a critical capability in our collective defense and credible deterrence. The USAF F-35A achieved operational certification on October 12, 2023, earlier than the need date of January 2024. DCA refers to the capability to carry and deliver conventional and non-conventional weapons. DCA operations for the F-35A is internal carriage of up to two B61-12s. Due to extensive certification requirements, the DCA capability planning and design, testing and certification will continue throughout Block 4. Funding in this PE will resource the following F-35A DCA activities: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                     PE 0207142F / F-35 Squadrons Operational Systems Development development, analysis, test, integration, certification and risk-reduction activities necessary to field and maintain F-35A DCA capabilities throughout post-SDD block upgrades; assessment of DCA weapon integration and certification impacts on the F-35 aircraft; identification and mitigation of potential technical and cost risks; definition of integration and certification trade-space to field the DCA capability with the B61-12 weapon; follow-on risk reduction efforts to ensure future integration alignment with the earliest feasible post-SDD block upgrade; and full integration efforts pending Service decisions. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207146F$$, $$F-15EX$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 80445000, 101996000, 56228000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207146F"}$$::jsonb, $$The F-15EX is a new multirole-capable fighter jet based on the 2-seat F-15QA (Qatar) configuration upgraded with advanced capabilities, including the Eagle Passive Active Warning Survivability System (EPAWSS) and the USAF F-15 Continuous Delivery & Integration (CD&I) Operational Flight Program (OFP) software. The F-15EX provides significant operational flexibility, enabling it to perform a wide range of missions sets with one or two aircrew. It will be used predominantly in defensive and offensive counter-air missions at both Air National Guard (ANG) and Air Combat Command (ACC) operational squadrons. F-15EX will perform the Homeland Defense mission and provide Combatant Commanders (CCDR) with strike packages capable of operating in Highly Contested Environments (HCE). The FY 2026 RDT&E funding request continues incremental funding of development activities started in prior years and adds funding for Long-Range Kill Chain (LRKC) and Hybrid SATCOM (Beyond Line-of-Sight communications) development, a FY 2026 new start. The FY 2026 request for the Research & Development appropriation for F-15EX includes $78,345 thousand of discretionary and $2,100 thousand of mandatory (reconciliation) for a total of $80,445 thousand. The mandatory funds will support LRKC efforts. Further information for this reconciliation request is Provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. The FY 2026 request was reduced by $0.811 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F or 0605898F. In FY 2024, 9.536M was executed for civilian pay expenses in this program element. In FY 2025, 6.206M is forecasted for civilian pay expenses in this program element. In FY 2025, the F-15EX program reduced civilian personnel to 38 positions which aligned to the Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” The FY 2026 request was reduced by 2.132 million from FY 2024 as reflected in the Direct Cite Authority line in Exhibit R-3. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207146F / F-15EX Operational Systems Development FY 2020 Prior Years RDT&E funding of $385.000 million was executed in PE 0207134F (F-15E Squadrons) and is not included in this exhibit. FY 2020 RDT&E funded two F-15EX test aircraft. In FY 2021, F-15EX RDT&E efforts were continued in PE 0207146F (F-15EX). This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 143358000, 238081000, 249897000, NULL, NULL, 181, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 54875000, 117715000, 133274000, 133274000, 0, 133274000, 358474000, $$The F-15EX is a new multirole-capable fighter jet based on the 2-seat F-15QA (Qatar) configuration upgraded with advanced capabilities, including the Eagle Passive Active Warning Survivability System (EPAWSS) and the USAF F-15 Continuous Delivery & Integration (CD&I) Operational Flight Program (OFP) software. The F-15EX provides significant operational flexibility, enabling it to perform a wide range of missions sets with one or two aircrew. It will be used predominantly in defensive and offensive counter-air missions at both Air National Guard (ANG) and Air Combat Command (ACC) operational squadrons. F-15EX will perform the Homeland Defense mission and provide Combatant Commanders (CCDR) with strike packages capable of operating in Highly Contested Environments (HCE). The FY 2027 RDT&E funding request continues incremental funding of development and test activities started in prior years, including for Long-Range Kill Chain (LRKC) and Hybrid SATCOM (Beyond Line-of-Sight communications) development, which was an FY 2026 new start. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F or 0605898F. FY 2020 Prior Years RDT&E funding of 385.000 million was executed in Program 0207134F (F-15E Squadrons) and is not included in this exhibit. FY 2020 RDT&E funded two F-15EX test aircraft. In FY 2021, F-15EX RDT&E efforts were continued in Program 0207146F (F-15EX). The FY 2026 spend plan amount for F-15EX 3600 includes $117,715 thousand of discretionary and $40,000 thousand of mandatory (reconciliation) for a total of $157,715 thousand. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207146F / F-15EX Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207147F$$, $$Collaborative Combat Aircraft$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 789365000, 0, 711747000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207147F"}$$::jsonb, $$Collaborative Combat Aircraft (CCA) are uncrewed weapon systems capable of enhancing crewed weapon systems ability to achieve air superiority. The program matures and leverages relevant Science and Technology investments to reduce risk by conducting targeted development, integration, and test activities. Key CCA attributes include cost of platforms, mission integrated autonomy, multi-platform interoperability, and lethality enhancement. Program activities include digital engineering, agile software development, open systems architectures, autonomy architecture, mission autonomy, crewed-uncrewed teaming, as well as the design, build, and test of full weapon systems with supporting elements. Funding provides information technology/test/training infrastructure investments, operational concept exploration, technology studies, multi-domain integration, operational assessments, architecture development, integrated weapons systems development, demonstration of air superiority related technologies, multi-level prototyping, and program management support. Program management support costs include, but are not limited to, contractor support services, civilian pay, supplies, and facility related expenses. CCA technologies are designed to become available to other Department of Defense systems based on emerging threats, Air Force priorities, and development capacity. The FY 2026 request for CCA includes 111,365 thousands of discretionary and 678,000 thousands of mandatory (reconciliation) for a total of 789,365 thousands. The mandatory funds address Air Superiority in FY 2026. Further information for this reconciliation request is provided in Section 20007 of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 9.966 million was expended for civilian pay expenses in program element 0207110F, and in FY 2026 13.537 million is forecast for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207147F / Collaborative Combat Aircraft Component Development & Prototypes (ACD&P)$$, NULL, 948982000, 1069030000, 1370091000, NULL, NULL, 66, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 688492000, 150574000, 1373740000, 1373740000, 0, 1373740000, 1300574000, $$Collaborative Combat Aircraft (CCA) are uncrewed weapon systems capable of enhancing crewed weapon systems ability to achieve air superiority. The program matures and leverages relevant Science and Technology investments to reduce risk by conducting targeted development, integration, and test activities. Key CCA attributes include cost of platforms, mission integrated autonomy, multi-platform interoperability, and lethality enhancement. Program activities include digital engineering, agile software development, open systems architectures, autonomy architecture, mission autonomy, crewed-uncrewed teaming, as well as the design, build, and test of full weapon systems with supporting elements. Funding provides information technology/test/training infrastructure investments, operational concept exploration, technology studies, multi-domain integration, operational assessments, architecture development, propulsion development, integrated weapons systems development, demonstration of air superiority related technologies, multi-level prototyping, digital systems infrastructure, and program management support. Program management support costs include, but are not limited to, contractor support services, civilian pay, supplies, and facility related expenses. CCA technologies are designed to become available to other Department of War systems based on emerging threats, Air Force priorities, and development capacity. FY25 was rescinded 8.019 million and is not reflected in this budget documentation. The FY 2026 spend plan amount for Research, Development, Test, and Evaluation includes $150,574 thousand of discretionary and $676,750 thousand of mandatory (reconciliation) for a total of $827,324 thousand. Funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Funding may be used to resolve Diminishing Manufacturing Sources and Material Shortages (DMSMS) and/or obsolescence issues. DMSMS activities may include, but are not limited to, bridge buys, life of type buys, buys to protect schedule, and engineering efforts. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207147F / Collaborative Combat Aircraft Component Development & Prototypes (ACD&P) This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207147M$$, $$(U) COLLABORATIVE COMBAT AIRCRAFT$$, $$rdte_navy_ba4$$, $$dw_osd$$, 2026, 58000000, 0, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "mc", "page_num": 31, "original_pe": "0207147M", "page_header": "Department of the Navy"}$$::jsonb, $$USMC Collaborative Combat Aircraft (CCA) is an uncrewed aircraft that enhances the survivability and lethality of the Marine Air Ground Task Force (MAGTF), complimenting the service's current 4th/5th Generation Tactical Aircraft (TACAIR) capability. The uncrewed weapons systems under development will enhance Marine Corps Aviation's lethality and ability to support the Stand-in Force (SiF) by delivering air-to-ground, reconnaissance, and Electronic Warfare (EW) capabilities. This Program Element leverages OSD Rapid Defense Experimentation Reserve (RDER) investments to rapidly field an uncrewed aircraft capable of collaborative effects with expeditionary manned aircraft (current 4th/5th Generation TACAIR) and amphibious forces as part of the Joint Force. Key attributes include enhanced survivability of tactical manned aircraft, integrated autonomy and improved lethality against near-peer/peer threats. Program activities include employment of digital acquisitions via digital engineering, agile software development, and open systems architecture. Funding provides information technology/test/training/infrastructure investments, operational concept exploration, technology studies, multi-domain integration, operational assessments, architecture development, and multi-level prototyping towards a Minimum Viable Product (MVP), as well as program management support. This effort also reduces risk towards enhanced technology development, integration and demonstration. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 187465000, 161158000, 214729000, NULL, NULL, 102, $$RDTEN_BA4_Book.pdf$$, NULL, FALSE, 0, 5000000, 213934000, 213934000, NULL, 213934000, 215551000, $$USMC Collaborative Combat Aircraft (CCA) is an uncrewed aircraft that enhances the survivability and lethality of the Marine Air Ground Task Force (MAGTF), complementing the Service's current 4th/5th Generation Tactical Aircraft (TACAIR) capability. The uncrewed weapons systems under development will enhance Marine Corps Aviation's lethality and ability to support the Stand-in Force (SiF) by delivering air-to-ground, reconnaissance, and Electronic Warfare (EW) capabilities. This PE leverages OSW Rapid Defense Experimentation Reserve (RDER) investments to rapidly field an uncrewed aircraft capable of collaborative effects with expeditionary manned aircraft (current 4th/5th Generation TACAIR) and amphibious forces as part of the Joint Force. Key attributes include enhanced survivability of tactical manned aircraft, integrated autonomy and improved lethality against near-peer/peer threats. Program activities include employment of digital acquisitions via digital engineering, agile software development, and open systems architecture. Funding provides critical infrastructure investments, operational concept exploration, technology studies, multi-domain integration, operational assessments, architecture development, and multi-level prototyping towards a Minimum Viable Product (MVP), as well as program management support. This effort also reduces risk towards enhanced technology development, integration and demonstration. The FY 2026 spend plan for Collaborative Combat Aircraft includes $5,000 thousand of discretionary and $270,000 thousand of mandatory (reconciliation) for a total of $275,000 thousand. FY 2026 total funding supports USMC Collaborative Combat Aircraft MUX TACAIR Increment I. The discretionary funds provide for rapid prototyping, test and procurement with prime vendor. The mandatory funds provide for accelerated prototyping, test and procurement including four (4) MUX TACAIR USMC CCA test articles for targeted squadron standup beginning in FY29. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under ADVANCED COMPONENT DEVELOPMENT AND PROTOTYPES because it includes all efforts necessary to evaluate integrated technologies, representative models or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 4: Advanced         PE 0207147M / (U) COLLABORATIVE COMBAT AIRCRAFT Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Navy/RDTEN_BA4_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207159D8Z_ba2$$, $$Golden Dome for America - Air Force$$, $$proc_gd_ba2$$, $$dw$$, 2026, 0, 0, 0, NULL, $${"ba": "02", "line": 7, "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 365700, "fy27_disc": 0, "fy27_mand": 365700, "fy26_total": 365700, "fy27_total": 365700, "appropriation": "3007D", "fy27_mand_v158": true}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, NULL, FALSE, NULL, 365700000, 0, 0, 365700000, 365700000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207161F$$, $$Tactical AIM Missiles$$, $$rdte_af_ba7$$, $$aflcmc_ww$$, 2026, 86549000, 40473000, 34932000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207161F"}$$::jsonb, $$The AIM-9X Block II Sidewinder (AIM-9X Blk II) continues the evolution of the AIM-9 series of missiles. This missile program delivers a launch and leave, air combat munition that uses passive Infrared (IR) energy to acquire and track enemy air targets and complements the radar guided Advanced Medium Range Air-to-Air Missile (AMRAAM). The missile provides fighter aircrew with the first shot, first kill opportunities that are essential for survival during air combat maneuvering in the visual arena. The AIM-9X delivers these opportunities with unmatched offensive and defensive capabilities against inner boundary threats, even when IR countermeasures are employed. The AIM-9X also supports air superiority in the Beyond Visual Range air-to-air battle. Anti-tamper features have been incorporated to protect improvements inherent in this design. The AIM-9X Block II missile provides the Joint Force with fighter aircraft lethality and survivability necessary to counter threats identified in the National Defense Strategy. AIM-9X is a Post Milestone C, Acquisition Category IC joint service program led by the Department of the Navy. The Block II program has completed independent operational testing and was found to be operationally effective and suitable. The program achieved Initial Operational Capability in March 2015 and received Full Rate Production decision in August 2015. This budget line item continues technical refresh hardware and software and develops advanced capabilities to meet requirements of the Capability Production Document against evolving threat aircraft countermeasures and unmanned aircraft systems. This program element leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. The FY 2026 request was reduced by -$.841 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207161F / Tactical AIM Missiles Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY 2024, 100K were expended for civilian pay expenses in this program element, and in FY 2025, 100K are forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 126802000, 123251000, 121751000, NULL, NULL, 182, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 33701000, 85449000, 98861000, 98861000, 0, 98861000, 62965000, $$The AIM-9X Block II Sidewinder (AIM-9X Blk II) continues the evolution of the AIM-9 series of missiles. This missile program delivers a launch and leave, air combat munition that uses passive Infrared (IR) energy to acquire and track enemy air targets and complements the radar guided Advanced Medium Range Air-to-Air Missile (AMRAAM). The missile provides fighter aircrew with the first shot, first kill opportunities that are essential for survival during air combat maneuvering in the visual arena. The AIM-9X delivers these opportunities with unmatched offensive and defensive capabilities against inner boundary threats, even when IR countermeasures are employed. The AIM-9X also supports air superiority in the Beyond Visual Range air-to-air battle. Anti-tamper features have been incorporated to protect improvements inherent in this design. The AIM-9X Block II missile provides the Joint Force with fighter aircraft lethality and survivability necessary to counter threats identified in the National Defense Strategy. The AIM-9X Compact Variant (CV) repackages the AIM-9X Blk II technology into a compact airframe optimized for internal carriage on advanced aircraft with improved kinematic performance. The program will deliver increased capability to the warfighter with greater standoff range, increased aircraft weapon station capacity, and maintains inner boundary performance. In FY 2027, the program will execute engineering, manufacturing, and development for the phase 4 of the System Improvement Program (SIP) hardware and software effort. Specifically, development of Operational Flight Software (OFS) 11.6X will continue. The SIP IV hardware Engineering Change Proposal (ECP) will be complete Q3 FY 2027. In addition, the program will continue AIM-9X CV risk reduction development activities to advance hardware and software designs. The AIM-9X CV integration activities will focus on ensuring compatibility with advanced platforms. CV risk reduction efforts were funded by USN in FY 2025 and FY 2026 Product Development under SIP risk reduction. This effort is not an FY 2027 new start. USAF effort to start FY28. AIM-9X is a Post Milestone C, Acquisition Category IC joint service program led by the Department of the Navy. The Block II program has completed independent operational testing and was found to be operationally effective and suitable. The program achieved Initial Operational Capability in March 2015 and received Full Rate Production decision in August 2015. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207161F / Tactical AIM Missiles Operational Systems Development This budget line item continues technical refresh hardware and software and develops advanced capabilities to meet requirements of the Capability Production Document against evolving threat aircraft countermeasures and unmanned aircraft systems. This program element leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207163F$$, $$Advanced Medium Range Air-to-Air Missile (AMRAAM)$$, $$rdte_af_ba7$$, $$aflcmc_ww$$, 2026, 51242000, 51976000, 53593000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207163F"}$$::jsonb, $$The Advanced Medium Range Air-to-Air Missile (AMRAAM) is a joint Air Force/Navy, Acquisition Category 1C program with Air Force as lead service. AMRAAM is the premier all-weather, all-environment, radar guided missile with improved capabilities against very low and high-altitude targets in an electronic attack environment. The current AMRAAM variant, the AIM-120D, delivers improved performance via Global Positioning System (GPS) aided navigation; two way datalink capability for enhanced aircrew survivability and improved network compatibility; and incorporates new guidance software that improves kinematic performance and weapon effectiveness. This Air Force/Navy program is structured in response to the Joint Service Operational Requirement Document and Mission Element Need Statement to develop an air superiority air-to-air missile with significant improvements in operational utility and combat effectiveness. The development program enhances AMRAAM capability and operational flexibility against current and projected threats, incorporates high payoff technology development, performs risk reduction activities, and investigates new variants and/or alternate missions that may use AMRAAM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Navy and Air Force also develop, test, and field improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. This program supports the integration of the Advanced Medium Range Air-to-Air Missile (AMRAAM) into Air Force aircraft with analysis of Air Force unique applications, aircraft missile integration tasks, product improvement efforts including missile software upgrade development and procurement of hardware to support Air Force test and evaluation tasks. Leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs; and program management administration (PMA). The FY 2026 request was reduced by -$.582 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY24, $0.00 were expended for civilian pay expenses in this program element and in FY25, $0.00 are forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207163F / Advanced Medium Range Air-to-Air Missile (AMRAAM) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 54716000, 55787000, 56847000, NULL, NULL, 183, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 51898000, 50539000, 53277000, 53277000, 0, 53277000, 57998000, $$The Advanced Medium Range Air-to-Air Missile (AMRAAM) is a joint Air Force/Navy, Acquisition Category 1C program with Air Force as lead service. AMRAAM is the premier all-weather, all-environment, radar guided missile with improved capabilities against very low and high-altitude targets in an electronic attack environment. The current AMRAAM variant, the AIM-120D, delivers improved performance via Global Positioning System (GPS) aided navigation; two way datalink capability for enhanced aircrew survivability and improved network compatibility; and incorporates new guidance software that improves kinematic performance and weapon effectiveness. This Air Force/Navy program is structured in response to the Joint Service Operational Requirement Document and Mission Element Need Statement to develop an air superiority air-to-air missile with significant improvements in operational utility and combat effectiveness. The development program enhances AMRAAM capability and operational flexibility against current and projected threats, incorporates high payoff technology development, performs risk reduction activities, and investigates new variants and/or alternate missions that may use AMRAAM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Navy and Air Force also develop, test, and field improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. This program supports the integration of the Advanced Medium Range Air-to-Air Missile (AMRAAM) into Air Force aircraft with analysis of Air Force unique applications, aircraft missile integration tasks, product improvement efforts including missile software upgrade development and procurement of hardware to support Air Force test and evaluation tasks. Leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs; and program management administration (PMA). This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207163F / Advanced Medium Range Air-to-Air Missile (AMRAAM) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207163N$$, $$AMRAAM$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 26286000, 28837000, 29638000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0207163N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 25588000, 25674000, 27066000, NULL, NULL, NULL, NULL, NULL, FALSE, 29247000, 26286000, 24675000, 24675000, NULL, 24675000, 27537000, $$The Department encourages additional vendor participation in the design, development, and production of alternative weapons systems to meet current and future warfighting requirements. With current major weapons systems production at capacity, the nation is looking for alternative systems to fill these gaps. The Department is implementing diverse procurement strategies to enable rapid acquisition. These will include the use of Other Transaction Authorities, 'Marketplace' acquisition platforms, and alternative concepts to increase supply and suppliers in addition to traditional FAR-based procurement strategies. The Advanced Medium Range Air-to-Air Missile (AMRAAM) is a joint Air Force/Navy, Acquisition Category 1C program with Air Force as lead service. AMRAAM is the premier all-weather, all-environment, radar guided missile with improved capabilities against very low and high-altitude targets in an electronic attack environment. The current AMRAAM variant, the AIM-120D, delivers improved performance via Global Positioning System (GPS) aided navigation; two-way datalink capability for enhanced aircrew survivability and improved network compatibility; and incorporates new guidance software that improves kinematic performance and weapon effectiveness. This Air Force/Navy program is structured in response to the Joint Service Operational Requirement Document and Mission Element Need Statement to develop an air superiority air-to-air missile with significant improvements in operational utility and combat effectiveness. The development program enhances AMRAAM capability and operational flexibility against current and projected threats, incorporates high payoff technology development, performs risk reduction activities, and investigates new variants and/or alternate missions that may use AMRAAM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Navy and Air Force also develop, test, and field improvements via software upgrades into fielded missiles, and/or hardware upgrades inserted into the production line. This program supports the integration of the AMRAAM into Navy aircraft with analysis of Navy unique applications, aircraft missile integration tasks, product improvement efforts including missile software upgrade development and procurement of hardware to support Navy test and evaluation tasks. Funding in FY 2027 through FY 2031 supports System Improvement Program (SIP) and Navy unique Test & Evaluation for software fielding. This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                  Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational     PE 0207163N / AMRAAM Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207171F$$, $$F-15 EPAWSS$$, $$rdte_af_ba5$$, $$aflcmc_wa$$, 2026, 0, 12975000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0207171F"}$$::jsonb, $$The legacy F-15 Tactical Electronic Warfare System (TEWS) is functionally obsolete. It uses 1970's analog technology to combat 1980s-era radar-based ground and air threats. In addition, this aging system is becoming more difficult and expensive to sustain. As a result, the Air Force is replacing TEWS with the F-15 Eagle Passive/Active Warning and Survivability System (EPAWSS). F-15 EPAWSS is an advanced digital electronic warfare system capable of detecting, identifying, locating, denying, degrading, disrupting, and defeating modern and emerging threat systems in contested airspace with dense radio-frequency (RF) background environments. F-15 EPAWSS will provide indication, type, and position of ground-based RF threats as well as the indication, type, and bearing of airborne threats with the situational awareness needed to avoid, engage, or negate the threat. It will also prevent RF threat systems from detecting or acquiring accurate targeting information to complicate and/or negate an enemy threat targeting solution. Finally, EPAWSS will counter RF and infrared threat systems at end-game via electronic countermeasures (jamming), chaff, and/or flares. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0207171F / F-15 EPAWSS Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 108, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207172F$$, $$Joint Advanced Tactical Missile (JATM)$$, $$rdte_af_ba7$$, $$dw_ousd_as$$, 2026, 425029000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207172F"}$$::jsonb, $$The Joint Advanced Tactical Missile (JATM), designated the AIM-260A, is a high speed, long range, air dominance missile designed to defeat current and projected enemy air threats. JATM is compatible with Air Force and Navy aircraft and is critical to preserving our nation's air dominance capability for the future. JATM is a joint Air Force and Navy program with the Air Force as the lead service. Funding supports development activities associated with the JATM program. These activities include development as well as system improvement, developmental and operational test, and continued threshold platform integration. Funding will also continue science and technology (S&T) and risk reduction efforts to mature critical technologies and packaging designs for future JATM improvements and will enhance system performance to defeat pacing threats through targeted hardware and software enhancements. Notes: This program is reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program Annual Report to Congress. For further information, please contact the Director of Special Programs, OUSD(A&S)/DSP. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 464641000, 295122000, 104711000, NULL, NULL, 184, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 0, 420110000, 500422000, 500422000, 0, 500422000, 106831000, $$The details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207179F$$, $$Autonomous Collaborative Platforms$$, $$rdte_af_ba4$$, $$afotec$$, 2026, 62019000, 110945000, 50666000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207179F"}$$::jsonb, $$Autonomous Collaborative Platforms (ACP) are uncrewed weapon systems designed to work in conjunction with current and future aircraft to provide operational flexibility and enhance operational effectiveness. Key ACP attributes include tailored cost of platforms, rapidly updateable software, autonomy, interoperability with multiple platforms and network capabilities, agility of use, lethality, and ability to penetrate challenging air environments. The program matures technology to reduce risk through development, integration, experimentation, and test activities. Autonomous Collaborative Technologies (ACT) served as the starting point for the Air Force's investment in the Collaborative Combat Aircraft (CCA) program. ACP will explore Doctrine, Organization, Training, Materiel, Leadership, Personnel, Facilities, and Policy (DOTMLPF-P) concepts for uncrewed vehicles. Program activities include digital engineering, agile software development, open systems architectures, and risk reduction projects. Funding provides digital systems infrastructure, operational concept exploration, technology studies, multi-domain integration assessments, operational and system architecture development, flight test and test support, prototypes, training and demonstration, program management support, as well as maturation and risk reduction of air superiority related technologies to include weapons systems, autonomy, and integrated system concept development. Program management support costs include but are not limited to contractor support services, civilian pay, supplies, and facility related expenses. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207179F / Autonomous Collaborative Platforms Component Development & Prototypes (ACD&P)$$, NULL, 58201000, 59435000, 60680000, NULL, NULL, 67, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 48983000, 63471000, 57217000, 57217000, 0, 57217000, 65007000, $$Autonomous Collaborative Platforms (ACP) are uncrewed weapon systems designed to work in conjunction with current and future aircraft to provide operational flexibility and enhance operational effectiveness. Key ACP attributes include tailored cost of platforms, rapidly updateable software, autonomy, interoperability with multiple platforms and network capabilities, agility of use, lethality, and ability to penetrate challenging air environments. The program matures technology to reduce risk through development, integration, experimentation, and test activities. Autonomous Collaborative Technologies (ACT) served as the starting point for the Air Force's investment in the Collaborative Combat Aircraft (CCA) program. ACP will explore Doctrine, Organization, Training, Materiel, Leadership, Personnel, Facilities, and Policy (DOTMLPF-P) concepts for uncrewed vehicles. Program activities include digital engineering, agile software development, open systems architectures, and risk reduction projects. Funding provides digital systems infrastructure, operational concept exploration, technology studies, multi-domain integration assessments, operational and system architecture development, flight test and test support, prototypes, training and demonstration, program management support, as well as maturation and risk reduction of air superiority related technologies to include weapons systems, autonomy, and integrated system concept development. Program management support costs include but are not limited to contractor support services, civilian pay, supplies, and facility related expenses. Funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207179F / Autonomous Collaborative Platforms Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207227F$$, $$Combat Rescue - Pararescue$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 0, 659000, 743000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207227F"}$$::jsonb, $$Beginning in FY26 this funding is reported in BA 07 Project 0207457F. GA is a Family of Systems (FoS) based in both human and equipment capabilities formulated to execute Air Force Personnel Recovery (PR) across the full spectrum of military operations. Established by the Air Force Chief of Staff in 2003 and officially captured in AFPD 10-9, the GA FoS is employed by three distinct Air Force specialties: Pararescuemen (PJ), Combat Rescue Officer (CRO), and Survival, Evasion, Resistance, Escape (SERE). The GA FoS is comprised of nine critical mission areas: Precision Aerial Insertion, Information Management, Force Application, Visual Augmentation, Maritime Recovery, Ground Mobility, Technical Rescue, Medical, and SERE. GA focus is on maintaining legacy weapon system capability while modernizing/improving subsystems for better mission effectiveness. Mission Description and Budget Item Justification: To stay aligned with SECAF Operational Imperatives, with OSD Focus Area C2, logistics mobility (land/water), funds will be used to obtain significant improvements in operational capability and develop items within the GA FoS to include but not limited to: Maritime Recovery (open ocean boat ), Ground Mobility, Technical Recovery, Precision Aerial Insertion (cargo & personnel parachutes), Medical (Simulators), Information Management, SERE, Visual Augmentation (night vision, augmented reality) and Force Protection. This may be conducted through industry technology demonstrations, prototypes, and associated engineering support to posture the GA program for technology insertion. The Guardian Angel weapon system development/Innovation activities also include studies, analysis, requirements development and developmental testing to support both current and future program planning and execution, quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funding will deliver enhanced capability for the dismounted Guardian Angel Operators in terms of dramatic weight reduction, standardization of items across units, and increased mission effectiveness across the conflict spectrum. This funding request will support potential DMS and obsolescence solutions, to include if optimal, life of type buys or bridge buys limited to the program of record quantity. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.443M was expended for civilian pay expenses in this program element, and in FY 2025 0.361M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0207227F / Combat Rescue - Pararescue Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 185, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 743000, 0, 0, 0, 0, 0, 0, $$Beginning in FY26 this funding is reported in BA 07 Project 0207457F. GA is a Family of Systems (FoS) based in both human and equipment capabilities formulated to execute Air Force Personnel Recovery (PR) across the full spectrum of military operations. Established by the Air Force Chief of Staff in 2003 and officially captured in AFPD 10-9, the GA FoS is employed by three distinct Air Force specialties: Pararescuemen (PJ), Combat Rescue Officer (CRO), and Survival, Evasion, Resistance, Escape (SERE). The GA FoS is comprised of nine critical mission areas: Precision Aerial Insertion, Information Management, Force Application, Visual Augmentation, Maritime Recovery, Ground Mobility, Technical Rescue, Medical, and SERE. GA focus is on maintaining legacy weapon system capability while modernizing/improving subsystems for better mission effectiveness. Mission Description and Budget Item Justification: To stay aligned with SECAF Operational Imperatives, with OSD Focus Area C2, logistics mobility (land/water), funds will be used to obtain significant improvements in operational capability and develop items within the GA FoS to include but not limited to: Maritime Recovery (open ocean boat ), Ground Mobility, Technical Recovery, Precision Aerial Insertion (cargo & personnel parachutes), Medical (Simulators), Information Management, SERE, Visual Augmentation (night vision, augmented reality) and Force Protection. This may be conducted through industry technology demonstrations, prototypes, and associated engineering support to posture the GA program for technology insertion. The Guardian Angel weapon system development/Innovation activities also include studies, analysis, requirements development and developmental testing to support both current and future program planning and execution, quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funding will deliver enhanced capability for the dismounted Guardian Angel Operators in terms of dramatic weight reduction, standardization of items across units, and increased mission effectiveness across the conflict spectrum. This funding request will support potential DMS and obsolescence solutions, to include if optimal, life of type buys or bridge buys limited to the program of record quantity. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.443M was expended for civilian pay expenses in this program element, and in FY 2025 0.361M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207227F / Combat Rescue - Pararescue Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207238F$$, $$E-11A$$, $$rdte_af_ba7$$, $$ssc_milcom$$, 2026, 15244000, 23044000, 30967000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207238F"}$$::jsonb, $$Budget Program Activity Code (BPAC) 671201 is primarily focused on Operational Systems Development for the E-11A Battlefield Airborne Communication Node (BACN) platform, and BPAC 675383 is primarily focused on BACN payload weapon system components. BACN enables tactical edge and Joint and Coalition information interoperability via air, space, and surface systems, to include a Backbone Network for high-capacity data transfer. As requirements emerge, BACN will integrate new hardware and software capabilities that improve system performance, interoperability, availability, prototyping of activities in line with department approach of system development upgrades to support current/future Open Mission System "OMS" technologies. Efforts may include onboard enhancements such as datalink receiving capability in platform cockpit to include but not limited to Link-16, as well as analysis and developmental efforts to explore feasibility of onboard operators to support onboard payload control capabilities. Efforts include, but are not limited to, expansion of external time reference capabilities, development/integration of additional communications systems/subsystems and components; Ka-Band Satellite Communications (Ka-SATCOM), Integrated Broadcast System (IBS), Protected Tactical Satellite Communications (PTS), enhancements to Military Global Positioning System (MilGPS), integration of advanced antennas and waveforms, development efforts enabling integration of Advanced Battle Management System (ABMS)/ Joint All Domain Command and Control (JADC2) capabilities, enhancements to ground support capabilities. Additionally, safety of flight considerations, to include weapon system performance, aircraft structural integrity, availability, continuity of service requirements will be addressed, aircraft avionics upgrades, as well as early system engineering assessments and risk reduction activities associated with weapon system "payload” & "platform” survivability in non-contested through contested environments. Efforts include, if needed, long lead items required for successful integration of subsystems (Ka-Band SATCOM, IBS, PTS, Mil-GPS), required non-recurring engineering and Diminishing Manufacturing Sources "DMS" issues, the development of simulators/trainers, development of training materials, the development of future waveforms that are backwards compatible with existing communications, and technical publications as well as the assimilation of any mandates levied on the BACN weapon system. Execute risk reduction activities for development of future capabilities on BACN payload/aircraft efforts. This includes future development and/or modification initiatives for payload form factor updates, integration efforts with other aerial gateway systems such as Roll on Beyond Line of Sight Enhancement (ROBE), as well as analysis and redesign efforts for improved data/voice range extension and translation. *This program element 0207238F is a continuation of legacy program element 0207610F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207238F / E-11A Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.671M was expended for civilian pay expenses in this program element, and in FY 2025 0.949M is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $0 for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 0, 0, 0, NULL, NULL, 186, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 29669000, 15035000, 0, 0, 0, 0, 0, $$Budget Program Activity Code (BPAC) 671201 is primarily focused on Operational Systems Development for the E-11A Battlefield Airborne Communication Node (BACN) platform, and BPAC 675383 is primarily focused on BACN payload weapon system components. BACN enables tactical edge and Joint and Coalition information interoperability via air, space, and surface systems, to include a Backbone Network for high-capacity data transfer. As requirements emerge, BACN will integrate new hardware and software capabilities that improve system performance, interoperability, availability, prototyping of activities in line with department approach of system development upgrades to support current/future Open Mission System "OMS" technologies. Efforts may include onboard enhancements such as datalink receiving capability in platform cockpit to include but not limited to Link-16, as well as analysis and developmental efforts to explore feasibility of onboard operators to support onboard payload control capabilities. Efforts include, but are not limited to, expansion of external time reference capabilities, development/integration of additional communications systems/subsystems and components; Ka-Band Satellite Communications (Ka-SATCOM), Integrated Broadcast System (IBS), Protected Tactical Satellite Communications (PTS), enhancements to Military Global Positioning System (MilGPS), integration of advanced antennas and waveforms, development efforts enabling integration of Advanced Battle Management System (ABMS)/ Joint All Domain Command and Control (JADC2) capabilities, enhancements to ground support capabilities. Additionally, safety of flight considerations, to include weapon system performance, aircraft structural integrity, availability, continuity of service requirements will be addressed, aircraft avionics upgrades, as well as early system engineering assessments and risk reduction activities associated with weapon system "payload” & "platform” survivability in non-contested through contested environments. Efforts include, if needed, long lead items required for successful integration of subsystems (Ka-Band SATCOM, IBS, PTS, Mil-GPS), required non-recurring engineering and Diminishing Manufacturing Sources "DMS" issues, the development of simulators/trainers, development of training materials, the development of future waveforms that are backwards compatible with existing communications, and technical publications as well as the assimilation of any mandates levied on the BACN weapon system. Execute risk reduction activities for development of future capabilities on BACN payload/aircraft efforts. This includes future development and/or modification initiatives for payload form factor updates, integration efforts with other aerial gateway systems such as Roll on Beyond Line of Sight Enhancement (ROBE), as well as analysis and redesign efforts for improved data/voice range extension and translation. This program element 0207238F is a continuation of legacy program element 0207610F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207238F / E-11A Operational Systems Development This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2026 request was reduced by 0 for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” No budget year funding is requested for FY 2027. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207242F$$, $$Special Program Applications$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 35000000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207242F"}$$::jsonb, NULL, NULL, 35128000, 35098000, 35071000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 35149000, 35149000, 0, 35149000, 35780000, $$This program is a new start. Additional details of this budget justification are classified, per Executive Order 13526, Sec 1.4 (a) and are submitted annually to Congress in the classified budget justification book. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207247F$$, $$AF TENCAP$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 52492000, 30649000, 50263000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207247F"}$$::jsonb, $$Air Force Tactical Exploitation of National Capabilities (TENCAP) increases warfighter effectiveness through the exploitation of national capabilities and promotes cross- domain integration of these capabilities into military operations/training and intelligence, surveillance and reconnaissance (ISR) activities. In FY 2026, AF TENCAP exploits existing National, global, and Non-Traditional ISR in air, space, and cyber domains for operational and tactical applications by rapidly prototyping and providing capability demonstrations. The program consists of multiple small projects supporting the Air Force warfighter. Projects are designed to transition to warfighters or national intelligence agencies for operational use and to appropriate acquisition Programs of Record for sustainment and further development. AF TENCAP projects influence the design and operation of current and future National, global, and Non-Traditional systems in air, space, and cyber while providing situational awareness to warfighters and intelligence organizations. AF TENCAP requirements and existing resources may be rapidly re-prioritized in response to emerging warfighter needs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, $0.000M was expected to expend for civilian pay expenses in this program element, and in FY 2025, $0.000M is forecasted for civilian pay expenses in this program element. This program element received $4.9M Ukraine Supplemental Funds in FY 2024. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207247F / AF TENCAP Operational Systems Development$$, NULL, 56029000, 56501000, 42483000, NULL, NULL, 188, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 50263000, 52492000, 50913000, 50913000, 0, 50913000, 43547000, $$Air Force Tactical Exploitation of National Capabilities (TENCAP) increases warfighter effectiveness through the exploitation of national capabilities and promotes cross- domain integration of these capabilities into military operations/training and intelligence, surveillance and reconnaissance (ISR) activities. In FY 2027, AF TENCAP exploits existing National, global, and Non-Traditional ISR in air, space, and cyber domains for operational and tactical applications by rapidly prototyping and providing capability demonstrations. The program consists of multiple small projects supporting the Air Force warfighter. Projects are designed to transition to warfighters or national intelligence agencies for operational use and to appropriate acquisition Programs of Record for sustainment and further development. AF TENCAP projects influence the design and operation of current and future National, global, and Non-Traditional systems in air, space, and cyber while providing situational awareness to warfighters and intelligence organizations. AF TENCAP requirements and existing resources may be rapidly re-prioritized in response to emerging warfighter needs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                               Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207247F / AF TENCAP Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207249F$$, $$Precision Attack Systems Procurement$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 13613000, 11459000, 9423000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207249F"}$$::jsonb, $$Advanced Targeting Pods (ATPs) provide long-range target acquisition and expanded weapon delivery envelopes for greater aircraft survivability which are imperative in supporting Long Range Kill Chain, as well as target identification, reduction in collateral damage, and fratricide prevention for F-15C/E/EX, F-16 (all blocks), A-10C, B-52H, B-1B. ATP expanded range capabilities (in all domains), such as high resolution imagery, larger aperture, eye safe laser, high system reliability and smaller deployment footprint provide greater combat effectiveness across several mission areas. Demonstrated capability to support Counter-Unmanned Aircraft System (cUAS) and Homeland Missile Defense missions. Each targeting pod provides long-range target acquisition and expanded weapon delivery envelopes during day, night, and all- weather conditions. Targeting pods are equipped with infrared (Longwave/Midwave/Shortwave Infrared, Color TV) sensor, laser designator, digital video, and real time video data link for connectivity with ground forces. FY 2026 funds will support integrating ATP advanced technology with aircraft Operational Flight Programs, upgrading pod capability, technical analysis, and testing. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.170M was expended for civilian pay expenses in this program element, and in FY 2025 0.489M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0207249F / Precision Attack Systems Procurement Operational Systems Development$$, NULL, 14282000, 14553000, 14829000, NULL, NULL, 189, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 9106000, 13429000, 14602000, 14602000, 0, 14602000, 15129000, $$Advanced Targeting Pods (ATPs) provide long-range target acquisition and expanded weapon delivery envelopes for greater aircraft survivability which are imperative in supporting Long Range Kill Chain, as well as target identification, reduction in collateral damage, and fratricide prevention for F-15C/E/EX, F-16 (all blocks), A-10C, B-52H, B-1B. ATP expanded range capabilities (for land, sea and air), such as high resolution imagery, larger aperture, eye safe laser, high system reliability and smaller deployment footprint provide greater combat effectiveness across several mission areas. Demonstrated capability to support Counter-Unmanned Aircraft System (cUAS) and Homeland Missile Defense missions. Each targeting pod provides long-range target acquisition and expanded weapon delivery envelopes during day, night, and all- weather conditions. Targeting pods are equipped with infrared (Longwave/Midwave/Shortwave Infrared, Color TV) sensor, laser designator, digital video, and real time video data link for connectivity with ground forces. FY 2027 funds will support integrating ATP advanced technology with aircraft Operational Flight Programs, upgrading pod capability, technical analysis, and testing. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207249F / Precision Attack Systems Procurement Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207253F$$, $$Compass Call$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 63137000, 62555000, 132475000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207253F"}$$::jsonb, $$Compass Call is the Air Force's wide-area, standoff, Airborne Electromagnetic Attack (AEA) Command and Control Warfare/Information Operations (C2W/IO) weapon system. The employment of this weapon system interrupts the adversary's use of the electromagnetic battlespace and is a key active component in the information battlespace and prosecution of current ground and airborne threats. Compass Call's sophisticated electromagnetic attack system is capable of surgical denial and/or disruption of adversary Radio Frequency (RF) communications, radar and sensor systems. Due to rapid advances in Electromagnetic Attack (EA) techniques and technology, Compass Call is designed to be adaptable, making it well-suited for a continuous modernization strategy. Such a strategy ensures Compass Call techniques evolve at a pace capable of addressing adversary tactics and emerging technologies. The Compass Call weapon system is continuously improved using a rapid development and acquisition process supporting a spiral baseline upgrade strategy. User needs and technology insertion opportunities are continuously reviewed. As a result of technology refresh initiatives, including incorporation of open architectures, "plug and play” systems, software defined radios, and modular software development, Compass Call is implementing agile processes to support weapon system development activities. In FY 2017, the Compass Call re-host program was initiated prompting transition of mission capabilities from the legacy EC-130H airframe to an EA-37B airframe. The re-hosted Compass Call platform is based on a commercial derivative G550 aircraft holding Federal Aviation Administration (FAA) Supplemental Type Certificates (STCs) for airworthiness. The platform will undergo modifications to host Compass Call's Prime Mission Equipment (PME) and antenna arrays and will receive additional STCs and Military Type Certificates (MTCs). The EA-37B aircraft will re-use PME from the EC-130H aircraft that will be upgraded to the latest Baseline. Due to the age of the EC-130H fleet, re-hosting of the PME is crucial to ensuring the longevity of this critical capability. In an effort to put capability into the warfighter's hands as soon as possible, the EA-37B program pursues concurrent developmental and production activities. EA-37B Baseline 3 (BL3) updates fielded EC-130H Mid-Baseline 2 (MBL2) capabilities, while significantly increasing operating altitude and standoff distances through re-host onto the EA-37B airframe. Baseline 4 (BL4) transitions the software baseline to an agile software framework and implements System-Wide Open Reconfigurable Dynamic Architecture (SWORD-A) to enable rapid integration of new capabilities offering increased target capacity. Requirements for Baseline 5 (BL5) are currently being determined and are intended to focus on external communications systems to improve connectivity across the battlespace. FY 2026 RDT&E efforts continue BL4 development activities, BL4 test and evaluation, maturation of AEA technologies, and trade studies for future Baseline efforts. Activities encompassed within the BL4 PME upgrade may include, but are not limited to, aircraft system integration; assembly, test and checkout; mission system Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:           PE 0207253F / Compass Call Operational Systems Development upgrades; obsolescence resolution; software development; systems engineering; test and evaluation; flight test; training systems; training events; support equipment; and Program Support Costs (PSC). Specific mission system developmental activities may include, but are not limited to, studies and analyses for future capabilities and baselines; preparation of white papers and technical reports; maturation of Technology Readiness Level (TRL) capabilities for future insertion; development of QRC applications for integration into Compass Call Software Defined Radios (SDRs); technology roadmap development; power expansion; transmit and receive development; size, weight, power and cooling (SWAP-C) reductions; transition of Compass Call PME to open architecture compliant standards; and continued migration of the Compass Call Operating System (CCOS) to an agile software construct. Compass Call funding also supports innovation activities to include studies, analyses, requirements definition, and QRC prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605832F, 0605833F, 0605898F or 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element. In FY 2025 1.0M is being expended for civilian pay expenses in this program element. In FY 2026 1.0M is being expended for civilian pay expenses in this program element. The FY 2026 request for Compass Call includes $0 thousand of discretionary and $63,137 thousand of mandatory (reconciliation) for a total of $63,137 thousand. The mandatory funds increase EA-37B production by continuing development, test and evaluation, maturation of AEA technologies, and trade studies for Baseline and Future Baselines. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 67348000, 73638000, 85033000, NULL, NULL, 190, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 115978000, 0, 66514000, 66514000, 0, 66514000, 84668000, $$Compass Call is the Air Force's wide-area, standoff, Airborne Electromagnetic Attack (AEA) Command and Control Warfare/Information Operations (C2W/IO) weapon system. The employment of this weapon system interrupts the adversary's use of the electromagnetic battlespace and is a key active component in the information battlespace and prosecution of current ground and airborne threats. Compass Call's sophisticated electromagnetic attack system is capable of surgical denial and/or disruption of adversary Radio Frequency (RF) communications, radar and sensor systems. Due to rapid advances in Electromagnetic Attack (EA) techniques and technology, Compass Call is designed to be adaptable, making it well-suited for a continuous modernization strategy. Such a strategy ensures Compass Call techniques evolve at a pace capable of addressing adversary tactics and emerging technologies. The Compass Call weapon system is continuously improved using a rapid development and acquisition process supporting a spiral baseline upgrade strategy. User needs and technology insertion opportunities are continuously reviewed. As a result of technology refresh initiatives, including incorporation of open architectures, "plug and play” systems, software defined radios, and modular software development, Compass Call is implementing agile processes to support weapon system development activities. In FY2017, the Compass Call re-host program was initiated prompting transition of mission capabilities from the legacy EC-130H airframe to an EA-37B airframe. The re-hosted Compass Call platform is based on a commercial derivative G550 aircraft holding Federal Aviation Administration (FAA) Supplemental Type Certificates (STCs) for airworthiness. The platform hosts Compass Call's Prime Mission Equipment (PME) and antenna arrays and is receiving additional STCs and Military Type Certificates (MTCs). The EA-37B aircraft re-uses PME from the EC-130H aircraft that is upgraded to the latest Baseline. Due to the age of the EC-130H fleet, re-hosting of the PME is crucial to ensuring the longevity of this critical capability. In an effort to put capability into the warfighter's hands as soon as possible, the EA-37B program pursues concurrent developmental and production activities. EA-37B Baseline 3 (BL3) updates fielded EC-130H Mid-Baseline 2 (MBL2) capabilities, while significantly increasing operating altitude and standoff distances through re-host onto the EA-37B airframe. Baseline 4 (BL4) transitions the software baseline to an agile software framework and implements System-Wide Open Reconfigurable Dynamic Architecture (SWORD-A) to enable rapid integration of new capabilities offering increased target capacity. Requirements for Baseline 5 (BL5) are intended to focus on external and resilient communications systems to improve connectivity across the battlespace. FY 2027 RDT&E efforts continue BL4 development activities, BL4 test and evaluation to include range funding, trade studies for Baseline 5 advanced capabilities and technology/baseline maturation. Activities encompassed within the BL4 PME upgrade may include, but are not limited to, aircraft system integration; assembly, test, and checkout; mission system upgrades; obsolescence resolution; software development; systems engineering; test and evaluation; flight test; training systems; training Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0207253F / Compass Call Operational Systems Development events; support equipment; and Program Support Costs (PSC). Activities encompassed within the BL5 include but are not limited to external communications, extended frequency ranges, other advanced capabilities, and Program Support Costs (PSC). Specific mission system developmental activities may include, but are not limited to, studies and analyses for future capabilities and baselines; preparation of white papers and technical reports; maturation of Technology Readiness Level (TRL) capabilities for future insertion; development of Quick Reaction Capabilities (QRC) applications for integration into Compass Call Software Defined Radios (SDRs); technology roadmap development; power expansion; transmit and receive development; size, weight, power and cooling (SWAP-C) reductions; transition of Compass Call PME to open architecture compliant standards; and continued migration of the Compass Call Operating System (CCOS) to an agile software construct. Compass Call funding also supports innovation activities to include studies, analyses, requirements definition, and QRC prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2026 spend plan amount for RDT&E includes $0 thousand of discretionary and $90,241 thousand of mandatory (reconciliation) for a total of $90,241 thousand. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207255N$$, $$MQ-25 STINGRAY$$, $$rdte_navy_ba7$$, $$peo_uw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 1211951000, 1011801000, 767577000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 513308000, 513308000, NULL, 513308000, 979529000, $$The MQ-25 program, PU 3278, rapidly develops an unmanned capability to embark on Carrier Vessel, Nuclear (CVN) as part of the Carrier Air Wing (CVW) to conduct aerial refueling as a primary mission and provide Intelligence, Surveillance, and Reconnaissance (ISR) capability as a secondary mission. MQ-25 extends Carrier Air Wing mission effectiveness range, partially mitigates the current Carrier Strike Group (CSG) organic ISR gap and fills the future Carrier Air Wing-tanker gap, mitigating Strike Fighter gap and preserving F/A-18E/F Fatigue Life Expenditure for its primary missions. As the first carrier-based, Group 5 Unmanned Aircraft System (UAS), MQ-25 will pioneer the integration of manned and unmanned operations, mature, complex sea-based Command, Control, Communications, Computers, and Intelligence (C4I) technologies, and pave the way for future multi-faceted, multi-mission Unmanned Aircraft Systems to pace emerging threats. The MQ-25 system will enhance CVN capability and versatility for the Joint Forces Commander through the integration of a persistent, sea-based, multi-mission aerial refueling and ISR Unmanned Aircraft System into the Carrier Air Wing. MQ-25 is the Air System which will integrate with the UMCS program. These architectural segments will be managed by the PMA-268 Government Lead Systems Integrator (LSI) that provides system-of-systems integration and is also responsible for managing enterprise-level Unmanned Carrier Aviation architecture and associated interfaces. MQ-25 Development includes development and test of the air vehicle to include software, peculiar support equipment, training systems and other logistics elements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational          PE 0207255N / MQ-25 STINGRAY Systems Development In FY 2027, the MQ-25 program will continue UMCS integration and continue flight test. All four Engineering Development Models (EDMs) will continue to support ground and flight testing. The program will continue to develop and integrate increased software capabilities into the aircraft in support of carrier suitability and mission systems evaluations. The program will continue to develop and integrate obsolescence redesign of critical flight system avionics to refine the production baseline. The program will begin development and integration efforts to incorporate Stingray to the Fight and to the Fleet capabilities necessary to enable and align MQ-25 operations with the Navy's Unmanned Campaign Plan and Air Wing of the Future requirements. The UMCS program, PU 3279, is the system-of-systems required for MQ-25 vehicle and payload control, both shipboard and shore based. UMCS consists of all ground and ship-based hardware, software, and networks associated with the planning and execution of flight operations and tactical missions. In addition to the GCS, consisting of Air Vehicle Pilot (AVP) workstations and servers, the UMCS program builds hardware to support line of sight (LOS) communications, beyond line of sight (BLOS) satellite communications (SATCOM), and integration with ship/shore-based systems. There are three GCS variants: MD-5C (CVN-based), MD-5D (Shore- based), and MD-5E (Embarkable system for use on CVNs that do not yet have permanent GCS systems installed). UMCS leverages existing Programs of Record (PoR) for network integration and LOS/BLOS communications and builds MQ-25 unique systems (e.g. an ARC-210 based LOS communication system and a Video Management System (VidMS) for AVP situational awareness). GCS streamlines software development, supports multiple classification levels, and positions MQ-25A interoperability with other DoW systems. Hardware development and fabrication is one facet of the program. UMCS develops and integrates software and modifies several aircraft carrier spaces to install and integrate the GCS and communication systems, in support of MQ-25A test events and operations aboard select NIMITZ Class CVNs. The UMCS program modifies and integrates with existing, external Command, Control, Communication, Computers, and Intelligence systems to provide network paths for air vehicle and mission payload data using a variety of wideband and narrowband communication paths. UMCS accomplishes this by integrating the GCS and the MQ-25A air vehicle with multiple networks and systems both at sea and on shore. In addition to controlling the MQ-25, UMCS will provide the GCS for Collaborative Combat Aircraft and the Air Wing of the Future (AWOTF). In FY2027, the UMCS team will continue to manage the two NSMA contracts with Lockheed Martin (one for development and one for production) while managing a NAVAIR contract for continuation of Block I production. The Block II contract with Lockheed Martin, through NSMA, which will support future uncrewed platforms (e.g. CCA, Air Wing of the Future) and be backwards compatible to support MQ-25. UMCS will continue developing Technical Data Packages for system level components and continue providing system engineering, program management, and development support for the program. JUSTIFICATION FOR BUDGET ACTIVITY: This program is funded under SYSTEM DEVELOPMENT AND DEMONSTRATION because it includes projects that have passed Milestone B approval and are conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to a full-rate production decision. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                   Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational          PE 0207255N / MQ-25 STINGRAY Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207268F$$, $$Aircraft Engine Component Improvement Program$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 52734000, 58262000, 60498000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207268F"}$$::jsonb, $$The Aircraft Engine Component Improvement Program (CIP) provides the only source of critical sustaining engineering support for in-service Air Force engines to maintain flight safety (highest priority), correct deficiencies, improve system Operational Readiness (OR), Reliability & Maintainability (R&M), reduce engine Life Cycle Cost (LCC), and sustain engines throughout their service lives. It also serves as the primary vehicle to implement emerging technology solutions (e.g., additive manufacturing and digital engineering) to resolve these issues, and improve engine performance. Past investments have reduced warfighter Class A rates, decreased Engine Related Loss of Aircraft (ERLOA) and generated significant returns on investments. Priority requirements include Accelerated Mission Tests (AMTs) required for complex redesigns. The AMT provides early identification of safety/reliability issues prior to the operational fleets discovering unknown safety and/or reliability issues. Ongoing tasks for this year support eliminating critical safety concerns, addressing obsolescence and Diminishing Manufacturing Sources and Material Shortage (DMSMS), developing critical repairs, and extending life limited parts. Also, improving environmental processes and materials to increase energy efficiency, supply chains and USAF's ability to operate effectively under any climate conditions. Engines are accepted into the CIP program after the first procurement-funded engine, and support continues over the engine's life, gradually decreasing to a minimum level (safety/depot repairs) sufficient to keep older engines operational. Engine CIP testing identifies and addresses engine-related problems before operational impacts materialize. R&M related Engine CIP efforts significantly reduce out year Operations and Maintenance (O&M) and spares costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. In FY 2024 $0.297 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.598 million is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $0.408 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207268F / Aircraft Engine Component Improvement Program Operational Systems Development$$, NULL, 208562000, 209639000, 210785000, NULL, NULL, 191, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 58429000, 64073000, 205938000, 205938000, 0, 205938000, 212023000, $$The Aircraft Engine Component Improvement Program (CIP) provides the only source of critical sustaining engineering support for in-service Air Force engines to maintain flight safety (highest priority), correct deficiencies, improve system Operational Readiness (OR), Reliability & Maintainability (R&M), reduce engine Life Cycle Cost (LCC), and sustain engines throughout their service lives. It also serves as the primary vehicle to implement emerging technology solutions (e.g., additive manufacturing and digital engineering) to resolve these issues, and improve engine performance. Past investments have reduced warfighter Class A rates, decreased Engine Related Loss of Aircraft (ERLOA) and generated significant returns on investments. Priority requirements include Accelerated Mission Tests (AMTs) required for complex redesigns. The AMT provides early identification of safety/reliability issues prior to the operational fleets discovering unknown safety and/or reliability issues. Ongoing tasks for this year support eliminating critical safety concerns, addressing obsolescence and Diminishing Manufacturing Sources and Material Shortage (DMSMS), developing critical repairs, and extending life limited parts. Engines are accepted into the CIP program after the first procurement-funded engine, and support continues over the engine's life, gradually decreasing to a minimum level (safety/depot repairs) sufficient to keep older engines operational. Engine CIP testing identifies and addresses engine-related problems before operational impacts materialize. R&M related Engine CIP efforts significantly reduce out year Operations and Maintenance (O&M) and spares costs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207268F / Aircraft Engine Component Improvement Program Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207325F$$, $$Joint Air-to-Surface Standoff Missile (JASSM)$$, $$rdte_af_ba7$$, $$aflcmc_ww$$, 2026, 232252000, 129314000, 181692000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207325F"}$$::jsonb, $$The Joint Air-to-Surface Standoff Missile (JASSM) family of missiles includes: JASSM Baseline (JASSM-BL/AGM-158A) and JASSM Extended Range (JASSM- ER/AGM-158B, AGM-158B-2, AGM-158B-3, and AGM-158D). JASSM-ER provides a long range, conventional air-to-surface, autonomous, precision-guided, low observable, standoff cruise missile compatible with fighter and bomber aircraft. JASSM-ER provides the capability to attack a variety of high value fixed or relocatable targets with precision, through preplanned missions or target-of-opportunity, deeper into enemy territory than JASSM-BL, all while minimizing the threat to launch aircraft. Aircraft integration of JASSM-ER/AGM-158B is complete on the B-1, F-15E, F-16, B-2, and B-52. Objective aircraft are F-15E, F-16, B-52, B-2, and further integration is required for the F-35. The AGM-158A, AGM-158B, and AGM-158B-2 are fielded. The AGM-158B-3 and AGM-158D are in development and will gradually insert into the production line as the new missile builds are approved and ready. Missiles accepted by the Air Force will not be returned for modification to the newest variant. Threats to JASSM survivability are being rapidly developed and fielded by near-to-peer adversaries. JASSM continued development enhances capability and provides operational flexibility against current and projected threats. This is accomplished by evaluating high payoff technology development, performing risk reduction activities, and investigating new variants and/or alternate missions that may use JASSM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Air Force develops, tests, and fields improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. The AGM-158B-2 is an upgrade to the existing JASSM-ER/AGM-158B, incorporating multiple development initiatives to respond to rapidly changing threats and is being produced in Lot 19. The AGM-158B-3 provides M-code capability and will begin a production cut-in starting in Lot 22. The AGM-158D provides Weapon Data Link (WDL) capability to re-target the missile, post-launch, against relocatable or higher priority targets during mission execution. The AGM-158D will begin a production cut-in starting in Lot 22. Weapon Data Link (WDL), This effort includes development of the WDL, as well as integration and testing efforts. The WDL allows warfighters to retarget the weapons via line-of-sight and beyond-line-of-sight, allowing the missile to attack relocatable and/or time sensitive targets post aircraft release. Test assets encompass AGM-158B-3 and AGM-158D in FY24-26. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207325F / Joint Air-to-Surface Standoff Missile (JASSM) Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24, .97M was allocated for civilian pay expenses in this program element. In FY25, 1.216M is forecasted for civilian pay expenses in this program element. Implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio tradespace studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. The Weapon Data link (WDL) allows warfighters to retarget the weapons via line-of-sight and beyond-line-of-sight, allowing the missile to attack relocatable and/or time sensitive targets post aircraft release. The WDL program is designed to use an open-system architecture standard with outside communication nodes. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Funding for this exhibit is contained in PE 0207325F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 76912000, 21075000, 21467000, NULL, NULL, 192, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 190710000, 226116000, 133092000, 133092000, 0, 133092000, 21901000, $$The Joint Air-to-Surface Standoff Missile (JASSM) family of missiles includes: JASSM Baseline (JASSM-BL/AGM-158A) and JASSM Extended Range (JASSM- ER/AGM-158B, AGM-158B-2, AGM-158B-3, and AGM-158D). JASSM-ER provides a long range, conventional air-to-surface, autonomous, precision-guided, low observable, standoff cruise missile compatible with fighter and bomber aircraft. JASSM-ER provides the capability to attack a variety of high value fixed or relocatable targets with precision, through preplanned missions or target-of-opportunity, deeper into enemy territory than JASSM-BL, all while minimizing the threat to launch aircraft. Aircraft integration of JASSM-ER/AGM-158B is complete on the B-1, F-15E, F-16, B-2, and B-52. Objective aircraft are F-15E, F-16, B-52, B-2, and further integration is required for the F-35. JASSM-ER/AGM-158B-2 is complete on the B-1 only. The AGM-158A, AGM-158B, and AGM-158B-2 are fielded. The AGM-158B-3 and AGM-158D are in development and will gradually insert into the production line as the new missile builds are approved and ready. Missiles accepted by the Air Force will not be returned for modification to the newest variant. Threats to JASSM survivability are being rapidly developed and fielded by near-to-peer adversaries. JASSM continued development enhances capability and provides operational flexibility against current and projected threats. This is accomplished by evaluating high payoff technology development, performing risk reduction activities, and investigating new variants and/or alternate missions that may use JASSM attributes. To maximize effectiveness of existing inventory and address findings from the field, the Air Force develops, tests, and fields improvements via software upgrades into fielded missiles and/or hardware upgrades inserted into the production line. The AGM-158B-2 is an upgrade to the existing JASSM-ER/AGM-158B, incorporating multiple development initiatives to respond to rapidly changing threats and started production in Lot 19. The AGM-158B-3 provides Military M-code capability and will begin a production cut-in starting in Lot 22. The AGM-158D provides Weapon Data Link (WDL) capability to re-target the missile, post-launch, against relocatable or higher priority targets during mission execution. The AGM-158D will begin a production cut-in starting in Lot 23. The Weapon Data Link (WDL) effort includes the development of the WDL, as well as various integration and testing efforts. The WDL allows warfighters to retarget the weapons via line-of-sight (objective capability) and beyond-line-of-sight (threshold capability), allowing the missile to attack relocatable and/or time sensitive targets post aircraft release. The WDL program is designed to use an open-system architecture standard with outside communication nodes. Test assets encompass AGM-158B-3 and AGM-158D in FY 2024-2028. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207325F / Joint Air-to-Surface Standoff Missile (JASSM) Operational Systems Development This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2026 spend plan amount for Research, Development, Test and Evaluation (RDT&E), Air Force includes $226,116 thousand of discretionary and $200,000 thousand of mandatory (reconciliation) funding for a total of $426,116 thousand. Implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio tradespace studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging Department of War (DoW) and Department of the Air Force (DAF) enterprise IT solutions. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Funding for this exhibit is contained in PE 0207325F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207327F$$, $$Small Diameter Bomb (SDB)$$, $$rdte_af_ba7$$, $$aflcmc_ww$$, 2026, 24810000, 42860000, 29910000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207327F"}$$::jsonb, $$GBU-53/B Small Diameter Bomb Increment II (SDB II) StormBreaker is a joint interest United States Air Force (USAF) and Department of Navy (DoN) Acquisition Category (ACAT) IC program, with the USAF as the lead service. SDB II addresses the following warfighter requirements: attack moving and stationary targets; adverse weather operations; multiple ordnance carriage; precision munitions capability; reduced munitions footprint; increased weapons effectiveness; minimized potential for collateral damage; reduced susceptibility of munitions to countermeasures; and provides a network-enabled weapon capability via Link-16 and Ultra High Frequency (UHF) weapon data link. SDB II is a key component of the Air Force Global Strike Task Force Concept of Operations (CONOPs). The threshold aircraft for the USAF is the F-15E, and the threshold aircraft for the DoN are the F-35B and F-35C. Objective aircraft include the F-22, F-16, F-35A, B-2, A-10, MQ-9, B-1, B-52, AC-130 and the F/A-18E/F. SDB II is compatible with the Bomb Rack Unit-61 (BRU-61) miniature munitions carriage, Type II carriage systems, the Container Numerical Unit-660/E (CNU-660/E) carriage system, the Common Munitions Built In Test (BIT)/Reprogramming Equipment (CMBRE), and the Joint Mission Planning System (JMPS). SDB II will develop and field a single weapon storage container (USAF) and a dual weapon storage container (DoN). SDB II completed a competitive Risk Reduction in October 2009 and entered Milestone B Engineering and Manufacturing Development (EMD) in August 2010. A Fixed Price Incentive Firm EMD contract with five options for annual Low Rate Initial Production (LRIP) lots (FY15-FY19) was awarded in August 2010. SDB II received Milestone C approval to enter LRIP in June 2015 and completed an Acquisition Program Baseline (APB) update. Contract options for LRIP Lots 1-5 have been exercised. Initial Operational Test and Evaluation (IOT&E) started June 2018 and completed December 2019. SDB II was fielded for the F-15E in September 2020. DoN's first production lot (Lot 4/FY19) supports F/A-18E/F Initial Operating Capability (IOC). The Milestone Decision Authority approved an APB update May 2022 to incorporate the new Air Force inventory objective and adjust for new F-35B/C software schedules. Implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio trade space studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging Department of Defense (DoD) and Department of Air Force (DAF) enterprise Information Technology (IT) solutions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                     PE 0207327F / Small Diameter Bomb (SDB) Operational Systems Development This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in relevant Open System Architecture (OSA) standards. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.718M was expended for civilian pay expenses in this program element, and in FY 2025 $0.752M is forecast for civilian pay expenses in this program element. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D The FY 2026 request was reduced by $0.025 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 25885000, 26375000, 26877000, NULL, NULL, 193, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 29047000, 24575000, 25497000, 25497000, 0, 25497000, 27421000, $$GBU-53 Small Diameter Bomb Increment II (SDB II) Stormbreaker is a United States Air Force (USAF)-led, joint interest ACAT-IC program with the Department of Navy (DoN). SDB II delivers and sustains GBU-53 weapons capability for the warfighter to attack mobile and stationary targets at standoff and stand in ranges through all weather. SDB II addresses the following warfighter requirements: precision munitions capability, attack moving and stationary targets, adverse weather operations, multiple kills per pass, multiple ordnance carriage, reduced munitions footprint, increased weapons effectiveness, minimized potential for collateral damage, Military- code (M-code) Global Positioning System (GPS) and inertial navigation, reduced susceptibility to anti-jam / anti-spoofing countermeasures, and Network Enabled Weapon (NEW) capabilities via Link-16. SDB II is a key component of Air Force's Global Strike Task Force CONOPS. The threshold aircraft for the USAF is the F-15E and the threshold aircraft for the DoN are the F-35B and F-35C. Funding for integration of threshold aircraft for F-15E, F-35B, and F-35C is in the SDB II program. Objective aircraft include the F/A-18E/F, F-15EX, F-35A, AC-130, F-16, F-22A, B-1B, B-2, B-52, A-10, and MQ-9. Funding for each objective aircraft is provided by that aircraft program. GBU-53 SDB II is compatible with the BRU-61 and BRU-55 miniature munitions carriages, the CNU-660/E weapon carriage container, the Common Munitions Bit and Reprogramming Equipment (CMBRE), and the Joint Mission Planning System (JMPS). The SDB II produces and fields GBU-53s in single-weapon USAF storage containers or dual-weapon DoN containers. DoN IOC declared F/A-18E/F in January 2026. The Milestone Decision Authority approved APB updates in May 2022 and again in May 2025 to incorporate the updates to USAF and DoN inventory objectives. The program is proceeding to a Full Rate Production (FRP) decision in FY 2027. SDB II implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio trade space studies by conducting trade studies, system engineering, test activities, and system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging Department of War (DoW) and Department of Air Force (DAF) enterprise Information Technology (IT) solutions. This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to electrical, logical, and physical interfaces defined in relevant Open System Architecture (OSA) standards. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207327F / Small Diameter Bomb (SDB) Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207328F$$, $$Stand In Attack Weapon$$, $$rdte_af_ba5$$, $$aflcmc_wa$$, 2026, 255336000, 220978000, 346341000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0207328F"}$$::jsonb, $$The Stand-in Attack Weapon (SiAW) system will provide capability to strike rapidly re-locatable targets that create the Anti-Access/Area Denial (A2/AD) environment for 5th Generation and Future Advanced Aircraft. SiAW targets include Theater Ballistic Missile Launchers, Land Attack and Anti-Ship Cruise Missile Launchers, Jammers, Anti-Satellite Systems, and Integrated Air Defense Systems. The SiAW missile system is being developed under a Digital Acquisition (DA) approach that emphasizes agility and innovation. Interim combat capability is pursued through the Navy's Advanced Anti-Radiation Guided Missile-Extended Range (AARGM-ER) program with improved warhead/fuze and F-35 integration (including Universal Armament Interface [UAI] and Mission Planning). Implements Digital Acquisition tenants of Open, Agile, and Digital; builds and establishes industrial base innovation around the program's enterprise for modularity and adaptability for the life cycle of the weapons system. Leverages common component development, in collaboration with other weapon systems, to reduce redundant costs between systems with similar subsystems requirements. Invests in analytical, data management, digital environments, networks, facilities, and security infrastructure upgrades supporting development of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Expands program office staff, facilities, and security infrastructure to support the required classification levels for this program's activities. Engages with DoD, DAF, and industry stakeholders to refine threat analysis, refine inventory requirements, and plan upgrade requirements. Capitalizes on and incorporates successful laboratory research and development efforts applicable to this program's capability. This effort includes design, development, test, integration, and implementation of appropriate modular open systems approach, related components, and efforts, such as, but not limited to logical interfaces defined in Weapon Open System Architecture (WOSA) and physical interfaces defined/developed in WOSA X. This approach allows modular and severable subsystems, to include those that are software-defined, at the appropriate level to be incrementally added, removed, or replaced throughout the life cycle. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. FY2026 RDT&E funding for PE 0207328F, Program 653133 is in compliance with budgeted end items per the approved test strategy This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY2024 $8.663 million was expended for civilian pay expenses in this program element, and in FY2025 $9.035 million is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System         PE 0207328F / Stand In Attack Weapon Development & Demonstration (SDD) The FY 2026 cost of Middle Tier of Acquisition (MTA) for SiAW is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. The FY2026 request was reduced by $0.515 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 146493000, 29488000, 24234000, NULL, NULL, 110, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 319559000, 252062000, 115882000, 115882000, 0, 115882000, 24749000, $$The Stand-in Attack Weapon (SiAW) is currently in development under the Middle Tier of Acquisition (MTA) pathway. SiAW will provide the capability to strike rapidly re-locatable targets that create the Anti-Access/Area Denial (A2/AD) environment. SiAW targets include Theater Ballistic Missile Launchers, Land Attack and Anti-Ship Cruise Missile Launchers, Jammers, Anti-Satellite Systems, and Integrated Air Defense Systems. SiAW missile system development emphasizes agility and innovation by leveraging Digital Engineering (DE) and Weapon Open System Architecture (WOSA) approaches to quickly integrate future capabilities at reduced cost. Interim capability will be pursued through the Navy's Advanced Anti-Radiation Guided Missile-Extended Range (AARGM-ER) program with improved warhead/fuze and F-35 integration (including Universal Armament Interface [UAI] and Mission Planning). The SiAW program is posturing to transition from development under the MTA pathway to production under the Major Capability Acquisition (MCA) pathway in FY2027. FY2027 funds will continue SiAW F-35 aircraft integration efforts (begun in FY2026) and next higher-level assembly development, will mature system security and anti- tamper capabilities, and will invest in increased flight test preparation activities. For the purposes of the MTA, the SiAW missile system will be integrated and tested on a surrogate aircraft. For post-MTA work (MCA) and fielding, SiAW will be integrated on the F-35. The total cost of the SiAW Middle Tier of Acquisition effort is 964.097 million, including RDT&E and procurement of prototype units. The SiAW program is fully funded across the Future Years Defense Program. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. FY27 RDT&E funding for PE 0207328F, Project 653133 is in compliance with budgeted end items per the approved test strategy and FY24 Omnibus, Sec. 8057. This program element includes all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System          PE 0207328F / Stand In Attack Weapon Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207407F$$, $$Electromagnetic Battle Management (EMBM)$$, $$rdte_af_ba5$$, $$aflcmc_hb$$, 2026, 20439000, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0207407F"}$$::jsonb, $$Electromagnetic Battle Management is an Air Force capability to provide electromagnetic spectrum situational awareness, decision support, and command and control linked by common architectures, standards, and data to enable planning, coordination, and synchronization of electromagnetic spectrum operations (EMSO) across the range of military operations. EMBM will consist of five component capabilities; the ability to attain and maintain EMS Situational Awareness (SA), EMS planning and decision support, non-kinetic command and control, spectrum deconfliction, and a training interface - linked by common architecture, standards, and data. EMBM enables the Combined/Joint Force Air Component Commander to prioritize, integrate, synchronize, C2, and de-conflict non-kinetic operations in support of current operations. AF EMBM will feed into EMBM-J at the COCOM-level. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 060531F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0207407F / Electromagnetic Battle Management (EMBM) Development & Demonstration (SDD)$$, NULL, 19265000, 44850000, 45698000, NULL, NULL, 111, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 17693000, 45322000, 45322000, 0, 45322000, 46647000, $$The Department of the Air Force (DAF) Electromagnetic Battle Management (EMBM) program is an automated family of systems/applications linked by common architectures, standards and data that will expeditiously receive, analyze, display, employ, and securely distribute friendly, neutral, and adversary Electromagnetic Spectrum (EMS) information. DAF EMBM will consist of five component capabilities; the ability to attain, maintain, and monitor the spectrum for EMS Situational Awareness (SA), assessment, and mission planning, decision support with command and control, and training interfaces to all levels of EMS Operations (EMSO). The coordination and synchronization of EMSO will provide real-time Non-Kinetic Fires Orchestration across domains in any range of military operations. DAF EMBM will feed into USSTRATCOM's EMBM-Joint (EMBM-J) at the Combatant Command-level enabling synchronization of Joint Non-Kinetic Fires and enabling resilient decision advantage in contested EM environments. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 00605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0207407F / Electromagnetic Battle Management (EMBM) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207410F$$, $$Air & Space Operations Center (AOC)$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 113086000, 69798000, 65102000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207410F"}$$::jsonb, $$The Air and Space Operations Center Weapon System (AOC WS) program element provides software engineering of Command and Control (C2) capabilities across the entire spectrum of air and space operations from the strategic to the tactical level. AOC WS Modifications allows for the consolidation of many C2 systems across the AOC enterprise to a single baseline to enable the capability, scalability, security, resiliently, and interoperability required to support Major Theater War. AOC WS modifications are also required to remain interoperable, certified, supportable, and compliant through software engineering solutions, integration, testing, fielding, and sustainment of new capabilities and upgrades. This includes utilization of agile software engineering methodologies and managed cloud infrastructure and platform services. Modifications are required for the AOC WS to keep pace with evolving Government Off the Shelf (GOTS) components, integrated Commercial Off the Shelf (COTS) components, DoD directives, changes in the underlying Information Technology (IT) environment, as well as to deliver effective operational capabilities for the user. The Flight Operations (Flight Ops) Program continues to develop and support software-based capabilities that optimize unit resource allocation to maximize the value of each mission or sortie and increase total force readiness. It combines scheduling, training, and standardizations/evaluations applications to support Air Mobility Command and Air Combat Command sorties, and U.S. Space Force scheduling. Funding supports the integration of existing Puckboard and Patriot Excalibur (PEX) products to provide a modernized user interface, resilient architecture, and full spectrum of needed capabilities for scheduling. The program also drives efficiencies in development, integration, sustainment, and management, and provides mission ready forces to meet global wartime and peacetime operations taskings. Efforts within this program element align with USAF investment in Mission Planning Systems (0208006F), All Domain Common Platform(0303248F), C2IMERA (0305015F/0305836F) and ABMS (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. The FY 2026 request was reduced by -$1.640 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver AOC WS capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 19.800 million was expended for civilian pay expenses in this program element, and in FY 2025 18.287 million is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207410F / Air & Space Operations Center (AOC) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 176616000, 182682000, 167158000, NULL, NULL, 194, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 63091000, 99217000, 158871000, 158871000, 0, 158871000, 169819000, $$The Air and Space Operations Center Weapon System (AOC WS) program element provides software engineering of Command and Control (C2) capabilities across the entire spectrum of air and space operations from the strategic to the tactical level. AOC WS Modifications allows for the consolidation of many C2 systems across the AOC enterprise to a single baseline to enable the capability, scalability, security, resiliently, and interoperability required to support Major Theater War. AOC WS modifications are also required to remain interoperable, certified, supportable, and compliant through software engineering solutions, integration, testing, fielding, and sustainment of new capabilities and upgrades. This includes utilization of agile software engineering methodologies and managed cloud infrastructure and platform services. Modifications are required for the AOC WS to keep pace with evolving Government Off the Shelf (GOTS) components, integrated Commercial Off the Shelf (COTS) components, Department of War (DoW) directives, changes in the underlying Information Technology (IT) environment, as well as to deliver effective operational capabilities for the user. Efforts within this program align with and depend upon USAF investment in Mission Planning Systems (PE 0208006F), All Domain Common Platform (0303248F), Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F), Advanced Battle Management System (ABMS) (0604003F) and Flight Ops (PE 0207461F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities necessary for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. This program element may include necessary civilian pay expenses required to manage, execute, and deliver AOC WS capabilities. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025, 18.844 million was expended for civilian pay expenses in this program element, and in FY 2026, 8.913 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207410F / Air & Space Operations Center (AOC) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207412F$$, $$Control and Reporting Center (CRC)$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 0, 0, 2012000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$The Air Force does not have an enterprise solution for multi-domain battlespace awareness and command and control (C2) tools below the Air Operations Center (AOC) level. This presents significant challenges in obtaining a Common Operating Picture (COP) capable of disaggregation from the AOC, particularly at Anderson AFB, Guam which is the center hub in the Air Force's Agile Combat Employment (ACE) capability in the Pacific. Sharing a COP with the AOC is essential at peacetime for defense and at wartime for conducting operations, and the lack of a current solution further complicates the conduct of ACE operations. Incorporating emerging technology into major operational exercises informs and refines Warfighter requirements and provides opportunities for early adoption and Tactics, Techniques, and Procedures (TTPs) development. Utilizing operationally relevant conditions also provides early opportunities for learning and materiel deficiency discovery. Efforts explore technology advancement to provide a common operating picture in support of Agile Combat Employment (ACE). FY2025 funds will be used to develop and incorporate the latest commercial or government solutions into our operations to help identify best-of-breed technology, permit feedback to developers for improvements and refine operational tactics, techniques, and procedures (TTPs) for the conduct of ACE. Deployment will initially be in Guam to enable learning and assessment of tools under real operating conditions and crucially to create a sub-AOC COP at the heart of our ACE operations in the Pacific immediately. Funds will be used to support experimentation with and deployment of the sub-AOC capability including TTP delineation. This program is in Budget Activity 3, Advanced Technology Development because this budget activity includes development of subsystems and components and efforts to integrate subsystems and components into system prototypes for field experiments and/or tests in a simulated environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                   Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 3: Advanced PE 0207412F / Control and Reporting Center (CRC) Technology Development (ATD)$$, NULL, 18925000, 19329000, 19695000, NULL, NULL, 31, $$FY26 Air Force Research and Development Test and Evaluation Vol I.pdf$$, NULL, FALSE, 16441000, 17407000, 18137000, 18137000, 0, 18137000, 20094000, $$The AN/TSY-7 Control and Reporting Center (CRC) is a mobile, ground-based battle management command and control (BMC2) theater air control system (TACS). It is a modular, transportable, and persistent tactical level weapon system which provides direct command and control to air assets in an assigned Area of Responsibility (AOR) and reports back to the Joint Force Air Component Commander (JFACC). The CRC is composed of the following subsystems: AN/TYQ-23A(V)1 Tactical Air Operations Module (TAOM), the AN/TSC-250 Communication Data Link System (CDLS), the AN/TRC-213/214 Remote Radio Secure Voice System (RRSVS), the AN/ TPS-75 organic sensor, and associated mission support equipment. CRC Modernization under this program element (PE) upgrades BMC2, sensors, and communications. This CRC modernization investment integrates the Distributable Battle Management Node (DBMN) and Cloud Based Command and Control (CBC2+) to enable fielding the Tactical Operations Center-Light (TOC-L) capability into CRCs and provide an upgraded, more modular, and threat relevant tactical command and control. In FY2027, CRC Modernization efforts include, but are not limited to: integration of long-haul SATCOM capability, tactical sensing capabilities, tactical data link upgrades, integration of the Cloud Based Command and Control (CBC2+), modernization of the CRC System Integration Lab (SIL) and CRC Test Bed. Additionally, CRC modifications include keeping the system in compliance with DoD directives, changes in the underlying IT/Cyber Security environment, and any other emerging requirements to remain inter-operable, certified, supportable, and compliant through the development, integration, testing, training, and fielding of equipment related to new CRC capabilities. Efforts within this PE align with USAF investment in ABMS (0604003F) and Air Base Air Defense Systems (0207522F) to deliver a common hardware and software baseline for DAF BATTLE NETWORK deployable systems. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207412F / Control and Reporting Center (CRC) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207418F$$, $$AFSPECWAR - TACP$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 1622000, 1433000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207418F"}$$::jsonb, $$a. The Joint Terminal Control Training and Rehearsal (JTC TRS) Program, under the Tactical Airborne Control System, funds development necessary to provide a Distributed Mission Operations (DMO) capable, high-fidelity simulator for Special Warfare airmen, to include Tactical Air Control Party (TACP), Special Tactics Combat Control Team (CCT), Joint Terminal Attack Controller (JTAC) operations and Air Support Operations Center (ASOC) operations. JTC TRS is essential to provide initial training, mission qualification training, continuation training, and currency control requirements to JTACs and Special Tactics personnel. JTAC control training requirements exceed the ability of live-fly aircraft to meet, and JTC TRS is the only capability enabling JTACs to achieve and maintain minimum required training for both qualification and proficiency in accordance with the U.S and Partner Nation Memorandum of Agreement for JTAC certification and qualification. The JTC TRS Program provides research and development to facilitate interoperability with joint and sister Service air-ground simulation using industry standards. JTC TRS will provide the capability to network aircrew full mission trainers and training centers in a live-virtual-constructive network. This development effort will also integrate ASOCs with the Joint Theater Air Ground Simulation System (JTAGSS) trainer for Joint Fires integration. The simulator will supplement live field training and live-fly sorties to provide realistic introductory, proficiency, currency, and upgrade training in a simulated battlefield, disaster, or humanitarian relief environment. b. JTAGSS is a continuation of the ASOC simulation trainer initially funded in 2009 and complements the JTC TRS trainer by providing a total air-ground constructive simulation environment for integrated networked training and mission rehearsal capability that will develop TACP/CCT/JTAC and ASOC/Special Operations Forces (SOF) Command and Control (C2) battle staff skills. JTAGSS will provide the ASOC, SOF, and TACP with the vertical and horizontal C2 communications and coordination training and mission rehearsal required for mission effectiveness. There are insufficient exercises and live training events available to meet mandated readiness requirements. The system will include a secure network connection, a constructive simulation environment generator with sharable databases, computer workstations that have synthetic reflex agent applications for each ASOC/SOF crew position to execute the Air Tasking Order. Funds may be used to address emerging and short notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. DMS efforts to include removal of end-of-life software/hardware within simulators systems and move to a modular, common open system architecture that is sustainable and cyber-resilient. Implement requirements and standards defined under the Simulator Common Architecture Requirements and Standards initiative. FY26 funding ($4.108M) for BA 07 Project 0207418F was transferred to BA 07 Project 0207457F. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207418F / AFSPECWAR - TACP Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver JTC TRS capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.00M was expended for civilian pay expenses in this program element, and in FY 2025 $0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 990000, 509000, 548000, NULL, NULL, 196, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 1380000, 0, 5206000, 5206000, 0, 5206000, 0, $$a. The Joint Terminal Control Training and Rehearsal (JTC TRS) Program, under the Tactical Airborne Control System, funds development necessary to provide a Distributed Mission Operations (DMO) capable, high-fidelity simulator for Special Warfare airmen, to include Tactical Air Control Party (TACP), Special Tactics Combat Control Team (CCT), Joint Terminal Attack Controller (JTAC) operations and Air Support Operations Center (ASOC) operations. JTC TRS is essential to provide initial training, mission qualification training, continuation training, and currency control requirements to JTACs and Special Tactics personnel. JTAC control training requirements exceed the ability of live-fly aircraft to meet, and JTC TRS is the only capability enabling JTACs to achieve and maintain minimum required training for both qualification and proficiency in accordance with the U.S and Partner Nation Memorandum of Agreement for JTAC certification and qualification. The JTC TRS Program provides research and development to facilitate interoperability with joint and sister Service air-ground simulation using industry standards. JTC TRS will provide the capability to network aircrew full mission trainers and training centers in a live-virtual-constructive network. This development effort will also integrate ASOCs with the Joint Theater Air Ground Simulation System (JTAGSS) trainer for Joint Fires integration. The simulator will supplement live field training and live-fly sorties to provide realistic introductory, proficiency, currency, and upgrade training in a simulated battlefield, disaster, or humanitarian relief environment. b. JTAGSS is a continuation of the ASOC simulation trainer initially funded in 2009 and complements the JTC TRS trainer by providing a total air-ground constructive simulation environment for integrated networked training and mission rehearsal capability that will develop TACP/CCT/JTAC and ASOC/Special Operations Forces (SOF) Command and Control (C2) battle staff skills. JTAGSS will provide the ASOC, SOF, and TACP with the vertical and horizontal C2 communications and coordination training and mission rehearsal required for mission effectiveness. There are insufficient exercises and live training events available to meet mandated readiness requirements. The system will include a secure network connection, a constructive simulation environment generator with sharable databases, computer workstations that have synthetic reflex agent applications for each ASOC/SOF crew position to execute the Air Tasking Order. Funds may be used to address emerging and short notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. DMS efforts to include removal of end-of-life software/hardware within simulators systems and move to a modular, common open system architecture that is sustainable and cyber-resilient. Implement requirements and standards defined under the Simulator Common Architecture Requirements and Standards initiative. FY2027 funding will continue development of AI-based Reflex Agent Manager/Role Player and both the development and integration of WARHAWK into JTAGSS Command and Control Trainers to implement the Joint Air Ground Integration Center (JAGIC). Funds may be used to address emerging and short notice Diminishing Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207418F / AFSPECWAR - TACP Operational Systems Development Manufacturing Sources and Material Shortage (DMSMS) issues. DMS efforts to include removal of end-of-life software/hardware within simulators systems and move to a modular, common open system architecture that is sustainable and cyber-resilient. Implement requirements and standards defined under the Simulator Common Architecture Requirements and Standards initiative. In FY2026 funding ($4.108 Million) for BA 07 Project 0207418F was transferred to BA 07 Project 0207457F in order to consolidate special warfare programs. In FY2027, PE 0207457F, (AF Special Warfare (SPECWAR), Project 675234 (TACP Support) efforts were transferred back to PE 0207418F, (AFSPECWAR-TACP), Project 675234, (TACP-Support), in order to better align these efforts. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207420F$$, $$Combat Identification$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 1713000, 1902000, 1914000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207420F"}$$::jsonb, $$Cooperative Combat Identification employs technologies required to rapidly identify friendly platforms. The program develops, integrates and evaluates technologies that provide Air Force platforms with a means of positively identifying an air or surface (maritime) platform as a friendly, via active (or passive reception) cooperative identification capabilities. The development funded by this project ensures availability of a Mode 5 upgrade path for implementing ground and air platforms across the Air Force fleet. As Executive Agent the Department of Defense International AIMSPO has system level interoperability testing and certification responsibilities for the current Mark XIIB system, development and integration of new Identification Friend or Foe (IFF) system capabilities, and development/integration of civil Mode S capabilities into Mark XIIB Identification Friend or Foe equipment. The AIMSPO ensures Identification Friend or Foe equipment/platform functionality in accordance with established standards and ensures total system interoperability to meet Department of Defense/Service mission areas (e.g. Offensive Counter Air, Defensive Counter Air, and Integrated Air and Missile Defense). The goals will be to test and certify the Mark XIIB system, develop and integrate the new Mark XIIB Identification Friend or Foe system capability (Mode 5 Level 2 Broadcast) and also continue the development/integration of civil Mode S capabilities into Mark XIIB Identification Friend or Foe equipment using newly fielded M-code GPS receivers. The Office of the Secretary of Defense and Federal Aviation Administration guidelines required Mode 5 be fully implemented by FY 2020 but many platforms continue to integrate this capability. The Department of Defense (DoD) AIMS Program will ensure those certifications are current on all applicable platforms/ systems and work with both domestic and foreign military sales partners to ensure compliance. The funds also support representation to several military (United States and NATO) and civil (Federal Aviation Administration, International Civil Aviation Organization and Radio Technical Commission for Aeronautics) requirements meetings for Mode 5, Mode S and ADS-B. These important meetings allow the Department of Defense to remain interoperable with our foreign military partners as well as the United States and international civil aviation community. Department of Defense AIMS Program will continue to update the Department of Defense AIMS Mark XIIB Standards, Security Classification Guide, Handbook, and Test Requirements. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207420F / Combat Identification Component Development & Prototypes (ACD&P)$$, NULL, 1727000, 1780000, 1815000, NULL, NULL, 68, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 1844000, 1689000, 1692000, 1692000, 0, 1692000, 1854000, $$Cooperative Combat Identification employs technologies required to rapidly identify friendly platforms. The program develops, integrates and evaluates technologies that provide Air Force platforms with a means of positively identifying an air or surface (maritime) platform as a friendly, via active (or passive reception) cooperative identification capabilities. The development funded by this project ensures availability of a Mode 5 upgrade path for implementing ground and air platforms across the Air Force fleet. As Executive Agent the Department of War International AIMSPO has system level interoperability testing and certification responsibilities for the current Mark XIIB system, development and integration of new Identification Friend or Foe (IFF) system capabilities, and development/integration of civil Mode S capabilities into Mark XIIB Identification Friend or Foe equipment. The AIMSPO ensures Identification Friend or Foe equipment/platform functionality in accordance with established standards and ensures total system interoperability to meet Department of War/Service mission areas (e.g. Offensive Counter Air, Defensive Counter Air, and Integrated Air and Missile Defense). The goals will be to test and certify the Mark XIIB system, develop and integrate the new Mark XIIB Identification Friend or Foe system capability (Mode 5 Level 2 Broadcast) and also continue the development/integration of civil Mode S capabilities into Mark XIIB Identification Friend or Foe equipment using newly fielded M- code GPS receivers. The Office of the Secretary of War and Federal Aviation Administration guidelines required Mode 5 be fully implemented by FY 2020 but many platforms continue to integrate this capability. The Department of War (DoW) AIMS Program will ensure those certifications are current on all applicable platforms/ systems and work with both domestic and foreign military sales partners to ensure compliance. The funds also support representation to several military (United States and NATO) and civil (Federal Aviation Administration, International Civil Aviation Organization and Radio Technical Commission for Aeronautics) requirements meetings for Mode 5, Mode S and ADS-B. These important meetings allow the Department of War to remain interoperable with our foreign military partners as well as the United States and international civil aviation community. Department of War AIMS Program will continue to update the Department of War AIMS Mark XIIB Standards, Security Classification Guide, Handbook, and Test Requirements. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207420F / Combat Identification Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207431F$$, $$Combat Air Intelligence System Activities$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 33601000, 75883000, 25049000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207431F"}$$::jsonb, $$The mission of Combat Air Intelligence Systems (CAIS) is to process, analyze, and disseminate intelligence for air component and unit operations worldwide by providing key intelligence infrastructure and production capabilities for the supported and supporting forces with true backbone type of intelligence support for air operations and air support to joint operations. CAIS is focused on providing the intelligence infrastructure and funding to Air Force Major Commands, Intelligence, Cyber and Space Squadrons, Field Operating Agencies, and subordinate units. Modernizations are required for the CAIS enterprise capabilities, inside and outside AOCs to keep pace with evolving Government Off the Shelf (GOTS) components, integrated Commercial Off the Shelf (COTS) components, Department of Defense (DoD) directives, and changes in the underlying Information Technology (IT) environment, as well as to deliver effective operational capabilities for the user. In Summer of FY20, the decision was made to transition from Middle Tier Acquisition (MTA), Sec 804 Rapid Prototyping/Fielding to the new NDAA FY20 - Software Acquisition Pathway, which is the preferred path for acquisition and development of software-intensive systems. In October 2021, Kessel Run Air Domain was authorized by the Service Acquisition Executive to enter the Software Acquisition Pathway in the Execution Phase. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Targeting and Geospatial Intelligence weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 58.706M (FY2024) was expended for civilian pay expenses in this program element, and in CY (FY2025) 48.512M is forecasted for civilian pay expenses in this program element. Kessel Run is part of the overarching 27431F portfolio. Additional CAIS funding associated with BA04 PE 24731F BPAC 640141. The Air Force requested to Congress a transfer of the remaining FY25 funds (18.733M) to its actual PE AF ISR DI (33010F). This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207431F / Combat Air Intelligence System Activities Operational Systems Development$$, NULL, 35280000, 36314000, 37000000, NULL, NULL, 198, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 25049000, 35646000, 33700000, 33700000, 0, 33700000, 37773000, $$The mission of Combat Air Intelligence Systems (CAIS) is to process, analyze, and disseminate full spectrum intelligence for air component and unit operations worldwide by providing key intelligence infrastructure, access, and production capabilities for the supported and supporting forces for air, space, and cyber operations to joint force operations. CAIS is focused on providing the intelligence infrastructure, systems, and training to Air Force Major Commands, Intelligence, Cyber and Space Squadrons, Field Operating Agencies, and subordinate units. Modernization is required for CAIS enterprise capabilities, to keep pace with evolving Government Off the Shelf (GOTS) components, integrated Commercial Off the Shelf (COTS) components, Department of War (DoW) directives, and changes in the underlying Information Technology (IT) environment. The objective is to continuously deliver effective operational capabilities for the user. In Summer of FY20, the decision was made to transition from Middle Tier Acquisition (MTA), Sec 804 Rapid Prototyping/Fielding to the new NDAA FY20 - Software Acquisition Pathway, which is the preferred path for acquisition and development of software-intensive systems. In October 2021, Kessel Run Air Domain was authorized by the Service Acquisition Executive to enter the Software Acquisition Pathway in the Execution Phase. Kessel Run is part of the overarching 0207431F portfolio. *PY (FY2025) AF JWICS/AF SCI PE:0305249F was established. As part of establishment USAF requested the transfer of 7.693M from AF JWICS/AF SCI (0305249F) to CAIS (0207431F) based on the re-distribution of program responsibilities for Unit-level continuous development. *CAIS funding associated with BA04 PE 0204731F BPAC 640141. The Air Force requested to Congress a transfer of the remaining FY25 funds (18.733M) to its actual PE AF ISR DI (0303010F). Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207431F / Combat Air Intelligence System Activities Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207438F$$, $$Theater Battle Management (TBM) C4I$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 6787000, 6231000, 4401000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207438F"}$$::jsonb, $$This budget line funds joint partner requirements of the Air Operations Center (AOC) Weapon System Modification effort. Applications Development efforts deliver capabilities identified in the 2013 Joint Command and Control Capability Development Document (CDD) and are executed under the Development, Security, and Operations (DevSecOps) Software Acquisition Pathway Program. Applications Development provides worldwide operational capabilities for Air Force Command and Control (C2) in support of DoD, Coalition Partners, and other government agencies. These efforts focus on support to the Joint Forces Air Component Commander (JFACC), who provides air, space and cyber support to other Air FOrce and Joint Services C2 systems. This program is dependent on the All Domain Common Platform (ADCP), which provides an extensible cloud-based infrastructure and platform as a service (IaaS/PaaS) hosting platform built to deliver highly resilient mission applications and data to Airmen deployed around the world. In FY 2026, Applications Development will focus on providing necessary software capabilities to build, disseminate, and execute the Master Air Attack Plan (MAAP). Applications Development also provides an Airspace Management tool used for building airspaces, evaluating requests, and instantaneously generating the Airspace Control Order (ACO). These efforts deliver modern software for inclusion to the AOC Weapon System modifications program to replace the Master Air Attack Plan- Toolkit (MAAPTK) and components of Theater Battle Management Core System - Force Level (TBMCS FL). Efforts within this PE align with USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (0207410F), All Domain Common Platform (0303248F), C2IMERA (0305015F/0305836F) and ABMS (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. The FY 2026 request was reduced by -$0.015 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funding would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 0.000 million is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207438F / Theater Battle Management (TBM) C4I Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 5782000, 5893000, 6005000, NULL, NULL, 199, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 4249000, 6698000, 7014000, 7014000, 0, 7014000, 6125000, $$This budget line funds joint partner requirements of the Air Operations Center (AOC) Weapon System Modification effort. Applications Development efforts deliver capabilities identified in the 2013 Joint Command and Control Capability Development Document (CDD) and are executed as a Software Acquisition Pathway program. Applications Development provides worldwide operational capabilities for Air Force Command and Control (C2) in support of DoW, Coalition Partners, and other government agencies. These efforts focus on support to the Joint Forces Air Component Commander (JFACC), who provides air, space and cyber support to other Air Force and Joint Services C2 systems. This program is dependent on the All Domain Common Platform (ADCP), which provides an extensible cloud-based infrastructure and platform as a service (IaaS/PaaS) hosting platform built to deliver highly resilient mission applications and data to Airmen deployed around the world. In FY 2027, Applications Development will focus on providing necessary software capabilities to build, disseminate, and execute the Master Air Attack Plan (MAAP). Applications Development also provides an Airspace Management tool used for building airspaces, evaluating requests, and instantaneously generating the Airspace Control Order (ACO). These efforts deliver modern software for inclusion to the AOC Weapon System modifications program to replace the Master Air Attack Plan- Toolkit (MAAPTK) and components of Theater Battle Management Core System - Force Level (TBMCS FL). Efforts within this program align with and depend upon USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (PE 0207410F), All Domain Common Platform (0303248F), Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F). Advanced Battle Management System (ABMS) (0604003F) and Flight Ops (PE 0207461F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities necessary for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funding would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2025 0.000 million was expended for civilian pay expenses in this program element, and in FY 2026 0.000 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207438F / Theater Battle Management (TBM) C4I Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1611_L037$$, $$Ship to Shore Connector$$, $$proc_navy_1611_ba5$$, $$mc$$, 2026, 0, 0, 18000000, NULL, $${"ba": "ba5", "ingest": "v18", "source": "p1_fy27", "line_no": "30", "appr_code": "1611", "fy26_v179": {"disc_K": 141500, "li_num": 32, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/SCN_Book.txt"}, "title_raw": "Next Generation Logistics Ship", "fy27_total_K": 0}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 2884197000, 10521273000, NULL, NULL, NULL, FALSE, 528039000, 335480000, 0, NULL, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/SCN_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207439F$$, $$Electromagnetic Warfare Int Reprog (EWIR)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 60072000, 10007000, 13577000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207439F"}$$::jsonb, $$Electromagnetic Warfare Integrated Reprogramming (EWIR) postures for the future of reprogramming by reducing risk through repairing and rebuilding existing Electronic Warfare (EW) programs and modernizing the Electromagnetic Spectrum and Electronic Warfare enterprise. This program creates new EW/Electromagnetic Spectrum Operations (EMSO) capabilities and conducts prototyping activities on emerging and enabling technologies to inform future EMSO capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F,0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0M was expended for civilian pay expenses in this program element, and in FY25 $0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207439F / Electromagnetic Warfare Int Reprog (EWIR) Operational Systems Development$$, NULL, 74308000, 79044000, 83427000, NULL, NULL, 200, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 13081000, 38639000, 73523000, 73523000, 0, 73523000, 84903000, $$Electromagnetic Warfare Integrated Reprogramming (EWIR) postures for the future of reprogramming by reducing risk through repairing and rebuilding existing Electronic Warfare (EW) programs and modernizing the Electromagnetic Spectrum and Electronic Warfare enterprise. This program creates new EW/Electromagnetic Spectrum Operations (EMSO) capabilities and conducts prototyping activities on emerging and enabling technologies to inform future EMSO capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements, but not limited to, 0605827F, 0605828F, 0605829F,0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207439F / Electromagnetic Warfare Int Reprog (EWIR) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207444F$$, $$Tactical Air Control Party-Mod$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 24093000, 12171000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207444F"}$$::jsonb, $$This budget line funds the Air Force Special Warfare (AFSPECWAR) Tactical Air Control Party (TACP) Weapon System which executes precision strike, integration, and all-domain command and control missions to meet Air Force power projection for the joint force's expanded maneuver. TACP Airmen are part of the Air Force's premier ground combat units that are highly maneuverable and scalable. They execute ground-based command and control functions and seamlessly integrate kinetic and non-kinetic effects across the entire spectrum of conflict. They do this by providing joint force air component commanders with a highly trained force that operates at the tactical edge in highly contested environments and complicates enemy decision-making processes. Additionally, TACP Airmen conduct precision strike and integration operations at all echelons of maneuver warfare, from dismounted operations on the forward edge of the battlefield to tactical command posts; TACP Airmen plan, request, advise, and control joint fires and air power to meet multinational operations and supported Combatant commander's objectives. The purpose of Tactical Air Control Party - Modernization (TACP-M) programs are to provide TACPs with modernized voice, data, and video communications, including diverse waveforms and software, advanced targeting equipment, and enhanced battlefield awareness/management capabilities across all domains. Improved targeting and data communications capabilities improve kill chain timelines, defeat adversary systems through opening and closing kill webs, extended critical networks to the forward edge, and when required reduce the probability of fratricide or collateral damage. TACP-M programs support include addressing frequent TACP combat deployments that sometimes lead users to change equipment procurement priorities to support urgent operational needs and respond to evolving threat environments. TACP-M programs jointly develop and procure software and hardware with other AFSPECWAR programs to consolidate requirements that are common across the AFSPECWAR enterprise. This teaming arrangement helps standardize equipment, improves efficiency by consolidating acquisition efforts, enabling a common baseline, and reducing overall costs. TACP-M programs provide and modernize capabilities in the following five major areas: (1) Air Support Operations Center (ASOC)/Tactical Operational Center (TOC) systems; also known as TACP Command and Control and communications (C3) (used in static, mobile and maneuverable operations centers), (2) Vehicle Mounted Systems (used in tactical vehicles) and for On-The-Move and At-The-Halt operations, (3) Dismounted Systems (used by TACPs in wearable configurations), (4) Joint all-Domain Command and Control (JADC2) software, and (5) Support distributed and resilient ground-based command and control teams that leverage airpower within the Theater Air Control System. To ensure survivable and effective C3 capabilities, TACP needs to develop equipment capable of sensing (passive and active) enemy activity within the electromagnetic environment and deliver non-kinetic effects through ground-based jamming Electro-Magnetic Spectrum (EMS) awareness, develop and integrate and a Wide Area Infrared System (WAIS) which will provide a 24/7 360 degree infrared imaging capability covering critical areas utilizing artificial intelligence for threat detection, High Capacity Beyond Line of Sight (BLOS) Baseband Backhaul (BB/BH) and other communications support equipment, advanced Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207444F / Tactical Air Control Party-Mod Operational Systems Development software defined waveforms (Low Probability of Intercept/Low Probability of Detection (LPI/LPD)); network architecture to move data across elements & echelons and Small Unmanned Aircraft System (sUAS) for force protection and network extension. FY26 funding will allow for the continued development of TACP Mission Software, WARHAWK and Special Warfare Assault Kit (SWAK)/Tactical Assault Kit (TAK) software Tactical Laser Communications capabilities, other JADC2 network enabling software applications and suites, EMS and BLOS BB/BH. The CASS 1.4.5 program (to be renamed to "TACP Mission Software”) includes the WARHAWK and SWAK software programs modernizing the software used in Command, Control, Communications and Cybersecurity (C4) processing systems for ASOC/TOC (TACP C2) operations, as well as vehicle Mounted and Dismounted operations. The software will allow enhanced capability and seamless communication between the operations centers and the TACP military units in high combat areas. The Tactical Laser Communications project includes the development of a Portable Optical Communication Terminal prototype, providing a Low Probability of Intercept/Low Probability of Detection, highly anti-jammable communication capability. The Tactical Laser Communications project also includes the development of supporting Tactical networks, enabling global access into the Department of Defense information Network, ensuring diverse and resilient pathways for data transmission for TACP military units in remote locations. TACP-M funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs such as but not limited to Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs. Items requested in FY2026 as identified in this Exhibit are representative but not limited to the items to be developed. Items developed during execution may change based on critical equipment needed to support current Air Force mission requirements. FY26 funding ($12.038M) for BA 07 0207444F was transferred to BA 07 Project 0207457F. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207444F / Tactical Air Control Party-Mod Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 201, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 11816000, 0, 0, 0, 0, 0, 0, $$This budget line funds the Air Force Special Warfare (AFSPECWAR) Tactical Air Control Party (TACP) Weapon System which executes precision strike, integration, and all-domain command and control missions to meet Air Force power projection for the joint force's expanded maneuver. TACP Airmen are part of the Air Force's premier ground combat units that are highly maneuverable and scalable. They execute ground-based command and control functions and seamlessly integrate kinetic and non-kinetic effects across the entire spectrum of conflict. They do this by providing joint force air component commanders with a highly trained force that operates at the tactical edge in highly contested environments and complicates enemy decision-making processes. Additionally, TACP Airmen conduct precision strike and integration operations at all echelons of maneuver warfare, from dismounted operations on the forward edge of the battlefield to tactical command posts; TACP Airmen plan, request, advise, and control joint fires and air power to meet multinational operations and supported Combatant commander's objectives. The purpose of Tactical Air Control Party - Modernization (TACP-M) programs are to provide TACPs with modernized voice, data, and video communications, including diverse waveforms and software, advanced targeting equipment, and enhanced battlefield awareness/management capabilities across all domains. Improved targeting and data communications capabilities improve kill chain timelines, defeat adversary systems through opening and closing kill webs, extended critical networks to the forward edge, and when required reduce the probability of fratricide or collateral damage. TACP-M programs support include addressing frequent TACP combat deployments that sometimes lead users to change equipment procurement priorities to support urgent operational needs and respond to evolving threat environments. TACP-M programs jointly develop and procure software and hardware with other AFSPECWAR programs to consolidate requirements that are common across the AFSPECWAR enterprise. This teaming arrangement helps standardize equipment, improves efficiency by consolidating acquisition efforts, enabling a common baseline, and reducing overall costs. TACP-M programs provide and modernize capabilities in the following five major areas: (1) Air Support Operations Center (ASOC)/Tactical Operational Center (TOC) systems; also known as TACP Command and Control and communications (C3) (used in static, mobile and maneuverable operations centers), (2) Vehicle Mounted Systems (used in tactical vehicles) and for On-The-Move and At-The-Halt operations, (3) Dismounted Systems (used by TACPs in wearable configurations), (4) Joint all-Domain Command and Control (JADC2) software, and (5) Support distributed and resilient ground-based command and control teams that leverage airpower within the Theater Air Control System. To ensure survivable and effective C3 capabilities, TACP needs to develop equipment capable of sensing (passive and active) enemy activity within the electromagnetic environment and deliver non-kinetic effects through ground-based jamming Electro-Magnetic Spectrum (EMS) awareness, develop and integrate and a Wide Area Infrared System (WAIS) which will provide a 24/7 360 degree infrared imaging capability covering critical areas utilizing artificial intelligence for threat detection, High Capacity Beyond Line of Sight (BLOS) Baseband Backhaul (BB/BH) and other communications support equipment, advanced Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207444F / Tactical Air Control Party-Mod Operational Systems Development software defined waveforms (Low Probability of Intercept/Low Probability of Detection (LPI/LPD)); network architecture to move data across elements & echelons and Small Unmanned Aircraft System (sUAS) for force protection and network extension. FY2027 funding will allow for the continued development of TACP Mission Software, WARHAWK and Special Warfare Assault Kit (SWAK)/Tactical Assault Kit (TAK) software Tactical Laser Communications capabilities, other JADC2 network enabling software applications and suites, EMS and BLOS BB/BH. Mission Software includes the WARHAWK and SWAK software programs modernizing the software used in Command, Control, Communications and Cybersecurity (C4) processing systems for ASOC/TOC (TACP C2) operations, as well as vehicle Mounted and Dismounted operations. The software will allow enhanced capability and seamless communication between the operations centers and the TACP military units in high combat areas. The Tactical Laser Communications project includes the development of a Portable Optical Communication Terminal prototype, providing a Low Probability of Intercept/Low Probability of Detection, highly anti-jammable communication capability. The Tactical Laser Communications project also includes the development of supporting Tactical networks, enabling global access into the Department of Defense information Network, ensuring diverse and resilient pathways for data transmission for TACP military units in remote locations. TACP-M funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs such as but not limited to Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs. Items requested in FY2026 as identified in this Exhibit are representative but not limited to the items to be developed. Items developed during execution may change based on critical equipment needed to support current Air Force mission requirements. FY2026 funding ($12.038M) and FY27 funding ($12.460) for BA 07 0207444F was transferred to BA 07 Project 0207457F. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 0.000M was expended for civilian pay expenses in this program element, and in FY 2026 0.000M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207444F / Tactical Air Control Party-Mod Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207448F$$, $$C2ISR Tactical Data Link$$, $$rdte_af_ba4$$, $$aflcmc_hb$$, 2026, 0, 0, 3500000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207448F"}$$::jsonb, $$Tactical Data Links (TDL), as a subset of the broader airborne network, are used in a combat environment to exchange information such as messages, data, radar tracks, target information, platform status, imagery, and command assignments. TDLs provide interoperability, local and global connectivity, and situational awareness to the user when operating under rapidly changing operational conditions. TDLs provide a jam-resistant; secure digital data transfer network capability with new and standardized waveforms and data formats allowing Line-of-Sight (LOS) and Beyond-Line- of-Sight (BLOS) intra- and inter-flight communications. TDLs increase mission effectiveness, provide positive identification of aircraft in the network, correlate on and off-board sensor data sharing, target, and threat information, and provide the data link to accomplish time critical targeting and other mission update functions. TDLs are used by all service theater Command and Control (C2) elements, weapons platforms, and sensors. This program provides critical capability and enhancements to the airborne network by supporting common development, integration and interoperability among ground and C2 platforms and responds to quick reaction capability integration and demonstration The E-7 program replaces the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the end of its service life, and costly to maintain. The E-7 will serve as the USAF's principal airborne platform for airborne command and control and airborne moving target indicator, providing a reliable, persistent critical node in the long range kill chain for the Joint Force Air Component Commander (JFACC). Project E-7 funds E-7A advanced communications data studies (to include but not limited to hybrid SATCOM, Internet Protocol Beyond Line-of-Sight (IP-BLOS), and datalink), analysis, and further requirements definition, and software and hardware development and testing. These advanced communication capabilities not in the E-7A Rapid Prototyping Baseline are required to increase E-7A communications resiliency, enabling seamless connectivity with the DAF Battle Network and ensuring that the platform can connect to various SATCOM networks and datalinks should one or more SATCOM networks or datalinks become unavailable. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, or 0606398F. In FY 2024, $0.000M was expended for civilian pay expenses in this program element. In FY 2025, $0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207448F / C2ISR Tactical Data Link Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 0, 0, 0, NULL, NULL, 70, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 3383000, 0, 0, 0, 0, 0, 0, $$Tactical Data Links (TDLs), as a subset of the broader airborne network, are used in a combat environment to exchange information such as messages, data, radar tracks, target information, platform status, imagery, and command assignments. TDLs provide interoperability, local and global connectivity, and situational awareness to the user when operating under rapidly changing operational conditions. TDLs provide a jam-resistant; secure digital data transfer network capability with new and standardized waveforms and data formats allowing Line-of-Sight (LOS) and Beyond-Line-of-Sight (BLOS) intra-and inter-flight communications. TDLs increase mission effectiveness, provide positive identification of aircraft in the network, correlate on and off-board sensor data sharing, target, and threat information, and provide the data link to accomplish time critical targeting and other mission update functions. TDLs are used by all service theater Command and Control (C2) elements, weapons platforms, and sensors. This program provided critical capability and enhancements to the airborne network by supporting common development, integration and interoperability among ground and C2 platforms. The E-7A program was created to replace the unsustainable E-3 Airborne Warning and Control System (AWACS). The E-3 AWACS, first fielded in the 1970s, is at the end of its service life, and costly to maintain. The E-7A was intended to serve as the USAF's principal airborne platform for airborne command and control and airborne moving target indicator, providing a reliable, persistent critical node in the long range kill chain for the Joint Force Air Component Commander (JFACC). This project funded E-7A advanced communications studies (to include but not limited to hybrid SATCOM, Internet Protocol Beyond Line-of-Sight (IP-BLOS), and datalink, analysis, further requirements definition, and software and hardware development and testing. These advanced communication capabilities that may ultimately be used on the E-7A or E-3 are required to increase airborne C2 communications resiliency, enabling seamless connectivity with the DAF Battle Network and ensuring that either platform can connect to various SATCOM networks and datalinks should one or more SATCOM networks or datalinks become unavailable. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F In FY 2026, 0.000 was expended for civilian pay expenses in this program element. In FY 2027, 0.000 is forecasted for civilian pay expenses in this program element. This program does not have funding in FY27. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207448F / C2ISR Tactical Data Link Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L042$$, $$Submarine Acoustic Warfare System$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 0, 7262000, 7402000, NULL, $${"page": 96, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "42", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 38", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 0, "p1_line_num": 38, "fy27_total_K": 0}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 51514000, 56482000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
