INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604201F_ba5$$, $$PNT Resiliency, Mods, and Improvements$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 125663000, 171555000, 214900000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604201F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604212M$$, $$Other Helo Development$$, $$rdte_navy_ba5$$, $$dw_osd$$, 2026, 0, 53360000, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 32, "original_pe": "0604212M", "page_header": "Department of the Navy"}$$::jsonb, $$This Program Element includes funding for the development of USMC Vertical Take-Off and Landing (VTOL) Family of Systems (FoS) capability. VTOL FoS is a USMC initiative to address vertical lift capability requirements and determine feasible and affordable solutions in support of the Warfighter. This PE will include development and prototype efforts developed to progress high-risk technology areas in support of future Marine capabilities.$$, NULL, NULL, NULL, NULL, NULL, NULL, 110, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207452F$$, $$DCAPES$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 8507000, 6686000, 8431000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207452F"}$$::jsonb, $$Deliberate and Crisis Action Planning and Execution System (DCAPES) is the Department of the Air Force (DAF) classified Command and Control (C2) National Security System (NSS) used to implement the Air Force Force Generation (AFFORGEN) process and project forces (includes weapon systems, logistics, and personnel). It enables the DAF to posture mission ready and equipped forces (organized in effects-based operational capability packages) to deliver air, space, and cyberspace capabilities to Joint commanders worldwide. DCAPES supports joint, combined, and DAF military operations worldwide. DCAPES Continuous Development defines specific requirements annually through an approved Capability Needs Statement (CNS) and also continues to address technical debt and engineering updates as a persistent requirement throughout the program. FY 2026 funding will be used to continue development efforts include creating a capability for on-demand updates to the Operation Plan (OPLAN) detail which reduces the corrective action time from days to minutes if the data is out of sync or deleted, interfacing with Joint Capabilities Requirements Manager (JCRM) to track when forces are officially ordered to a Combatant Command (COCOM), creating an unclassified server in the production environment for personnel accountability in areas where classified environments are not available, enhancing the Unit Type Availability (UTA) module with Log Assessment for reporting equipment shortfalls, Database Export for printable AFFORGEN dashboards, and Mass Edit for direct dashboard editing of AFFORGEN Force Elements. The FY 2026 funding also supports the development of the system by continuing to enhance the functionality of the system: crucial in supporting war planning. DCAPES completed Increment 2B full deployment in Q1 FY 2025 and transitioned to the Software Acquisition Pathway (SWP). DCAPES funding will be executed against capabilities packaged into agile development projects for multiple releases based on warfighter priorities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0207452F / DCAPES Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 5453000, 5560000, 5665000, NULL, NULL, 202, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 8154000, 8390000, 5254000, 5254000, 0, 5254000, 5780000, $$Deliberate and Crisis Action Planning and Execution System (DCAPES) is the Department of the Air Force (DAF) classified Command and Control (C2) National Security System (NSS) used to implement the Air Force Force Generation (AFFORGEN) process and project forces (includes weapon systems, logistics, and personnel). It enables the DAF to posture mission ready and equipped forces (organized in effects-based operational capability packages) to deliver air, space, and cyberspace capabilities to Joint commanders worldwide. DCAPES supports joint, combined, and DAF military operations worldwide. FY 2027 funding will be used to support the continued development of capabilities within the DCAPES system. These efforts will enhance the Shortfall Management Module which enables units to report and route manpower deficiencies to appropriate command level for resolution. The funding will also be used to develop the Manpower Analysis Tool used to analyze and inform personnel planning and prevent future shortfalls. The FY 2027 funding continues to enhance the functionality of the system, crucial in supporting war planning, and will be executed against capabilities packaged into agile development projects for multiple releases based on warfighter priorities. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207452F / DCAPES Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207455F$$, $$Three Dimensional Long-Range Radar (3DELRR)$$, $$rdte_af_ba4$$, $$afrl_ry$$, 2026, 17344000, 13875000, 8100000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207455F"}$$::jsonb, $$The Three-Dimensional Expeditionary Long-Range Radar (3DELRR) program develops the AN/TPY-4 system which is the designated replacement for the AN/TPS-75 radar. The AN/TPS-75 is an outdated and unsustainable system which was first fielded in the early 1970s. The 3DELRR system will be the United States Air Force's (USAF's) principal long-range, ground-based sensor for detecting, identifying, tracking, and reporting aerial tracks for the Joint Force Air Component Commander (JFACC). The 3DELRR system consists of the AN/TPY-4 radar and associated ground support equipment which includes Prime Movers, Generators, and other smaller mission support items. When fielded, the 3DELRR system will provide multiple benefits and increased capabilities to the USAF and the Joint Services, including: the ability to detect and track modern and emerging highly maneuverable, small radar cross-section airborne target; greater battlefield and battlespace awareness through a precise, real-time air picture of sufficient quality to control individual aircraft under a wide range of environmental and operational conditions; and increased reliability, operational availability, maintainability, transportability, survivability, and sustainability. FY 2026 funding will continue system capability development, which include development of electronic protection (EP) techniques, continued software fixes and Non- Recurring Engineering (NRE) costs. Additionally, FY 2026 funding will support continued test and evaluation activity, to include Initial Operational Test and Evaluation (IOT&E) of the system. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2025 $0.12 million was expended for civilian pay expenses in this program element, and in FY 2026 $0.17 million is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207455F / Three Dimensional Long-Range Radar (3DELRR) Component Development & Prototypes (ACD&P)$$, NULL, 12741000, 11461000, 0, NULL, NULL, 71, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 7809000, 12677000, 22335000, 22335000, 0, 22335000, 0, $$The Three-Dimensional Expeditionary Long-Range Radar (3DELRR) program develops the AN/TPY-4 radar system which is the designated replacement for the AN/ TPS-75 radar. The AN/TPS-75 is an outdated and unsustainable system which was first fielded in the early 1970s. The 3DELRR system will be the United States Air Force's (USAF's) principal long-range, ground-based sensor for detecting, identifying, tracking, and reporting aerial tracks for the Joint Force Air Component Commander (JFACC). The 3DELRR system consists of the AN/TPY-4 radar and associated ground support equipment which includes Prime Movers, Generators, and other smaller mission support items. The 3DELRR system will provide multiple benefits and increased capabilities to the USAF and the Joint Services, including: the ability to detect and track modern and emerging highly maneuverable, small radar cross-section airborne targets; greater battlefield and battlespace awareness through a precise, real-time air picture of sufficient quality to control individual aircraft under a wide range of environmental and operational conditions; and increased reliability, operational availability, maintainability, transportability, survivability, and sustainability. FY 2027 funding will continue system capability development, which includes continued work on electronic protection (EP) techniques, continued software fixes and Non-Recurring Engineering (NRE) costs. Additionally, FY 2027 funding will support continued test and evaluation activity, to include Initial Operational Test and Evaluation (IOT&E) of the system and Operational Utility Evaluation Test preparation. FY2027 funding will support development of enhanced capabilities of the AN/ TPY-4 radar. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207455F / Three Dimensional Long-Range Radar (3DELRR) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207457F$$, $$Air Force Special Warfare (SPECWAR)$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 27526000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207457F"}$$::jsonb, $$Air Force Special Warfare (AFSPECWAR) includes Guardian Angel (GA), Special Tactics/Combat Control (ST/CC), Tactical Air Control Party-Modernization (TACP-M) and Air Force Special Warfare-TACP (AFSPECWAR-TACP) programs that develop, integrate, train and test equipment and systems to provide TACPs, GA airmen and ST/CC airmen capabilities to accomplish unique and challenging missions. All three are human based weapons systems. AFSPECWAR Airmen execute seven Mission Essential Tasks: -Gain access to allies, partners, and terrain for Joint All Domain Operations -Conduct reconnaissance and surveillance -Provide resilient Command and Control forward -Execute Forward Airfield Operations -Accomplish cyberspace and electromagnetic spectrum operations (CO/EMSO) -Perform Personnel Recovery and Reconstitution -Integrate to deliver joint fires and effects A. Guardian Angel (GA) is a Family of Systems (FoS) based in both human and equipment capabilities formulated to execute Air Force Personnel Recovery (PR) across the full spectrum of military operations. The GA FoS is employed by three distinct Air Force specialties: Pararescue men (PJ), Combat Rescue Officer (CRO), and Survival, Evasion, Resistance, Escape (SERE) and is comprised of nine critical mission areas: Precision Aerial Insertion, Information Management, Force Application, Visual Augmentation, Maritime Recovery, Ground Mobility, Technical Rescue, Medical, and SERE. In order to stay aligned with with OSD Focus Area Command and Control (C2), logistics mobility (land/water), FY2026 funding will be used to obtain significant improvements in operational capability and develop items within the GA FoS to include but not limited to: Maritime Recovery (open ocean boat ), Ground Mobility, Technical Recovery, Precision Aerial Insertion (cargo & personnel parachutes), Medical (Simulators), Information Management, SERE, Visual Augmentation (night vision, augmented reality) and Force Protection. The GA weapon system development/Innovation activities also include studies, analysis, requirements development Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207457F / Air Force Special Warfare (SPECWAR) Operational Systems Development and developmental testing to support both current and future program planning and execution, quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funding will deliver enhanced capability for the dismounted GA Operators in terms of dramatic weight reduction, standardization of items across units, and increased mission effectiveness across the conflict spectrum.$$, NULL, 18434000, 13882000, 6162000, NULL, NULL, 203, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 0, 27149000, 24423000, 24423000, 0, 24423000, 7826000, $$Air Force Special Warfare (AFSPECWAR) includes Guardian Angel (GA), Special Tactics/Combat Control (ST/CC), Tactical Air Control Party-Modernization (TACP-M) and Air Force Special Warfare-TACP (AFSPECWAR-TACP) programs that develop, integrate, train and test equipment and systems to provide TACPs, GA airmen and ST/CC airmen capabilities to accomplish unique and challenging missions. All three are human based weapons systems. AFSPECWAR Airmen execute seven Mission Essential Tasks: -Gain access to allies, partners, and terrain for Joint All Domain Operations -Conduct reconnaissance and surveillance -Provide resilient Command and Control forward -Execute Forward Airfield Operations -Accomplish cyberspace and electromagnetic spectrum operations (CO/EMSO) -Perform Personnel Recovery and Reconstitution -Integrate to deliver joint fires and effects A. Guardian Angel (GA) is a Family of Systems (FoS) based in both human and equipment capabilities formulated to execute Air Force Personnel Recovery (PR) across the full spectrum of military operations. The GA FoS is employed by three distinct Air Force specialties: Pararescue men (PJ), Combat Rescue Officer (CRO), and Survival, Evasion, Resistance, Escape (SERE) and is comprised of nine critical mission areas: Precision Aerial Insertion, Information Management, Force Application, Visual Augmentation, Maritime Recovery, Ground Mobility, Technical Rescue, Medical, and SERE. In order to stay aligned with with the Department of War Focus Area Command and Control (C2), logistics mobility (land/water), FY2027 funding will be used to obtain significant improvements in operational capability and develop items within the GA FoS to include but not limited to: Maritime Recovery (open ocean boat ), Ground Mobility, Technical Recovery, Precision Aerial Insertion (cargo & personnel parachutes), Medical (Simulators), Information Management, SERE, Visual Augmentation (night vision, augmented reality) and Force Protection. The GA weapon system development/Innovation activities also include studies, analysis, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207457F / Air Force Special Warfare (SPECWAR) Operational Systems Development requirements development and developmental testing to support both current and future program planning and execution, quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funding will deliver enhanced capability for the dismounted GA Operators in terms of dramatic weight reduction, standardization of items across units, and increased mission effectiveness across the conflict spectrum. Items requested in FY2027 as identified in this Exhibit are representative but not limited to the items to be developed. Items developed during execution may change based on critical equipment needed to support current Air Force mission requirements. Due to the rapidly changing threat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current slated and emerging requirements for operational units.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207521F$$, $$Air Force Calibration Programs$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 2273000, 2172000, 2223000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207521F"}$$::jsonb, $$This program develops, tests, and evaluates national and Air Force measurement standards (hardware) and calibration equipment in support of all Air Force programs and activities, including Precision Measurement Equipment Laboratories (PMELs) worldwide. Metrology research and development provides technology to support systems in all phases of development and acquisition, as well as Air Force R&D laboratories, test ranges, ground test facilities, and operational weapons systems support. Rapidly changing technology requires continuing research and development of measurement standards and calibration equipment to ensure modern weapon systems meet Air Force readiness objectives. This program addresses all metrology disciplines and includes the technology areas of laser, infrared, microwave, millimeter wave, optical, physical, mechanical, electrical, electronic, and ionizing radiation measurements. Metrology is a technical discipline devoted to the science of measurements and to the study and improvement of measurement technology. Measurements are the foundation of military system development, quality assurance, hardware conformance testing and system readiness tests. The integrity of these tests is assured through calibration and traceability assurance schemes. The capability to measure and calibrate must parallel the emergence of new technology, new ranges, and new capabilities of military systems. Lack of new measurement capability impedes or blocks the successful exploitation of new technologies, especially in the movement from development laboratory to production to deployment. R&D efforts are essential within the DoD to pace these requirements, otherwise, these same new systems will suffer time delays, excessive cost, and increased risk due to unreliable test results in all phases of development, production, deployment and operation. This program element may include necessary civilian pay expenses required to manage, execute and deliver Air Force Calibration capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605826F, 0605827F, 0605828F, 0605829F, 0605830F, 0605831F, 0605832F, 0605898F, and 0605833F. In FY24 $0K was expended for civilian pay expenses in this program element and in FY25 $175K is forecasted for civilian pay expenses in this program element. Program is managed by Air Force Materiel Command, Agile Combat Support Directorate, Air Force Metrology Division (WNM). This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207521F / Air Force Calibration Programs Operational Systems Development$$, NULL, 2300000, 2344000, 2388000, NULL, NULL, 204, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 2213000, 2242000, 2220000, 2220000, 0, 2220000, 2437000, $$This program develops, tests, and evaluates national and Air Force measurement standards (hardware) and calibration equipment in support of all Air Force programs and activities, including Precision Measurement Equipment Laboratories (PMELs) worldwide. Metrology research and development provides technology to support systems in all phases of development and acquisition, as well as Air Force R&D laboratories, test ranges, ground test facilities, and operational weapons systems support. Rapidly changing technology requires continuing research and development of measurement standards and calibration equipment to ensure modern weapon systems meet Air Force readiness objectives. This program addresses all metrology disciplines and includes the technology areas of laser, infrared, microwave, millimeter wave, optical, physical, mechanical, electrical, electronic, and ionizing radiation measurements. Metrology is a technical discipline devoted to the science of measurements and to the study and improvement of measurement technology. Measurements are the foundation of military system development, quality assurance, hardware conformance testing and system readiness tests. The integrity of these tests is assured through calibration and traceability assurance schemes. The capability to measure and calibrate must parallel the emergence of new technology, new ranges, and new capabilities of military systems. Lack of new measurement capability impedes or blocks the successful exploitation of new technologies, especially in the movement from development laboratory to production to deployment. R&D efforts are essential within the DoD to pace these requirements, otherwise, these same new systems will suffer time delays, excessive cost, and increased risk due to unreliable test results in all phases of development, production, deployment and operation. In direct support of SecDefs direction to increase readiness across the DoD, efforts within this PEC will be prioritized based on the National Defense Authorization Act (NDAA), USAF Force Design, Agile Combat Employment (ACE), and the Defense Planning Guide (DPG) These efforts will support work and collaboration efforts across the Combat Readiness Directorate in PE's 78051F, 71212F, 72833F, 64706F, 65827F, 22834F, 52834F, 28031F, 41135F and 27521F) -- to increase readiness across the Air Force Enterprise This program element may include necessary civilian pay expenses required to manage, execute and deliver Air Force Calibration capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605826F, 0605827F, 0605828F, 0605829F, 0605830F, 0605831F, 0605832F, 0605898F, and 0605833F. In FY24 0K was expended for civilian pay expenses in this program element and in FY25 175K is forecasted for civilian pay expenses in this program element. Program is managed by Air Force Materiel Command, Agile Combat Support Directorate, Air Force Metrology Division (ROM). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207521F / Air Force Calibration Programs Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207522F$$, $$Airbase Air Defense Systems (ABADS)$$, $$rdte_af_ba4$$, $$ssc_bmcs$$, 2026, 30785000, 67182000, 17273000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207522F"}$$::jsonb, $$The Airbase Air Defense Systems (ABADS) program element is the principal Air Force (AF) program to provide the ability to detect, track, identify, and defeat airborne threats to missions and assets. These threats include small-unmanned aircraft systems (sUAS), Rockets, Artillery and Mortars (RAM), and cruise missiles. These two efforts (Missile Defense (MD) and Counter-sUAS (C-sUAS)) aim to protect personnel, assets, and infrastructure vital to supporting the national security strategy. ABADS MD is designed as a configurable combination of Commercial Off the Shelf (COTS)/Government Off the Shelf (GOTS) sensor and Non-Kinetic Effector (NKE) technologies integrated with tailored Battle Management Command and Control (BMC2) subsystem that leverages GOTS products and Advanced Battle Management System (ABMS) Digital Infrastructure to provide adaptive, resilient, and dedicated air defense capability. The ABADS MD system is designed to operate independently or combine with other local and distributed capabilities to form a multi-layered defense-in-depth, improving airbase defense and airbase resiliency. ABADS MD FY2026 funding will support development efforts to operationalize the NKE following prototype transition from AFRL. Funding will also support and maintain a Government Development Security and Operations (DevSecOps) software pipeline, supporting software updates and prioritized capability upgrades. The Government DevSecOps pipeline will also support further alignment with the ABMS portfolio (Distributed Battle Management Node, Digital Infrastructure, and Cloud Based Command and Control). FY2026 funding also supports Director, Operational Test and Evaluation (DOT&E) oversight required test activities. The FY 2026 request was reduced by 0.015 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” The FY 2026 request for ABADS MD includes 5,041 thousand of discretionary and 15,000 thousand of mandatory (reconciliation) for a total of 20,041 thousand. The mandatory funds support ABADS MD development and integration activities in support of Golden Dome. Further information for this reconciliation request is provided in Section 20004 (Enhancement of Department of Defense Resources for Munitions and Defense Supply Chain Resiliency) of the Reconciliation Exhibit. ABADS Counter-small Unmanned Aircraft Systems (C-sUAS) specifically aims to counter the threats posed by the rapid proliferation of inexpensive yet highly capable systems, and the enemies who target US Service members, Allies, and Coalition partners. The ABADS C-sUAS program will continue to analyze evolving threats, evaluate new capabilities, and design an open system architecture that reduces life cycle cost and enables fielding to all 180+ AF installations. ABADS C-sUAS features a system of systems approach to integrate sensors and effectors into a robust Command and Control (C2) interface able to detect, track, identify, and defeat sUAS threats. The AF works closely with the DoD Joint C-sUAS Office (JCO) to align annual efforts. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207522F / Airbase Air Defense Systems (ABADS) Component Development & Prototypes (ACD&P) ABADS C-sUAS FY2026 funding will further develop and test Command, Control, Communication, Computers, and Intelligence (C4I) systems to include follow-on of Medusa C2 System and focus on needed fixed and expeditionary site sense and defeat capability development. The Medusa C2 system supports Joint All-Domain Command & Control (JADC2) development and is required to employ electronic warfare capabilities, artificial intelligence, operator workload and task reduction capabilities, closed-loop training system for operator certification and proficiency, identification capabilities, and sensor fusion. Funding will support development and test of Medusa C2 software to further interoperability and incorporation within the ABMS architecture. It will continue electronic warfare upgrades, to include but not limited to new sensor and effector components, and add new Electronic Warfare skills which leverage current Ninja or future EW capabilities within Medusa C2 and other C2 systems. Funding will also continue efforts in alignment with the DoD's JCO, including cyber hardening of all new system changes, and support management of JCO funded Ninja development. Additionally, funding will be utilized to conduct studies, analysis, and evaluations of threats and capability gaps along with evaluation and streamlined acquisition of new capabilities. ABADS C-sUAS funding will also support innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Funds will be used to further develop detection, tracking, ID, fusion and C2 technical solutions for a National Capital Region (NCR) C-sUAS system for protection of Presidential aviation assets and Common Operational Picture (COP). The NCR COP will include cloud-based infrastructure and system architectures. The FY 2026 cost of the ABADS C-sUAS Next Gen C2 Systems (CNGCS) Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission. The FY 2026 request was reduced by 2.356 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.000M was expended for civilian pay expenses in this program element, and in FY 2025 0.231M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207522F / Airbase Air Defense Systems (ABADS) Component Development & Prototypes (ACD&P)$$, NULL, 77861000, 33325000, 29370000, NULL, NULL, 72, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 19273000, 15666000, 85305000, 85305000, 0, 85305000, 29947000, $$The Airbase Air Defense Systems (ABADS) program element is the principal Air Force (AF) program to provide the ability to detect, track, identify, and defeat airborne threats to missions and assets. These threats include small-unmanned aircraft systems (sUAS), Rockets, Artillery and Mortars (RAM), and cruise missiles. These two efforts (Missile Defense (MD) and Counter-small Unmanned Aerial Systems (C-sUAS)) aim to protect personnel, assets, and infrastructure vital to supporting the national security strategy. ABADS MD was originally designed as a configurable combination of Commercial Off the Shelf (COTS)/Government Off the Shelf (GOTS) sensor and Non-Kinetic Effector (NKE) technologies integrated with tailored Battle Management Command and Control (BMC2) subsystem that leverages GOTS products and Advanced Battle Management System (ABMS) systems to provide adaptive, resilient, and dedicated air defense capability. FY27 adds the integration of kinetic effectors, additional non- kinetic effectors and active radar systems. The ABADS MD system is designed to operate independently or in concert with other local and distributed capabilities to form a multi-layered defense-in-depth, improving airbase defense and airbase resiliency. ABADS MD FY2027 funding continues development efforts to operationalize the NKE following prototype transition from the Air Force Research Laboratory (AFRL). Additionally, the funding supports integration of short to medium range kinetic effectors, active defense radars, and additional non-kinetic effector capabilities. Funding also supports and delivers Government Development Security and Operations (DevSecOps) software pipeline, supporting software updates and prioritized capability upgrades. The Government DevSecOps pipeline also supports further alignment with the ABMS portfolio (TOC-L, Digital Infrastructure, and Cloud Based Command and Control). FY2027 funding continues support to Director, Operational Test and Evaluation (DOT&E) oversight required test activities. ABADS MD FY2027 funding will support testing and integration for the kinetic and non-kinetic effector capabilities. Funding will also support and maintain a Government DevSecOps software pipeline, supporting software updates and prioritized capability upgrades. The Government DevSecOps pipeline will also support further alignment with the ABMS portfolio (Distributed Battle Management Node, Digital Infrastructure, and Cloud Based Command and Control). FY2027 funding also supports Director, Operational Test and Evaluation (DOT&E) oversight required test activities. ABADS C-sUAS specifically aims to counter the threats posed by the rapid proliferation of inexpensive yet highly capable systems, and the enemies who target US Service members, Allies, and Coalition partners. The ABADS C-sUAS program will continue to analyze evolving threats, evaluate new capabilities, and design an open system architecture that reduces life cycle cost and enables fielding to all 180+ DAF installations. ABADS C-sUAS features a system of systems approach to integrate Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207522F / Airbase Air Defense Systems (ABADS) Component Development & Prototypes (ACD&P) sensors and effectors into a robust Command and Control (C2) interface able to detect, track, identify, and defeat sUAS threats. The AF works closely with the DoW Joint Interagency Task Force (JIATF) 401 to align annual efforts. ABADS C-sUAS FY2027 funding will further develop and test Command, Control, Communication, Computers, and Intelligence (C4I) systems to include follow-on of Medusa C2 System and focus on needed fixed and expeditionary site sense and defeat capability development. The Medusa C2 system supports Joint All-Domain Command & Control (JADC2) development and is required to employ electronic warfare capabilities, artificial intelligence, operator workload and task reduction capabilities, closed-loop training system for operator certification and proficiency, identification capabilities, and sensor fusion. Funding will support development and test of Medusa C2 software to further interoperability and incorporation within the ABMS architecture. It will continue electronic warfare upgrades, to include but not limited to new sensor and effector components, and add new Electronic Warfare skills which leverage current Ninja or future EW capabilities within Medusa C2 and other C2 systems. Funding will also continue efforts in alignment with the DoW's Joint Interagency Task Force (JIATF) 401, including cyber hardening of all new system changes, and support management of JIATF funded Ninja development. Additionally, funding will be utilized to conduct studies, analysis, and evaluations of threats and capability gaps along with evaluation and streamlined acquisition of new capabilities. ABADS C-sUAS funding will also support innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/ demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. The total cost of the ABADS C-sUAS Next Gen C2 Systems (CNGCS) Middle Tier of Acquisition effort is 111.8 million, including RDT&E and procurement of prototype units. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207522F / Airbase Air Defense Systems (ABADS) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2032_L044$$, $$LAUNCHED EFFECTS FAMILY$$, $$proc_army_2032_ba6$$, $$peo_ms$$, 2026, 80403000, 0, 0, NULL, $${"page": 21, "ba_num": "06", "source": "p1_fy26", "ba_name": "AGILE PROFILE MANAGEMENT", "line_no": "44", "service": "army", "fy24_qty": null, "fy25_qty": null, "fy27_v20": {"K": 0, "ba": "06", "appr": "MIPA", "note": "surplus_DB_pid"}, "appr_code": "2032", "appr_name": "Missile Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 67816000, "fy26r_cost": 12587000, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Missile Procurement Army.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207573F$$, $$National Technical Nuclear Forensics$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 1974000, 2060000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207573F"}$$::jsonb, $$This is an amendment, prior verbiage had this funding pointing to National Technical Nuclear Forensics [NTNF]. The United States Nuclear Detonation [NUDET] Detection System [USNDS] is the system used for the collection, analysis, and evaluation of signatures from NUDETS in the Atmosphere or Space. This funding is to integrate the data from the seconds and third Space and Atmospheric Burst Reporting System [SABRS] sensors into the Integrated Correlation and Display System [ICADS] and to develop algorithms, codes, and tools necessary to enable detailed Subject Matter Expert analysis of SABRS data. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY23 $0 was expended for civilian pay expenses in this program element, and in FY24 $0 is forecasted for civilian pay expenses in this program element This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 2011000, 2009000, 2047000, NULL, NULL, 205, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 1984000, 0, 0, 0, 0, 0, 2089000, $$This is an amendment, prior verbiage had this funding pointing to National Technical Nuclear Forensics [NTNF]. The United States Nuclear Detonation [NUDET] Detection System [USNDS] is the system used for the collection, analysis, and evaluation of signatures from NUDETS in the Atmosphere or Space. This funding is to integrate the data from the seconds and third Space and Atmospheric Burst Reporting System [SABRS] sensors into the Integrated Correlation and Display System [ICADS] and to develop algorithms, codes, and tools necessary to enable detailed Subject Matter Expert analysis of SABRS data. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207590F$$, $$Seek Eagle$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 33707000, 33417000, 34985000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207590F"}$$::jsonb, $$The Air Force SEEK EAGLE Office (AFSEO) is designated by the Assistant Secretary of the Air Force (Acquisition, Technology, and Logistics) as the center of expertise for aircraft-store compatibility activities and as the primary source of technical analysis and test support, as well as the central data repository, for the SEEK EAGLE process. The SEEK EAGLE process is a rigorous analysis of many factors to assure the safe and acceptable carriage and release (employment and jettison), safe escape, and ballistics accuracy of all stores on Air Force and foreign military sales aircraft. Thus, the AFSEO's mission as an accelerator is to ensure that every aircraft type is capable of employing the weapons and stores needed to meet Combatant Commander requirements, directly supporting the Secretary of the Air Force's (SECAF) Operational Imperatives (OI), and Cross-cutting Operational Enablers (COE). The Air Force operates a variety of combat and other aircraft that carry numerous and varied stores: bombs, missiles, rockets, fuel tanks, cargo pods, targeting pods, electronic countermeasures pods, etc. Stores are carried in many different loading combinations determined by operational and training scenarios, missions, tactics, and weapon development programs. Additionally, aircraft-store configuration (carriage and employment) requirements change as operational plans and tactics are updated and/or as new stores are developed and fielded. Aircraft program managers must provide SEEK EAGLE certifications for all aircraft-store configurations within their user-established carriage and employment parameters before they may be used for operations, test, or training. The AFSEO completes flight clearance and certification recommendations through any combination of engineering analysis, wind tunnel testing, modeling and simulation, and ground/flight test and evaluation. The SEEK EAGLE process encompasses eight engineering disciplines: Fit and Function, Flutter, Aircraft and Store Structural Integrity, Stability and Control, Electromagnetic Compatibility/Interference (EMC/EMI), Separations, Ballistics, and Safe Escape. In support of certification, the AFSEO recommends approximately 1000 aircraft-store combinations for flight each year through engineering analysis and testing. The AFSEO certification portfolio includes the Next Generation Air Dominance (NGAD) Family of Systems and B-21, as well as the following Mission Design Series aircraft: A-10, B-1, B-2, B-52, F-15C/D/E/EX, F-16, QF-16, F-22, F-35, KC-135, WC-130, MC-130H, HH-60W, MH-139A, MQ-9, T-7A, AT-6, and more. Integrated solutions for combat delivery mission planning problems are developed and provided to combat forces via Combat Weapons Delivery Software (CWDS) and Joint Safe Escape Analysis Solution (JSEAS) software. The SEEK EAGLE Office also works in coordination with the Air Force Safety Center to provide Hazards of Electromagnetic Radiation to Ordnance (HERO) analysis and certification recommendations for ordnance systems containing electro-explosive devices. Additionally, the AFSEO is responsible for incorporating new and emerging technologies into the SEEK EAGLE process to make certification more efficient in support of rapid acquisition timelines, as well as resourcing for the sustainment of a viable Air Force aircraft-store certification capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207590F / Seek Eagle Operational Systems Development SEEK EAGLE funds are budgeted to support certification testing and analysis for new and inventory stores including, but not limited to: Small Diameter Bomb (SDB) I and II, Laser Joint Direct Attack Munitions (LJDAM), Joint Air-to-Surface Standoff Missile (JASSM), Long-Range Anti-Ship Missile (LRASM), Advanced Medium Range Air-to-Air Missile (AMRAAM), Miniature Air-Launched Decoy (MALD), BRU-57 (Smart Bomb Rack), BRU-61 (SDB Bomb Rack), Advanced Precision Kill Weapon System (APKWS), Sniper Targeting Pod with video data link, LITENING Targeting Pod with video data link, B61-12 nuclear free-fall weapon, penetrator warhead upgrades, practice bombs, electronic warfare pods, reconnaissance pods, and aircraft instrumentation pods. SEEK EAGLE funds also support certification of other inventory stores on Combat Air Forces (CAF) and Special Operations Command (SOCOM) aircraft. In addition, these funds further support capability development and weapons certification efforts required by Air Combat Command (ACC) to achieve Full Operational Capability (FOC) for the F-35A. Many of these weapons certification efforts are directly involved in SECAF OI-3, Moving Target Engagement, and all of them contribute to COE-1, Munitions. Additionally, many of the pods and other stores these funds support contribute directly to COE-2, Electromagnetic Spectrum. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24, 9.893M was obligated for civilian pay expenses in this program element, and 10.880M was forecasted for civilian pay expenses in FY25 in this program element. The FY26 request has been reduced by .034M for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 38024000, 38743000, 39481000, NULL, NULL, 206, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 34982000, 33706000, 36710000, 36710000, 0, 36710000, 40280000, $$The Air Force SEEK EAGLE Office (AFSEO) is designated by the Assistant Secretary of the Air Force (Acquisition, Technology, and Logistics) as the center of expertise for aircraft-store compatibility activities and as the primary source of technical analysis and test support, as well as the central data repository, for the SEEK EAGLE process. The SEEK EAGLE process is a rigorous analysis of many factors to assure the safe and acceptable carriage and release (employment and jettison), safe escape, and ballistics accuracy of all stores on Air Force and foreign military sales aircraft. Thus, the AFSEO's mission as an accelerator is to ensure that every aircraft type is capable of employing the weapons and stores needed to meet Combatant Commander requirements, directly supporting the Secretary of the Air Force's (SECAF) and Secretary of War (SECWAR) operational and acquisition priorities. The Air Force operates a variety of combat and other aircraft that carry numerous and varied stores: bombs, missiles, rockets, palletized munitions, chaff/flare, fuel tanks, cargo pods, targeting pods, electronic countermeasures pods, etc. Stores are carried in many different loading combinations determined by operational and training scenarios, missions, tactics, and weapon development programs. Additionally, aircraft-store configuration (carriage and employment) requirements change as operational plans and tactics are updated and/or as new stores are developed and fielded. Aircraft program managers must provide SEEK EAGLE certifications for all aircraft-store configurations within their user-established carriage and employment parameters before they may be used for operations, test, or training. The AFSEO completes flight clearance and certification recommendations through any combination of engineering analysis, wind tunnel testing, modeling and simulation, and ground/flight test and evaluation. These AFSEO recommendations are key artifacts for aircraft program managers demonstrating MIL-STD compliance for airworthiness and safety. AFSEO's efforts within the SEEK EAGLE process primarily encompass these eight engineering disciplines: Fit and Function, Flutter, Aircraft and Store Structural Integrity, Stability and Control, Electromagnetic Compatibility/Interference (EMC/EMI), Separations, Ballistics, and Safe Escape. In support of certification, the AFSEO recommends approximately 1000 aircraft-store combinations for flight each year through engineering analysis and testing. The AFSEO certification portfolio includes the Next Generation Air Dominance (NGAD) Family of Systems, Collaborative Combat Aircraft (CCA) and B-21, as well as the following Mission Design Series aircraft: B-1, B-2, B-52, F-15, F-16, QF-16, F-22, F-35, KC-135, C-130, C-17, HH-60, MH-139, MQ-9, OA-1k, T-7, AT-6, and more. Accounting for factors from aircraft dynamics to day-of-flight conditions, AFSEO develops sophisticated Safe Escape and Ballistics tools that are integrated into the Joint Mission Planning System (JMPS). AFSEO also provides specialized software like Combat Weapon Delivery Software (CWDS) and Guided Weapon Trajectory Software (GWTS) directly to specific users, including approximately 25 FMS customers FMS customers. The SEEK EAGLE Office also works in coordination with the Air Force Safety Center to provide Hazards of Electromagnetic Radiation to Ordnance (HERO) analysis and certification recommendations for ordnance systems containing electro-explosive devices. Additionally, to accelerate certification timelines and ensure a sustainable Air Force aircraft-store capability, AFSEO actively integrates cutting-edge technologies into the SEEK EAGLE process, streamlining the path to rapid acquisition and deployment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0207590F / Seek Eagle Operational Systems Development SEEK EAGLE funds are budgeted to support certification testing and analysis for a variety of new and inventory stores, including a growing focus on Advanced Precision Kill Weapon System (APKWS) rockets used for Counter-UAS, as well as Family of Affordable Mass Missiles (FAMM), specifically the -L (lugged) and -P (palletized) variants, Small Diameter Bombs (SDB I and II), Joint Direct Attack Munition (JDAM) variants, Quickstrike mines, Joint Air-to-Surface Standoff Missile (JASSM), Long- Range Anti-Ship Missile (LRASM), Air-to-Air Missiles (AIM-120 and AIM-9X), Miniature Air-Launched Decoy (MALD), smart bomb racks, targeting pods with video data link capabilities, the B61-12 nuclear free-fall weapon, penetrator warhead upgrades, electronic warfare and reconnaissance pods, and instrumentation pods. SEEK EAGLE funds also support certification of other inventory stores on Combat Air Forces (CAF) and Special Operations Command (SOCOM) aircraft. To ensure that these certification efforts are as cost-effective and efficient as possible, the AFSEO maintains the central data archive for all aircraft store compatibility analyses; while this archive requires ongoing investment in hardware, software, and licensing, it drastically reduces the need for costly and time-consuming ground and flight re-testing and speeds up acquisition and development by providing critical data, lessons learned, and reduced analysis time to other Department of Defense (DoD) organizations. In addition, these funds further support capability development and weapons certification efforts required by Air Combat Command (ACC) to achieve Full Operational Capability (FOC) for the F-35A. These weapons certification efforts directly support SECAF emphasis areas (NGAD, B-21 and F-47 Families of Systems) and SECWAR emphasis areas (Nuclear Modernization, CCAs, Counter-small UAS Initiatives, and Munitions). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2025, 8.925M was expended for civilian pay expenses in this program element, and 11.550M is forecasted for civilian pay expenses in FY 2026 in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207606F$$, $$Joint Simulation Environment (JSE)$$, $$rdte_af_ba4$$, $$aftc$$, 2026, 260667000, 0, 149502000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0207606F"}$$::jsonb, $$Joint Simulation Environment (JSE) is the Air Force's synthetic solution for High-End Advanced Training, Tactics, and Testing (HEAT3). JSE supports operational plan rehearsals, large force exercises, and aircrew training events. This capability directly supports United States Air Force Warfare Center (USAFWC), United States Air Force Weapons School, Air Force Test Center (AFTC), Air Force Operational Test and Evaluation Center (AFOTEC), and augments platform training efforts that cannot be performed in open air. JSE encompasses, but is not limited to, lab facilities for development and experimentation, as well as multiple test and training locations, to include, but not limited to: Joint Integrated Test & Training Center Nellis AFB (JITTC-N), Digital Test & Training Range Nellis AFB (DTTR-N), Digital Test & Training Range Edwards AFB (DTTR-E), and future planned location JITTC-Joint Base Elmendorf-Richardson (JITTC-E). JSE Platform-In-A-Box (PIAB) Operational Flight Program (OFP) Based Simulator Development: Entails the study, evaluation, early experimentation, and development for platforms beyond the current/existing F-35 capability. Activities include analysis of OFPs against JSE software and interface standards, as well as common hardware standards enabling remote monitoring, updates, and security management. JSE Digital Test and Training Ranges (DTTR): Maintains and upgrades existing test capabilities, to include the continuation of installation, integration, and verification/ validation activities in support of fielded and future platforms and virtual air threats. Furthermore, the 445 Test Squadron at DTTR-E manages Developmental Test (DT) and Operational Test (OT) events, as well as cyber testing integration for the JSE Enterprise as part of their Lead Developmental Test Organization (LDTO) designation. JSE Core Environment Development/Integration: Continues to develop JSE foundational capabilities enabling further test, integration, and training. Activities include but are not limited to experimentation, development/enhancement of JSE connected systems, tools, services, hardware, and simulators to integrate new and existing digital entities (platforms, sensors, adversary & friendly weapons, ground & airborne threats), and common services including but not limited to weather effects, infrared (IR) models, cyber, and space. Funding may also be used to address Diminishing Manufacturing Sources (DMS) issues, obsolescence resolution and similar emerging requirements, as well as for overarching programmatic support. Funding for this exhibit is contained in PE 0207606F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207606F / Joint Simulation Environment (JSE) Component Development & Prototypes (ACD&P) This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F. As this PE was established in FY 2025, FY 2024 civilian pay costs are not applicable, and in FY25 10.395M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 352178000, 333950000, 323465000, NULL, NULL, 73, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 147368000, 247491000, 302801000, 302801000, 0, 302801000, 313126000, $$Joint Simulation Environment (JSE) is the Air Force's synthetic solution for High-End Advanced Training, Tactics, and Testing (HEAT3). JSE supports operational plan rehearsals, large force exercises, aircrew training events, and aircraft platform operational test campaigns. This capability directly supports United States Air Force Warfare Center (USAFWC), United States Air Force Weapons School, Air Force Test Center (AFTC), Air Force Operational Test and Evaluation Center (AFOTEC), and addresses platform training and test efforts that cannot be performed in open air. JSE encompasses, but is not limited to, lab facilities for development and experimentation, as well as multiple test and training locations, to include, but not limited to: Joint Integrated Test & Training Center Nellis AFB (JITTC-N), Digital Test & Training Range Nellis AFB (DTTR-N), Digital Test & Training Range Edwards AFB (DTTR-E), and future planned location JITTC-Joint Base Elmendorf-Richardson (JITTC-E). JSE Platform-In-A-Box (PIAB) Operational Flight Program (OFP) Based Simulator Development: Entails the study, evaluation, early experimentation, and development for platforms beyond the current/existing F-35 capability. Activities include analysis of OFPs, to include high-fidelity aircraft mission system and sensor models, against JSE software and interface standards, as well as common hardware standards enabling remote monitoring, updates, and security management. JSE Digital Test and Training Ranges (DTTR): Maintains and upgrades existing test capabilities, to include the continuation of installation, integration, and verification/ validation activities in support of fielded and future platforms and virtual air threats. Furthermore, the 445 Test Squadron at DTTR-E manages Developmental Test (DT) and Operational Test (OT) events, as well as cyber testing integration for the JSE Enterprise as part of their Executing Test Organization (ETO) role, delegated to the 445th TS by the 412th Test Wing as the JSE Enterprise's Lead Developmental Test Organization (LDTO). JSE Core Environment Development/Integration: Continues to develop JSE foundational capabilities enabling further test, integration, and training. Activities include but are not limited to experimentation, development/enhancement of JSE connected systems, tools, services, hardware, and simulators to integrate new and existing digital entities (platforms, sensors, adversary & friendly weapons, ground & airborne threats), and common services including but not limited to weather effects, infrared (IR) and radiofrequency (RF) propagation models, weather effects on IR and RF propagation, Datalinks, cyber, and space. Funding may also be used to address Diminishing Manufacturing Sources (DMS) issues, obsolescence resolution and similar emerging requirements, as well as for overarching programmatic support. Funding for this exhibit is contained in PE 0207606F. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0207606F / Joint Simulation Environment (JSE) Component Development & Prototypes (ACD&P) This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207611F$$, $$Readiness Decision Support Enterprise$$, $$rdte_af_ba7$$, $$dw_osd$$, 2026, 8880000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207611F"}$$::jsonb, $$This package incorporates RDT&E funds to maintain constant readiness landscape changes, which entail software changes, new requirements, etc. to Air Force DRRS-S. DRRS-S is an OSD platform providing readiness reporting capabilities to the DoD. The DRRS-S mission is to establish a mission focused, capabilities based, common framework that provides the combatant commanders, military services, Joint Chiefs of Staff, and other key DoD users a data-driven environment and tools in which to evaluate, in near real-time, the readiness and capability of the U.S. Armed Forces to carry our assigned and potential tasks. These assigned and potential tasks sometimes drive software changes and development specifically for the Air Force which require RDT&E funding to achieve the ability to measure readiness. One example would be the development of Combat Wing. This drives a new assessment framework which needs to be developed within DRRS-S so commanders can measure the readiness of combat wings as a single capability, which are different from the way the Air Force currently assesses readiness. By not having the development ability with the RDT&E funding, readiness reporting will not meet the needs of Joint Staff, Congress, Commanders, or any end users of Air Force Readiness data. MODIFY THE DEFENSE READINESS REPORTING SYSTEM TO SUPPORT ENCHANCE RESOURCE REPORTING FOR COMBAT WINGS: Air Force modifications to force presentation and organization requires modifications new capabilities in DRRS to allow for presented forces to reflect meaningful resource and capability ratings that fully encompass the entirety of capability packages. This change will allow the AF to present fully capability packages with a single resource rating informed by supporting unit ratings. This will provide key decision makers with decision quality data reflecting the full capability package. This is in addition to the current functional unit structure that requires deeper cross referencing to account for the full capability package. The system will combine resource data from multiple units (where reasonable) to reflect combat unit readiness informed by combat support and combat service support limits. MODIFY THE DEFENSE READINESS REPORTING SYSTEM AIR FORCE INPUT TOOL TO STREAMLINE REPORTING: The Air Force Input Tool module of DRRS is the interface by which Air Force units report Readiness. This effort streamlines the input process with structured in-system guidance to increase data quality. This effort utilizes robust tools to summarize unit resources for assessors and direct both qualitative and quantitative inputs to generate, value and risk to assigned capabilities and missions. The end state provides robust qualified Readiness data that highlights resource impacts to specific capabilities. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                             Date: June 2025 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                     PE 0207611F / Readiness Decision Support Enterprise Operational Systems Development MODIFY THE DEFENSE READINESS REPORTING SYSTEM AIR FORCE INPUT TOOL TO SUPPORT ENHANCED ANALYITCS: Updating the Air Force Input Tool to align reported resources to specific capability elements and support advanced analytics that reflect detailed data impact to specific resource shortfalls. Additionally, this effort will support ‘what if' reporting to provide AF leadership with preliminary evaluations given proposed Courses of Action (COA) options. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 6594000, 6462000, 6320000, NULL, NULL, 208, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 0, 8758000, 6823000, 6823000, 0, 6823000, 6448000, $$This package incorporates RDT&E funds to maintain constant readiness landscape changes, which entail software changes, new requirements, etc. to Air Force DRRS-S. DRRS-S is an OSD platform providing readiness reporting capabilities to the DoD. The DRRS-S mission is to establish a mission focused, capabilities based, common framework that provides the combatant commanders, military services, Joint Chiefs of Staff, and other key DoD users a data-driven environment and tools in which to evaluate, in near real-time, the readiness and capability of the U.S. Armed Forces to carry our assigned and potential tasks. These assigned and potential tasks sometimes drive software changes and development specifically for the Air Force which require RDT&E funding to achieve the ability to measure readiness. One example would be the development of Combat Wing. This drives a new assessment framework which needs to be developed within DRRS-S so commanders can measure the readiness of combat wings as a single capability, which are different from the way the Air Force currently assesses readiness. By not having the development ability with the RDT&E funding, readiness reporting will not meet the needs of Joint Staff, Congress, Commanders, or any end users of Air Force Readiness data. MODIFY THE DEFENSE READINESS REPORTING SYSTEM TO SUPPORT ENCHANCE RESOURCE REPORTING FOR COMBAT WINGS: Air Force modifications to force presentation and organization requires modifications new capabilities in DRRS to allow for presented forces to reflect meaningful resource and capability ratings that fully encompass the entirety of capability packages. This change will allow the AF to present fully capability packages with a single resource rating informed by supporting unit ratings. This will provide key decision makers with decision quality data reflecting the full capability package. This is in addition to the current functional unit structure that requires deeper cross referencing to account for the full capability package. The system will combine resource data from multiple units (where reasonable) to reflect combat unit readiness informed by combat support and combat service support limits. MODIFY THE DEFENSE READINESS REPORTING SYSTEM AIR FORCE INPUT TOOL TO STREAMLINE REPORTING: The Air Force Input Tool module of DRRS is the interface by which Air Force units report Readiness. This effort streamlines the input process with structured in-system guidance to increase data quality. This effort utilizes robust tools to summarize unit resources for assessors and direct both qualitative and quantitative inputs to generate, value and risk to assigned capabilities and missions. The end state provides robust qualified Readiness data that highlights resource impacts to specific capabilities. MODIFY THE DEFENSE READINESS REPORTING SYSTEM AIR FORCE INPUT TOOL TO SUPPORT ENHANCED ANALYITCS: Updating the Air Force Input Tool to align reported resources to specific capability elements and support advanced analytics that reflect detailed data impact to specific resource shortfalls. Additionally, this effort will support ‘what if' reporting to provide AF leadership with preliminary evaluations given proposed Courses of Action (COA) options. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207611F / Readiness Decision Support Enterprise Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207697F$$, $$Distributed Training and Exercises$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 4399000, 3678000, 3964000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207697F"}$$::jsonb, $$Funding supports the CSAF Title 10 wargaming efforts to test concepts, capabilities, programming choices, and plans using simulation and other techniques, otherwise known as wargaming. Based on the Department and Air Force direction, there is a concerted effort in these periods of fiscal restraint to reinvigorate, institutionalize, and systematize wargaming across the Department. This effort requires continued funding to maintain the level of effort to most effectively pursue an innovative strategy, avoid operational and technical surprise and make best use of limited resources. The Air Force continues to refine the wargame process and design to better integrate and synergize those efforts in support of the Air Force Strategy, Planning, Programming, Budget, and Execution (SPPBE) process. Specifically, in addition to maintaining a robust Title 10 Wargame series, Global Engagement, servicing Chief of Staff of the Air Force (CSAF) objectives. The HAF Wargaming Enterprise is executing on-call Wargaming in support of the AF/A5/7, the Agile series, along with quick-turning wargame support to the USAF Enterprise Capability Collaboration Team (ECCT) requirements, the Enterprise series, Plan Blue, and to service AF/A5/7 strategy and concept development objectives; all to better address the requirements of the Strategy, Planning, Programming, Budget, and Execution (SPPBE)process and cycles. Additionally, HAF Wargaming provides and coordinates Air Force representation at other Service and Joint wargames as they execute across the department. These efforts are providing decision support to senior Air Force leaders involving investment strategies and develop concepts to best employ U.S. forces in future conflicts. The Wargame Information Environment (WIE) is a continually evolving system that provides an array of services to game players which enables the accomplishment of game objectives. The backbone of the WIE is GameNet, a deployable, standalone, Local Area Network (LAN) with servers and laptops that host applications to support virtual battlespace collaboration, decision making, three-dimensional visualizations & mapping, and services. Behind these applications are cutting edge technologies and database architectures from both commercial off-the-shelf and government developed software that assures relevance to the wargame. The modeling, simulation, and analysis applications allow participants, adjudicators, and control team members to effectively and efficiently collaborate, make decisions, present those decisions, and execute moves within the wargame; documenting each step in the process. This information capture enables discovery during the wargame and permits postgame analysis. These findings inform portfolio rebalancing exercises, concept and strategy development, and very senior leader decision making. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0207697F / Distributed Training and Exercises Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 3871000, 3972000, 4044000, NULL, NULL, 209, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 3826000, 4342000, 83659000, 83659000, 0, 83659000, 4127000, $$Funding supports the CSAF Title 10 wargaming efforts to test concepts, capabilities, programming choices, and plans using simulation and other techniques, otherwise known as wargaming. Based on the Department and Air Force direction, there is a concerted effort in these periods of fiscal restraint to reinvigorate, institutionalize, and systematize wargaming across the Department. This effort requires continued funding to maintain the level of effort to most effectively pursue an innovative strategy, avoid operational and technical surprise and make best use of limited resources. The Air Force continues to refine the wargame process and design to better integrate and synergize those efforts in support of the Air Force Strategy, Planning, Programming, Budget, and Execution (SPPBE) process. Specifically, in addition to maintaining a robust Title 10 Wargame series, Global Engagement, servicing Chief of Staff of the Air Force (CSAF) objectives. The HAF Wargaming Enterprise is executing on-call Wargaming in support of the AF/A5/7, the Agile series, along with quick-turning wargame support to the USAF Enterprise Capability Collaboration Team (ECCT) requirements, the Enterprise series, Plan Blue, and to service AF/A5/7 strategy and concept development objectives; all to better address the requirements of the Strategy, Planning, Programming, Budget, and Execution (SPPBE)process and cycles. Additionally, HAF Wargaming provides and coordinates Air Force representation at other Service and Joint wargames as they execute across the department. These efforts are providing decision support to senior Air Force leaders involving investment strategies and develop concepts to best employ U.S. forces in future conflicts. The Wargame Information Environment (WIE) is a continually evolving system that provides an array of services to game players which enables the accomplishment of game objectives. The backbone of the WIE is GameNet, a deployable, standalone, Local Area Network (LAN) with servers and laptops that host applications to support virtual battlespace collaboration, decision making, three-dimensional visualizations & mapping, and services. Behind these applications are cutting edge technologies and database architectures from both commercial off-the-shelf and government developed software that assures relevance to the wargame. The modeling, simulation, and analysis applications allow participants, adjudicators, and control team members to effectively and efficiently collaborate, make decisions, present those decisions, and execute moves within the wargame; documenting each step in the process. This information capture enables discovery during the wargame and permits postgame analysis. These findings inform portfolio rebalancing exercises, concept and strategy development, and very senior leader decision making. The FY2026 spend plan amount for Research, Development, Testing and Evaluation includes $4,342 thousand of discretionary and $10,000 of mandatory (reconciliation) for a total of $14,342 thousand. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0207697F / Distributed Training and Exercises Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604283F_ba4$$, $$Battle Mgmt Com & Ctrl Sensor$$, $$rdte_af_ba4$$, $$afrl_ry$$, 2026, 150000000, 0, 0, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0604283F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
