INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1507_L061$$, $$Spares and Repair Parts$$, $$proc_navy_1507_ba6$$, $$navair$$, 2026, 202425000, 177819000, 240697000, NULL, $${"page": 72, "ba_num": "06", "source": "p1_fy26", "ba_name": "Spares and repair parts", "line_no": "61", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "06", "appr": "WPN", "title": "P-1 Line 46", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/WPN_Book.pdf", "fy27_base_K": 167242, "p1_line_num": 46, "fy27_total_K": 167242}, "appr_code": "1507", "appr_name": "Weapons Procurement, Navy", "fy26_v179": {"disc_K": 202425, "li_num": 46, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/WPN_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 202425000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 202425000, 167242000, 167242000, 0, 167242000, NULL, NULL, $$Budget J-Books/FY27/Navy/WPN_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207701F$$, $$Full Combat Mission Training$$, $$rdte_af_ba5$$, $$afrl$$, 2026, 12898000, 0, 7754000, NULL, $${"source": "jbook_fy26", "fy27_base_v158_t7b": "I-3 hygiene: total=req but base held stale sibling value post v7 I-24"}$$::jsonb, $$Full Combat Mission Training (FCMT) supports Air Force Distributed Mission Operations (DMO), Live-Synthetic Blended integration. FCMT funding provides research in areas benefiting the DMO/Live Virtual Constructive (LVC) environment and the Air Force synthetic training enterprise. It also provides research and development to facilitate integration of fielded and newly acquired Air Force owned training devices into DMO/LVC networks; enhances the quality of training for the systems added to the network; enables aircrews to network with LVC components to form the integrated DMO battlespace; links geographically distributed high-fidelity combat and combat support training devices including Command and Control and Intelligence, Surveillance, and Reconnaissance systems and develops, demonstrates, and inserts Multi- Level Security (MLS) capability. This capability enables warfighters to exercise and train at the operational and strategic levels of war, conduct networked unit-level training at home station and high-end test and training at joint test and training sites. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.00M was expended for civilian pay expenses in this program element. FY25 $0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System      PE 0207701F / Full Combat Mission Training Development & Demonstration (SDD)$$, NULL, 6856000, 6971000, 7089000, NULL, NULL, 112, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 3808000, 7985000, 6501000, 6501000, 0, 6501000, 7232000, $$The Distributed Mission Operations Center (DMOC) provides comprehensive Live, Virtual, and Constructive (LVC) simulation capabilities which prepare warfighters to conduct Joint All-Domain Command & Control (JADC2) operations in air, land, sea, space, and cyber domains for Air Force (AF), joint service, and coalition partners' theater-level, full spectrum combat training. The DMOC training capabilities reach over 40 geographically separated LVC locations representing real-world weapon systems, operator-in-the-loop, and constructive/computer-driven simulations. DMOC is responsible for development and integration of scenarios, models, and databases of participating sites into Virtual Flag (VF) and other Distributed Mission Operations (DMO) training events via network connectivity, interoperability tools, and controlled interfaces in support of Air Force, joint, and coalition warfighter readiness. In addition, activities include DMO technology and capability studies/analyses which support both current and future program planning and execution by: DISTRIBUTED MISSION OPERATIONS CAPABILITY/BATTLESPACE SYSTEMS DEVELOPMENT: The DMOC develops, upgrades and enhances capabilities of various systems, tools, and simulators incorporating emerging technology and training requirements into DMO events, such as Bamboo Eagle, VF and VF: Coalition (VF:C), enhancing the quality of warfighter training. Activities include Environment Generator development, DMO Tool Development, and Simulator Enhancement. DMOC partners with the US Naval Air Warfare Center-Aircraft Division (NAWCAD) to enhance Next Generation Threat System (NGTS) capabilities. The NGTS is the primary environment generator for both Blue and Red Air in DMOC White Force. DMO Tool development includes: a) DMOC Replay Tool (DRT), which facilitates a more complete exercise mission review and debrief capability as more sites and systems are added to events; b) enhancement & improvement of the Distributed Interactive Simulation (DIS) Filter and the Doctor-J (Dr. J) tools to enable tactical datalinks communication and translation between disparate simulator and operationally fielded (i.e. live aircraft) communication formats; c) Development of Intelligence, Surveillance, and Reconnaissance (ISR)/Battle Damage Assessment (BDA) to improve damage state models used by intelligence analysts in exercises; d) development of solutions for integrating Contested Degraded Operations Gateway (CDOG, geographical and communications jamming) into DMO events; e) and simulator enhancement efforts to incorporate Mission Package standards upgrades into the Control and Reporting Center (CRC) Simulation Package (CSP), allowing a real-world system to be used as a simulator when needed in DMO events. ASSESSMENT & AUTHORIZATION (A&A)/SOFTWARE CERTIFICATION: The DMOC supports cybersecurity requirements definition, integration/test support, analysis, systems engineering support, A&A of core systems, and support software certification. The DMOC implements cybersecurity requirements and complies with the application of the Risk Management Framework (RMF) and Continuous Monitoring. Efforts include Cross-Domain Information Sharing / Multi-national Information Sharing (CDIS/MNIS) ruleset development, load sharing, and testing; integration and testing of various newly developed / updated systems such as the DMOC Replay Tool, Dr. J, DIS Filter, and the DMOC Battlespace; support of Air Force Network Integration Center (AFNIC) software certification. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0207701F / Full Combat Mission Training Operational Systems Development DISTRIBUTED TRAINING SITES & SYSTEMS INTEGRATION: The Distributed Mission Operations Center (DMOC) integrates over 40 geographically separated Live, Virtual, and Constructive (LVC) training locations and 50+ systems into LVC Distributed Mission Operations (DMO) training events such as Virtual Flag (VF) and VF: Coalition (VF:C) by resolving interoperability issues between disparate systems and networks so that all exercise participants can interact in the DMO environment. New sites and systems are incorporated into LVC DMO events each year based on higher headquarters and Combatant Commander's (CCDRs) emerging requirements. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207701F_ba5$$, $$Full Combat Mission Training$$, $$rdte_af_ba5$$, $$aflcmc$$, 2026, 12898000, 7597000, 7754000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0207701F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0207701F_ba7$$, $$Full Combat Mission Training$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 8096000, 0, 3948000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0207701F", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, 6644000, 6644000, NULL, 6644000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208006F$$, $$Mission Planning Systems$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 138745000, 83500000, 80709000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0208006F"}$$::jsonb, $$Budget line 0208006F funds the Precision Aerial Delivery Systems (PADS) and Mission Planning Systems (MPS) Modernization efforts and is used to develop automated mission planning systems to support U.S. Air Force (USAF) flying operations. Airdrop Mission Planning/Joint Precision Airdrop System (JPADS) consists of hardware and software that serve as the primary mission planning system for all airdrop operations, enabling high-altitude logistical resupply and payload delivery. JPADS efforts are focused on hardware and software enhancements supporting airdrop delivery of cargo and resources while enabling Command and Control (C2) of aircrews and payloads during mission execution. These software upgrades will increase the survivability and lethality of our mobility forces. MPS are foundational to effective airpower projection and mission execution. MPS aircraft mission planning software integrates the latest tasking orders, mission profile, order of battle, routes, weight and balance, formation, payload, cargo, intelligence, weather, aircraft performance, autonomous air vehicle and weapon flight out models, and threat data into flight systems and associated Battle Management systems and networks. This integrated operating picture is used pre-flight to prepare the crew and aircraft for each mission; in-flight to receive and respond to C2 direction, enhance survivability, and react to mission changes; and post-flight for aircrew, intelligence, and maintenance debriefing. MPS Joint Mission Planning System (JMPS), utilized by USAF and the U.S. Navy (USN), focuses solely on pre-mission planning operations. Modernization efforts, including JMPS Open Mission System (JOMS), focus on connected and disconnected planning and execution for all phases of mission planning (pre-mission, in-flight, and post-mission planning). Software development is essential for real-time mission data C2 updates and collaboration with mission partners as well as dynamic mission replanning for evolving conditions and sharing post-mission data to inform follow on operations. Additionally, MPS is lead on Theater Air Planning System of Systems (TAP-SoS) efforts to enable mission planning modernization integration and real-time data sharing with multiple C2 systems, including but not limited to Advanced Battle Management System (ABMS), Air Operations Centers, and Mobility Air Force C2 (MAFC2) across the Department of the Air Force (DAF) BATTLE NETWORK (DBN). Efforts within this PE align with USAF investment in Air Operations Center (0207410F), All Domain Common Platform (0303248F), C2IMERA (0305015F/0305836F) and ABMS (0604003F) to deliver the TAP-SoS architecture for the DBN. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0208006F / Mission Planning Systems Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F or 0605898F. In FY2024 $0.826M was expended for civilian pay expenses in this program element, and in FY2025 $1.038M is forecast for civilian pay expenses in this program element. The FY2026 request was reduced by $2.407 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 123093000, 118969000, 115975000, NULL, NULL, 211, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 78113000, 123103000, 122175000, 122175000, 0, 122175000, 113648000, $$Budget line 0208006F funds the Precision Aerial Delivery Systems (PADS), Mission Planning Systems (MPS), and Theater Air Planning System of Systems (TAP-SOS) modernization efforts and is used to develop automated mission planning systems to support U.S. Air Force (USAF) flying operations. Airdrop Mission Planning/Joint Precision Airdrop System (PADS) consists of hardware and software that serve as the primary mission planning system for all airdrop operations, enabling high-altitude logistical resupply and payload delivery. PADS enhances operational efficiency, survivability, and lethality by enabling the safe and effective delivery of critical supplies and equipment to forces in the field, including from altitudes beyond the range of certain surface-to-air threats. PADS efforts are focused on hardware and software enhancements supporting airdrop delivery of cargo and resources while enabling Command and Control (C2) of aircrews and payloads during mission execution. These software upgrades will increase the survivability and lethality of our mobility forces. MPS are foundational to effective airpower projection and mission execution. MPS aircraft mission planning software integrates the latest tasking orders, mission profile, order of battle, routes, weight and balance, formation, payload, cargo, intelligence, weather, aircraft performance, autonomous air vehicle and weapon flight out models, and threat data into flight systems and associated Battle Management systems and networks. This integrated operating picture is used pre-flight to prepare the crew and aircraft for each mission; in-flight to receive and respond to C2 direction, enhance survivability, and react to mission changes; and post-flight for aircrew, intelligence, and maintenance debriefing. MPS Joint Mission Planning System (JMPS), utilized by USAF and the U.S. Navy (USN), focuses solely on pre-mission planning operations. Modernization efforts, including JMPS Open Mission System (JOMS), focus on connected and disconnected planning and execution for all phases of mission planning (pre-mission, in-flight, and post-mission planning). Software development is essential for real-time mission data Command, Control, Computers, Communications, Cyber, Intelligence, Surveillance, Reconnaissance, Position, Navigation, and Timing (C5ISRC-PNT) updates and collaboration with mission partners as well as dynamic mission replanning for evolving conditions and sharing post-mission data to inform follow on operations. Additionally, MPS is lead on Theater Air Planning System of Systems (TAP-SoS) efforts to enable mission planning modernization integration and real-time data sharing with multiple C5ISRC-PNT systems, including but not limited to Advanced Battle Management System (ABMS), Air Operations Centers, and Mobility Air Force C2 (MAFC2) across the Department of the Air Force (DAF) BATTLE NETWORK (DBN). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0208006F / Mission Planning Systems Operational Systems Development Efforts within this program align with and depend upon USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (0207410F), All Domain Common Platform (0303248F), Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F), Flight Operations (0207461F), and Advanced Battle Management System (ABMS) (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities required for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F or 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. Common services will be built upon in FY27 for future platform releases. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L043$$, $$Surface Ship Torpedo Def (SSTD)$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 144425000, 133803000, 134637000, NULL, $${"page": 96, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "43", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 39", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 142355, "p1_line_num": 39, "fy27_total_K": 142355}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 144425, "li_num": 39, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 144425000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 9647000, 14915000, 142355000, 142355000, 0, 142355000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208007F$$, $$Tactical Deception$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 13711000, 35250000, 539000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0208007F"}$$::jsonb, $$Tactical Deception is a Service program to provide a suite of technologies that will enable the USAF to minimize, distort, or create signatures. This includes technologies to confuse or mislead all major categories of adversary sensors. These capabilities can reduce confidence in adversary assessments, exhaust intelligence enterprises, and disrupt targeting cycles. In addition, these technologies and tactics techniques and procedures (TTPs) can be employed across the competition continuum for deterrence or advantage in conflict. Tac-D, CISR also supports all activities and costs needed to support the Air Force to further these types of development projects, as well as, required program support costs (PSC). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. In FY24 $0 million was expended for civilian pay expenses in this program element, and in FY25 $200 thousand is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 25730000, 12572000, 12613000, NULL, NULL, 212, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 519000, 13523000, 48857000, 48857000, 0, 48857000, 12862000, $$Tactical Deception (Tac-D) is a Service program to provide a suite of technologies that will enable the USAF to minimize, distort, or create signatures. This includes technologies to confuse or mislead all major categories of adversary sensors. These capabilities can reduce confidence in adversary assessments, exhaust intelligence enterprises, and disrupt targeting cycles. In addition, these technologies and tactics techniques and procedures (TTPs) can be employed across the competition continuum for deterrence or advantage in conflict. Tac-D, Counter- Intelligence, Surveillance, and Reconnaissance (C-ISR) also supports all activities and costs needed to support the Air Force to further these types of development projects, as well as required program support costs (PSC). This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0208007F / Tactical Deception Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208030F$$, $$War Reserve Materiel - Ammunition$$, $$rdte_af_ba4$$, $$acc$$, 2026, 9865000, 7897000, 5226000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0208030F"}$$::jsonb, $$The Operational Weaponeering and Analysis (OWA) project provides mission critical classified weapons' effectiveness analysis and Modeling and Simulation (M&S) tools in direct support of the Air Combat Command (ACC) Targeting mission. The M&S Targeting tool capabilities are designed to meet both Air Force (AF) Master Plan and DoD National Defense Strategy objectives and LOEs. The program is integrating ACC and AFRL MAJCOM goals to establish a Digital Engineering and Transformation path to create a ‘pipeline' of capabilities that will support weapon and target requirements integration from R&D to Operational Warfighting within ACC, Combatant Commands (CCMDs), and other DoD Intelligence Agencies. OWA provides mission critical National Security Software (NSS) M&S software to meet instructions and directives found in CJCSI 3160 and 3170, as well as, AFI 14-401 and JP 3-60. M&S classified software tools are operationally critical to overall mission success and weapons employment. Weapons employment is not legally possible until a complete target and weapon analysis has been completed. The classified M&S software tools are in constant development to support evolving weapon phenomenology (conventional, directed energy, high power microwave, cyber, hypersonic, etc.) within the Weapons PEO and target modeling of a wide range of multi-domain targets, which includes structural, ground mobile, ships, and more. The Integrated Munitions Effects Analysis (IMEA) software is a classified mission critical program that provides Air Force Operational Warfighters with unique analytical capabilities. These unique capabilities are associated with Hard Deeply Buried Targets (HDBTs), Nuclear Weapons, and Weapons of Counter Mass Destruction (C- WMD) weapons employment. In addition, IMEA also analyzes national strategic sites facility defeat information with Nuclear and WMD weapons in support of Global Strike Command operational warfighter requirement. IMEA is also the software for Massive Ordinance Penetrator (MOP) and Massive Ordinance Air Blast (MOAB) lethality estimates in DoD. The Air Force Target and Effect Software (AFTES) provides an all-domain weapon and target capability to support Advanced Target Development and Intermediate Target Development within ACC and Joint environments. This classified software creates software that is digital, agile, and open. The tool is focused on integration of capabilities from ABMS into the JADC2 environment within a single open Modelling and Simulation (M&S) Engagement Framework to provide capabilities to the tactical edge. In addition, AFTES will draw it requirements from the ACC Agile Combat Employment (ACE) LOE to meet objectives laid out by the CSAF. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0208030F / War Reserve Materiel - Ammunition Component Development & Prototypes (ACD&P) In addition to operational support, IMEA and AFTES provides analytical reachback for both operational and weapon acquisition communities. OWA also aligns with Air Force Research Laboratory (AFRL) and Defense Threat Reduction Agency (DTRA) Research and Development (R&D) weapon lethality and effectiveness missions to create an R&D pipeline of capabilities all maintained in a single M&S software framework which allows the software to be easily developed, deployed, and maintained within the OWA Division. The AF assumed operational support and development of the IMEA program from the Defense Threat Reduction Agency in FY22. DTRA will continue to support Air Force with basic R&D research of new capabilities associated with HDBT, Nuclear, and WMD as defined by Memorandum of Agreement (MOA) between DTRA and the AF. OWA has become the operational transition partner for DTRA and AFRL to integrate and field all weapon and target R&D technology to AF and other Joint Environments. This program leverages Digital acquisition tenets of open, agile, and digital. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY24 $.000 thousand was expended for civilian pay expenses in this program element, and in FY25 $.000 thousand is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $545 thousand for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 9939000, 10171000, 10374000, NULL, NULL, 74, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 5042000, 9732000, 14663000, 14663000, 0, 14663000, 10595000, $$The Operational Weaponeering and Analysis (OWA) project provides mission critical classified weapons' effectiveness analysis and Modeling and Simulation (M&S) tools in direct support of the Air Combat Command (ACC) Targeting mission. The M&S Targeting tool capabilities are designed to meet both Air Force (AF) Master Plan and DoW National Defense Strategy objectives and LOEs. The program is integrating ACC and AFRL MAJCOM goals to establish a Digital Engineering and Transformation path to create a ‘pipeline' of capabilities that will support weapon and target requirements integration from R&D to Operational Warfighting within ACC, Combatant Commands (CCMDs), and other DoW Intelligence Agencies. OWA provides mission critical National Security Software (NSS) M&S software to meet instructions and directives found in CJCSI 3160 and 3170, as well as, AFI 14-401 and JP 3-60. M&S classified software tools are operationally critical to overall mission success and weapons employment. Weapons employment is not legally possible until a complete target and weapon analysis has been completed. The classified M&S software tools are in constant development to support evolving weapon phenomenology (conventional, directed energy, high power microwave, cyber, hypersonic, etc.) within the Weapons PEO and target modeling of a wide range of multi-domain targets, which includes structural, ground mobile, ships, and more. The Integrated Munitions Effects Analysis (IMEA) software is a classified mission critical program that provides Air Force Operational Warfighters with unique analytical capabilities. These unique capabilities are associated with Hard Deeply Buried Targets (HDBTs), Nuclear Weapons, and Weapons of Counter Mass Destruction (C- WMD) weapons employment. In addition, IMEA also analyzes national strategic sites facility defeat information with Nuclear and WMD weapons in support of Global Strike Command operational warfighter requirement. IMEA is also the software for Massive Ordinance Penetrator (MOP) and Massive Ordinance Air Blast (MOAB) lethality estimates in DoW. The Air Force Target and Effect Software (AFTES) provides an all-domain weapon and target capability to support Advanced Target Development and Intermediate Target Development within ACC and Joint environments. This classified software creates software that is digital, agile, and open. The tool is focused on integration of capabilities from ABMS into the JADC2 environment within a single open Modelling and Simulation (M&S) Engagement Framework to provide capabilities to the tactical edge. In addition, AFTES will draw it requirements from the ACC Agile Combat Employment (ACE) LOE to meet objectives laid out by the CSAF. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0208030F / War Reserve Materiel - Ammunition Component Development & Prototypes (ACD&P) In addition to operational support, IMEA and AFTES provides analytical reachback for both operational and weapon acquisition communities. OWA also aligns with Air Force Research Laboratory (AFRL) and Defense Threat Reduction Agency (DTRA) Research and Development (R&D) weapon lethality and effectiveness missions to create an R&D pipeline of capabilities all maintained in a single M&S software framework which allows the software to be easily developed, deployed, and maintained within the OWA Division. The Air Force assumed operational support and development of the IMEA program from the Defense Threat Reduction Agency in FY22. DTRA will continue to support Air Force with basic R&D research of new capabilities associated with HDBT, Nuclear, and WMD as defined by Memorandum of Agreement (MOA) between DTRA and the AF. OWA has become the operational transition partner for DTRA and AFRL to integrate and field all weapon and target R&D technology to AF and other Joint Environments. This program leverages Digital acquisition tenets of open, agile, and digital. Invests in analytical, information management, data management, digital environments, networks, facilities, and security infrastructure upgrades directly supporting development and sustainment of this program's capabilities, while leveraging DoW and DAF enterprise IT solutions. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604617F_ba5$$, $$Agile Combat Support$$, $$rdte_af_ba5$$, $$aflcmc_az$$, 2026, 23474000, 50747000, 23635000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0604617F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208036F$$, $$Medical C-CBRNE Programs$$, $$rdte_af_ba5$$, $$acc$$, 2026, 0, 2006000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0208036F"}$$::jsonb, $$Current projects in this program include Aeromedical Readiness (Project 654910). Aeromedical Readiness projects provide aerospace medical systems and treatment equipment to improve casualty care and meet worldwide warfighter medical operational requirements. Aeromedical Readiness provides key aeromedical devices, life-saving capabilities and quality of life technologies and equipment. This program enables the critical care of combat casualties by further developing and optimizing existing technologies for ground Expeditionary Medical Systems (EMEDS) and aeromedical evacuation systems. EMEDS and aeromedical evacuation systems provide the urgent care needed to treat deployed injured warfighters and return them to duty while in country, and to treat combat casualties that need to be safely transported to a stateside hospital for follow on treatment. The program also supports critical capabilities development in the multi-disciplinary areas for light-weight, durable, and rapidly deployable medical equipment to ensure the Air Force is poised to meet future medical readiness and operational requirements, to include but not limited to Spinal Immobilization Transport Device (SIT-D), Pathogen Detection Capability, Automated Vision Testing, Whole Blood Transport and other FDA approved medical treatment devices. This program supports projects ranging from research efforts to optimize human physiologic and cognitive performance for Air Combat Command, to development of patient isolation and transportation devices for Air Mobility Command that enable aeromedical evacuation of patients suffering with highly infectious diseases. In FY 2024, PE 0604617F, (Agile Combat Support), Project 654910, (Aeromedical Readiness) efforts were transferred to PE 0208036F, (Medical Counter-CBRN), Project 654910, (Aeromedical Readiness), in order to consolidate Combat Support medical readiness requirements under a single PE. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0208036F / Medical C-CBRNE Programs Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 113, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1203913SF$$, $$NUDET Detection System (SPACE)$$, $$rdte_sf_ba7$$, $$ssc_milcom$$, 2026, 96836000, 0, 83426000, NULL, $${"source": "jbook_fy26"}$$::jsonb, $$Universal Ground NDS Terminal (UGNTs) 7 modernization effort, a FY26 new start, is the USG's only Survivable/Endurable (S/E) system capable of processing United States Nuclear Detonation (NUDET) data from the next-gen NDS payloads on GPS IIIF. Obsolete hardware and software will be replaced within the UGNT trailers. Integrated Correlation and Display Systems (ICADS 7) will be installed on the system enabling UGNT to be fully mission capable (FMC) and to download nuclear detonation data from GPS IIIF satellites enabling DoD and COCOM decision makers to have near-real time decision quality data for nuclear force management in support of the NC3 mission set. The NUDET Detection System (USNDS) provides a near real-time worldwide, highly survivable/endurable capability to detect, locate, and report any nuclear detonations in the earth's atmosphere or in near space. USNDS supports NUDET detection requirements across five mission areas: Integrated Tactical Warning and Attack Assessment (ITW/AA), Nuclear Force Management (NFM), Space Control, Treaty Monitoring, and a classified mission. The USNDS program is jointly sponsored and funded by the Department of Defense (DoD), through the Space Force, and the Department of Energy (DOE), through the National Nuclear Security Administration (NNSA) and its Nuclear Detonation Detection (NA-22) office, respectively. NNSA/NA-22 supplies USNDS space sensors as Government Furnished Equipment to the Space Force's USNDS Program Office, which is responsible for all acquisition and Systems Engineering, Integration and Test activities on Space Vehicles (SVs), to include Global Positioning System (GPS) and additional hosts, and their supporting ground control segments. The AF directly funds the development of the USNDS ground segment (described below). DoD funds their contribution to the USNDS program in Program Element 1203913SF, Research, Development, Test and Evaluation, Space Force (RDT&E, SF), Procurement, Space Force, and Operations and Maintenance. USNDS consists of space sensors and complex ground segments. The space segment sensors, funded by DOE, consists of three nuclear detection sensor payloads: the Radiation Detection Capability (RADEC) payload for Defense Support Program (DSP) satellites, the Global Burst Detection (GBD) payload for Medium Earth Orbit platforms (GPS satellites), and the Space Atmospheric Burst Reporting System (SABRS) payload for Geosynchronous Earth Orbit (GEO) platforms (classified GEO host), and Space Test Platform 3. Together, these sensors and associated communications capability provided by the host satellites comprise the global NUDET space segment detection capability for the USNDS. Space sensors communicate NUDET indications to the fixed ground segment, the RADEC Data Processor, and the Integrated Correlation and Display System (ICADS), the five deployable mobile ground segment survivable Ground Nuclear Detonation Detection System Terminals Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:          PE 1203913SF / NUDET Detection System (SPACE) Operational Systems Development (GNTs), and the survivable/endurable UGNTs, when operationally accepted. The ground segment provides ground receiving analysis and reporting capabilities to national authorities, commands, and forward users as well as Department of State for the Treaty Monitoring and Verification mission. The ground control segment is being modernized and continuously improved through an incremental, evolutionary acquisition approach. The upgrades to the GNTs are the survivable/endurable UGNT which are funded with RDT&E in this program. The UGNT provides NUDET Detection Reports to end users through survivable/endurable USNDS communications via MilStar/Future Communication Systems (FCS)/Advanced Extremely High Frequency (AEHF) circuits. The GNT supports ITW/AA and NFM missions. The UGNT program modifies the baseline of the GNT subsystem and deploys as an integral part of the Space Based Infrared System Survivable (SBIRS) / Endurable Evolution (S2E2) Mobile Ground System (MGS) (SMGS) units also in support of ITW/AA and NFM. The UGNT, when integrated with the SMGS, will perform NUDET event processing with fused NDS data from GPS and DSP. SMGS capability refers to the result of the S2E2 upgrade program for the MGS mission processing capability, including the integration of UGNT. The intended end state of UGNT integration is delivery of enhanced NUDET detection capabilities which meet survivable/endurable attack assessment requirements directed by the President, Secretary of Defense, Joint Staff, USSPACECOM, and USSTRATCOM, delivering long-term, cost effective, multi-role, multi-mission space effects to warfighters across the range of military operations. ICADS 7 upgrades the ICADS 6 baseline necessary to process future GPS IIIF satellites GBD USNDS messages, address technology obsolescence, and meet updated cybersecurity requirements for system resiliency. Universal Ground NDS Terminal (UGNTs) 7 are a component of the S2E2 Force Package (FPAK). UGNT upgrades will be of the S2E2 system. The UGNT hardware and software (ICADS 6) requires an upgrade to be compatible with GPS IIIF satellites. USNDS detect, identify, locate, and report nuclear detonations in earth's atmosphere or near-space in near real time from peacetime through nuclear conflict. UGNTs provide mobile S/E NUDET reporting capability. USNDS has five missions per operational requirement document (ORD); ITW/AA, Space Control, Nuclear Force Management, Treaty Monitoring & Classified Mission. UGNT 7 is dependent on firm CONOPS being established. This budget line includes systems engineering, research and development, on-orbit and field testing and end-to-end verification of USNDS space sensors, ground analysis and reporting systems in support of the five USNDS mission areas. Sensor integration for GPS III and GPS III Follow-on (IIIF) are funded in their respective programs. This program may include necessary civilian pay expenses required to manage, execute, and deliver NUDET Detection System (SPACE) weapon system capability. The use of such program funds is in addition to the civilian pay expenses budgeted in programs 1206392SF and 1206398SF. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                     Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:         PE 1203913SF / NUDET Detection System (SPACE) Operational Systems Development$$, NULL, 99892000, 71910000, 9271000, NULL, NULL, 66, $$FY26 Space Force Research and Development Test and Evaluation.pdf$$, NULL, FALSE, 83426000, 96836000, 114004000, 114004000, 0, 114004000, 9750000, $$The Program Office is developing the Universal Ground NUDET Detection System (NDS) Terminal (UGNT) 7 modernization effort (Project 672808) for Guardians across Missile Warning and Missile Tracking (MW/MT) mission area. As a result, the Service will improve readiness and operational reach of existing force structure. The UGNT 7 modernization effort is the Survivable/Endurable (S/E) system capable of processing United States Nuclear Detonation (NUDET) data from the next-gen NDS payloads on Global Positioning System (GPS) IIIF. The receiver development portion is included as part of the Integrated Correlation and Display Systems (ICADS) 7 strategy. Portions of hardware and software will be replaced within the UGNT trailers. ICADS 7 software baseline will require updates and to be installed in UGNTs, enabling them to be Fully Mission Capable. These updates are required to download nuclear detonation data from GPS IIIF satellites enabling Department of War (DoW) and Combatant Command decision makers to have near-real time decision quality data for nuclear force management in support of the Nuclear Command, Control and Communication (NC3) mission set. The United States NUDET Detection System (USNDS) provides a near real-time worldwide, highly survivable/endurable capability to detect, locate, and report any nuclear detonation in the earth's atmosphere or in near space. USNDS supports NUDET detection requirements across five mission areas: Integrated Tactical Warning and Attack Assessment (ITW/AA), Nuclear Force Management (NFM), Space Control, Treaty Monitoring, and a classified mission. The USNDS program is jointly sponsored and funded by the DoW, through the Space Force, and the Department of Energy (DOE), through the National Nuclear Security Administration (NNSA) and its Nuclear Detonation Detection office (NA-22), respectively. NNSA/NA-22 supplies USNDS space sensors as Government Furnished Equipment to the Space Force's USNDS Program Office, which is responsible for all acquisition and Systems Engineering, Integration and Test activities on Space Vehicles (SVs), to include GPS and additional hosts, and their supporting ground control segments. The USSF directly funds the development of the USNDS ground segment (described below). DoW funds their contribution to the USNDS program in Program Element 1203913SF, Research, Development, Test and Evaluation, Space Force (RDT&E, SF), Procurement, Space Force, and Operations and Maintenance. USNDS consists of space sensors and complex ground segments. The space segment sensors, funded by DOE, consists of three nuclear detection sensor payloads: the Radiation Detection Capability (RADEC) payload for Defense Support Program (DSP) satellites, the Global Burst Detection (GBD) payload for Medium Earth Orbit platforms (GPS satellites), and the Space Atmospheric Burst Reporting System (SABRS) payload for Geosynchronous Earth Orbit (GEO) platforms (classified GEO Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:            PE 1203913SF / NUDET Detection System (SPACE) Operational Systems Development host), and Space Test Platform 3. Together, these sensors and associated communications capability provided by the host satellites comprise the global NUDET space segment detection capability for the USNDS. Space sensors communicate NUDET indications to the fixed ground segment, the RADEC Data Processor, and the ICADS, the five deployable mobile ground segment survivable Ground Nuclear Detonation Detection System Terminals (GNTs), and the survivable/endurable UGNTs. The ground segment provides ground receiving analysis and reporting capabilities to national authorities, commands, and forward users as well as Department of State for the Treaty Monitoring and Verification mission. The ground control segment is being modernized and continuously improved through an incremental, evolutionary acquisition approach. The upgrades to the GNTs are the survivable/endurable UGNT which are funded with RDT&E in this portfolio. The UGNT provides NUDET Detection Reports to end users through survivable/endurable USNDS communications via MilStar/Future Communication Systems (FCS)/Advanced Extremely High Frequency (AEHF) circuits. The GNT supports ITW/AA and NFM missions. The UGNT program modifies the baseline of the GNT subsystem and deploys as an integral part of the Space Based Infrared System (SBIRS) Survivable / Endurable Evolution (S2E2) Mobile Ground System (MGS) (SMGS) units also in support of ITW/AA and NFM. The UGNT, when integrated with the SMGS, will perform NUDET event processing with fused NDS data from GPS and DSP. SMGS capability refers to the result of the S2E2 upgrade program for the MGS mission processing capability, including the integration of UGNT. The intended end state of UGNT integration is delivery of enhanced NUDET detection capabilities which meet survivable/endurable attack assessment requirements directed by the President, Secretary of War, Joint Staff, USSPACECOM, and USSTRATCOM, delivering long-term, cost effective, multi-role, multi-mission space effects to warfighters across the range of military operations. ICADS 7 upgrades the ICADS 6 baseline necessary to process future GPS IIIF satellites GBD USNDS messages, address technology obsolescence, and meet updated cybersecurity requirements for system resiliency. UGNT 7 is a component of the S2E2 Force Package (FPAK). UGNT 7 upgrades will be part of the S2E2 system. The UGNT hardware and software (ICADS 6) requires an upgrade to be compatible with GPS IIIF satellites. USNDS detect, identify, locate, and report nuclear detonations in earth's atmosphere or near-space in near real time from peacetime through nuclear conflict. UGNTs provide mobile S/E NUDET reporting capability. USNDS has five missions per operational requirement document (ORD); ITW/AA, Space Control, Nuclear Force Management, Treaty Monitoring & Classified Mission. UGNT 7 is dependent on firm CONOPS being established. This budget line includes systems engineering, research and development, on-orbit and field testing and end-to-end verification of USNDS space sensors, ground analysis and reporting systems in support of the five USNDS mission areas. Sensor integration for GPS III and GPS III Follow-on (IIIF) are funded in their respective programs. This program may include necessary civilian pay expenses required to manage, execute, and deliver NUDET Detection System (SPACE) weapon system capability. The use of such program funds is in addition to the civilian pay expenses budgeted in programs 1206392SF and 1206398SF. This program falls within the Missile Warning and Missile Tracking (MW/MT) mission area which provides the multi-orbit space and ground architecture required to detect and track missiles and hypersonic glide vehicles worldwide. Space Force investment program interdependencies include: Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3620F: Research, Development, Test & Evaluation, Space Force / BA 7:        PE 1203913SF / NUDET Detection System (SPACE) Operational Systems Development RDT&E Budget Line Items: Missile Defense Radars (1203873SF); Ballistic Missile EW Systems (1203909SF); Joint Tactical Ground System (1208053SF); NCMC - TW/ AA System (1203906SF); Next - Generation OPIR (1206442SF); Next - Generation - GEO (1206443SF); Next - Generation - Ground (1206440SF); Next - Generation - Polar (1206444SF); Resilient MW / MT - LEO (1206446SF); Resilient MW / MT - MEO (1206447SF) and elements of Procurement Budget Line Item: Space Mods (SPCMOD) This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Space Force Research, Development, Test & Evaluation.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1506_L048$$, $$MAGTF EW for Aviation$$, $$proc_navy_1506_ba5$$, $$peo_aasm$$, 2026, 115545000, 104076000, 97265000, NULL, $${"page": 60, "ba_num": "05", "source": "p1_fy26", "ba_name": "Modification of aircraft", "line_no": "48", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v24": {"ba": "05", "appr": "APN", "title": "P-1 Line 30", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/APN_BA1-4_Book.pdf + APN_BA5_Book.pdf + APN_BA6-7_Book.pdf", "fy27_base_K": 236555, "p1_line_num": 30, "fy27_total_K": 236555}, "appr_code": "1506", "appr_name": "Aircraft Procurement, Navy", "fy26_v179": {"disc_K": 100093, "li_num": 30, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/APN_BA5_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 115545000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 1075841000, 1512666000, NULL, NULL, NULL, FALSE, 25597000, 22356000, 236555000, 236555000, 0, 236555000, NULL, NULL, $$Budget J-Books/FY27/Navy/APN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208043N$$, $$PLANNING AND DECISION AID SYSTEM (PDAS)$$, $$rdte_navy_ba7$$, $$peo_digital$$, 2026, 3572000, 3554000, 3559000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0208043N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 3563000, 3637000, 3713000, NULL, NULL, NULL, NULL, NULL, FALSE, 3545000, 3572000, 3491000, 3491000, NULL, 3491000, 3788000, $$Planning and Decision Aid System (PDAS): PDAS is a classified, protected program operated by the Navy. PDAS is a command and control system that provides capabilities to Office of the Secretary of War, services, Unified Combatant Commanders (CCMD), Intelligence Community and Coalition partners for operational planning/coordination of special access programs (SAPs). PDAS enables Integrated Joint Special Technical operations (IJSTO) to incorporate SAPs into operational planning and execution from battlefield operators through the Commander-in-Chief in support of national security objectives. PDAS is the system for the Chairman of the Joint Chiefs of Staff (CJCS) for IJSTO. PDAS is a worldwide network protecting sensitive information that meets the Intelligence Community Directive 503 security requirements. PDAS provides office automation packages, document and information management tools; collaboration, voice, and video tools in a secure, flexible architecture that promotes a distributed enterprise. Within the enterprise, PDAS users have access to their data regardless of log-on location, secure data exchange, conferencing and planning sessions among physically distributed continental United States and outside continental United States locations. PDAS provides users with access to a Help Desk and remote troubleshooting within the PDAS enterprise. As the number of capabilities increase and threats evolve, the need for development of innovative and efficient planning and collaboration tools necessitates the use of research and development for future implementation.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208045K$$, $$C4I Interoperability$$, $$rdte_dw_ba6$$, $$dw_disa$$, 2026, 70893000, 66108000, 65144000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0208045K", "page_header": "Defense-Wide"}$$::jsonb, $$The Joint Interoperability Test Command (JITC) is the only joint element of the Department of Defense’s (DoD) Major Range and Test Facility Base (MRTFB) that primarily performs Test and Evaluation (T&E) of Information Technology and National Security Systems (IT/NSS) in support of Command, Control, Communications, Computers and Intelligence (C4I). JITC is the DoD's only Joint Interoperability Certifier at the only Non-Service Operational Test Agency. Interoperability is vital to the DoD’s success as it allows forces, units and/or systems of military services, and U.S. partners to share data, information, materiel, and services required to operate collaboratively. Operational testing addresses critical issues of a system's effectiveness in combat-like environments. Additionally, operational testing provides decision makers an independent evaluation to better understand the risks and capabilities of a system’s effectiveness, suitability, and cyber- security before fielding to the warfighters. JITC’s T&E efforts determine the degree to which the DoD is fielding interoperable, operationally effective, suitable, and cyber survivable joint warfighting capabilities to achieve DoD’s goal of information superiority. JITC evaluates DoD system and capability conformance to applicable Military Standards and technical specifications and performs Cyber T&E of DoD IT and NSS (including Cloud services and Mobility). Collectively, JITC's Test, Evaluation, and Certification (TE&C) services support DISA's strategy to operate and secure the DISA portion of the DoD Information Network. JITC is responsible for: • Evaluating DoD IT/NSS for Joint/Coalition (involving two or more US military services and/or partner nations) interoperability to provide decision makers objective information on systems issues, risks and capabilities. • Issuing Joint Interoperability Certifications and Assessments to document system functionality and capability. • Conducting operational evaluations of production representative systems to determine how they perform in typical real-world scenarios. • Maintaining a federated IT infrastructure which provides a national test asset to DoD and other organizations as an MRTFB activity. • Providing interoperability mission support to warfighters to enable effective communication and operations between U.S. Military Services and other foreign nations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                                    Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0208045K / C4I Interoperability RDT&E Management Support$$, NULL, 73515000, 73419000, 76423000, NULL, NULL, 209, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 65144000, 70893000, 72581000, 72581000, NULL, 72581000, 76414000, $$The Joint Interoperability Test Command (JITC) is the only joint element of the Department of War’s (DoW) Major Range and Test Facility Base (MRTFB) that primarily performs Test and Evaluation (T&E) of Information Technology and National Security Systems (IT/NSS) in support of Command, Control, Communications, Computers and Intelligence (C4I). JITC is the DoW's only Joint Interoperability Certifier at the only Non-Service Operational Test Agency. Interoperability is vital to the DoWs success as it allows forces, units and/or systems of military services, and U.S. partners to share data, information, materiel, and services required to operate collaboratively. Operational testing addresses critical issues of a system's effectiveness in combat-like environments. Additionally, operational testing provides decision makers an independent evaluation to better understand the risks and capabilities of a system’s effectiveness, suitability, and cyber- security before fielding to the warfighters. JITC’s T&E efforts determine the degree to which the DoW is fielding interoperable, operationally effective, suitable, and cyber survivable joint warfighting capabilities to achieve DoW’s goal of information superiority. JITC evaluates DoW system and capability conformance to applicable Military Standards and technical specifications and performs Cyber T&E of DoW IT and NSS (including Cloud services and Mobility). Collectively, JITC's Test, Evaluation, and Certification (TE&C) services support DISA's strategy to operate and secure the DISA portion of the DoW Information Network. JITC is responsible for: • Evaluating DoW IT/NSS for Joint/Coalition (involving two or more US military services and/or partner nations) interoperability to provide decision makers objective information on systems issues, risks and capabilities. • Issuing Joint Interoperability Certifications and Assessments to document system functionality and capability. • Conducting operational evaluations of production representative systems to determine how they perform in typical real-world scenarios. • Maintaining a federated IT infrastructure which provides a national test asset to DoW and other organizations as an MRTFB activity. • Providing interoperability mission support to warfighters to enable effective communication and operations between U.S. Military Services and other foreign nations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0208045K / C4I Interoperability RDT&E Management Support$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208059JCY$$, $$CYBERCOM Activities$$, $$rdte_dw_ba4$$, $$dw_cybercom$$, 2026, 30212000, 65484000, 35700000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0208059JCY", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 32531000, 33111000, 33967000, NULL, NULL, NULL, NULL, NULL, FALSE, 35700000, 30212000, 31735000, 31735000, NULL, 31735000, 34272000, $$This program provides the foundational engineering, analytic rigor, and IT development required for U.S. Cyber Command (USCYBERCOM) to plan, direct, and synchronize full‑spectrum cyberspace operations. These investments enable the nation to defend critical infrastructure, impose costs on adversaries in cyberspace, and ensure the Joint Force can operate with confidence in a contested digital environment.$$, $$Budget J-Books/FY27/DW/RDTE_CYBERCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208085JCY$$, $$Robust Infrastructure$$, $$rdte_dw_ba7$$, $$dw_cybercom$$, 2026, 141522000, 133630000, 0, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0208085JCY", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 162405000, 165638000, 168925000, NULL, NULL, NULL, NULL, NULL, FALSE, 127372000, 88522000, 155613000, 155613000, NULL, 155613000, 172303000, $$The U.S. Cyber Command (USCYBERCOM) conducts full‑spectrum cyberspace operations to deter or defeat strategic threats to United States interests and critical infrastructure, ensure mission assurance for the operation and defense of the Department of War Information Environment (DoWIE), and support the achievement of Joint Force objectives. The Robust Infrastructure Program Element provides the platforms, operational environments, and enabling infrastructure required to conduct both Offensive Cyberspace Operations (OCO) and Defensive Cyberspace Operations (DCO). These capabilities ensure the Cyber Mission Force (CMF) can generate, deploy, and sustain cyberspace effects in support of national and combatant commander requirements. The Joint Common Access Platform (JCAP) is USCYBERCOM’s enterprise platform for executing Title 10 OCO. JCAP provides the CMF with a standardized, resilient, and scalable operational environment that enables mission agility, minimizes detection, and ensures precise attribution against approved targets. With the transition of all legacy Service‑specific platforms complete, JCAP is now focused on modernization to deliver the next‑generation platform, incorporating enhanced resilience, operational scalability, and advanced artificial intelligence‑enabled capabilities. The program element also supports DCO through managed unclassified infrastructure that provides virtual tenant environments for Cyber National Mission Force (CNMF) Hunt Forward Operations (HFO). These environments enable CNMF teams to conduct remote defensive missions, analyze partner‑provided data, and identify malicious cyber activity. Robust Infrastructure includes resources for the Cyberspace Rapid Response Platform (CRRP), which provides the CNMF with the ability to rapidly implement new capabilities, tradecraft, and services in response to emergent or crisis scenarios. CRRP enables Joint Task Force ZERO to accelerate access to adversary networks, generate actionable intelligence, and disseminate insights across the Joint Force to counter adversary aggression. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 United States Cyber Command                                                            Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:              PE 0208085JCY / Robust Infrastructure Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_CYBERCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0300_L040$$, $$Major Equipment, DLA$$, $$proc_dw_0300_ba1$$, $$dw_dla$$, 2026, 5212657000, 0, 0, NULL, $${"page": 165, "ba_num": "01", "source": "p1_fy26", "ba_name": "Major equipment", "line_no": "40", "service": "dw", "fy24_qty": null, "fy25_qty": null, "fy27_v27": {"ba": "01", "p1_li": 22}, "appr_code": "0300", "appr_name": "Procurement, Defense-Wide", "fy26_v181": {"li_num": 22, "source": "p1_master_fy26_v181", "source_pdf": "Budget J-Books/FY27/Remaining/FY2027_p1.pdf", "fy26_disc_K": 79251, "fy26_supp_K": 0, "fy26_total_K": 79251, "name_partial": "Major Equipment, DLA"}, "fy26t_qty": null, "fy26d_cost": 0, "fy26r_cost": 5212657000, "ident_code": "B"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 79251000, 19707000, 19707000, 0, 19707000, NULL, NULL, $$Budget J-Books/FY27/DW_Procurement/PROC_DLA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1109_L002$$, $$Amphibious Combat Vehicle Family of Vehi...$$, $$proc_mc_1109_ba2$$, $$peo_lsmc$$, 2026, 790789000, 545109000, 810276000, NULL, $${"ba": "ba2", "ingest": "v17", "source": "p1_fy27", "line_no": "2", "appr_code": "1109", "fy26_v179": {"note": "appropriation_supp_concentrated_on_largest_disc_li", "disc_K": 782441, "li_num": 2, "source": "p40_fy26_v179", "supp_K": 311000, "source_pdf": "uploads/Budget J-Books/FY27/Navy/PMC_Book.txt", "concentrated": true}, "fy26_v197": {"method": "title_fuzzy_match", "delta_K": -311000, "src_pdf": "Budget J-Books/FY27/Navy/PMC_Book.pdf", "applied_at": "2026-05-09T_v197c", "supersedes": "fy26_v179_concentrated_or_v180", "table2_total_K": 311000}, "title_raw": "of Vehicles", "fy27_total_K": 237336}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 810276000, 780296000, 237336000, NULL, 0, 237336000, NULL, NULL, $$Budget J-Books/FY27/Navy/PMC_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208086JCY$$, $$Cyber Training Environment$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 124971000, 114980000, 149145000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0208086JCY", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 137513000, 140262000, 143303000, NULL, NULL, NULL, NULL, NULL, FALSE, 149145000, 124971000, 120814000, 120814000, NULL, 120814000, 146169000, $$In the cyber domain, readiness is perishable. The skills, tools, and teamwork required to counter advanced adversaries demand continuous, high‑fidelity training. The Persistent Cyber Training Environment (PCTE) is the Department of War’s enterprise solution to this challenge, providing a standardized, on‑demand training platform essential for building and certifying the readiness of the Cyber Mission Force (CMF) at the individual, team, and force levels. PCTE delivers a common training capability that maximizes shared content across the Military Services. The platform emulates realistic network environments, integrates with other cyber ranges and training systems, and enables complex, scenario‑based training events that replicate operational conditions. PCTE is managed by the Capability Program Executive for Simulation, Training, Test and Threats (CPE ST3), designated as the Department of War’s acquisition lead for the program. The program is directed by Section 1645 of the FY 2016 National Defense Authorization Act (NDAA). PCTE achieved Milestone B on 06 December 2019 and subsequently received approval to transition from a Major Capability Acquisition program to the Software Acquisition Pathway Execution Phase, as documented in the Acquisition Decision Memorandum signed by the Army Acquisition Executive on 02 May 2025. An updated Cyber Capability Integration and Development System (CCIDS) validated Information System – Capability Development Document (IS‑CDD‑U) was approved on 08 January 2024. Through ongoing rapid prototyping and iterative development, PCTE has delivered a standardized CMF training capability since the release of PCTE Version 2 in FY 2020 and continues to evolve through a continuous integration and continuous delivery (CI/CD) approach. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 United States Cyber Command                                           Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 4:       PE 0208086JCY / Cyber Training Environment Advanced Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/DW/RDTE_CYBERCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L044$$, $$Fixed Surveillance System$$, $$proc_navy_1810_ba2$$, $$navsea$$, 2026, 498597000, 519272000, 465824000, NULL, $${"page": 96, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "44", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 40", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 454161, "p1_line_num": 40, "fy27_total_K": 454161}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 498597, "li_num": 40, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 498597000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 405854000, 352312000, 454161000, 454161000, 0, 454161000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208087F$$, $$Distributed Cyber Warfare Operations$$, $$rdte_af_ba7$$, $$afrl_ri$$, 2026, 31197000, 40457000, 29996000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0208087F"}$$::jsonb, $$Distributed Cyber Warfare Operations (DCWO) consists of a portfolio of programs and projects that conduct Research, Development, Testing and Evaluation (RDT&E) leading to operations-ready offensive cyberspace capabilities. This includes the transition of efforts from laboratory, industry, and academia via studies, accelerated prototyping, and technology demonstrations. DCWO effectiveness comes from balancing acquisition related RDT&E efforts in three Air Force (AF) offensive cyber operations (OCO) mission threads (Off Network, Telephony Network, and the associated Infrastructure that propel the Off Network and Telephony Network mission threads) across three OCO-related subsystems and technical enablers (Platforms, Access, and Cyber Weapons) that enable products, services, and systems in the DCWO portfolio. The resulting DCWO capabilities provide cyber effects to Combatant Commanders and other offensive cyber customers to enable air superiority. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $1.995M was expended for civilian pay expenses in this program element, and in FY25 $2.046M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $1.049 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0208087F / Distributed Cyber Warfare Operations Operational Systems Development$$, NULL, 69404000, 66982000, 46719000, NULL, NULL, 213, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 28792000, 30893000, 71868000, 71868000, 0, 71868000, 47639000, $$Distributed Cyber Warfare Operations (DCWO) consists of a portfolio of programs and projects focused on Research, Development, Testing, and Evaluation (RDT&E). Its purpose is to develop Non-Kinetic Cyber Effects (NKCE) support to Long Range Kill Chains. This is accomplished by increasing fielded technologies focused on increased aircraft survivability and munitions effectiveness to achieve tactical air objectives. The initiative transitions these efforts from laboratories, industry, and academia through studies, accelerated prototyping, and technology demonstrations. To accomplish its mission, success relies on balanced efforts across three Air Force (AF) offensive cyber operations (OCO) mission threads: Off Network, Telephony Network, and their supporting infrastructure. These efforts provide NKCE to Combatant Commanders, ultimately enhancing Cyber Enabled Air Superiority (CEAS). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. The FY 2026 request was reduced by 1.049 Million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222 & Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0208087F / Distributed Cyber Warfare Operations Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208088F$$, $$AF Defensive Cyberspace Operations$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 95034000, 62058000, 89618000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0208088F"}$$::jsonb, $$Air Force Defensive Cyberspace Operations (AF DCO) allows the Department of the AF (DAF) to keep pace with the ever-evolving cyberspace threats. AF DCO develops capabilities that provide the DAF increased assurance in prosecuting air campaigns through enhanced cyber defense and situational awareness over the systems and assets required to enable the movement of forces. AF DCO is building an integrated architecture that extends cyber defense to, and integrates data from, information systems, mission systems, and control systems relevant to air campaigns. The Integrated Defensive Cyberspace System (IDCS) will unify the missions of network defense and cyber protection teams, allowing them to conduct cyber missions from the same system with shared, mission-relevant data. IDCS safeguards AF Information Network (AFIN) and Department of Defense (DoD) network enclaves including their associated computer systems, software applications and sensitive operational information against unauthorized access, intrusion, data exfiltration, corruption, and/or destruction. Legacy system modernization activities have been combined into IDCS (BPAC 677824). The Firestarter effort will continue to be funded in BPAC 677820. Firestarter capabilities will be incrementally integrated to be compatible with and operate within the IDCS. IDCS continually improves its capabilities through modern software delivery practices: continuous research and development (R&D), testing, fielding, and modification based on operational feedback. IDCS is operated by the DAF Total Force, including Active Duty (AD), Air National Guard (ANG), and AF Reserve Command (AFRC) Airmen. IDCS enables rapid deployment of defensive cyber sensor capabilities while disrupting bad actors from exploiting critical vulnerabilities by developing and employing both automated decision making (ADM) and human/machine teaming (HMT) with trained defensive cyber operators. IDCS supports both enterprise (fixed) and edge/mobile use cases and allows the DAF to execute the Cyberspace Vulnerability Assessment/Hunter (CVA/H), AF Cyber Defense (ACD), and Cyber Defense Analysis (CDA) missions. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0208088F / AF Defensive Cyberspace Operations Operational Systems Development IDCS addresses a critical capability gap identified by the Secretary of the AF - the lack of a synchronized, enterprise-level approach to mitigate cyberspace vulnerabilities related to mission performance and/or mission assurance. Failing to address this gap will hinder the DAF ability to project Air Power and dominate in a fight against near-peer adversaries. IDCS integrates with, and makes its data available to, the DAF Data Fabric, Joint Cyberspace Warfighting Architecture (JCWA), and the Advanced Battle Management System (ABMS). IDCS provides increased visibility into health and readiness of cyberspace systems for both local and enterprise commanders. Activities also include various Advisory and Assistance Services (A&AS) and Program Management Administration (PMA) activities to support the aforementioned development efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.953M was expended for civilian pay expenses in this program element, and in FY25 3.237M is forecasted for civilian pay expenses in this program element. In FY25, PE 0208088F, AF Defensive Cyberspace Operations, Project 677821, Cyberspace Vulnerability Assessment, Project 677822, Cyber Defense Analysis, and Project 677823, AFCERT efforts were transferred to PE 0208088F, AF Defensive Cyberspace Operations, Project 677824, Integrated Defensive Cyber System, in order to distinguish IDCS from previous efforts. The FY 2026 request was reduced by $.998 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                    Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0208088F / AF Defensive Cyberspace Operations Operational Systems Development$$, NULL, 93484000, 96260000, 99067000, NULL, NULL, 214, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 83231000, 121433000, 76758000, 76758000, 0, 76758000, 101072000, $$Air Force Defensive Cyberspace Operations (AF DCO) allows the Department of the AF (DAF) to keep pace with the ever-evolving cyberspace threats. AF DCO develops capabilities that provide the DAF increased mission assurance through enhanced cyber defense and situational awareness over the systems and assets required to enable the movement of forces. AF DCO is building an integrated architecture that extends cyber defense to, and integrates data from, information systems, mission systems, and control systems relevant to the DAF. The Integrated Defensive Cyberspace System (IDCS) will unify the missions of network defense and cyber protection teams, allowing them to conduct cyber missions from the same system with shared, mission-relevant data. IDCS safeguards DAF Information Network (DAFIN) and Department of War (DoW) network enclaves including their associated computer systems, software applications and sensitive operational information against unauthorized access, intrusion, data exfiltration, corruption, and/or destruction. Legacy system modernization activities (BPAC 677821, 677822, 677823) have been combined into IDCS (BPAC 677824). The Firestarter effort (BPAC 677820) will deliver the final IDCS related software requirements in FY2026. IDCS continually improves its capabilities through modern software delivery practices: continuous research and development (R&D), testing, fielding, and modification based on operational feedback. IDCS is operated by the DAF Total Force, including Active Duty (AD), Air National Guard (ANG), and AF Reserve Command (AFRC) Airmen. IDCS enables rapid deployment of defensive cyber sensor capabilities while disrupting bad actors from exploiting critical vulnerabilities by developing and employing both automated decision making (ADM) and human/machine teaming (HMT) with trained defensive cyber operators. IDCS supports both enterprise (fixed) and edge/mobile use cases and allows the DAF to execute the Cyberspace Vulnerability Assessment/Hunter (CVA/H), AF Cyber Defense (ACD), and Cyber Defense Analysis (CDA) missions. IDCS addresses a critical capability gap - the lack of a synchronized, enterprise-level approach to mitigate cyberspace vulnerabilities related to mission performance and/or mission assurance. Failing to address this gap will hinder the DAF ability to project Air Power and dominate in a fight against near-peer adversaries. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:          PE 0208088F / AF Defensive Cyberspace Operations Operational Systems Development The Integrated Defensive Cyberspace System (IDCS) integrates with, and makes its data available to, the Department of the Air Force (DAF) Data Fabric, Joint Cyberspace Warfighting Architecture (JCWA), and the Advanced Battle Management System (ABMS). IDCS provides increased visibility into health and readiness of cyberspace systems for both local and enterprise commanders. Activities also include various Advisory and Assistance Services (A&AS) and Program Management Administration (PMA) activities to support the aforementioned development efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. The FY 2026 request was reduced by 0.998 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208099JCY$$, $$Cloud & Unified Platform$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 83039000, 118558000, 106053000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0208099JCY", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 83586000, 85255000, 86936000, NULL, NULL, NULL, NULL, NULL, FALSE, 91550000, 83039000, 84687000, 84687000, NULL, 84687000, 88675000, $$The Joint Cyber Warfighting Architecture (JCWA) cannot function without a foundational, cloud-based platform to host its capabilities and a secure method to move data between its various components. This program element delivers both: The Unified Platform (UP) provides the core infrastructure—the digital factory and fighting platform —for all of JCWA, while the Cross Domain Solution (CDS) provides the accredited, high-speed 'data highways' required to move critical intelligence and operational data securely across classification boundaries. UP provides the cloud-based infrastructure for the Joint Cyber Warfighting Architecture (JCWA) that enables integration of cyberspace operations capabilities, systems, data and analytics for Cyber Mission Forces. Cross Domain Solution (CDS) will deliver development and subject matter expertise to enable a scalable cross domain solution for JCWA based on industry best practices and requirements specified within National Cross Domain Strategy and Management Office (NCDSMO) Raise The Bar Strategy’s Baseline, and National Security Memorandum (NSM)-8 “Improving the Cybersecurity of National Security, Department of War and Intelligence Community Systems."$$, $$Budget J-Books/FY27/DW/RDTE_CYBERCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604776F_ba3$$, $$Deployment & Distribution Enterprise$$, $$rdte_af_ba3$$, $$afrl$$, 2026, 28316000, 0, 19441000, NULL, $${"ba_raw": "6.3", "source": "af_r1_fy26", "original_pe": "0604776F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
