INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1109_L034$$, $$Comm & Elec Infrastructure Supt$$, $$proc_mc_1109_ba4$$, $$mc$$, 2026, 14991000, 46951000, 50593000, NULL, $${"ba": "ba4", "ingest": "v17", "source": "p1_fy27", "line_no": "26", "appr_code": "1109", "fy26_v179": {"disc_K": 19991, "li_num": 26, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/PMC_Book.txt"}, "title_raw": "Unmanned Air Systems (Intel)", "fy27_total_K": 262815}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 763322000, NULL, NULL, NULL, FALSE, 16948000, 16163000, 262815000, NULL, 0, 262815000, NULL, NULL, $$Budget J-Books/FY27/Navy/PMC_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208201F$$, $$Offensive small Unmanned Aircraft Systems (sUAS)$$, $$rdte_af_ba6$$, $$saf_aq$$, 2026, 4985000, 0, 0, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0208201F"}$$::jsonb, $$(U) The Offensive sUAS (O-sUAS) effort identifies requirements addressing capability gaps in the AF ability to rapidly generate a family of sUAS capable of executing Intelligence, Surveillance, and Reconnaissance (ISR), Electronic Warfare, and precision strike in permissive, contested, and denied environments. Funding supports operationalizing the AF UAS Strategy and force-present emerging systems, including exquisite, attributable, and expendable platforms, for collaborative operations within permissive, contested, and denied environments. O-sUAS funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs such as but not limited to Small Business Innovation Research (SBIR) and Small Business Technology Transfer (STTR) programs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2025 0.000 million was expended for civilian pay expenses in this program element, and in FY 2026 0.276 million is forecast for civilian pay expenses in this program element. Items requested in FY26 are representative but not limited to the system development and program support. Items developed during execution may change based on critical equipment needed to support current Air Force mission requirements. Due to the rapidly changing threat environment, the acquisition program manager has the authority to redirect funding as necessary to meet current slated and emerging requirements for operational units. O-sUAS funding also supports innovation activities to include studies, analyses, requirements definition, intelligence and data management activities, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E        PE 0208201F / Offensive small Unmanned Aircraft Systems (sUAS) Management Support$$, NULL, 30168000, 134731000, 134763000, NULL, NULL, 142, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 0, 4917000, 30187000, 30187000, 0, 30187000, 134896000, $$(U) The Offensive small Unmanned Aircraft System (O-sUAS) program fills critical capability gaps by rapidly generating a family of sUAS capable of executing Intelligence, Surveillance, and Reconnaissance (ISR), Electronic Warfare, and precision strike in permissive, contested, and denied environments. Funding supports operationalizing the AF O-sUAS strategy and force-present emerging systems, including exquisite, attritable, and expendable platforms for collaborative operations within permissive, contested, and denied environments. This Program received $58.6 million due to a Rapid Acquisition Authority adjudicated requirement in FY2025 as a result of a classified Urgent Operational Need. The FY2026 spend plan amount for RDT&E includes $4,917 thousand of discretionary and $12,000 thousand of mandatory (reconciliation) for a total of $16,917 thousand. Items requested in FY2027 are representative of but not limited to system development and program support. Items developed during execution may change based on critical equipment needed to support current Air Force mission requirements. Due to the rapidly changing threat environment, the acquisition program manager has the authority to prioritize funding as necessary to meet current and emerging requirements for operational units. O-sUAS funding also supports innovation activities to include studies, analyses, requirements definition, intelligence and data management activities, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion, and future acquisition programs. Commercial off-the-shelf (COTS) hardware and software solutions will be leveraged when able to meet the technical needs of implementing O-sUAS and Command and Control (C2) capabilities in operational environments when applicable. Software will support a wide variety of sUAS, targeting, radio systems and other emerging systems to be employed by AFSPECWAR, SOF, and other Air Force users in the future. Technical maturation efforts will be necessary to maintain interoperability with conventional joint force capabilities including but not limited to joint fire support systems and emerging data networking waveforms. Software upgrades will provide a modular architecture for platforms, digital communications, messaging, data handling, hardware management, targeting, and battle space awareness capabilities. Key characteristics of hardware and software fielding activities will be the agile configuration and development of Modular and Open Systems architectures that will enable rapid integration with new end user devices (such as sensors, laser range finders, radios, Full Motion Video (FMV), targeting and laptops/hand held computing devices, and tactical gateways) and rapid development, testing and fielding of new mission capability modules to meet immediate and future requirements. O-sUAS elements will be aligned and integrated with the Advanced Battle Management System to ensure synergy of effort. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E       PE 0208201F / Offensive small Unmanned Aircraft Systems (sUAS) Management Support This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. In FY2026 $0.949 million was expended for civilian pay expenses in this program element, and in FY2027 $5.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0208288F$$, $$Intel Data Applications$$, $$rdte_af_ba7$$, $$aflcmc_az$$, 2026, 7712000, 5217000, 988000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0208288F"}$$::jsonb, $$Funding supports the development of communication infrastructures required for the application of intelligence data for combat and combat support users. This communication infrastructure must have the ability to apply multiple types of intelligence data such as datasets, databases, models and simulations (M&S), and analysis. Additionally, this funding supports the development of advanced signal processing techniques and the enablement of process automation, data triage, and artificial intelligence (AI) machine learning (AI/ML) algorithms to accelerate the processing and extraction of intelligence data. Objectives include execution of competitive accelerated prototyping efforts, technology demonstrations, and the development, testing and integration of operations-ready applications to existing and future operational Processing, Exploitation and Dissemination (PED) systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 6,773 thousand was expended for civilian pay expenses in this program element, and in FY2025 6,5320 thousand is forecasted for civilian pay expenses in this program element. FY2026 5,196 thousand is forecasted for civilian pay expenses in this program element. Efficiency - Workforce Optimization Reduces 15 civilian personnel full-time equivalents and funding to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative.” FY 2024 Overseas Operations Costs funding accounted for in the Base budget total 5,217 thousand supports Threat Representation and Validation project within Intelligence Data Application program. FY 2025 Overseas Operation Costs funding accounted for in the Base budget total 0.988 thousand supports Threat Representation and Validation project within Intelligence Data Applications program. FY 2026 Overseas Operation Costs funding accounted for in the Base budget total 1.012 thousand supports Threat Representation and Validation project within Intelligence Data Applications program. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0208288F / Intel Data Applications Operational Systems Development FY 2026 request for Intelligence Data Application includes 1,012 thousand of discretionary and 6,700 thousand of mandatory (reconciliation) for a FY26 total of 7,712 thousand. The mandatory funds Threat Representation and Validation. Further information for this reconciliation request is provided in Section 20003 of the Reconciliation Exhibit. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 7753000, 7975000, 7998000, NULL, NULL, 218, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 988000, 1012000, 7511000, 7511000, 0, 7511000, 8166000, $$In FY 2027 Funding supported the development of communication infrastructures required for the application of intelligence data for combat and combat support users. This communication infrastructure was designed to have the ability to apply multiple types of intelligence data such as datasets, databases, models and simulations (M&S), analysis, and Counter Unmanned Aerial Vehicles (C-UAS) data. Additionally, this funding supports the development of advanced signal processing techniques and the enablement of process automation, data triage, and artificial intelligence (AI) machine learning (AI/ML) algorithms to accelerate the processing and extraction of intelligence data. Objectives included execution of competitive accelerated prototyping efforts, technology demonstrations, and the development, testing, and integration of operations-ready applications into existing and future operational Processing, Exploitation, and Dissemination systems. Efficiency-Contract Services Reduces contracts for 0.414 million in FY 2027 in contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0208288F / Intel Data Applications Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
