INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0300206R$$, $$Enterprise Information Technology Systems$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 0, 2077000, 2162000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0300206R", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 2162000, NULL, 0, 0, NULL, 0, 0, $$B. Program Change Summary ($ in Millions)                         FY 2025           FY 2026             FY 2027 Base              FY 2027 OOC               FY 2027 Total Previous President's Budget                                  2.162              0.000                   0.000                          -                    0.000 Current President's Budget                                   2.162              0.000                   0.000                          -                    0.000 Total Adjustments                                            0.000              0.000                   0.000                          -                    0.000 • Congressional General Reductions                      -                  - • Congressional Directed Reductions                     -                  - • Congressional Rescissions                             -                  - • Congressional Adds                                    -                  - • Congressional Directed Transfers                      -                  - • Reprogrammings                                        -                  - • SBIR/STTR Transfer                                    -                  -$$, $$Budget J-Books/FY27/DW/RDTE_DCAA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0301025F$$, $$GeoBase$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 999000, 1458000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0301025F"}$$::jsonb, $$Funds the research and development of AF Civil Engineer (CE) NexGen IT systems for all Total Force installations. The purpose for the funds are to develop/modernize NexGen IT, a Commercial-Off-The-Shelf (COTS) system; specifically to develop a Space Management/Utilization capability as well as new interfaces with other Civil Engineer data systems (i.e. Builder SMS). NexGen IT provides an integrated asset management system for the CE community with the capability to support cost accounting, Operations (Work Management and Material Control), Real Property, Project Management, and Energy Management. NexGen IT replaces several Legacy IT systems that lack the capability to meet present and future mission requirements and the ability to be compliant with Congressionally-mandated Financial Audit Improvement Readiness (FIAR). The Comprehensive Planning Platform (CPP) is a Civil Engineering Enterprise solution that enables installations and 2,800 users to make investment decisions based on asset management principles, strategic guidance, and data through a repeatable planning process. The platform digitally integrates Installation Development Plans (IDPs), Component Plans, & Asset Management Plans (AMPs) - strengthens installation planning & operationalizes asset management responsive to changes at the installation and enterprise by allowing for continuous updates. Funding is necessary to support migration activities from the current SharePoint Online (SPO) environment to Cloud-based servers, as well as support continued development of features necessary for the long-term build out of the CPP. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and deliver NexGen IT and CPP development/modernization for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0207479F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                  Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0301025F / GeoBase Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 219, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 0, 985000, 403000, 403000, 0, 403000, 0, $$Funds the research and development of AF Civil Engineer (CE) NexGen IT systems for all Total Force installations. The purpose for the funds are to develop/modernize NexGen IT, a Commercial-Off-The-Shelf (COTS) system; specifically to develop a Space Management/Utilization capability as well as new interfaces with other Civil Engineer data systems (i.e. Builder SMS). NexGen IT provides an integrated asset management system for the CE community with the capability to support cost accounting, Operations (Work Management and Material Control), Real Property, Project Management, and Energy Management. NexGen IT replaces several Legacy IT systems that lack the capability to meet present and future mission requirements and the ability to be compliant with Congressionally-mandated Financial Audit Improvement Readiness (FIAR). The Comprehensive Planning Platform (CPP) is a Civil Engineering Enterprise solution that enables installations and 2,800 users to make investment decisions based on asset management principles, strategic guidance, and data through a repeatable planning process. The platform digitally integrates Installation Development Plans (IDPs), Component Plans, & Asset Management Plans (AMPs) - strengthens installation planning & operationalizes asset management responsive to changes at the installation and enterprise by allowing for continuous updates. Funding is necessary to support migration activities from the current SharePoint Online (SPO) environment to Cloud-based servers, as well as support continued development of features necessary for the long-term build out of the CPP. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary emergent or unanticipated civilian pay expenses required to manage, execute, and deliver NexGen IT and CPP development/modernization for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0207479F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0301025F / GeoBase Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0301113F$$, $$Cyber Security Intelligence Support$$, $$rdte_af_ba7$$, $$afrl_ri$$, 2026, 14749000, 8476000, 18141000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0301113F"}$$::jsonb, $$Mission Description: Provides funding to the Air Force owned DoD Cyber Crime Center to fund continued development and modifications of cybersecurity tools and activities to support DoD-wide military intelligence efforts to include CADO-IS (formerly CI-PED), Automated Data Obfuscation (ADO) formerly known as STORMSYSTEM, Encompasses specialized range of cyber defense services that support the 2023 National Cybersecurity Strategy with specific focus on protecting companies who do business with the DoD. DC3 lead development, integration, and deployment of network detection solutions that include scalable solutions; real- time alerting; detection/reporting of malicious cyber activity. Located on Defense Industrial Base (DIB) networks to detect data exfiltration or unauthorized access. Sensor program viewed as complementary and more advanced capabilities than legacy efforts (Service-specific sensors, in-house Intrusion Detect Systems, etc.), and DC3 conducts a Capabilities Based Assessment (CBA) for the Defense Forensic Evidence Networked Data Repository (DFENDR) which is a key component of the Law Enforcement Evidence Data Repository (LEEDR) program ongoing at Fort Eisenhower, GA. Activities include but are not limited to development of software/ hardware systems, integration and transition of lab-developed cyber capabilities, developmental testing, operational evaluation, manpower, studies, analysis, pilots, demonstrations, and risk reduction efforts to improve protection of critical technologies. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 $0 was expended for civilian pay expenses in this program element, and in FY2026 $0 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0301113F / Cyber Security Intelligence Support Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 220, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 18141000, 14749000, 0, 0, 0, 0, 0, $$Mission Description: Provides funding to the Air Force owned DoD Cyber Crime Center to fund continued development and modifications of cybersecurity tools and activities to support DoD-wide military intelligence efforts to include CADO-IS (formerly CI-PED), Automated Data Obfuscation (ADO) formerly known as STORMSYSTEM, Encompasses specialized range of cyber defense services that support the 2023 National Cybersecurity Strategy with specific focus on protecting companies who do business with the DoD. DC3 lead development, integration, and deployment of network detection solutions that include scalable solutions; real-time alerting; detection/reporting of malicious cyber activity. Located on Defense Industrial Base (DIB) networks to detect data exfiltration or unauthorized access. Sensor program viewed as complementary and more advanced capabilities than legacy efforts (Service-specific sensors, in-house Intrusion Detect Systems, etc.), and DC3 conducts a Capabilities Based Assessment (CBA) for the Secure Hosted Information Environment for Law Enforcement Data (SHIELD) which is a key component of the Law Enforcement Evidence Data Repository (LEEDR) program ongoing at Fort Eisenhower, GA. Activities include but are not limited to development of software/ hardware systems, integration and transition of lab-developed cyber capabilities, developmental testing, operational evaluation, manpower, studies, analysis, pilots, demonstrations, and risk reduction efforts to improve protection of critical technologies. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 0 was expended for civilian pay expenses in this program element, and in FY2026 0 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0301113F / Cyber Security Intelligence Support Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0301377F$$, $$Countering Advanced Conventional Weapons (CACW)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 1117000, 0, 834000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0301377F"}$$::jsonb, $$Countering Advanced Conventional Weapons (CACW) investment is a Congressionally approved and OUSDI backed focused on improving Scientific and Technical Intelligence (S&TI) for the combined Defense Intelligence Enterprise (DIE) program through the accelerated creation of authoritative threat engineering analysis, weapon system models, and integrated simulation of top-priority threat scenarios. CACW's goal is to increase the overall analytic health of the DIE to meet S&TI analysis and threat Modeling and Simulation (M&S) weapons technical intelligence requirements against near peer threat competitors. CACW investments are a scalable, scenario- based approach to increase S&TI analysis and threat model development capacity across the DIE to close the intelligence gap on the understanding, characterization and impact of top priority threat systems and system-of-systems. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 3.868M was expended for civilian pay expenses in this program element, and in FY2025 5.818 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 1604000, 1634000, 1666000, NULL, NULL, 226, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 834000, 1117000, 1343000, 1343000, 0, 1343000, 1699000, $$Countering Advanced Conventional Weapons (CACW) investment is a Congressionally approved and OUSD(I&S) backed focused on improving Scientific and Technical Intelligence (S&TI) for the combined Defense Intelligence Enterprise (DIE) program through the accelerated creation of authoritative threat engineering analysis, weapon system models, and integrated simulation of top-priority threat scenarios. CACW's goal is to increase the overall analytic health of the DIE to meet S&TI analysis and threat Modeling and Simulation (M&S) weapons technical intelligence requirements against near peer threat competitors. CACW investments are a scalable, scenario-based approach to increase S&TI analysis and threat model development capacity across the DIE to close the intelligence gap on the understanding, characterization and impact of top priority threat systems and system-of- systems. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0301377N$$, $$(U)Countering Advanced Conventional Weapons (CACW)$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 16906000, 17531000, 19517000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0301377N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, NULL, 15942000, 16231000, 16281000, NULL, NULL, 178, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 19517000, 16906000, 15563000, 15563000, NULL, 15563000, 16586000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0301401F$$, $$AF Multi-Domain Non-Traditional ISR Battlespace Awareness$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 2987000, 2890000, 3006000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0301401F"}$$::jsonb, $$Cross Domain Tactical OPIR Processing delivers a mechanism providing reach-back support for battlespace awareness functions and manages the timely transfer of newly developed tools to operational users. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 2.01 million was expended for civilian pay expenses in this program element, and in FY25 3.64 million is forecasted for civilian pay expenses in this program element. Efficiency - Workforce Optimization Reduces 3 civilian personnel full-time equivalents and funding to optimize the workforce in compliance with Executive Order 14210, "Implementing the President's Department of Government Efficiency Workforce Optimization Initiative." Efficiency-Contract Services Reduces contracts for $0.817 million in FY26 in contracts for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0301401F / AF Multi-Domain Non-Traditional ISR Battlespace Awareness Operational Systems Development$$, NULL, 2943000, 3047000, 3115000, NULL, NULL, 228, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 3006000, 2987000, 2754000, 2754000, 0, 2754000, 3184000, $$Cross Domain Tactical OPIR Processing delivers a mechanism providing reach-back support for battlespace awareness functions and manages the timely transfer of newly developed tools to operational users. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0302015F$$, $$E-4B National Airborne Operations Center (NAOC)$$, $$rdte_af_ba7$$, $$afnwc_nc$$, 2026, 54457000, 42074000, 57441000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0302015F"}$$::jsonb, $$The four (4) aircraft E-4B National Airborne Operations Center (NAOC) fleet satisfies the military need for an airborne operations center with communications capabilities permitting military and civilian leadership to monitor and control military and civil national assets during all phases of conflict (nuclear and non-nuclear) or natural disaster. The E-4B NAOC fleet also satisfies the military requirement to provide a highly survivable node of the National Military Command System (NMCS). This program's developmental efforts include, but are not limited to, upgrades and enhancements to aircraft structures, propulsion system, fuel system, environmental control system, electrical generation and distribution systems, flight safety and navigation systems (with their associated communications equipment), and the Systems Integration Lab. Modifications may enhance the aircraft's mission capabilities necessary for the E-4B fleet to execute its mission, to include but not limited to those necessary for the Senior Leadership Command, Control and Communications System (SLC3S), National Leadership Command Capability (NLCC), and Nuclear Command, Control, and Communications (NC3). Funds may also be used to explore and develop modifications, upgrades, and future systems required to meet evolving mission requirements. This budget supports the following developmental modifications and studies/projects currently underway or planned for accomplishment: - Survivable Super High Frequency (SSHF) will upgrade and replace portions of the E-4B's Jam-Resistant Secure Communications (JRSC) system to meet existing Presidential Policy Directive (PPD)-35 and National Security Presidential Directive (NSPD)-51/Homeland Security Presidential Directive (HSPD)-20 requirements and to ensure continued connectivity and interoperability as satellite and communications infrastructure evolves. Expected modifications include, but are not limited to, component and sub-system upgrades and replaces portions of the current Super High Frequency (SHF) system that are obsolete or near end of service life. A replacement to the SHF system is required as secure, survivable communications capability transitions from the Defense Satellite Communications System (DSCS). A risk-reduction study was completed in FY19 to further define the acquisition strategy of the SSHF program. The program will be acquired in 2 increments and each increment will be split into 2 installs to expedite fielding and reduce impact to Aircraft Availability. Increment 1A will upgrade the existing Ka-band system. Increment 1B will include technical solutions such as upgrading the existing modems and systems integration lab. Increment 2A will include new modem technology and common workstation. Increment 2B will include a new Ku-band system upgrades to the X-band system. Due to Air Force priorities, the X-band requirements will be deferred. - The E-4B Systems Integration Laboratory (SIL) program will develop a test environment configured to represent the mission systems of the E-4B with connectivity to mission networks and services. E-4B SIL started as the Test Accreditation Integration Lab (TAIL) 5 for development of the E-4B SSHF program. The E-4B SIL program will expand the capabilities of TAIL 5 beyond SSHF to include the other mission communication systems within the E-4B. The E-4B SIL is necessary to minimize Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0302015F / E-4B National Airborne Operations Center (NAOC) Operational Systems Development modernization and technical refresh schedules by reducing time on aircraft for install, test, ground connections/configurations, technical orders, redlines/rework, and training. Schedule reduction by the E-4B SIL will directly support increased Aircraft Availability (AA). The E-4B SIL will be developed in blocks begin with the Advanced Extremely High Frequency/Presidential National Voice Conferencing (AEHF/PNVC) Backbone being added to the existing SSHF baseline to provide the basic platform communications systems. The next block will incorporate the Mission Equipment Section (MES) systems to allow reproduction of necessary data to operate both the SIL and operational aircraft. The next blocks will continue to build out network and communication systems based their associated priorities and system dependencies. - Touchscreen Executive Phone - Airborne (TXP-A) - effort replaces the existing secure obsolete touch screen phones for senior national leaders to maintain multi-level security. The TXP-A will upgrade computing capabilities of the secure phone and durability of various components such as processors and touch screen displays. The replacement of the TXP-A phones will allow the NAOC to continue to meet Presidential Policy Directive (PPD)-35 requirements across the full spectrum of crisis. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.0M was expended for civilian pay expenses in this program element, and in FY 2025 0.0M is forecasted for civilian pay expenses in this program element. The FY 2026 cost of Middle Tier of Acquisition (MTA) effort E-4B is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 21830000, 2695000, 2744000, NULL, NULL, 229, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 52362000, 55095000, 50873000, 50873000, 0, 50873000, 2799000, $$The four (4) aircraft E-4B National Airborne Operations Center (NAOC) fleet satisfies the military need for an airborne operations center with communications capabilities permitting military and civilian leadership to monitor and control military and civil national assets during all phases of conflict (nuclear and non-nuclear) or natural disaster. The E-4B NAOC fleet also satisfies the military requirement to provide a highly survivable node of the National Military Command System (NMCS). This program's developmental efforts include, but are not limited to, upgrades and enhancements to aircraft structures, propulsion system, fuel system, environmental control system, electrical generation and distribution systems, flight safety and navigation systems (with their associated communications equipment), and the Systems Integration Lab. Modifications may enhance the aircraft's mission capabilities necessary for the E-4B fleet to execute its mission, to include but not limited to those necessary for the Senior Leadership Command, Control and Communications System (SLC3S), National Leadership Command Capability (NLCC), and Nuclear Command, Control, and Communications (NC3). Funds may also be used to explore and develop modifications, upgrades, and future systems required to meet evolving mission requirements. This budget supports the following developmental modifications and studies/projects currently underway or planned for accomplishment: - Survivable Super High Frequency (SSHF) will upgrade and replace portions of the E-4B's Jam-Resistant Secure Communications (JRSC) system to meet existing Presidential Policy Directive (PPD)-35 and National Security Presidential Directive (NSPD)-51/Homeland Security Presidential Directive (HSPD)-20 requirements and to ensure continued connectivity and interoperability as satellite and communications infrastructure evolves. Expected modifications include, but are not limited to, component and sub-system upgrades and replaces portions of the current Super High Frequency (SHF) system that are obsolete or near end of service life. A replacement to the SHF system is required as secure, survivable communications capability transitions from the Defense Satellite Communications System (DSCS). A risk-reduction study was completed in FY 2019 to further define the acquisition strategy of the SSHF program. The program will be acquired in 2 increments and each increment will be split into 2 installs to expedite fielding and reduce impact to Aircraft Availability. Increment 1A will upgrade the existing Ka-band system. Increment 1B will include technical solutions such as upgrading the existing modems and systems integration lab. Increment 2A will include new modem technology and common workstation. Increment 2B will include a new Ku-band system upgrades to the X-band system. Due to Air Force priorities, the X-band requirements will be deferred. - The E-4B Systems Integration Laboratory (SIL) program will develop a test environment configured to represent the mission systems of the E-4B with connectivity to mission networks and services. E-4B SIL started as the Test Accreditation Integration Lab (TAIL) 5 for development of the E-4B SSHF program. The E-4B SIL program will expand the capabilities of TAIL 5 beyond SSHF to include the other mission communication systems within the E-4B. The E-4B SIL is necessary to minimize Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0302015F / E-4B National Airborne Operations Center (NAOC) Operational Systems Development modernization and technical refresh schedules by reducing time on aircraft for install, test, ground connections/configurations, technical orders, redlines/rework, and training. Schedule reduction by the E-4B SIL will directly support increased Aircraft Availability (AA). The E-4B SIL will be developed in blocks begin with the Advanced Extremely High Frequency(AEHF)/Presidential & National Voice Conferencing (PNVC) Integration Program (APIP) Backbone being added to the existing SSHF baseline to provide the basic platform communications systems. The next block will incorporate the Mission Equipment Section (MES) systems to allow reproduction of necessary data to operate both the SIL and operational aircraft. The next blocks will continue to build out network and communication systems based their associated priorities and system dependencies. - Touchscreen Executive Phone - Airborne (TXP-A) - effort replaces the existing obsolete secure touch screen phones for senior national leaders to maintain multi-level security. The TXP-A will upgrade computing capabilities of the secure phone and durability of various components such as processors and touch screen displays. The replacement of the TXP-A phones will allow the NAOC to continue to meet Presidential Policy Directive (PPD)-35 requirements across the full spectrum of crisis. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0302019K$$, $$Defense Info. Infrastructure Engineering and Integration$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 16162000, 18807000, 12843000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0302019K", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Information Infrastructure Engineering and Integration effort encompasses two projects, the Modeling and Simulation End-to-End (E2) Architecture and the DoD Information Network (DoDIN) Systems Support. Within the Modeling and Simulation End-to-End Architecture project, there are two major activities: Modeling and Simulation and Enterprise Architecture. Modeling and Simulation: The Modeling and Simulation activity provides systems engineering and E2E analytical functions for DISA and its customers, ensuring integrated capabilities fulfill warfighter mission requirements. Ongoing beneficiaries of these network modeling, simulation, and analysis capabilities include: • Services and Regional Combatant Commands (COCOMs): Receive modeling analyses and recommendations for architecture changes such as circuit rerouting due to Military Construction and planning for additional sites and the increased capacity for the Pacific theater. • DoD CIO and Services: Receive modeling projections for the utilization of new classified desktop and mobility services to be migrated to cloud environments. • DoD Agencies: Receive training and support on the Joint Communications Simulation System, which is the system used to model network and applications. Additional activity resolves near term (one to three years) high-priority technical issues, as defined by DoD CIO and DISA, that impact operational capabilities, affecting DoDIN E2E interoperability and performance. For example, new DISN Resiliency (HyperCore) architecture, P router removal, Time Division Multiplexing (TDM) Elimination, resolution of poor M365 DoD365-SEC Teams performance or planning for new high bandwidth routers. Additional activities include development and testing of models to simulate planned changes to enterprise services, to include migrating DISA enterprise services to cloud architectures, adding capacity to support new Fourth Estate customers, and completing network changes to support enhanced security. End-to-End (E2E) Architecture: The E2E Architecture effort establishes Enterprise Architecture (EA) development standards, documents and generates needed IT architecture artifacts to provide E2E interoperability and performance analysis, and provides systems engineering support for architecture evolution across DISA. DISA works with its customers to ensure integrated capabilities can fulfill warfighter mission requirements and continuously revises these Enterprise Architectures to meets the needs of the department. Some of the ongoing EA activities and projects include the follow areas: • Create EA development framework, EA taxonomy and associated templates to support agency-wide DoD Architecture Framework (DoDAF)-based architecture development and model-based systems engineering (MBSE) requirements in a standardized, effective way to meet the program and agency mission needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                               Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:              PE 0302019K / Defense Info. Infrastructure Engineering and Integration Operational Systems Development • Help the DISA develop enterprise level architectures to support its mission critical and high priority projects. Examples of work include the development of the DISA Zero Trust Reference Design (ZTRD) architecture; DISA enterprise Privileged Access Management (PAM) solution architecture development and AoA analysis; DOD 5G architecture documentation, DISA Robotics Process Automation (RPA) architecture; DISA DISN Out-of-band (OOB) Management Network architecture and AoA, and other emerging requirements from the agency senior leaders. • Develop capabilities and automated tools to support E2E architecture assessment and analysis in support of data-driven decisions. Examples of activities include developing automated cybersecurity assessments, architecture assessments for future architectures (e.g. SIPR 2.0), and DISA Common Enterprise Service (CES) analysis and recommendations study. DoD Information Network Systems Engineering Support: The DoDIN Systems Engineering and Support project performs research, development, and experimentation of emerging technologies to fill capability shortfalls and technology gaps. Through conducting Technical Exchange Meetings (TEM) with other DoD components, Program Management Offices, and Technical Directors, DISA identifies gaps and shortfalls, pursues innovative solutions, and engages industry for commercial best practices. The DoDIN Systems Engineering and Support project supports technical system engineering reviews for enterprise products and services and resolves gaps related to Machine Learning/Artificial Intelligence (AI), Classified and Unclassified mobile access, Quantum Resistant Cryptography (the cryptography used to authenticate and secure data-in-transit that is susceptible to attacks), Enterprise Architecture development, Cyber Defense, and other technologies.$$, NULL, 13434000, 13673000, 13770000, NULL, NULL, 235, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 12374000, 16162000, 13312000, 13312000, NULL, 13312000, 13770000, $$The Defense Information Infrastructure Engineering and Integration effort encompasses two projects, the Modeling and Simulation End-to-End (E2) Architecture and the DoW Information Network (DoWIN) Systems Support. Within the Modeling and Simulation End-to-End Architecture project, there are two major activities: Modeling and Simulation and Enterprise Architecture. Modeling and Simulation: The Modeling and Simulation activity provides systems engineering and E2E analytical functions for DISA and its customers, ensuring integrated capabilities fulfill warfighter mission requirements. Ongoing beneficiaries of these network modeling, simulation, and analysis capabilities include: • Services and Regional Combatant Commands (COCOMs): Receive modeling analyses and recommendations for architecture changes such as circuit rerouting due to Military Construction and planning for additional sites and the increased capacity for the Pacific theater. • DoW CIO and Services: Receive modeling projections for the utilization of new classified desktop and mobility services to be migrated to cloud environments. • DoW Agencies: Receive training and support on the Joint Communications Simulation System, which is the system used to model network and applications. Additional activity resolves near term (one to three years) high-priority technical issues, as defined by DoW CIO and DISA, that impact operational capabilities, affecting DoWIN E2E interoperability and performance. For example, new DISN Resiliency (HyperCore) architecture, P router removal, Time Division Multiplexing (TDM) Elimination, resolution of poor M365 DoW365-SEC Teams performance or planning for new high bandwidth routers. Additional activities include development and testing of models to simulate planned changes to enterprise services, to include migrating DISA enterprise services to cloud architectures, adding capacity to support new Fourth Estate customers, and completing network changes to support enhanced security. End-to-End (E2E) Architecture: The E2E Architecture effort establishes Enterprise Architecture (EA) development standards, documents and generates needed IT architecture artifacts to provide E2E interoperability and performance analysis, and provides systems engineering support for architecture evolution across DISA. DISA works with its customers to ensure integrated capabilities can fulfill warfighter mission requirements and continuously revises these Enterprise Architectures to meets the needs of the department. Some of the ongoing EA activities and projects include the follow areas: • Create EA development framework, EA taxonomy and associated templates to support agency-wide DoW Architecture Framework (DoWAF)-based architecture development and model-based systems engineering (MBSE) requirements in a standardized, effective way to meet the program and agency mission needs. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                               Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:              PE 0302019K / Defense Info. Infrastructure Engineering and Integration Operational Systems Development • Help the DISA develop enterprise level architectures to support its mission critical and high priority projects. Examples of work include the development of the DISA Zero Trust Reference Design (ZTRD) architecture; DISA enterprise Privileged Access Management (PAM) solution architecture development and AoA analysis; DoW 5G architecture documentation, DISA Robotics Process Automation (RPA) architecture; DISA DISN Out-of-band (OOB) Management Network architecture and AoA, and other emerging requirements from the agency senior leaders. • Develop capabilities and automated tools to support E2E architecture assessment and analysis in support of data-driven decisions. Examples of activities include developing automated cybersecurity assessments, architecture assessments for future architectures (e.g. SIPR 2.0), and DISA Common Enterprise Service (CES) analysis and recommendations study. DoW Information Network Systems Engineering Support: The DoWIN Systems Engineering and Support project performs research, development, and experimentation of emerging technologies to fill capability shortfalls and technology gaps. Through conducting Technical Exchange Meetings (TEM) with other DoW components, Program Management Offices, and Technical Directors, DISA identifies gaps and shortfalls, pursues innovative solutions, and engages industry for commercial best practices. The DoWIN Systems Engineering and Support project supports technical system engineering reviews for enterprise products and services and resolves gaps related to Machine Learning/Artificial Intelligence (AI), Classified and Unclassified mobile access, Quantum Resistant Cryptography (the cryptography used to authenticate and secure data-in-transit that is susceptible to attacks), Enterprise Architecture development, Cyber Defense, and other technologies.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605030F$$, $$Joint Tactical Network Center (JTNC)$$, $$rdte_af_ba5$$, $$aflcmc_hn$$, 2026, 0, 2256000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0605030F"}$$::jsonb, $$No FY 2026 funding requested in the Program Element. No FY 2025 funding was requested in the Program Element. All JTNC funding has been shifted to Army PE 0605030A. The Joint Tactical Networking Center (JTNC) is chartered to enable the Department of Defense (DoD)'s rapid identification, characterization, procurement, fielding, and sustainment of modular, innovative tactical communications products that ensure secure, interoperable, and resilient Command, Control, Communications, Computers, Intelligence, Surveillance, and Reconnaissance (C4ISR) capabilities. The JTNC provides technical expertise to facilitate tactical communications management, innovation, and standardization. The JTNC: (1) maintains a cyber-hardened DoD Information Repository (IR), (2) provides Technical Analyses/Capability Characterizations on tactical communications products, (3) provides Open Systems Architecture Standards, (4) provides exportability analysis and licensing reviews, and (5) serves as Technical Advisor to the Communications, Command, and Control Leadership Board (C3LB) and Tactical Communications Senior Steering Group (TCSSG). JTNC mission is executed in coordination with key government stakeholders to include: C3LB, TCSSG, Communications Technologies and Waveforms Working Group (CTWWG), Resiliency Sub-Working Group (RSWG), the Department of Defense (DoD) Chief Information Officer (CIO), Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), Joint Staff J6 (JS J6), The Under Secretary of Defense for Research and Engineering, abbreviated USD(R&E), and the Services. Particular attention is paid to ensuring that interagency work is collaborative and eliminates duplicative capability. The JTNC enables a common software baseline that is hardware agnostic leading to increased competition for Software Defined Radios (SDR). Current JTNC directed requirements, outlined by the C3LB, consist of the CTWWG, Joint All-Domain Command and Control (JADC2) support, development/maturation of the DoD IR framework & Cloud migration, and development of the Joint Communications Marketplace (JCM) to meet DoD and Industry requirements in conjunction with DoD Instruction 4630.09. Through collaboration with USD R&E (INSS) and industry partners, JTNC is in the process of capturing information on resilient waveform technologies and portfolio products. The ultimate goal is to expedite market research activities by collecting, analyzing, and making data available in support of emerging Government waveform acquisitions. The JTNC and Joint Interoperability Test Command (JITC) co-chair the High-Frequency Interoperability and Architecture Sub- Working Group (HF I&A SWG) to resolve HF 3G and 4G interoperability issues, thus facilitating next-generation HF systems. The JTNC HF team is also pathfinding for a Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0605030F / Joint Tactical Network Center (JTNC) Development & Demonstration (SDD) new tactical MIL-STD to provide more resilient communications. Additionally, the JTNC is engaged in the analysis of software artifacts involving high assurance devices, such as software defined radios ported with specific waveforms to support National Security Agency (NSA) efforts. The JTNC participates in Standards-related activities such as the Interface Control Working Group (ICWG) and has been collaborating with the Army on the development of C4ISR/Electronic Warfare Modular Open Suite of Standards (CMOSS) specifications. Finally, the JTNC continues evolving its Waveform Assessment and Milestone Review (WASMR) and Capability Characterization processes. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, NULL, NULL, NULL, NULL, NULL, 98, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
