INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0302060F$$, $$Looking Glass Next$$, $$rdte_af_ba4$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 409500000, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 65277000, 65277000, 0, 65277000, 0, $$Looking Glass - Next (LG-N) is a pre-Major Defense Acquisition Program (MDAP) to recapitalize the Looking Glass (previously known as Airborne National Command Post (ABNCP)) and provide Intercontinental Ballistic Missile (ICBM) Secondary Launch Capability (SLC). To satisfy operational requirements, the LG-N weapon system will be comprised of an air vehicle, mission systems, and ground support systems. The air vehicle will be hardened to protect against nuclear and electromagnetic effects and use a Modular Open System Approach (MOSA) for a mission system that will integrate secure communications and planning capabilities on modern information technology (IT) infrastructure. The ground systems should include aircrew trainers, mission crew trainers, maintenance training devices, ground support equipment, sustainment system integration laboratories (SIL), and other ground systems to enable the operations, sustainment, and future modifications of the LG-N weapon system across its lifecycle. Program funding includes funds for emerging requirements to support program office operations, management services (Federally Funded Research and Development Centers [FFRDC], Advisory and Assistance Services [A&AS], etc.), Program Management Support (PMS), security, facilities, prototyping, equipment, integrate Digital Engineering and other efforts as required to establish the required program office capabilities. Funding will also support all activities required to award and execute development contract(s) for the LG-N Weapon System to include supporting test activities and prototype, development, sustainment, and integration activities of Nuclear Command, Control, and Communications (NC3) or other Department of War (DoW) programs required to meet mission requirements. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0302060F / Looking Glass Next Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
