INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605229F_ba7$$, $$HH-60W$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 58708000, 0, 39629000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0605229F"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0302315F$$, $$Non-Kinetic Countermeasure Support$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 7006000, 0, 7590000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0302315F"}$$::jsonb, $$Non-Kinetic Countermeasure support at NASIC enables the testing, prototyping, and development efforts for a DoD wide federated data architecture and repository for the specific mission set identified in 2025 Classified CJB MIP Vol 5. The repository will include the tools to provide tailored analysis and visualization to meet the scientific and technical intelligence needs of the acquisition intelligence enterprise, DoD Intelligence Enterprise, and Title 10 operations. The original FY25 PDM that initially funded this PE split the RDT&E funds between two organizations. NASIC's portion of the funding is described above and the other organization and the description of their funds are at a higher classification level. All funding was then programmed in error sending all funds starting in FY25 and through the FYDP to NASIC. Due to the classified nature of the incorrectly programmed the funds sent to NASIC, justification was only provided for NASIC's portion of the funding leading to a cut of half of the FY25 programmed amount. This is a new MIP project in FY25 This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0.427M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0302315F / Non-Kinetic Countermeasure Support Operational Systems Development$$, NULL, 2011000, 0, 0, NULL, NULL, 230, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 7590000, 7006000, 4024000, 4024000, 0, 4024000, 0, $$Non-Kinetic Countermeasure Support (NKCS) at NASIC enables the testing, prototyping, and development efforts for a DoD-wide federated data architecture and repository for the specific mission set identified in 2025 Classified CJB MIP Vol 5. The repository will include the tools to provide tailored analysis and visualization to meet the scientific and technical intelligence (S&TI) needs of the Acquisition Intelligence enterprise, DoD Intelligence Enterprise (DIE), and Title 10 operations. *The FY25 funds split between two organizations. NASIC's portion of the funding is described above and the other organization and the description of their funds are at a higher classification level. All funding was then programmed in error sending all funds starting in FY25 and through the FYDP to NASIC. Due to the classified nature of the incorrectly programmed funds sent to NASIC, justification was only provided for NASIC's portion of the funding leading to a cut of half of the FY25 programmed amount. The programming has been corrected across the FYDP. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
