INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0302315N$$, $$Non-Kinetic Countermeasure Support$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 23818000, 0, 8324000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0302315N", "page_header": "Department of the Navy"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, NULL, 25639000, 26368000, 26356000, NULL, NULL, 179, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 8324000, 23818000, 23146000, 23146000, NULL, 23146000, 26868000, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified budget justification books.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0302609V$$, $$Countering Threats Automated Platform$$, $$rdte_dw_ba7$$, $$dw_dcsa$$, 2026, 5030000, 0, 6057000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0302609V", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 18659000, 18738000, 11816000, NULL, NULL, NULL, NULL, NULL, FALSE, 5617000, 5030000, 11710000, 11710000, NULL, 11710000, 10816000, $$The Defense Counterintelligence Security Agency (DCSA) is a strategic asset to the nation and our allies - continuously ensuring a trusted federal, industrial, and affiliated workforce, and enabling industry's delivery of uncompromised capabilities by leveraging advanced technologies and innovation. DCSA uniquely blends critical technology protection, counterintelligence, security and professional education and certification to advance and preserve America's strategic edge. The DoW Insider Threat Management and Analysis Center (DITMAC) provides an integrated capability to collect and analyze information for insider threat detection and mitigation. The system gathers, integrates, reviews, assesses, and responds to information derived from DoW Insider Threat hubs, Counterintelligence (CI), security, cybersecurity, civilian and military personnel management, workplace violence, anti-terrorism risk management, law enforcement, user activity monitoring on DoW information networks, and other sources as necessary and appropriate to support the identification, mitigation, and countering of insider threats to DoW personnel, assets and information. The Defense Security Analysis and Threat System (DSATS) (formerly referred to as DITMAC System of Systems - DSOS) requires the capability to operate within a self-hosted cloud environment, add new roles, migrate data from legacy systems, integrate and share data with other DCSA and external systems, improve dashboards and reporting, and complete independent verification and validation testing. It also requires adaptation to allow for automated data ingest which will directly support and enhance analytic efforts to focus on areas of increased risk. These features will enable Commanders to better manage insider threat cases at the installation level and will improve analytic capabilities to all levels. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Counterintelligence and Security Agency                               Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0302609V / Countering Threats Automated Platform Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_DCSA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303004F$$, $$EIT CONNECT$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 0, 7923000, 16120000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0303004F"}$$::jsonb, $$This activity builds upon the deployment and connectivity of solutions being delivered under the DAF Advanced Battle Management System (ABMS) Program Element 64003F. The DAF executed Task Force Sentinel Stand (TFSS) to assess cyber command relations (COMREL) at the tactical edge. TFSS proved warfighters have a critical need to take their endpoint devices to austere locations and still access needed classified data without High Assurance IP Encryptor devices. Connectivity will allow relevant mission data requirements to the edge and through space with diverse access paths to deter adversary intrusions. This will include the SD-WAN (Software-Defined Wide Area Network) routing layer to transport content across nodes through both government and commercial communication paths. Through this effort the DAF will deploy, connect, and test SD-WAN solutions in direct support of USAFE, Air Force Forces Generation (AFFORGEN), and Agile Combat Employment (ACE) initiatives, to allow Combat Air Forces to connect, move and maneuver, and recover safely, reducing risk to mission and life. DAF CIO's vision is to provide resilient, software-defined, transport and portable end points that create efficiencies and resiliency in transport by creating a "Black Fabric" that allows multiple providers to transport multiple classifications, rather than the historic and vulnerable approach of 1 fiber, 1 network, 1 classification. In FY2024, funding was allocated for activities to support deployment, connection and testing of an Operational EIT SD-WAN network in an "operational prototype" configuration, to demonstrate distributed edge intelligence and C2 "on-the-move" focusing on the PACAF region. Funding initiated deployment of network capability that could be scaled for employment across any DAF (or DoD) installation or weapon system. In FY2025 funds were allocated to further Operational SD-WAN activities to design, install, and configure hardware/software solutions focusing on the USAFE region. This is to provide Global Teleport (voice) services and alternate connectivity capabilities. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 $0.000M was expended for civilian pay expenses in this program element, and in FY2025 $0.000M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0303004F / EIT CONNECT Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 0, 0, 0, NULL, NULL, 231, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 15531000, 0, 0, 0, 0, 0, 0, $$This activity builds upon the deployment and connectivity of solutions being delivered under the Department of the Air Force (DAF) Advanced Battle Management System (ABMS) Program Element 64003F. The DAF executed Task Force Sentinel Stand (TFSS) to assess cyber command relations (COMREL) at the tactical edge. TFSS proved warfighters have a critical need to take their endpoint devices to austere locations and still access needed classified data without High Assurance IP Encryptor devices. Connectivity will allow relevant mission data requirements to the edge and through space with diverse access paths to deter adversary intrusions. This will include the Software-Defined Wide Area Network (SD-WAN) routing layer to transport content across nodes through both government and commercial communication paths. Through this effort the DAF will deploy, connect, and test SD-WAN solutions in direct support of USAFE, Air Force Forces Generation (AFFORGEN), and Agile Combat Employment (ACE) initiatives, to allow Combat Air Forces to connect, move and maneuver, and recover safely, reducing risk to mission and life. The DAF, Chief Information Officer's (CIO) vision is to provide resilient, software-defined, transport and portable end points that create efficiencies and resiliency in transport by creating a "Black Fabric" that allows multiple providers to transport multiple classifications, rather than the historic and vulnerable approach of 1 fiber, 1 network, 1 classification. In FY2024, funding was allocated for activities to support deployment, connection and testing of an Operational Enterprise Information Technology (EIT) SD-WAN network in an "operational prototype" configuration, to demonstrate distributed edge intelligence and C2 "on-the-move" focusing on the PACAF region. Funding initiated deployment of network capability that could be scaled for employment across any DAF (or Department of War (DoW)) installation or weapon system. In FY2025 funds were allocated to further Operational SD-WAN activities to design, install, and configure hardware/software solutions focusing on the USAFE region. This is to provide Global Teleport (voice) services and alternate connectivity capabilities. In FY 2026, Project 673100, (Operational System Development) was terminated/completed. 0.000M has been allocated to this effort and no further programmatic activities are expected at this time. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0303004F / EIT CONNECT Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 0.000M was expended for civilian pay expenses in this program element, and in FY2026 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303008F$$, $$SATURN$$, $$rdte_af_ba5$$, $$haf_a$$, 2026, 4985000, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0303008F"}$$::jsonb, $$Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) Lead Service activities support Headquarters Air Force in its Lead Service role for SATURN. Each role consists of several distinct engineering and fielding responsibilities, to include, but not limited to leading and overseeing the engineering and analysis activities, fielding strategy, cost and schedule data, resolving cross-service disconnects, and training operators on the use of SATURN. DoD Instruction 4630.09, "Communications Waveform Management and Standardization” outlines the roles of a Lead Service that will be pursued via the funds in the program element. To note, DoDI 4630.09 identifies specific roles for a "Lead Service” and a "Waveform Sponsor”. "Waveform Sponsor” activities are unique and provided for in a separate program element 0604281F. "Lead Service” activities, which differ from "Waveform Sponsor” activities, will be utilized to: - Foster development of joint capability needs; - Expedite adoption across the Services, NATO and other Coalition partners of the SATURN and affiliate (e.g. SATURN Enhanced Data Rate (SEDR) and others) waveform(s) - Foster adoption of terminals capable of operating SATURN - Resolve Joint/NATO/Coalition issues which are slowing adoption of the SATURN waveform - Developing, centralizing, and/or providing training, coordinating exercises or demonstrations to foster Lead Service objectives. As the Lead Service for the Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN), Headquarters Air Force is responsible for overseeing the development, refinement, updating, and U.S. interoperability of this fast frequency hopping waveform, designed to replace Have Quick and provide improved radio resistance to jamming. This encompasses a wide range of activities, including joint enterprise-level system engineering and analysis, development of joint fielding and terminal development strategies, monitoring compliance with reference implementations, establishing policies for common interfaces, collecting cost and schedule data, documenting mission threads, maintaining network management tools, resolving cross-Service disconnects, and providing technical advice for foreign military sales and export controls. Furthermore, the Lead Service will make policy recommendations and develop roadmaps to support the continued development and maturity of the SATURN waveform and its associated applications, including the SATURN Enhanced Data Rate (SEDR) program. Crucially, this role involves coordinating with the Principal Staff Assistant (PSA), the Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), and the Under Secretary of Defense for Research and Engineering (USD(R&E)) to advocate for waveform and terminal development within the Service budget processes, and to ensure appropriate technology protection requirements and processes are in place to advance waveform and terminal development with the Military Services. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System       PE 0303008F / SATURN Development & Demonstration (SDD) This program element may include necessary civilian pay expenses required to support, manage, execute, and deliver weapon system capabilities across the aerial network and tactical data network enterprise. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024, 0.903M was expended for civilian pay expenses in this program element. In FY 2025, 1.715M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 4767000, 4763000, 4760000, NULL, NULL, 114, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 4917000, 4771000, 4771000, 0, 4771000, 4856000, $$Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN) Lead Service activities support Headquarters Air Force in its Lead Service role for SATURN. Each role consists of several distinct engineering and fielding responsibilities, to include, but not limited to leading and overseeing the engineering and analysis activities, fielding strategy, cost and schedule data, resolving cross-service disconnects, and training operators on the use of SATURN. DoD Instruction 4630.09, "Communications Waveform Management and Standardization” outlines the roles of a Lead Service that will be pursued via the funds in the program element. To note, DoDI 4630.09 identifies specific roles for a "Lead Service” and a "Waveform Sponsor”. "Waveform Sponsor” activities are unique and provided for in a separate program element 0604281F. "Lead Service” activities, which differ from "Waveform Sponsor” activities, will be utilized to: - Foster development of joint capability needs; - Expedite adoption across the Services, NATO and other Coalition partners of the SATURN and affiliate (e.g. SATURN Enhanced Data Rate (SEDR) and others) waveform(s) - Foster adoption of terminals capable of operating SATURN - Resolve Joint/NATO/Coalition issues which are slowing adoption of the SATURN waveform - Developing, centralizing, and/or providing training, coordinating exercises or demonstrations to foster Lead Service objectives. As the Lead Service for the Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN), Headquarters Air Force is responsible for overseeing the development, refinement, updating, and U.S. interoperability of this fast frequency hopping waveform, designed to replace Have Quick and provide improved radio resistance to jamming. This encompasses a wide range of activities, including joint enterprise-level system engineering and analysis, development of joint fielding and terminal development strategies, monitoring compliance with reference implementations, establishing policies for common interfaces, collecting cost and schedule data, documenting mission threads, maintaining network management tools, resolving cross-Service disconnects, and providing technical advice for foreign military sales and export controls. Furthermore, the Lead Service will make policy recommendations and develop roadmaps to support the continued development and maturity of the SATURN waveform and its associated applications, including the SATURN Enhanced Data Rate (SEDR) program. Crucially, this role involves coordinating with the Principal Staff Assistant (PSA), the Under Secretary of Defense for Acquisition and Sustainment (USD(A&S)), and the Under Secretary of Defense for Research and Engineering (USD(R&E)) to advocate for waveform and terminal development within the Service budget processes, and to ensure appropriate technology protection requirements and processes are in place to advance waveform and terminal development with the Military Services. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System     PE 0303008F / SATURN Development & Demonstration (SDD) Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303010F$$, $$AF ISR Digital Infrastructure$$, $$rdte_af_ba4$$, $$aflcmc_hb$$, 2026, 27017000, 0, 18733000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0303010F"}$$::jsonb, $$New Program Element FY25 Congressional technical adjustment transferred 18.733M from CAIS PE 0207431F in RDT&E for FY25. The mission of Air Force (AF) Intelligence Surveillance Reconnaissance (ISR) Digital Infrastructure (DI) (AF ISR DI) is to provide the secure commercial cloud-based infrastructure, platform and data services, to be scaled with tenant funding to meet requirements for Sensitive Compartmented Information (SCI) and ISR cloud, platform and data services, globally, including at the edge with a focus on Artificial Intelligence and Machine Learning (AI/AL). AF ISR DI provides enterprise services and a secure development-security-operations (DevSecOps) platform, enabling developers to focus on delivery of mission capabilities as software applications that can be continually updated, dramatically accelerating the time to field and lowering the total ownership cost to the Department of Air Force (DAF) and can scale on demand to meet operational needs to shorten and improve Long Range Kill Chain. AF ISR DI provides the foundation for all DAF SCI cloud-based capabilities. The portfolio ensures compliance with the Intelligence Community (IC) requirements for security, architecture, data safeguarding and sharing, and integrated defense to protect IC data. AF ISR DI partners with Advanced Battle Management System Digital Infrastructure (ABMS DI, executed under PE 0604003F) to provide a consistent set of capabilities, services and customer experience across all classification levels, and meets DAF requirements while ensuring compliance with Director of National Intelligence (DNI) requirements and minimizing duplication of effort. The remaining Funding is Re-aligned in FY26 to AF ISR DI PE 0303010F. AF ISR has two primary thrusts SCI Cloud Services and Cybersecurity Automation and Ops. SCI Cloud services -Leveraging IC-governed commercial cloud enterprise capability, provides a common and robust foundation for agile ISR and C2 operations requiring SCI data, across the globe. Invests in engineering, Security and architectural expertise to provide a fully managed, redundant and secure development, security and operations environment to rapidly develop and deploy mission applications. Provides identity access management, security and secure commercial cloud services, as well as customer service and support to tenants, who fund their use. FY 2026 request for AF ISR DI includes $24,817 thousand of discretionary and $2,200 thousand of mandatory (reconciliation) for a total of $27,017 thousand. The mandatory funding is erroneously programmed to AF ISR DI project. Funding will be properly realigned to the intended Special Access Program (SAP) project in FY26. Funding fulfills intelligence support requirements to support Golden Dome of America. Further information for this reconciliation request is provided in Section 20003 of the Reconciliation Exhibit. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0303010F / AF ISR Digital Infrastructure Component Development & Prototypes (ACD&P)$$, NULL, 24440000, 24419000, 24413000, NULL, NULL, 75, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 18733000, 21711000, 24455000, 24455000, 0, 24455000, 24913000, $$The Air Force (AF) Intelligence, Surveillance, Reconnaissance (ISR) Digital Infrastructure (DI) (AF ISR DI) project was previously reported with Combat Air Intelligence Systems (CAIS) in the FY2025. Department of the Air Force (DAF) created a new project for AF ISR DI and will now be reported on within this project. AF ISR DI provides secure commercial cloud-based infrastructure, platform and data services, to be scaled with tenant funding to meet requirements for Sensitive Compartmented Information (SCI) and ISR cloud, platform and data services, global edge access. Secure commercial cloud architectures are uniquely able to meet the processing, scaling, resilience and agility demands of dynamic multi-domain operations. AF ISR DI ensures compliance with Intelligence Community (IC) requirements for security, architecture, data safeguarding and sharing, and integrated defense, to protect IC data. AF ISR DI also provides enterprise services and a secure development-security-operations (DevSecOps) platform, enabling developers to focus on delivery of mission capabilities as software applications that can be continually updated, dramatically accelerating the time to field and lowering the total cost of ownership. FY 2027 request for AF ISR DI includes 24.455 million. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0303010F / AF ISR Digital Infrastructure Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303089F$$, $$Cyberspace and DoDIN Operations$$, $$rdte_af_ba7$$, $$dw_disa$$, 2026, 10080000, 4738000, 9776000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0303089F"}$$::jsonb, $$Cyberspace Operations Support (CSOS) consists of a portfolio of capabilities that provide the ability to visualize and process data from weapon/mission systems, sensored by the Integrated Defensive Cyberspace System (IDCS). CSOS supports situational awareness (SA) over Mission Relevant Terrain-Cyber (MRT-C) initially focusing development for the Pacific Air Forces (PACAF) Area of Responsibility (AOR) in FY25 and then shifting focus on development to support Global Air Force missions. CSOS positions the Air Force to comply with the FY22 National Defense Authorization Act (NDAA) Section 1505, which requests a complete mapping of MRT- C for Defense Critical Assets (DCAs) and Task Critical Assets (TCAs) to enable mission thread analysis and SA. CSOS will focus on data analytics, visualization, dashboards, threat, and network awareness enabling missions across the Department of the Air Force (DAF). Development will focus on improvement of visualization dashboards to provide cyber-SA and decision tools. Development teams will produce Air Force-specific software modules and/or enhancements to existing suites of cyber command and control (C2) software or new software development efforts, to include Mission Defense Team (MDT) C2 software, provide weapon systems cyber awareness, and provide SA for the Air Force Information Network (AFIN) Security Operations Center (SOC). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.000M was expended for civilian pay expenses in this program element, and in FY25 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0303089F / Cyberspace and DoDIN Operations Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 232, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 9432000, 9955000, 0, 0, 0, 0, 0, $$Cyberspace Operations Support (CSOS) consists of a portfolio of capabilities that provide the ability to visualize and process data from weapon/mission systems, sensored by the Integrated Defensive Cyberspace System (IDCS). CSOS supports situational awareness (SA) over Mission Relevant Terrain-Cyber (MRT-C) across the Global Air Force missions. CSOS positions the Air Force to comply with the FY22 National Defense Authorization Act (NDAA) Section 1505, which requests a complete mapping of MRT-C for Defense Critical Assets (DCAs) and Task Critical Assets (TCAs) to enable mission thread analysis and SA. CSOS will focus on data analytics, visualization, dashboards, threat, and network awareness enabling missions across the Department of the Air Force (DAF). Development will focus on improvement of visualization dashboards to provide cyber-SA and decision tools leveraging data gained from the IDCS sensor suite. Development teams will produce Air Force-specific software modules and/or enhancements to existing suites of cyber command and control (C2) software or new software development efforts, to include Mission Defense Team (MDT) C2 software, provide weapon systems cyber awareness, and provide SA for the Air Force Information Network (AFIN) Security Operations Center (SOC). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0303089F / Cyberspace and DoDIN Operations Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303126K$$, $$Long-Haul Communications - DCS$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 40293000, 36222000, 51214000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0303126K", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Information Systems Network (DISN) is the Department of Defense's (DoD's) consolidated worldwide telecommunications infrastructure that provides end- to-end information transport for DoD operations to the warfighters and the Combatant Commanders via a robust Command, Control, Communications, Computers and Intelligence information long-haul transport infrastructure. The DISN, seamlessly spanning the full spectrum from terrestrial to space and strategic to tactical domains, provides the interoperable telecommunications connectivity required to plan, implement, and support all operational missions, anytime. DISN services reach the edge of the communications network; the warfighter can access them worldwide. Continual enhancement of the DISN is needed to provide optimal network resources to the warfighter. The Defense Red Switch Network (DRSN) is a global, secure voice service providing the President, the Secretary of Defense, the Joint Chiefs of Staff, the Combatant Commands (COCOMs) and selected agencies with Nuclear Command, Control, and Communications (NC3) secure voice and video conferencing capabilities and higher classification levels. The DRSN consists of Military Department and Agency-owned secure voice switches connected by a DISA provided transport backbone. The RDT&E funding supports the following efforts: DISN Networking - Tech Refresh (TR) (formally known as Next Generation Networking Technologies): Provides engineering technical expertise to update the global network with the latest technologies. DRSN Peripheral and Component Re-Design and MLSV2: Supports Peripheral and Component Re-Design to continue interoperability between DRSN and its operators. This capability is not commercially available and satisfies unique military requirements for multi-level secure voice services and conferencing capabilities. Additionally, RDT&E funding supports the development, testing, and fielding of a prototype of the modern Multi-Level Secure Voice and Video (MLSV2) conference capability. The MLSV2 prototype effort will modernize voice, video and chat conferencing capability providing a flexible and interoperable capability through standardization of protocols and interfaces as well as orchestration between hardware (HW) and software (SW). The MLSV2 initiative will show future possibilities for classified conferencing at three classification levels with the same system. DoD Mobility: The virtual/zero desktop infrastructure and zero-sign on experience will enable the warfighter to access mobile device applications by entering credentials once. The warfighter will then be automatically verified as he or she accesses additional applications. Additionally, it supports the continued evolution and expansion of Unified Endpoint Management (UEM) Capabilities for unclassified mobility within the Department. The Unified Endpoint Management Capabilities are a class of software tools that provide a single management interface for mobile devices, enhancing user experience for the warfighter and COCOMs. The Mobility program is also Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                                 Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:            PE 0303126K / Long-Haul Communications - DCS Operational Systems Development expanding research on Derived Credential capabilities, which allows for the automation of the operations, administration, maintenance, and provisioning functions of unclassified and classified mobile endpoints.$$, NULL, 10721000, 10939000, 11148000, NULL, NULL, 237, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 47729000, 38466000, 10508000, 10508000, NULL, 10508000, 11148000, $$The Defense Information Systems Network (DISN) is the Department of War's (DoW's) consolidated worldwide telecommunications infrastructure that provides end- to- end information transport for DoW operations to the warfighters and the Combatant Commanders via a robust Command, Control, Communications, Computers and Intelligence information long-haul transport infrastructure. The DISN, seamlessly spanning the full spectrum from terrestrial to space and strategic to tactical domains, provides the interoperable telecommunications connectivity required to plan, implement, and support all operational missions, anytime. DISN services reach the edge of the communications network; the warfighter can access them worldwide. Continual enhancement of the DISN is needed to provide optimal network resources to the warfighter. The Defense Red Switch Network (DRSN) is a global, secure voice service providing the President, the Secretary of War, the Joint Chiefs of Staff, the Combatant Commands (COCOMs) and selected agencies with Nuclear Command, Control, and Communications (NC3) secure voice and video conferencing capabilities and higher classification levels. The DRSN consists of Military Department and Agency-owned secure voice switches connected by a DISA provided transport backbone. The RDT&E funding supports the following efforts: DISN Networking - Tech Refresh (TR) (formally known as Next Generation Networking Technologies): Provides engineering technical expertise to update the global network with the latest technologies. DRSN Peripheral and Component Re-Design and MLSV2: Supports Peripheral and Component Re-Design to continue interoperability between DRSN and its operators. This capability is not commercially available and satisfies unique military requirements for multi-level secure voice services and conferencing capabilities. Additionally, RDT&E funding supports the development, testing, and fielding of a prototype of the modern Multi-Level Secure Voice and Video (MLSV2) conference capability. The MLSV2 prototype effort will modernize voice, video and chat conferencing capability providing a flexible and interoperable capability through standardization of protocols and interfaces as well as orchestration between hardware (HW) and software (SW). The MLSV2 initiative will show future possibilities for classified conferencing at three classification levels with the same system. DoW Mobility: The virtual/zero desktop infrastructure and zero-sign on experience will enable the warfighter to access mobile device applications by entering credentials once. The warfighter will then be automatically verified as he or she accesses additional applications. Additionally, it supports the continued evolution and expansion of Unified Endpoint Management (UEM) Capabilities for unclassified mobility within the Department. The Unified Endpoint Management Capabilities are a class of software tools that provide a single management interface for mobile devices, enhancing user experience for the warfighter and COCOMs. The Mobility program is also Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                                 Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:            PE 0303126K / Long-Haul Communications - DCS Operational Systems Development expanding research on Derived Credential capabilities, which allows for the automation of the operations, administration, maintenance, and provisioning functions of unclassified and classified mobile endpoints.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303131F$$, $$Minimum Essential Emergency Communications Network (MEECN)$$, $$rdte_af_ba7$$, $$afnwc_nc$$, 2026, 99599000, 31099000, 25500000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0303131F"}$$::jsonb, $$Nuclear Deterrence Operations (NDO) is an Air Force Core Function. Within this core function, Nuclear Command and Control (NC2) is the exercise of authority and direction by the President, as Commander in Chief, through established command lines, over nuclear weapon operations of military forces. The President's authority and direction are exercised through the Nuclear Command and Control System (NCCS). The NCCS is the designated combination of flexible and enduring elements including facilities, equipment, communications, procedures, personnel, and the structure in which these elements are integrated, all of which are essential for planning, directing, and controlling nuclear weapon operations. The Minimum Essential Emergency Communications Network (MEECN) portfolio modernizes the systems necessary to effectively provide assured communications connectivity between the President and the strategic deterrence forces in stressed environments. MEECN System Improvements (MSI) is a long-range planning effort with users (Air Force Global Strike Command (AFGSC), Air Combat Command (ACC), United States Space Force (USSF), Air Mobility Command (AMC), Air Force Special Operations Command (AFSOC), US Strategic Command (USSTRATCOM), and the US Navy (USN)) to monitor and assess the performance of existing NC3 systems and develop recommendations for strategic and tactical architecture upgrades, requirements, and issues based on available and emerging technologies. MSI is used to conduct technology testing; model performance; analyze technology strategies; conduct requirement trade space analysis, technology maturation and risk reduction efforts, and mission analysis; and build technology roadmaps as proactive support to the NC3 community. MSI performs analysis, integration, and testing activities for the NC3 Weapon System. This project may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.00M is budgeted for civilian pay expenses in this project, and in FY 2025 0.00M is forecasted for civilian pay expenses in this project. The Common Very Low Frequency/Low Frequency (VLF/LF) Receiver (CVR) Increment 2 (CVRi2) Program will develop and produce a modular open systems approach (MOSA), Cryptographic Modernization 2.0 (CM 2), New VLF Waveform compliant advanced VLF/LF receiver for all ground and airborne NC3 platforms. As the USAF VLF receiver integrator, the VLF Enterprise Program Office (VLF EPO) will continue to be responsible for VLF sustainment to include configuration management of the Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0303131F / Minimum Essential Emergency Communications Network (MEECN) Operational Systems Development CVR Increment 1 (CVRi1) materiel solution while also providing management support to the B-52 VLF Modernization Program for its procurement and production of the directed VLF receiver. The VLF EPO will provide the same management and engineering support to other legacy NC3 platforms' VLF receiver requirements. The VLF EPO will also develop an acquisition strategy for adaptation of CVRi2 for the current and future NC3 platforms, while establishing an overarching contract to capture both development and production of CVRi2 for multiple NC3 platforms, which will enable enterprise level management of the VLF receivers for the current and future USAF airborne and ground-based NC3 platforms. This project may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.00M is budgeted for civilian pay expenses in this project, and in FY 2025 0.559M is forecasted for civilian pay expenses in this project. The Family of Advanced Beyond Line-of-Sight Terminals - Force Element Terminal (FAB-T FET) program replaces the Ultra High Frequency (UHF) Milstar terminals and provides secure, protected, and survivable communications for the strategic warfighter through airborne-based Military Satellite Communication (MILSATCOM) terminals. The FAB-T FET will provide worldwide nuclear and non-nuclear, survivable, anti-jam Low Probability of Detect (LPD)/ Low Probability of Intercept (LPI) data and voice communications. The FAB-T FET will be interoperable with Advanced Extremely High Frequency (AEHF), Enhanced Polar Systems - Recapitalization (EPS- R), and Evolved Strategic SATCOM (ESS) satellite constellations and will be installed on the B-52 aircraft (threshold). FAB-T FET was designated as a Middle Tier of Acquisition (MTA) in February 2019. The FAB-T FET program transitioned from AFPEO/SP to AFPEO/NC3 effective December 2018. FAB-T FET is planned to transition to the Major Capability Acquisition (MCA) Pathway at the conclusion of MTA. The FY 2026 cost of Middle Tier of Acquisition effort FAB-T FET is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. This project may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. The Global Aircrew Strategic Network Terminal (Global ASNT) program replaces antiquated, unsustainable strategic communications equipment at bomber, tanker and reconnaissance Wing Command Posts (WCPs), Nuclear Task Forces and Munitions Support Squadrons (MUNSS) and for Mobile Support Teams (MSTs). Global ASNT is a ground-based system that will provide survivable, secure communication paths to receive Emergency Action Messages (EAMs), Force Management messages, and Force Direction messages and disseminate them to bomber, tanker, and reconnaissance aircrews. Global ASNT is being fielded in separate capability increments. Global ASNT Increment 1 (Inc 1) fields required Extremely High Frequency/Advanced Extremely High Frequency (EHF/AEHF) capabilities and replaces antiquated, unsustainable strategic mobile and fixed-site Single Channel Anti-jam Man-Portable (SCAMP) terminals and Secure, Mobile, Anti-Jam, Reliable, Tactical - Terminal (SMART-T) equipment. FY 2019 was the last year of RDT&E funding for Global ASNT Inc 1; development is complete, full rate production is in process, and fielding of terminals commenced in 2QFY22. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0303131F / Minimum Essential Emergency Communications Network (MEECN) Operational Systems Development Global ASNT Increment 2 (Inc 2) Block 1 delivers a replacement Aircrew Alerting System (AAS) consisting of personal and general area alerting as well as Ultra High Frequency (UHF) line of sight (LOS) voice communications to bomber, tanker, and reconnaissance aircraft. Increment 2 replaces aging legacy Electromagnetic Pulse Hardened Dispersal Communication (EHDC) and Aircrew Alerting Communications Electromagnetic Pulse (AACE) systems. Global ASNT Inc 2 Block 1, the FY 2026 cost of Middle Tier of Acquisition effort is reflected in the budget request, including RDT&E and procurement of prototype units. The Department will certify Future Years Defense Program (FYDP) funding in a future budget submission. Global ASNT Increment 2 (Inc 2) Block 2 delivers High Frequency (HF) Beyond Line of Sight (BLOS) communications to bomber and tanker aircraft. The FY 2026 request was reduced by [0.001] million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, Implementing the President's Department of Government Efficiency Cost Efficiency Initiative. This project may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.00M was expended for civilian pay expenses in this project, and in FY 2025 0.00M is forecasted for civilian pay expenses in this project. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 368485000, 402931000, 413945000, NULL, NULL, 233, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 24763000, 98548000, 254837000, 254837000, 0, 254837000, 296826000, $$Nuclear Deterrence Operations (NDO) is an Air Force Core Function. Within this core function, Nuclear Command and Control (NC2) is the exercise of authority and direction by the President, as Commander in Chief, through established command lines, over nuclear weapon operations of military forces. The President's authority and direction are exercised through the Nuclear Command and Control System (NCCS). The NCCS is the designated combination of flexible and enduring elements including facilities, equipment, communications, procedures, personnel, and the structure in which these elements are integrated, all of which are essential for planning, directing, and controlling nuclear weapon operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0303131F / Minimum Essential Emergency Communications Network (MEECN) Operational Systems Development The Minimum Essential Emergency Communications Network (MEECN) portfolio modernizes the systems necessary to effectively provide assured communications connectivity between the President and the strategic deterrence forces in stressed environments. The FAB-T - Command Post Terminal (FAB-T CPT) project replaces legacy Milstar (AFCPT) terminals and will provide Extremely High Frequency (EHF) protected high data rate communication for nuclear and conventional forces to include the Presidential and National Voice Conferencing (PNVC). FAB-T CPT will provide this new, highly secure, state-of-the-art capability for Department of War (DoW) platforms to include strategic platforms and airborne/ground command posts via Advanced EHF (AEHF), and Evolved Strategic Satellite Communications (ESS) satellite constellations. FAB-T CPTs will also support the critical command and control (C2) of Advanced EHF (AEHF) and ESS satellite constellations. MEECN System Improvements (MSI) is a long-range planning effort with users (Air Force Global Strike Command (AFGSC), Air Combat Command (ACC), United States Space Force (USSF), Air Mobility Command (AMC), Air Force Special Operations Command (AFSOC), US Strategic Command (USSTRATCOM), and the US Navy (USN)) to monitor and assess the performance of existing NC3 systems and develop recommendations for strategic and tactical architecture upgrades, requirements, and issues based on available and emerging technologies. MSI is used to conduct technology testing; model performance; analyze technology strategies; conduct requirement trade space analysis, technology maturation and risk reduction efforts, and mission analysis; and build technology roadmaps as proactive support to the NC3 community. MSI performs analysis, integration, and testing activities for the NC3 Weapon System. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The Common Very Low Frequency/Low Frequency (VLF/LF) Receiver (CVR) Increment 2 (CVRi2) Program will develop and produce a modular open systems approach (MOSA), Cryptographic Modernization 2.0 (CM-2), New VLF Waveform (WF) compliant advanced VLF/LF receiver for all ground and airborne NC3 platforms. As the USAF VLF receiver integrator, the VLF Enterprise Program Office (VLF EPO) will continue to be responsible for VLF receiver sustainment, to include configuration management of the CVR Increment 1 (CVRi1) materiel solution (KGR-72) and sustainment of legacy receivers, while also providing management support to the B-52 VLF Modernization Program for its procurement and production of the directed VLF receiver (KGR-72). The VLF EPO will provide management and engineering support for VLF receiver requirements across legacy and emerging NC3 platforms. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The Presidential and National Voice Conferencing (PNVC) Integrator project is a critical element of the Nuclear Command, Control, and Communications (NC3) System. PNVC integrator replaces the Survivable Emergency Conferencing Network (SECN) capability, and provides anti-jam, anti-scintillation, survivable, and enduring voice communications via AEHF and ESS satellite constellations for national and strategic users. There are several components being developed and procured by other organizations that must be synchronized to expeditiously field the capability. The PNVC Integrator is responsible for end-to-end integration of these components, to include requirements traceability, end-to-end system testing, configuration and checkout activities, training and technical manuals, network transition support, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0303131F / Minimum Essential Emergency Communications Network (MEECN) Operational Systems Development identification of deficiencies in overall PNVC system capability, enterprise, and life cycle support for PNVC components. The AFPEO/SP approved entry into the acquisition lifecycle as a post MS-A Acquisition Category (ACAT) III Program of Record in January 2016. Starting in December 2018, PNVC Integrator became responsible for the funding requests of all program elements related to the Defense Information Systems and Agency (DISA) components of the PNVC System in accordance with FY 2018 National Defense Authorization Act, Sec. 1661. In March 2019, the AFPEO/NC3 declared the PNVC Integrator an ACAT II Program based on the inclusion of DISA funding in the program budget. The Family of Advanced Beyond Line-of-Sight Terminals - Force Element Terminal (FAB-T FET) program replaces the Ultra High Frequency (UHF) Milstar terminals and provides secure, protected, and survivable communications for the strategic warfighter through airborne-based Military Satellite Communication (MILSATCOM) terminals. The FAB-T FET will provide worldwide nuclear and non-nuclear, survivable, anti-jam Low Probability of Detect (LPD)/ Low Probability of Intercept (LPI) data. The FAB-T FET will be interoperable with Advanced Extremely High Frequency (AEHF), Enhanced Polar Systems - Recapitalization (EPS-R), and Evolved Strategic SATCOM (ESS) satellite constellations and will be installed on the B-52 aircraft (threshold). FAB-T FET was designated as a Middle Tier of Acquisition (MTA) in February 2019. In January 2026, FAB-T FET was designated as a Major Capability Acquisition (MCA) program with closure of the MTA program. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. ICBM MEECN Terminal (IMT) will provide resilient Nuclear Command, Control, and Communications capabilities for the Intercontinental Ballistic Missile (ICBM) Forces. IMT will deliver an integrated NC3 suite which includes Extremely High Frequency (EHF) capabilities and an open architecture-based framework. This framework will enable faster and extensible capabilities integration and upgrades for other communication pathways. IMT will integrate the Common Very Low Frequency (VLF) Receiver (CVR). For ICBM risk reduction, IMT will prepare for integration with ICBM Weapon Systems. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The Minuteman MEECN Program (MMP) Service Life Extension Program (SLEP) will enable the legacy MMP System that is beyond end-of-life to continue to provide Intercontinental Ballistic Missile (ICBM) Forces with a survivable link for reception of Emergency Action Messages (EAMs) from the President and Secretary of War (SECWAR). Until the new follow-on system can be fielded. MMP is a Command and Control (C2) system directly supporting the Chairman of the Joint Chiefs of Staff in the National Command Center and the Strategic Nuclear Command Centers. MMP provides super high-frequency (SHF) down-link/extremely high-frequency (EHF) up- link and very low-frequency (VLF)/low-frequency (LF) messaging support for Minuteman III ICBM Launch Control Centers (LCCs). The MMP SLEP is needed to support the Minuteman III weapon system, beyond its expected service life of 2030. The significant delays to the Sentinel program requires life extension of the current Minuteman III system, and subsystems, which include MMP. Without a Service Life Extension Program (SLEP), MMP will continue to experience severe spare parts availability and Diminishing Manufacturing Sources and Material Shortages (DMSMS). The MMP operational availability will continue to decrease, and future modifications will not be addressed creating a significant gap in capability, further reducing our nation's nuclear deterrence. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0303131F / Minimum Essential Emergency Communications Network (MEECN) Operational Systems Development The Global Aircrew Strategic Network Terminal (Global ASNT) program replaces antiquated, unsustainable strategic communications equipment at bomber and tanker Wing Command Posts (WCPs), Nuclear Task Forces and Munitions Support Squadrons (MUNSS) and for Mobile Support Teams (MSTs). Global ASNT is a ground- based system that will provide survivable, secure communication paths to receive Emergency Action Messages (EAMs), Force Management messages, and Force Direction messages and disseminate them to bomber and tanker aircrews. Global ASNT is being fielded in separate capability increments. Global ASNT Increment 1 (Inc 1) fields required Extremely High Frequency/Advanced Extremely High Frequency (EHF/AEHF) capabilities and replaces antiquated, unsustainable strategic mobile and fixed-site Single Channel Anti-jam Man-Portable (SCAMP) terminals and Secure, Mobile, Anti-Jam, Reliable, Tactical - Terminal (SMART-T) equipment. Global ASNT Inc 1 system met Full Operational Capability in January 2026. RDT&E funding in FY27 enables interoperability with the ESS satellite constellations. Global ASNT Increment 2 (Inc 2) Block 1 delivers a replacement Aircrew Alerting System (AAS) consisting of personal and general area alerting as well as Ultra High Frequency (UHF) line of sight (LOS) voice communications to bomber and tanker aircraft. Increment 2 replaces aging legacy Electromagnetic Pulse Hardened Dispersal Communication (EHDC) and Aircrew Alerting Communications Electromagnetic Pulse (AACE) systems. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Global ASNT Increment 2 (Inc 2) Block 2 delivers High Frequency (HF) Beyond Line of Sight (BLOS) communications to bomber and tanker aircraft, and emerging NC3 platforms. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                   Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0303131F / Minimum Essential Emergency Communications Network (MEECN) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303131K$$, $$Minimum Essential Emergency Communications Network (MEECN)$$, $$rdte_dw_ba7$$, $$dw_osd$$, 2026, 5113000, 5037000, 4985000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 79, "original_pe": "0303131K", "page_header": "Defense-Wide"}$$::jsonb, $$Minimum Essential Emergency Communications Network (MEECN) provides the Nuclear Command, Control, and Communications (NC3) Engineer with a variety of services. MEECN equips the NC3 Engineer with planning, systems analysis, operational assessments, systems engineering, and architectural and concept development. Through the National Military Command System, the NC3 System provides connectivity between the President and the Secretary of Defense to critical nuclear execution forces (spanning both “homeland-to-homeland” and theater nuclear war). MEECN includes the Emergency Action Message dissemination systems and the systems used for integrated Tactical Warning/Attack Assessment, presidential decision-making conferencing, force report back, re-targeting, force management, and requests for permission nuclear weapons use. These efforts assure positive control of nuclear forces and connectivity between the Secretary of Defense and military forces. They also help allow the President, the Secretary of Defense, and the Combatant Commands to communicate and make more informed decisions. MEECN ensures U.S. national leadership has proper command and control of military forces during national security emergencies, including the possibility of nuclear war.$$, NULL, 8653000, 8866000, 9095000, NULL, NULL, 238, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 4985000, 5113000, 10307000, 10307000, NULL, 10307000, 9323000, $$Minimum Essential Emergency Communications Network (MEECN) provides the Nuclear Command, Control, and Communications (NC3) Engineer with a variety of services. MEECN equips the NC3 Engineer with planning, systems analysis, operational assessments, systems engineering, and architectural and concept development. Through the National Military Command System, the NC3 System provides connectivity between the President and the Secretary of War to critical nuclear execution forces (spanning both “homeland-to-homeland” and theater nuclear war). MEECN includes the Emergency Action Message dissemination systems and the systems used for integrated Tactical Warning/Attack Assessment, presidential decision-making conferencing, force report back, re-targeting, force management, and requests for permission nuclear weapons use. These efforts assure positive control of nuclear forces and connectivity between the Secretary of War and military forces. They also help allow the President, the Secretary of War, and the Combatant Commands to communicate and make more informed decisions. MEECN ensures U.S. national leadership has proper command and control of military forces during national security emergencies, including the possibility of nuclear war.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303133F$$, $$High Frequency Radio Systems$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 19955000, 26370000, 8667000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0303133F"}$$::jsonb, $$This program element funds the Airborne High Frequency Radio Modernization (AHFRM) program. The AHFRM program is critical for maintaining long-range High Frequency (HF) communication capabilities across multiple U.S. military aircraft platforms. This program replaces the existing, end-of-life AN/ARC-190 HF radios with the modernized AN/ARC-260 digital, software-defined HF radio. Federal Aviation Administration (FAA) regulation mandates that all aircraft have HF radio capability on all transoceanic flights. This replacement is essential because the AN/ARC-190 is the only HF radio currently available for 15 critical aircraft platforms used by the U.S. Air Force, U.S. Marine Corps, and U.S. Coast Guard, encompassing 1,300 aircraft in total, many of which require multiple radios. By mid FY 2027, the AN/ARC-190 (no longer in production) is projected to fall below supply chain thresholds due to obsolescence, creating a critical capability gap. Impacted aircraft include AC-130J, B-1, B-52, C-5, C-17, C-130H, C-130J, E-4C, EC-130J, HC-130J (Air Force & Coast Guard), KC-46, KC-130T (US Marine Corps), KC-135, LC-130H, and MC-130J. The AN/ARC-260 is the only airborne HF digital radio currently in development capable of bridging this gap. It provides critical long-range HF communication, especially when satellite communications are disrupted. The AN/ARC-260 also incorporates advanced technologies, including 3G/4G Automatic Link Establishment and Low Probability of Intercept/Detection/Geolocation features, with an open architecture that supports software upgrades and future technology integration. These requirements ensure a survivable and secure communication path for critical Force Direction messages, making the AHFRM program essential for maintaining mission readiness. FY 2026 BUDGET JUSTIFICATION: In FY 2026, the AHFRM program will prioritize development of a digital antenna coupler and critical software upgrades for the AN/ARC-260 radio. The legacy analog coupler from the AN/ARC-190 was used in the development of the AN/ARC-260, however, it restricts the HF radio's processing power to 10 kHz instead of the desired 48 kHz wideband throughput. While the legacy analog coupler is compatible with the AN/ARC-260, it significantly diminishes the radio's overall capabilities. Furthermore, the analog coupler is no longer in production, creating significant supportability challenges beginning in FY 2027. Developing a digital antenna coupler unlocks the AN/ARC-260's full capabilities, ensuring optimal performance and long-term sustainability. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                               Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0303133F / High Frequency Radio Systems Operational Systems Development FY 2026 digital coupler development activities include vendor site visits to determine vendor eligibility, vendor source selection, and initiating efforts in risk assessment and cost analysis, system engineering trade studies, requirements refinement and validation, and prototyping. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY24 $0.000M was expended for civilian pay expenses in this program element, and in FY25 $0.000M is forecasted for civilian pay expenses in this program element. The FY 2026 request was reduced by $1.984 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 17929000, 18711000, 18858000, NULL, NULL, 234, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 8423000, 19709000, 33215000, 33215000, 0, 33215000, 19240000, $$This program element funds the Airborne High Frequency Radio Modernization (AHFRM) program to address the obsolescence of the legacy AN/ARC-190 High Frequency (HF) radio system, which is currently installed on over a thousand aircraft. Production of the AN/ARC-190 HF radio ceased in 2018, and the system is becoming unsustainable due to a diminishing supply of spare parts, with assets falling below supply chain thresholds by late 2027. The program is developing a replacement modern, software-defined radio, designated as the AN/ARC-260. This development ensures the continuity of high-frequency communication capabilities for a wide range of mission-essential aircraft without requiring costly airframe modifications. This modernization is mission critical because HF radio capability provides resilient and survivable communications, especially in environments where satellite communications are denied, contested, or unavailable. It is an essential alternative for beyond-line-of-sight command and control (C2), enabling strategic communication, the transmission of critical force direction messaging, and routine Air Traffic Control (ATC) during long-range and oversea flights. Federal Aviation Administration (FAA) regulations also mandate HF radio capability for aircraft to fly outside the continental United States. Failure to modernize these radios would result in the loss of critical C2 pathways and could lead to the grounding of aircraft, severely impacting mission readiness and operational availability. The AHFRM program directly supports a diverse fleet of approximately 1,300 aircraft within the U.S. Air Force, Navy, and Coast Guard. This includes strategic bombers like the B-1 and B-52; mobility platforms such as the C-5, C-17, C-130, and KC-135; and various special mission aircraft. The new AN/ARC-260 system introduces significant technological advancements, including digital voice, high-speed data and text messaging, and an open architecture that allows for rapid software upgrades and the insertion of new capabilities. This modular and expandable design ensures the system can adapt to future requirements, such as advanced waveforms and enhanced security, guaranteeing long-term sustainability and interoperability across joint forces. While the core development of the AN/ARC-260 radio is set to conclude in FY 2026, new operational requirements were levied in January 2023, initiating a phased capability enhancement plan that began with the development of a modern antenna coupler and is scheduled to continue in FY 2027 with modifications of the radio. These enhancements are structured into four distinct increments: Increment 1 will focus on software and firmware upgrades to improve data handling and messaging without hardware modifications. Increment 2 involves the development of a modernized, wideband digital coupler for enhanced Digital HF capability. Increment 3 will introduce more substantial hardware and software changes to add wider bandwidth and new surveillance capabilities. Increment 4 will implement high-assurance multi-level security architecture enhancements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0303133F / High Frequency Radio Systems Operational Systems Development The initial phase covering Increments 1 and 2 is scheduled to commence in FY 2027, with the more complex hardware-centric upgrades of Increments 3 and 4 planned to begin in FY 2028. FY 2027 BUDGET JUSTIFICATION: In FY 2027, the AHFRM program will shift its focus to the next phase of capability enhancement, funded to pursue two primary efforts. The first is the development of a critical software update to integrate new digital HF capabilities, corresponding to the planned Increment 1 enhancements. The second major effort will be the development of a new digital antenna coupler, which aligns with Increment 2. Notably, the significant increase in program funding for FY 2027 is directly allocated to the development of Increment 1, a comprehensive software and firmware effort projected to last a year and a half, which is required for the successful integration of the new digital coupler. The development of the digital coupler is a key priority for FY 2027, aimed at addressing the significant supportability challenges posed by the current, obsolete analog coupler. To achieve this, the program will initiate requirements refinement and validation, conduct prototyping, and begin on-aircraft integration testing for the new digital design. This effort is essential not only to modernize the antenna interface but also to ensure the continued availability and reliability of beyond-line-of-sight HF communications for the fleet, mitigating risks associated with the aging and unsustainable legacy hardware. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303138N$$, $$AFLOAT NETWORKS$$, $$rdte_navy_ba7$$, $$peo_c4i$$, 2026, 70742000, 49071000, 56915000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 38, "original_pe": "0303138N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 74098000, 73994000, 73747000, NULL, NULL, NULL, NULL, NULL, FALSE, 56115000, 78465000, 68369000, 68369000, NULL, 68369000, 73310000, $$The details of program element 0303138N Project 0403/0725/3240/9C87 are CLASSIFIED and are submitted to Congress in the CLASSIFIED budget justification books.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303140D8Z$$, $$Information Systems Security Program$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 25347000, 137157000, 36127000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0303140D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The DoD CIO information systems security program (ISSP) provides focused defense cybersecurity and information assurance technology and technical solutions research, development, testing, and integration critical to meet Title 10 U.S. Code Section 2224 (10 U.S.C. §2224) (Defense Information Assurance Program); Public Law 113-283 (Federal Information Security Modernization Act of 2014); Office of Management and Budget (OMB) Circular A-130; multiple DoD cybersecurity-related instruction series, such as 8500, 8510, 8520, 8530, and 8540; Executive Order 14028, “Improving the Nation’s Cybersecurity”; National Defense Authorization Act (NDAA) for Fiscal Year (FY) 2022, Section 1528; National Cybersecurity Strategy (March 2023), OMB M-22-09, “Moving the U.S. Government Toward Zero Trust Cybersecurity Principles”; National Security Memorandum 8, “Memorandum on Improving the Cybersecurity of National Security, Department of Defense, and Intelligence Community Systems”; Fulcrum: The DoD Information Technology Advancement Strategy; FY 2022 – 2026 DoD Strategic Management Plan; DoD CIO 2024 Defense Industrial Base Cybersecurity Strategy; and DoD CIO 2022 Zero Trust (ZT) Strategy. ISSP assists the DoD CIO and mission partners in: developing cybersecurity governance processes; modernizing communications security (COMSEC) and cryptography, including post-quantum solutions; integrating and synchronizing the DoD information environment; enhancing communications cybersecurity and national security system protection; adopting Zero Trust (ZT) cybersecurity principles; defending against supply-chain attacks; overseeing cybersecurity risk management; developing and sustaining Defense Industrial Base (DIB) cybersecurity activities; integrating cybersecurity standards across the DoD. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                              Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:          PE 0303140D8Z / Information Systems Security Program Operational Systems Development$$, NULL, 36820000, 42359000, 43221000, NULL, NULL, 240, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 34804000, 60524000, 35214000, 35214000, NULL, 35214000, 42977000, $$The DoW CIO information systems security program (ISSP) provides focused defense cybersecurity and information assurance technology and technical solutions research, development, testing, and integration critical to meet Title 10 U.S. Code Section 2224 (10 U.S.C. §2224) (Defense Information Assurance Program); Public Law 113-283 (Federal Information Security Modernization Act of 2014); Office of Management and Budget (OMB) Circular A-130; multiple DoW cybersecurity-related instruction series, such as 8500, 8510, 8520, 8530, and 8540; Executive Order 14028, “Improving the Nation’s Cybersecurity”; National Defense Authorization Act (NDAA) for Fiscal Year (FY) 2022, Section 1528; National Cybersecurity Strategy (March 2023), OMB M-22-09, “Moving the U.S. Government Toward Zero Trust Cybersecurity Principles”; National Security Memorandum 8, “Memorandum on Improving the Cybersecurity of National Security, Department of Defense, and Intelligence Community Systems”; FY 2022 – 2026 DoW Strategic Management Plan; DoW CIO 2024 Defense Industrial Base Cybersecurity Strategy; and DoW CIO 2022 Zero Trust (ZT) Strategy. ISSP assists the DoW CIO and mission partners in: developing cybersecurity governance processes; modernizing communications security (COMSEC) and cryptography, including post-quantum solutions; integrating and synchronizing the DoW information environment; enhancing communications cybersecurity and national security system protection; adopting ZT cybersecurity principles; defending against supply-chain attacks; overseeing cybersecurity risk management; developing and sustaining defense industrial base (DIB) cybersecurity activities; and integrating cybersecurity standards across the DoW. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0303140D8Z / Information Systems Security Program Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303140F$$, $$Information Systems Security Program$$, $$rdte_af_ba7$$, $$afrl_ri$$, 2026, 98414000, 89233000, 94424000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0303140F"}$$::jsonb, $$Information Systems Security Program (ISSP) - Includes resources, manpower authorizations, necessary facilities and equipment required to develop, deliver, and sustain Cryptographic Modernization (CM) capabilities to nearly all Department of the Air Force (DAF) weapon systems that encrypt/decrypt sensitive information. CM ensures confidentiality, integrity, and availability of the information and the systems. The CM work done in the Information Systems Security Program (ISSP) ensures that DAF systems receive cryptographic capabilities that are compliant with National Security Agency (NSA) mandates and that commanders can confidently leverage for Joint All Domain Command and Control (JADC2) capabilities. The ISSP Element and associated CM activities provide a foundational Communications Security (COMSEC) capability that is the first and last line of cyber defense against adversary exploitation. The DAF and the DoD require the capability to securely collect, process, store, and disseminate an uninterrupted flow of information, while denying an adversary the ability to intercept, collect, destroy, interpret, or manipulate our information flows. CM provides secure communication to allow the DoD to achieve and maintain decision superiority, the key to successful application of the military instrument of national power in modern full-spectrum operations. DAF COMSEC equipment protects sensitive information such as warfighter positions, mission planning, target strikes, commanders' orders, intelligence, force strength, and force readiness. When an adversary is capable of interpretation, manipulation, or destruction of the information used by the warfighter, DoD military forces will suffer significant and/or devastating mission degradation that can result in loss of life and resources and/or exceptionally grave damage to national security. The advanced threats and capabilities of near-peer adversaries will necessitate the exclusion of weapon systems with obsolete cryptography from Combatant Commander Areas of Responsibility (AORs)—diminishing the ability of the DAF to communicate securely in a high-end fight. The 2021 National Defense Authorization Act (NDAA) mandates the services begin reporting on their CM activities and status of obsolete products starting in Jan 2022, as well as the National Security Memorandum 10 (4 May 2022) which identifies the need for quantum-resistant crypto. These documents highlight the high importance of ISSP efforts. The overall focus of the Research, Development, Test, and Evaluation (RDT&E) efforts within the ISSP program is to transform current CM devices to protect against current technology threats, which include quantum computing. The modernization effort is required by Chairman Joint Chiefs of Staff Notice (CJCSN) 6510 and NSA Decertification Messages (CED-31-15/037-21/032-16) from FY23 for the need to add Quantum Resilience (QR) to the existing high assurance cryptographic products. This effort will allow protection against advanced & evolving quantum computing threats. All existing crypto devices will be vulnerable and must be modernized to be quantum resilient. These efforts are driven by the NSA requirements to implement newly developed Quantum Resistant Algorithms (QRAs). The NSA requires an inventory of cryptographic devices that are more resilient to future threats through full software re-programmability. This will enable protection against near peer adversary exploitation and provide the ability to rapidly adapt against newer threats. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0303140F / Information Systems Security Program Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 2.074M was expended for civilian pay expenses in this program element, and in FY 2025 3.894M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 200992000, 211387000, 189537000, NULL, NULL, 235, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 91663000, 101551000, 117658000, 117658000, 0, 117658000, 208277000, $$Information Systems Security Program (ISSP) - Includes resources, manpower authorizations, necessary facilities and equipment required to develop, deliver, and sustain Cryptographic Modernization (CM) capabilities to nearly all Department of the Air Force (DAF) weapon systems that encrypt/decrypt sensitive information. CM ensures confidentiality, integrity, and availability of the information and the systems. The CM work done in the ISSP ensures that DAF systems receive cryptographic capabilities that are compliant with National Security Agency (NSA) mandates and that commanders can confidently leverage for Joint All Domain Command and Control (JADC2) capabilities. The ISSP element and associated CM activities provide a foundational Communications Security (COMSEC) capability that is the first and last line of cyber defense against adversary exploitation. The DAF and the Department of War (DoW) require the capability to securely collect, process, store, and disseminate an uninterrupted flow of information, while denying an adversary the ability to intercept, collect, destroy, interpret, or manipulate our information flows. CM provides secure communication to allow the DoW to achieve and maintain decision superiority, the key to successful application of the military instrument of national power in modern full-spectrum operations. DAF COMSEC equipment protects sensitive information such as warfighter positions, mission planning, target strikes, commanders' orders, intelligence, force strength, and force readiness. When an adversary is capable of interpretation, manipulation, or destruction of the information used by the warfighter, DoW military forces will suffer significant and/or devastating mission degradation that can result in loss of life and resources and/or exceptionally grave damage to national security. The advanced threats and capabilities of near-peer adversaries will necessitate the exclusion of weapon systems with obsolete cryptography from Combatant Commands—diminishing the ability of the DAF to communicate securely in a high-end fight. The 2021 National Defense Authorization Act (NDAA) mandates the services begin reporting on their CM activities and status of obsolete products starting in Jan 2022. The overall focus of the Research, Development, Test, and Evaluation (RDT&E) efforts within the ISSP program is to transform current CM devices to protect against current technology threats, which include quantum computing. The modernization effort is required by Chairman Joint Chiefs of Staff Notice (CJCSN) 6510 and NSA Decertification Messages (CED-31-15/037-21/032-16) from FY 2023 for the need to add Quantum Resilience (QR) to the existing high assurance cryptographic products. This effort will allow protection against advanced & evolving quantum computing threats. All existing crypto devices will be vulnerable and must be modernized to be quantum resilient. These efforts are driven by the NSA requirements to implement newly developed Quantum Resistant Algorithms (QRAs). The NSA requires an inventory of cryptographic devices that are more resilient to future threats through full software re-programmability. This will enable protection against near-peer adversary exploitation and provide the ability to rapidly adapt against newer threats. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element (PE) 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2025 3.214 million was expended for civilian pay expenses in this PE, and in FY 2026 4.279 million is forecast for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0303140F / Information Systems Security Program Operational Systems Development Information System Security Program (ISSP) received a Congressional add for FY 2026 4.0 million for a project under Business Enterprise Systems Product Innovation (BESPIN). Upon Congressional spend plan approval, an internal reprogramming will be processed aligning the funding to PE 0605829F Acquisition Workforce Cyber, Network and Business Systems for proper execution. The FY 2025 spend plan amount for Research, Development, Test and Evaluation includes $91,663 thousand in discretionary and $6,487 thousand of mandatory (reconciliation) for a total of $98,150 thousand, used for Information Assurance Technical Assistance Center support in fielding systems. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303140K$$, $$Information Systems Security Program$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 23224000, 8034000, 31414000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0303140K", "page_header": "Defense-Wide"}$$::jsonb, $$Cyber Security & Analytics enables mission operations for global partners and the warfighter by providing communications through the delivery of optimized cyber infrastructure solutions. The intent is to be dominant in providing strategic and innovative cyber infrastructure to support Department of Defense (DoD) missions. Cyber Security & Analytics ensures enterprise services evolve support for a joint information assurance model. The joint information assurance model manages risks related to the use, storage, and transmission of information and supports a broad range of information sharing policies across the unclassified and classified communities. The enhancements to SIPRNet and its enablers will help to secure devices on the network. Cyber Security & Analytics will: • Test and develop active defensive capabilities. • Test and integrate software defined networking and orchestration closed-loop security, which through analytics, monitors and assesses network activities to improve network performance and mitigate negative network occurrences. • Perform research, development, and engineering of emerging cyber situational awareness technologies. • Improve the network performance by providing architecture support, systems engineering and analytical functions.$$, NULL, 16313000, 16498000, 15419000, NULL, NULL, 242, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 8881000, 23224000, 33502000, 33502000, NULL, 33502000, 15419000, $$Cyber Security & Analytics enables mission operations for global partners and the warfighter by providing communications through the delivery of optimized cyber infrastructure solutions. The intent is to be dominant in providing strategic and innovative cyber infrastructure to support Department of War (DoW) missions. Cyber Security & Analytics ensures enterprise services evolve support for a joint information assurance model. The joint information assurance model manages risks related to the use, storage, and transmission of information and supports a broad range of information sharing policies across the unclassified and classified communities. The enhancements to SIPRNet and its enablers will help to secure devices on the network. Cyber Security & Analytics will: • Test and develop active defensive capabilities. • Test and integrate software defined networking and orchestration closed-loop security, which through analytics, monitors and assesses network activities to improve network performance and mitigate negative network occurrences. • Perform research, development, and engineering of emerging cyber situational awareness technologies. • Improve the network performance by providing architecture support, systems engineering and analytical functions.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303140N$$, $$Information Sys Security Program$$, $$rdte_navy_ba7$$, $$peo_c4i$$, 2026, 64147000, 31475000, 35339000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0303140N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 93167000, 81386000, 81471000, NULL, NULL, NULL, NULL, NULL, FALSE, 34397000, 64147000, 79128000, 79128000, NULL, 79128000, 83011000, $$The Information Systems Security Program (ISSP) ensures the protection of Navy and Navy hosted joint telecommunication and Information Technology (IT) systems from cyber exploitation and attack. The ISSP extends cybersecurity to ensure confidentiality, integrity, and availability of these systems and content processed, stored, or transmitted therein by performing the acquisition, modernization and sustainment of cybersecurity platforms and systems; cyberspace operations include both defensive and offensive measures, which preserve the ability to protect data, networks, net-centric capabilities, and other designated systems while projecting power by the application of force in or through cyberspace. The ISSP includes the protection of the Navy's National Security Systems (NSS). The ISSP must be rapid, predictive, adaptive, and tightly coupled to cyberspace technology. The ISSP provides cybersecurity systems and infrastructure based on mission impacts, cybersecurity threats, information criticality, vulnerabilities, and required defensive countermeasure capabilities. The ISSP focuses on efforts that address the risk management of cyberspace, which provides capabilities to protect, detect, restore and respond. The ISSP provides the Navy with the following cybersecurity elements: (1) defense of NSS, including other mission requirements (details held at a higher classification), naval weapons systems, critical naval infrastructure for Command, Control, Communications, Computers, & Intelligence (C4I) afloat and ashore networks, joint time and navigation systems, and industrial control systems, using modern cryptographic solutions and cyber security tools; (2) technologies for the Navy's Computer Network Defense (CND) service provider that accelerates the Navy's ability to prevent, constrain, and mitigate cyber attacks and critical vulnerabilities; (3) Navy Cyber Situational Awareness (NCSA) technologies that provides the operational context for cyber threat intelligence and Situational Awareness (SA), from external boundaries to tactical edge infrastructures; (4) assurance of the Navy's Cryptography (Crypto) telecommunications infrastructure and the wireless spectrum; (5) sensing cyber threats across all Navy ashore and afloat networks to expand the capabilities of monitoring, assessing, and detecting adversary activities across multiple enclaves through the collection of tools in SHARKCAGE; (6) assurance of joint-user cyberspace domains, using a Defense-In-Depth (DiD) security architecture and its alignment with the Joint Information Environment (JIE)/Joint Regional Security Stack (JRSS); (7) assurance technologies, including Key Management (KM) and Public Key Infrastructure (PKI). The Cybersecurity Engineering effort funds a continuing cybersecurity program, Situational Awareness Boundary Enforcement and Response (SABER), and a maturing Cybersecurity project, High Availability Virtual Environment (HAVEN). SABER is the research, design, development, testing, and installation of Cybersecurity solutions for installed integrated computer networks to include shipboard Hull Mechanical and Electrical (HM&E), Navigation Systems, Combat Systems, Fire Control, Sonar, Radar, Communications, and other shipboard computerized control systems for all afloat U.S. Navy platforms. SABER provides network boundary defense and situational awareness to protect and detect against external and internal cybersecurity-threats. HAVEN is a secure operating environment that provides a resilient and redundant infrastructure platform for rapid software deployment and system restoration. HAVEN provides the secure operating environment for SABER and a secure Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational  PE 0303140N / Information Sys Security Program Systems Development hosting environment. HAVEN has been considered a part of SABER and continued HAVEN development has led the Navy to understand that this capability may have use beyond hosting SABER.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303141A$$, $$Global Combat Support System$$, $$rdte_army_ba7$$, $$peo_eis$$, 2026, 0, 12605000, 2566000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0303141A", "page_header": "Department of the Army"}$$::jsonb, $$GCSS-Army gives combat forces a decisive edge by providing soldiers a seamless flow of timely, accurate, accessible, and secure logistics information to get combat power at the right place, at the right time. The GCSS-Army program is an information and communications technology investment that provides key enabling support to the transformation of the Army into a network-centric, knowledge-based future force. The GCSS-Army approved Capability Development Document (CDD) and Capability Production Document (CPD) require an enterprise approach to replace current logistics and maintenance Standard Army Management Information Systems (STAMIS) to include supply, maintenance, ammunition, aviation, and property book. GCSS-Army implements best business practices to streamline supply, accountability, maintenance, distribution, and reporting procedures in support of the future force transition path of The Army Campaign Plan. The funds in the GCSS-Army Research Development Test & Evaluation (RDT&E) line are for building the software solution for disconnected supply, ground maintenance and accountability, and Store and Forward Capability. In FY 2024 after transition to capability support, RDT&E funding for Continuous Enhancements was used to execute system change requests (SCRs) to enhance sustainment activities, accountability, auditability, and calculations of total cost of ownership. Implementation of SCRs enhance capability support and effectiveness by synchronizing system data and utilizing enterprise interface tools to eliminate input errors. FY 2025 Base dollars in the amount of $2.566 million continues to support GCSS-Army Audit related fixes and Cyber updates. Other FY 2025 enhancements include: follow-on Identity, Credential, and Access Management (ICAM) to include privilege user access management and zero trust. The FY 2025 RDT&E funds also support the completion of the software solution for disconnected supply, ground maintenance and accountability, and Store and Forward Capability. GCSS-Army does not have an RDTE funding request in FY 2026. GCSS-Army Enterprise Aviation is integrating the Aircraft Notebook (ACN) data into GCSS-Army via an interface with the Enterprise Aviation Middleware components. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                 Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 7: Operational   PE 0303141A / Global Combat Support System Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 231, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 2472000, 0, NULL, NULL, NULL, NULL, NULL, $$GCSS-Army gives combat forces a decisive edge by providing soldiers a seamless flow of timely, accurate, accessible, and secure logistics information to get combat power at the right place, at the right time. The GCSS-Army program is an information and communications technology investment that provides key enabling support to the transformation of the Army into a network-centric, knowledge-based future force. The GCSS-Army approved Capability Development Document (CDD) and Capability Production Document (CPD) require an enterprise approach to replace current logistics and maintenance Standard Army Management Information Systems (STAMIS) to include supply, maintenance, ammunition, aviation, and property book. GCSS-Army implements best business practices to streamline supply, accountability, maintenance, distribution, and reporting procedures in support of the future force transition path of The Army Campaign Plan. The funds in the GCSS-Army Research Development Test & Evaluation (RDT&E) line are for building the software solution for disconnected supply, ground maintenance and accountability, and Store and Forward Capability. GCSS-Army Enterprise Aviation is integrating the Aircraft Notebook (ACN) data into GCSS-Army via an interface with the Enterprise Aviation Middleware components.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303150K$$, $$Global Command and Control System Software and Digital Technology Pi$$, $$rdte_dw_ba8$$, $$dw_js$$, 2026, 44474000, 30777000, 31619000, NULL, $${"act": "08", "ba_raw": "6.8", "source": "r1_fy26", "service": "dw", "page_num": 82, "original_pe": "0303150K", "page_header": "Defense-Wide"}$$::jsonb, $$The Global Command and Control System-Joint (GCCS-J) is the Joint Command and Control (C2) system of record and an essential component for warfighting situational awareness. It provides an integrated near real-time picture of the battlespace to support joint and multinational operations on U.S. and coalition networks. GCCS-J displays air, maritime, ground, space, and cyber tracks for decision making. It also provides applications for missile warning, intelligence, targeting, imagery, and exploitation. Key decision makers at the strategic national, strategic theater, and operational levels rely on GCSS-J. GCCS-J supports Combined Joint All Domain Command and Control (CJADC2), which is the modernized approach to military decision making by promoting information sharing between Services. Through integrated and synchronized capability development, CJADC2 achieves agile and resilient C2 across the Services. CJADC2 capabilities provide the ability to connect distributed sensors, intelligence, information, data, and effects from all Services to decision makers at the speed of the mission. GCCS-J: • Provides a Common Operational Picture (COP) with ground, air, maritime, cyber, and space tracks of U.S., coalition, and enemy forces. • Has many tactical decision aids and other applications for COP management and situational awareness. • Is the system of record for Theater Missile Warning, which provides alerting and display for real time missile events. • Displays launch points, missile locations, threat fans, and projected impact points. • Provides intelligence support to C2 operators with national and tactical intelligence data from DIA's Modernized Integrated Database (MIDB), still and motion imagery, and other sources of intelligence. 1000+ GCCS-J instances can be found around the world (air, land and sea), on 30+ US and Coalition networks, and in 13 active Foreign Military Sales (FMS) cases with an additional two pending. The following Joint Staff instructions apply: CJCSI 3265.01A (Governance), CJCSI 6731.01C (Security), and CJCSI 3151.31D (Reporting). In FY 2026, DISA is aggressively funding the modernization of GCCS-J in accordance with Joint Staff priorities. GCCS-J has not had a dedicated modernization fund since 2020. As part of modernization, DISA is taking GCCS-J to the cloud, making it Zero Trust and IPv6 compliant, and creating web-based access on SIPRNet. DISA is also addressing its underlying data model to decrease latency and simplify future modernization. The goal is to provide a centralized hybrid cloud system that generates, displays, and distributes common tactical picture (CTP), common operational picture (COP) and common intelligence picture (CIP) data in near-real-time using the CJADC2 data fabric to users around the world, including those operating under Denied - Disconnected, Intermittently Connected Limited (D-DIL) conditions on mission partner networks. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                              Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 8:          PE 0303150K / Global Command and Control System Software and Digital Technology Pi Software and Digital Technology Pilot Programs                                lot Programs$$, NULL, 85036000, 84994000, 85545000, NULL, NULL, 302, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 32632000, 44474000, 124329000, 124329000, NULL, 124329000, 85545000, $$The Global Command and Control System-Joint (GCCS-J) is the designated joint Command and Control (C2) system that provides a near-real-time, integrated picture of the battlespace, which is essential for situational awareness in warfighting scenarios. GCCS-J is a crucial tool for decision-makers at the strategic national, strategic theater, and operational levels. GCCS-J supports both joint and multinational operations across various networks by displaying air, maritime, ground, space, and cyber tracks. GCCS-J also includes applications for missile warning, intelligence, targeting, and imagery exploitation. GCCS-J is a key component of the Combined Joint All Domain Command and Control (CJADC2) framework. CJADC2 is a modernized approach to military decision- making that emphasizes information sharing across all service branches to achieve agile and resilient C2. This integration allows for the connection of distributed sensors, intelligence, and data from all services to provide decision-makers with information at the speed of the mission. Key features of GCCS-J include: • Common Operational Picture: Provides a comprehensive view of U.S., coalition, and enemy forces across all domains (ground, air, maritime, cyber, and space). • Tactical Decision Aids: Offers various applications to manage the Common Operational Picture and enhance situational awareness. • Theater Missile Warning: Serves as the system of record for real-time missile event alerts and displays, including launch points, missile locations, threat fans, and projected impact points. • Intelligence Support: Delivers national and tactical intelligence data to C2 operators from sources like the Defense Intelligence Agency’s (DIA)'s Military Intelligence Integrated Database (MIDB) as well as still and motion imagery. Originally built in 1996, GCCS-J needs significant modernization. GCCS-J takes in sensor and data feeds from 45+ other Department of War (DoW) and non-DoW systems and fuses them into a Common Operational Picture to share with more than 35 consuming systems used by the DoW, Department of State, Department of Homeland Security, and allied mission partners. In addition to producing the Common Operational Picture, GCCS-J is part of many systems of systems fielded by the U.S. Military Services, including the U.S. Coast Guard, and the U.S Intelligence community. Modifying the functionality of GCCS-J can impact all the systems that contain GCCS-J. Since 1996, the C2 landscape has shifted dramatically, and the amount of data available to the warfighter from sensors, Unmanned Arial Vehicles (UAVs), and satellite feeds has grown exponentially. Further, the informational advantage offered by artificial intelligence, automation, and cloud computing has evolved beyond the scope of the original architecture. Developed on a small scale relevant to the 1990s, the GCCS-J architecture is incapable of efficiently interfacing with an increasing diversity of contributing and receiving operational systems. To be able to meet the growing demands and dependencies, GCCS-J must be modernized to eliminate legacy system components that prevent the delivery and analysis of data in near-real-time for success in contested battlespace. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 8:               PE 0303150K / Global Command and Control System Software and Digital Technology Pi Software and Digital Technology Pilot Programs                                     lot Programs However, the Department has pursued a strategy of ongoing incremental modernization, canceling planned full-scale replacements in 2009 and 2017 due to the complexity of GCCS-J’s decentralized architecture. GCCS-J’s complexity is compounded by its nature as a heterogeneous system of systems operating across a diverse set of national asset and multinational partner customers, requiring intricate integration of legacy software, commercial off-the-shelf hardware, and government- developed applications.1,000+ GCCS-J instances can be found around the world (air, land, and sea), on 30+ U.S. and Coalition networks, and in 13 active Foreign Military Sales cases with an additional two pending. In FY 2026, the Defense Information Systems Agency (DISA) began funding the modernization of GCCS-J in accordance with Joint Staff priorities. GCCS-J had not had a dedicated modernization fund since 2020. DISA is taking GCCS-J to the cloud, making it Zero Trust and Internet Protocol Version Six (IPv6) compliant, and creating web-based access on the Secret Internet Protocol Router Network (SIPRNet). DISA is also addressing its underlying data model to decrease latency and simplify future modernization. The goal is to provide a centralized hybrid cloud system that generates, displays, and distributes Common Tactical Picture, Common Operational Picture, and Common Intelligence Picture data in near-real-time to users around the world, including those operating under Denied - Disconnected, Intermittently Connected, Limited (D-DIL) conditions on mission partner networks. Given the Departmental priorities to Reestablish Deterrence and Rebuild the Military, DISA is rapidly accelerating GCCS-J modernization beginning in FY 2027. This entails porting the functionality of the legacy system into the modern architecture using the Global Logical Data Model for C2 systems, developing new capabilities and features to meet evolving requirements (IPv6, Zero Trust, cloud deployment, container orchestration, and open application platform interfaces), and divesting of functions no longer relevant to the mission or that are provided from other sources. DISA will roll out new features in usable increments starting in FY 2027 until the modernization effort is complete and the program returns to an evolutionary sustainment model. As part of modernization, DISA is adapting its intelligence community capabilities to keep pace with the DIA’s migration from its retiring Military Intelligence Integrated Database (MIDB) to the Machine-assisted Analytic Rapid-repository System (MARS). This deeply rich new intelligence system delivers data in an entirely different format and methodology yet remains critical to allowing decision makers to see intelligence data in context with other friendly, hostile, and neutral elements in the battlespace. Apart from GCCS-J modernization, DISA is also addressing United States Space Command (USSPACECOM) priorities for the existing GCCS-J baseline. To effectively and efficiently meet its current operational needs to defend the United States and its allies in and from space, USSPACECOM has determined it needs new capabilities to be developed and fielded starting in FY 2027. USSPACECOM requirements overlap with operational priorities the Joint Staff provided DISA following consultation with the user community. Addressing these Joint Staff operational priorities will benefit both USSPACECOM and the world-wide GCCS-J user community. DISA is developing GCCS-J capabilities in accordance with the Mission Network as a Service (MNaaS) framework, which aims to deliver a unified, secure, and agile Secret environment for the Combined Joint Force. GCCS-J contributes to MNaaS by providing the Combined Joint Force with a Common Operational Picture to coordinate complex operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 8:           PE 0303150K / Global Command and Control System Software and Digital Technology Pi Software and Digital Technology Pilot Programs                                 lot Programs$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303153K$$, $$PEO Spectrum$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 20174000, 24878000, 24991000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0303153K", "page_header": "Defense-Wide"}$$::jsonb, $$The Program Executive Office (PEO) Spectrum delivers Electromagnetic Spectrum (EMS) operations (EMSO) management software capabilities, engineering, and analytical services. These software programs, engineering and analysis services mitigate negative effects from harmful EMS interference and enable friendly forces to gain and maintain advantages in contested and congested EMS environments to meet their warfighting needs. Access to the radio frequency portion of the EMS plays a critical role in national security. The PEO Spectrum delivers a broad range of capabilities and services to enable spectrum access to support data links and decision making at all levels of the DoD from strategic to tactical. The entire DoD uses these spectrum capabilities with the DISA as the sole provider for many of the DoD’s EMSO needs. The PEO Spectrum develops the primary capabilities for these functions, which include cloud-based spectrum management software and services, under the Electromagnetic Battle Management-Joint (EMBM-J) and the Global Electromagnetic Spectrum Information System (GEMSIS) capability portfolios. The PEO Spectrum EMBM-J program is the Joint EMS Command and Control (C2) system for the DoD and critical to CJADC2 and DoDs EMSO warfighting needs. The PEO Spectrum GEMSIS portfolio delivers the End to End Spectrum Supportability (E2ESS) capability, the DoD’s enterprise Blue data capture and host nation coordination capability. DoD personnel (Services and CCMDs) use the E2ESS application to create a digital record of DoD spectrum dependent systems (C5ISR) and to coordinate host nation spectrum access for all of DoD. GEMSIS also delivers the Joint Spectrum Data Repository, an authoritative EMS Blue data repository containing millions of DoDs and coalition partner records needed for the planning and execution of DoD EMS Operations. Additionally, the PEO Spectrum Sharing and Coordination capabilities portfolio enables Dynamic Spectrum Sharing, which involves coordinating DoD spectrum access with the United States Federal Regulator. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                         Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:        PE 0303153K / PEO Spectrum Operational Systems Development$$, NULL, 52094000, 61129000, 49261000, NULL, NULL, 243, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 24530000, 20174000, 49466000, 49466000, NULL, 49466000, 38695000, $$The Department of War (DoW) faces growing threats to its use of the Electromagnetic Spectrum (EMS) from peer and near-peer adversaries. Operations are further complicated by debilitating electromagnetic interference from friendly forces operating without coordination in the same environment. These significant challenges are compounded by the Department's reliance on manual, siloed, and non-interoperable legacy EMS systems and processes. Overlapping legacy tools and capabilities are housed in disparate environments and managed by both the Defense Information Systems Agency (DISA) (e.g., Electromagnetic Battle Management-Joint (EMBM-J) and Global Electromagnetic Spectrum Information System (GEMSIS)) and the Services (e.g. Automated Communications Engineering System (ACES) and Systems Planning, Engineering, and Evaluation Device (SPEED)). In FY 2027, the DoW is investing in EMS Information Technology (EMS IT) modernization, consolidating these spectrum tools and capabilities into a single artificial intelligence-enabled platform – Maven Smart Systems (MSS). MSS is a comprehensive, Software as a Service-based enterprise data operating system designed to integrate, manage, and analyze data from disparate sources in support of U.S. military operations. MSS serves as a central hub connecting raw data, analytics, and artificial intelligence/machine learning models to real-world military operations. The initial work in FY 2027 will focus on migrating DISA-owned capabilities, with an emphasis on EMBM-J. EMS IT modernization will replace legacy spectrum management capabilities and apply automation and artificial intelligence to enable joint force commanders to coordinate, synchronize, and integrate the use of EMS across the full range of military operations, by providing robust and integrated spectrum management, Situational Awareness (SA), Command and Control (C2), and Decision Support (DS). Further, by transforming the EMS into a truly agile, resilient, and intelligently managed domain, EMS IT Modernization will provide the critical EMS end-to-end data layer for Combined Joint All-Domain Command and Control (CJADC2), enabling the rapid, secure, and uninterrupted flow of information necessary for decision advantage to achieve EMS superiority in any conflict. EMS IT modernization principles are outlined in the 2026 National Defense Strategy, 2023 Department Data, Analytics, and Artificial Intelligence Adoption Strategy, and 2020 Department of War Electromagnetic Spectrum Superiority Strategy (EM SSS). Capability development and modernization also align with Joint Staff validated requirements derived from combined Joint Force Commander (JFC)/Joint Task Force (JTF), Military Departments (MILDEPs), Services, and Combatant Command (CCMD) requirement needs under 2025 Joint Requirements Oversight Council Memorandum (JROCM) 070-25 Modern Electromagnetic Spectrum Information Technology Environment, 2023 JROCM 23-007 U.S. Strategic Command 2023 Electromagnetic Spectrum Operational Assessment, 2020 Joint Publication 3-85 Joint Spectrum Operations, and 2020 JROCM 086-20 Electromagnetic Battle Management. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0303153K / PEO Spectrum Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0605516N$$, $$Long Range Fires$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 138443000, 0, 120728000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "navy", "page_num": 35, "original_pe": "0605516N", "page_header": "Department of the Navy", "fy27_base_v158_t7": "hygiene: base=request for disc-only RDT&E rows post v7 I-23/I-24 + v9 I-2 INSERTs"}$$::jsonb, $$The details of this program element are classified SECRET and are submitted annually to Congress in the classified books.$$, NULL, NULL, NULL, NULL, NULL, NULL, 174, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, NULL, NULL, 186735000, 186735000, NULL, 186735000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303169D8Z$$, $$Information Technology Rapid Acquisition$$, $$rdte_dw_ba6$$, $$dw$$, 2026, 4355000, 0, 0, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0303169D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiative to modernize critical legacy information technology (IT) portfolio management systems and develop strategies and initiatives to improve the efficiency and effectiveness of IT investments across the DoD information enterprise. The current systems (Select and Native Programming Data Input System – Information Technology (SNaP-IT), Department of Defense Information Technology Investment Portal (DITIP), and DoD Information Technology Portfolio Repository (DITPR)) were developed as standalone applications/systems to meet specific data requirements, which results in data inaccuracy and inconsistency. The modernization effort includes developing business process maps, system design diagrams, and data dictionaries, which will form the baseline to analyze processes, data, and system redundancies and required improvements across the various systems. The modernization effort will achieve an integrated IT portfolio management process and a more homogenous data and reporting environment, which delivers timely, accurate, and transparent information to leadership. This program element also supports developing information enterprise strategies, policies, architectures, and deliver DoD’s software modernization implementation-plan, while also streamlining business systems.$$, NULL, 6599000, 6721000, 6875000, NULL, NULL, 210, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 0, 4294000, 6416000, 6416000, NULL, 6416000, 7019000, $$Supports and enables Department initiatives to modernize legacy information technology (IT)-based systems, infrastructure, and supporting portfolio management tools and processes to achieve cost efficiency, mission effectiveness and improved IT investment management across the DoW Information Network (DoWIN). Provides technical studies and analysis to inform Department-wide strategies, policies, and investments for the enterprise information environment and business mission areas. Provides studies and analysis to inform and support modernization or replacement of disparate SNaP-IT, DITIP, and DITPR systems – which currently lead to data inconsistency – with a unified process based on detailed business process maps, system designs, and data dictionaries. The program delivers timely, accurate, and transparent information to leadership, enabling better decision-making. It enhances combatant command capabilities by analyzing major cloud initiatives, implementing DevSecOps practices for secure software development, improving network efficiency and resilience through assessments and recommendations, and conducting research to inform strategic objectives.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303171K$$, $$Joint Planning and Execution Services (JPES)$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 6242000, 6605000, 3304000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0303171K", "page_header": "Defense-Wide"}$$::jsonb, $$The DISA, through the Joint Planning & Execution Services (JPES) Program Management Office (PMO), provides information technology (IT) capabilities to support the DoD’s Joint Planning Process (JPP). These capabilities support force planning, deployment planning, allocation of forces, and execution of Global Force Management (GFM) processes for military operations as part of the Joint Command & Control (JC2) mission. The JPES capability represents the modernization effort of critical JC2 GFM mission-enabling capabilities in two phases. Phase I encompasses the modernization of the Joint Operations Planning and Execution System (JOPES) and Phase II encompasses the modernization of the Joint Capabilities Requirements Manager (JCRM). • Phase I, the modernization of JOPES, is currently underway. In accordance with the DISA Component Acquisition Executive (CAE) Acquisition Decision Memorandum (ADM) of 09 September 2022 which established objective and threshold dates, delivery of completed JPES software from the contractor was originally scheduled to occur in Q2FY2024 (objective). Interoperability and operational testing was originally scheduled to occur in Q2/3FY2024 (objective) and transition with JOPES was originally scheduled to occur in Q3FY2024 (objective) and end in Q4FY2024 (objective) with the threshold dates being one quarter later. Due to vendor delays, JPES is currently re-baselining its schedule and will submit to a Milestone Decision Authority for approval. Accordingly, current re-baselined dates for JPES or JOPES sunset are not available at this time. DISA expects JPES development to extend well into FY 2025. JOPES sunset will follow a successful transition. Once deployed and operational, the JPES effort will address new functional requirements and enhancements related to military operation monitoring, planning, and execution activities. JPES will support thousands of operational users across the globe. Additionally, there are 25 external systems across the Combatant Commands (CCMDs), Military Services, and Defense Agencies that are dependent on JOPES to perform force planning, deployment planning and execution activities. • Phase II, which includes the development of new JPES functional requirements and the modernization of JCRM, will begin in FY 2025. Incorporating functionality into JPES begins mid-FY 2026 with full engagement in FY 2027. JCRM is a web-based application and database supported by web services. It enables the Global Force Management Allocation Process (GFMAP) for CCMDs to draft, staff, store, and submit force requirements for ongoing and emerging military operations, contingency plans, and military exercises worldwide. JCRM is vital to managing complex global force requirements and tracking the distribution of U.S. military forces among the CCMDs. Regardless of modernization, there is no alternate capability to fulfill the ongoing capabilities of JCRM. Modernization of JOPES is crucial because current capabilities are increasingly expensive to maintain, and the existing system is composed of an increasing number of End-of-Life (EOL) and End-of-Support (EOS) components. Because there is no other equivalent tool available to support the deployment of troops or equipment and Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                                      Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:              PE 0303171K / Joint Planning and Execution Services (JPES) Operational Systems Development supplies to support the National Military Strategy and the National Security Strategy, the existing system is incurring significant risk for mission failure. By improving planning and execution of military operations and enabling the ability to respond to ongoing military operations and crises that require military intervention, replacing JOPES reduces the risk of mission failure.$$, NULL, 11583000, 11807000, 12069000, NULL, NULL, 244, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 3816000, 6242000, 10615000, 10615000, NULL, 10615000, 12069000, $$The DISA Global Force Management Program Management Office provides information technology capabilities to support the Department of War’s (DOW’s) Joint Planning Process (JPP). These capabilities enable force planning, deployment planning, allocation of forces, and execution of Global Force Management (GFM) processes for military operations as part of the Joint Command & Control (JC2) mission. Joint Planning and Execution Services (JPES) is the two-phased modernization of critical JC2 GFM mission-enabling capabilities; Phase I is the replacement of the Joint Operations Planning and Execution System (JOPES) with the new JPES system, and Phase II is the continued enhancement of JPES to meet Service-specific requirements and eventual Joint Capabilities Requirements Manager (JCRM) replacement. There are no DoW alternatives to JCRM and JOPES/JPES. Phase I: The replacement of JOPES with JPES is currently underway. Previous delays in the development of JPES have been resolved and the program is meeting its Milestone Decision Authority approved cost, schedule, and performance thresholds. A deployment of the JPES application was executed via the cloud (Azure Impact Level 6) in Q3 FY 2025, and JPES is on schedule to declare Initial Operational Capability by Q2 FY 2026 and Full Operational Capability (FOC) by Q3 FY 2026. Once FOC is declared, JPES will provide a modern application and architecture for all Combatant Commands (CCMDs), Services, and Defense Agencies and Field Activities (DAFAs) to monitor, plan, and execute the mobilization, deployment, employment, and sustainment activities associated with operations and exercises. Additionally, JPES will be interoperable with 25 external systems to perform force planning, deployment, and execution activities. Phase II: Even though JPES is reaching FOC, JPES still requires further customization to meet the unique needs of the Services and CCMDs. Enhancements to JPES will add functionality and integrate GFM processes into the overarching operation planning and execution domain. Additionally, modernization will address DoW Chief Information Officer (CIO) priorities by incorporating Enterprise Identity, Credential, and Access Management, Zero Trust, Internet Protocol Version Six (IPv6), metadata tagging, and other service requirements including Newsgroups modernization and artificial intelligence to optimize planning and resourcing. DISA will also be moving JCRM to a secure Impact Level Six (IL6) cloud environment to prepare for future modernization. Continuous enhancement of JPES is essential due to JPES being the sole tool for deploying troops, equipment, and supplies in support of the National Military and National Security Strategies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                             Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0303171K / Joint Planning and Execution Services (JPES) Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303228K$$, $$Joint Information Environment (JIE)$$, $$rdte_dw_ba7$$, $$dw_disa$$, 2026, 0, 3079000, 2371000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0303228K", "page_header": "Defense-Wide"}$$::jsonb, $$Joint Information Environment (JIE)/The Joint Regional Security Stack (JRSS) is a joint Department of Defense (DoD) security architecture deployed regionally throughout the world. There are fourteen Non-Secure Internet Protocol Router (NIPR) stacks, which are a collection of software components designed to operate as a single unit. DISA will achieve cost reductions through planned Decommissioning Efforts and user transition off of JRSS in accordance with the JRSS Senior Advisory Group-approved Decommissioning Plan. The current JRSS footprint will be reduced to nine at the end of FY 2025 before closeout of the remaining stacks in FY 2027. Each stack is comprised of complementary defensive security solutions that: • Streamline cybersecurity protections. • Leverage enterprise defensive capabilities with standardized security suites to protect against attacks that disrupt or cause damage to the network. • Protect the JRSS enclaves (internal networks separate from the rest of the network) after the separation. • Provide the tool sets necessary to monitor all security mechanisms throughout the network. The JRSS Management System (JMS) provides management and operational control capabilities for the JRSS. The JMS centralizes and enhances the management of JRSS components and achieve economies of scale. The JMS enables DoD Components to maintain Title 10 required management and visibility of IT security while providing high level visibility to U.S. Cyber Command (CYBERCOM). This is done by: • Providing centralized management of the JRSS. • Providing visibility and control over network transport and associated security systems. • Enabling the monitoring and analysis of data to determine the impact on current operations. This centralized capability allows standardization of policies, procedures, and configurations and allows for Cyber Operations to take proactive actions to ensure the uninterrupted availability and protection of information. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                            Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0303228K / Joint Information Environment (JIE) Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 245, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 2284000, 0, NULL, NULL, NULL, NULL, NULL, $$Joint Information Environment (JIE)/The Joint Regional Security Stack (JRSS) is a joint Department of War (DoW) security architecture deployed regionally throughout the world. There are fourteen Non-Secure Internet Protocol Router (NIPR) stacks, which are a collection of software components designed to operate as a single unit. DISA will achieve cost reductions through planned Decommissioning Efforts and user transition off of JRSS in accordance with the JRSS Senior Advisory Group- approved Decommissioning Plan. The current JRSS footprint will be reduced to nine at the end of FY 2025 before closeout of the remaining stacks in FY 2027. Each stack is comprised of complementary defensive security solutions that: • Streamline cybersecurity protections. • Leverage enterprise defensive capabilities with standardized security suites to protect against attacks that disrupt or cause damage to the network. • Protect the JRSS enclaves (internal networks separate from the rest of the network) after the separation. • Provide the tool sets necessary to monitor all security mechanisms throughout the network. The JRSS Management System (JMS) provides management and operational control capabilities for the JRSS. The JMS centralizes and enhances the management of JRSS components and achieve economies of scale. The JMS enables DoW Components to maintain Title 10 required management and visibility of IT security while providing high level visibility to U.S. Cyber Command (CYBERCOM). This is done by: • Providing centralized management of the JRSS. • Providing visibility and control over network transport and associated security systems. • Enabling the monitoring and analysis of data to determine the impact on current operations. This centralized capability allows standardization of policies, procedures, and configurations and allows for Cyber Operations to take proactive actions to ensure the uninterrupted availability and protection of information. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                              Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:          PE 0303228K / Joint Information Environment (JIE) Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303248F$$, $$All Domain Common Platform$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 76642000, 69565000, 82927000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0303248F"}$$::jsonb, $$This budget line funds the All Domain Common Platform (ADCP), an extensible cloud-based Infrastructure and Platform as a Service (IaaS/PaaS) hosting medium built to deliver highly resilient Command and Control (C2) mission applications and data to Airmen deployed around the world. The ADCP is a warfighting capability that enables on-boarded users to build, deploy, and monitor mission applications to the end state of production. Having applications operational in various environments ensures data is accessible as it is needed across United States Air Force (USAF) mission sets. The ADCP's collection of technologies, services, and tooling enables warfighter outcomes by abstracting away technical complexity and enabling the deployment of products onto its infrastructure. Efforts within this PE align with USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (0207410F), C2IMERA (0305015F/0305836F) and ABMS (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. The FY 2026 request was reduced by -$1.869 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 13.074 million was expended for civilian pay expenses in this program element, and in FY 2025 16.800 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                               Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0303248F / All Domain Common Platform Operational Systems Development$$, NULL, 73848000, 74783000, 75743000, NULL, NULL, 236, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 86301000, 75711000, 71312000, 71312000, 0, 71312000, 75365000, $$All Domain Common Platform (ADCP) provides platform, infrastructure, networking, cloud hosting, Air Operations Center (AOC) hybrid cloud architecture, operational edge, and engineering services using Agile methodologies and Development, Security, and Operations (DevSecOps) practices to deliver improved capabilities at scale in support of Command-and-Control mission requirements. Platform customers include the Air Operations Center (AOC), Intelligence Programs, the Command and Control Incident Management Emergency Response Application (C2IMERA), etc. ADCP contributes to the DAF Battle Network and Joint All-Domain Command and Control (JADC2), meeting system resiliency requirements through the escalating phases of warfare. Efforts within this program align with and depend upon USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (PE 0207410F), Command and Control Incident Management Emergency Response Application (C2IMERA) (0305836F), Advanced Battle Management System (ABMS) (0604003F) and Flight Ops (PE 0207461F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities necessary for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. In FY 2025 15.862 million was expended for civilian pay expenses in this program element, and in FY 2026 10.285 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0303248F / All Domain Common Platform Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303255F$$, $$Command, Control, Communication, and Computers (C4) - STRATCOM$$, $$rdte_af_ba6$$, $$aflcmc_hn$$, 2026, 15662000, 45725000, 39607000, NULL, $${"ba_raw": "6.6", "source": "af_r1_fy26", "original_pe": "0303255F"}$$::jsonb, $$Secretary of Defense tasked USSTRATCOM Nuclear Command, Control and Communications (NC3) Enterprise Center (NEC) to oversee and monitor operations and security of the enterprise, develop tools to assist in monitoring the readiness of the NC3 architecture, and capture the operational risks as adversaries develop the ability to disrupt our capabilities from multiple threat vectors. This effort will fund enterprise operations, requirements, systems engineering and assessment activities. The NEC will capture and integrate process and system data to assess operational risk, characterize multi-domain threats, and explore operational trade space associated with next generation NC3 architectures. The NEC will work with the Services to explore new technologies and develop innovative solutions in a virtual environment, and capture metrics that identify system problems and readiness issues before they impact operations. The NEC will also develop digital engineering capabilities to support governance responsibilities of NC3. The USSTRATCOM Strategic Mission Research and Development is an effort to tackle the hard Scientific and Technological (S&T) problems USSTRATCOM and DoD face in today's environment. Leveraging built-in tools and DoD/DHS data to anticipate and quickly analyze and assess national, strategic, and operational impacts/risks associated with the loss or disruption of critical systems, assets and infrastructure to help with USSTRATCOM Unified Command Plan (UCP) assigned mission sets. Current information together with logical links-nodes dependency views directly support mitigation COA development. This USSTRATCOM S&T initiative includes the three earliest stages of Department of Defense (DoD) RDT&E, including basic research, applied research, and advanced technology development. The FY 2026 request was reduced by [5.408] million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E         PE 0303255F / Command, Control, Communication, and Computers (C4) - STRATCOM Management Support This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, 0605898F, 0606398F. In FY 2024 00.725M was expended for civilian pay expenses in this program element, and in FY 2025 00.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, NULL, 16322000, 11585000, 12043000, NULL, NULL, 143, $$FY26 Air Force Research and Development Test and Evaluation Vol III.pdf$$, NULL, FALSE, 38161000, 61447000, 18068000, 18068000, 0, 18068000, 12286000, $$Department of War (DoW) tasked United States Strategic Command (USSTRATCOM) Nuclear Command, Control and Communications (NC3) Enterprise Center (NEC) to oversee and monitor operations and security of the enterprise, develop tools to assist in monitoring the readiness of the NC3 architecture, and capture the operational risks as adversaries develop the ability to disrupt our capabilities from multiple threat vectors. This effort will fund enterprise operations, requirements, systems engineering and assessment activities. The NEC will capture and integrate process and system data to assess operational risk, characterize multi-domain threats, and explore operational trade space associated with next generation NC3 architectures. The NEC will work with the Services to explore new technologies and develop innovative solutions in a virtual environment, and capture metrics that identify system problems and readiness issues before they impact operations. The NEC will also develop digital engineering capabilities to support governance responsibilities of NC3. The USSTRATCOM Strategic Mission Research and Development is an effort to tackle the hard Scientific and Technological (S&T) problems USSTRATCOM and DoW face in today's environment. Leveraging built-in tools and DoW/DHS data to anticipate and quickly analyze and assess national, strategic, and operational impacts/risks associated with the loss or disruption of critical systems, assets and infrastructure to help with USSTRATCOM Unified Command Plan (UCP) assigned mission sets. Current information together with logical links-nodes dependency views directly support mitigation COA development. This USSTRATCOM S&T initiative includes the three earliest stages of Department of War (DoW) RDT&E, including basic research, applied research, and advanced technology development. The FY 2026 request was reduced by 5.408 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 6: RDT&E           PE 0303255F / Command, Control, Communication, and Computers (C4) - STRATCOM Management Support This program is in Budget Activity 6, RDT&E Management Support because this budget activity includes research, development, test and evaluation efforts and funds to sustain and/or modernize the installations or operations required for general research, development, test and evaluation.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume III.pdf$$) ON CONFLICT DO NOTHING;
