INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305103C$$, $$Cyber Security Initiative$$, $$rdte_dw_ba4$$, $$dw$$, 2026, 2131000, 2692000, 1831000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "dw", "page_num": 73, "original_pe": "0305103C", "page_header": "Defense-Wide"}$$::jsonb, $$The Missile Defense Agency (MDA) Counterintelligence (CI) Division conducts CI in Cyberspace activities pursuant to Department of Defense (DoD) Directive 5240.02 (Counterintelligence) and DoD Instruction S-5240.23 (CI Activities in Cyberspace) to identify, disrupt, neutralize, and mitigate foreign intelligence services and international terrorist organizations, hereafter referred to as foreign entities, to act in observable or exploitable ways. To this end, the MDA CI Division conducts activities to detect, neutralize, and mitigate foreign entity-directed malicious and insider threat activities targeting MDA administrative and Missile Defense fire control networks and mobile devices.$$, NULL, 2026000, 1794000, 1683000, NULL, NULL, 135, $$RDTE_Vol2_MDA_RDTE_PB26_Justification_Book.pdf$$, $$MDA$$, FALSE, 1895000, 2104000, 2160000, 2160000, NULL, 2160000, 1695000, $$The Missile Defense Agency (MDA) Counterintelligence (CI) Division conducts CI in Cyberspace activities pursuant to Department of Defense (DoD) Directive 5240.02 (Counterintelligence) and DoD Instruction 5240.23 (CI Activities in Cyberspace) to identify, disrupt, neutralize, and mitigate foreign intelligence services and international terrorist organizations, hereafter referred to as foreign entities, to act in observable or exploitable ways. To this end, the MDA CI Division conducts activities to detect, neutralize, and mitigate foreign entity-directed malicious and insider threat activities targeting MDA administrative and Missile Defense fire control networks and mobile devices.$$, $$Budget J-Books/FY27/Remaining/RDTE_Vol2_MDA_RDTE_PB27_Justification_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305103F$$, $$Cyber Security Initiative$$, $$rdte_af_ba7$$, $$afrl_ri$$, 2026, 310000, 0, 304000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305103F"}$$::jsonb, $$Integrate MDCO network sensor collections and analytical capabilities to enable data sharing. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Cyber Security Initiative capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605831F, 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.0M was expended and in FY26 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 330000, 337000, 344000, NULL, NULL, 250, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 292000, 305000, 318000, 318000, 0, 318000, 351000, $$Integrate MDCO network sensor collections and analytical capabilities to enable data sharing. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Cyber Security Initiative capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605831F, 0605827F, 0605828F, 0605829F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 $0.0M was expended and in FY26 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305104D8Z$$, $$Defense Industrial Base (DIB) Cyber Security Initiative$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 10840000, 20922000, 15524000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305104D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The DoD CIO defense industrial base (DIB) cybersecurity initiative includes the Cybersecurity Maturity Model Certification (CMMC) program that was previously contained in PE 0606771D8Z (Cyber Resiliency & Cybersecurity Policy), and additional cybersecurity strategy, policy, and capability development efforts to support our DIB partners and our DIB supporting capabilities. This program works side-by-side with other DoD CIO programs, including the DoD CIO information systems security program (PE 0303140D8Z), to provide focused DoD capability requirements to assess DIB contractor and subcontractor compliance with existing federal contract and controlled unclassified information (CUI) protection requirements, protecting the information from cybersecurity risks, including advanced persistent threats. It also includes efforts to develop, test, and distribute DoD cybersecurity services for DIB partners and stakeholders. This program works in alignment with/to meet the “Fulcrum: The DoD Information Technology Advancement Strategy”, FY 2022 – 2026 DoD Strategic Management Plan, DoD CIO 2024 DIB Cybersecurity Strategy, and DoD CIO 2022 Zero Trust (ZT) Strategy. This PE also supports the objectives of an integrated deterrence though deterrence tailored approaches and building enduring advantages by transforming the future force foundation and adapting and fortifying our defense ecosystem.$$, NULL, 17535000, 17845000, 18246000, NULL, NULL, 252, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 14956000, 10687000, 17077000, 17077000, NULL, 17077000, 18628000, $$The DoW CIO defense industrial base (DIB) cybersecurity initiative includes the Cybersecurity Maturity Model Certification (CMMC) program, cybersecurity strategy, policy, and capability development efforts to support our DIB partners and our DIB supporting capabilities. This program works side-by-side with other DoW CIO programs, including the DoW CIO information systems security program (PE 0303140D8Z), to provide focused DoW capability requirements to assess DIB contractor and subcontractor compliance with existing federal contract and controlled unclassified information (CUI) protection requirements, protecting the information from cybersecurity risks, including advanced persistent threats. It also includes efforts to develop, test, and distribute DoW cybersecurity services for DIB partners and stakeholders. This program works in alignment with/to meet the FY 2022 – FY 2026 DoW Strategic Management Plan, DoW CIO 2024 DIB Cybersecurity Strategy, and DoW CIO 2022 Zero Trust (ZT) Strategy. This program also supports defending the homeland and revitalizing America’s DIB by transforming the future force foundation and adapting and fortifying our defense ecosystem.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305111F$$, $$Weather Service$$, $$rdte_af_ba7$$, $$aflcmc_hn$$, 2026, 30509000, 52701000, 40782000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305111F"}$$::jsonb, $$This budget activity funds the operational development necessary to acquire and modernize Air Force Weather Service [AFWS] capabilities in support of the 2022 National Defense Strategy's [NDS] three lines of effort. To improve readiness for a more lethal force, AFWS provides timely, accurate, resilient, and relevant environmental information to enable global battle-space situational awareness for the Air Force [AF], Army, Special Operations Forces [SOF], Space Force [USSF], combatant commands, the Intelligence Community [IC], and other government agencies. AFWS provides extreme weather impacts and assessments, as well as space and terrestrial weather sensing, forecasting, and weather analytic capabilities, at home station and deployed, in order to deliver critical environmental information in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. AFWS decreases the risk to mission and risk to force by increasing the lethality, effectiveness, and survivability of Department of Defense [DoD] weapon systems. To strengthen alliances and partnerships, AFWS development efforts integrate DoD, government agency, commercial, and international partner environmental data and software with AFWS information systems for processing, storing, exploiting, and disseminating all-domain weather information for analysis, forecasting, mission integration, and greater interoperability. To ensure greater performance and affordability for the Department of the AF, AFWS sensors and information systems are being modernized through improvements to architecture and system efficiency, cybersecurity, joint all-domain command and control [JADC2] and sensing grid integration, environmental sensor development, migration to cloud computing, artificial intelligence and machine learning [AI/ML] initiatives, and expanding agile software development, rapid delivery, and integration practices. The AF Weather Enterprise digital transformation and cloud migration effort modernizes key capabilities providing the military advantage to accurately predict environmental impacts optimizing mission planning, targeting, weaponeering, mission execution, battle damage assessment, and space systems operations. AFWS aligns activities under four capability areas: Weather Data Collection, Weather Data Analysis and Dissemination, Weather Forecasting, and Product Tailoring/Warfighter Applications [PTWA]. This alignment ensures an integrated and systems-oriented approach to program management and technical baseline decisions. All four capability areas are addressed by APPN 3600, BA 07, PE 0305111F, Project 672738 - Weather Service. Weather Data Analysis [WDA] Increment 5 and Weather Applications Rapid Production [WARPspeed] programs of record are Software Acquisition Pathway Programs. 1. Weather Data Collection provides automated atmospheric and ground-based space environmental sensing capabilities at fixed and deployed locations worldwide. The data gathered by multiple sensor systems is exploited for environmental battlespace awareness, characterization, safety of flight, resource protection, and satellite anomaly assessments and impacts. 2. Weather Data Analysis and Dissemination provides a multi-level security classification and cybersecure cloud computing-based platform supporting large-scale environmental data ingest, processing, and product generation, Continuous Integration/Continuous Delivery [CI/CD] and AI/ML environments for AFWS software development and deployment, and machine-to-machine dissemination of specific, mission-tailored weather data on-demand to support warfighter operations, weapon Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0305111F / Weather Service Operational Systems Development system interoperability, rapidly integrating into C2 nodes, and shortening the Combatant Commander kill chain. The Weather Data Analysis and Dissemination capability area includes activities for Weather Data Analysis Increment 5 [WDA Inc 5]. 3. Weather Forecasting provides global and regional advanced scientific numerical weather and extreme weather prediction capabilities for automated, high-resolution forecast products supporting mission planning and execution with an emphasis on clouds, theater scale weather, aerosol/chemical constituents, hydrology, machine learning, and space environmental characterization. Weather Forecasting includes activities for Numerical Weather Modeling [NWM] 4. Product Tailoring Warfighter Applications [PTWA] develops and modernizes software applications that provide and enhance environmental information to support rapid warfighter decision-making. PTWA includes the program, Weather Applications Rapid Production [WARPspeed], which is a suite of software applications developed and delivered across multiple security classification levels. WARPspeed encompasses weather workflow tools and decision aids used to tailor terrestrial and space environmental information, which include both Forecaster-in-the-Loop [FITL] and automated machine-to-machine processes enhanced by AI/ML. WARPspeed leverages the WDA Inc 5 cloud computing, data processing, and CI/CD and AI/ML platforms to rapidly develop, deliver, and sustain software capabilities, whether deployed into the AF Weather Virtual Private Cloud [AFW-VPC] and to warfighter processing nodes at the edge. Activities include research and analysis to support current program planning. Management Service costs include Federally Funded Research and Development Centers [FFRDC] and Advisory and Assistance Service [A&AS]. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, SEC 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver Weather Service capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 $0.264M was expended for civilian pay expenses in this program element, and in FY25 $0.337M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305111F / Weather Service Operational Systems Development$$, NULL, 32735000, 32709000, 32895000, NULL, NULL, 251, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 39438000, 50129000, 29331000, 29331000, 0, 29331000, 33553000, $$This budget activity funds the operational development necessary to acquire and modernize Air Force Weather Service [AFWS] capabilities in support of the 2026 National Defense Strategy's [NDS] lines of effort. To prioritize military excellence and readiness, AFWS provides timely, accurate, resilient, and relevant environmental information to enable global battle-space situational awareness for the Air Force [AF], Army, Special Operations Forces [SOF], Space Force [USSF], combatant commands, the Intelligence Community [IC], and other government agencies. AFWS provides extreme weather impacts and assessments, as well as space and terrestrial weather sensing, forecasting, and weather analytic capabilities, at home station and deployed, in order to deliver critical environmental information in support of decision makers to gain the asymmetric advantage during the full spectrum of air and space combat operations. AFWS decreases the risk to mission and risk to force by increasing the lethality, effectiveness, and survivability of Department of War [DoW] weapon systems. To re-establish deterrence, AFWS development efforts integrate DoW, government agency, commercial, and international partner environmental data and software with AFWS information systems for processing, storing, exploiting, and disseminating all-domain weather information for analysis, forecasting, mission integration, and greater interoperability. To rebuild our military and maximize lethality, AFWS sensors and information systems are being modernized through improvements to architecture and system efficiency, cybersecurity, joint all- domain command and control [JADC2] and sensing grid integration, environmental sensor development, migration to cloud computing, artificial intelligence and machine learning [AI/ML] initiatives, and expanding agile software development, rapid delivery, and integration practices. The AF Weather Enterprise digital transformation and cloud migration effort modernizes key capabilities providing the military advantage to accurately predict environmental impacts optimizing mission planning, targeting, weaponeering, mission execution, battle damage assessment, and space systems operations. AFWS aligns activities under four capability areas: Weather Data Collection, Weather Data Analysis and Dissemination, Weather Forecasting, and Product Tailoring/Warfighter Applications [PTWA]. This alignment ensures an integrated and systems-oriented approach to program management and technical baseline decisions. All four capability areas are addressed by APPN 3600, BA 07, PE 0305111F, Project 672738 - Weather Service. Weather Data Analysis [WDA] Increment 5 and Weather Applications Rapid Production [WARPspeed] programs of record are Software Acquisition Pathway Programs. 1. Weather Data Collection provides automated atmospheric and ground-based space environmental sensing capabilities at fixed and deployed locations worldwide. The data gathered by multiple sensor systems is exploited for environmental battlespace awareness, characterization, safety of flight, resource protection, and satellite anomaly assessments and impacts. 2. Weather Data Analysis and Dissemination provides a multi-level security classification and cybersecure cloud computing-based platform supporting large-scale environmental data ingest, processing, and product generation, Continuous Integration/Continuous Delivery [CI/CD] and AI/ML environments for AFWS software development and deployment, and machine-to-machine dissemination of specific, mission-tailored weather data on-demand to support warfighter operations, weapon Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                     R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                 PE 0305111F / Weather Service Operational Systems Development system interoperability, rapidly integrating into C2 nodes, and shortening the Combatant Commander kill chain. The Weather Data Analysis and Dissemination capability area includes activities for Weather Data Analysis Increment 5 [WDA Inc 5] and Commercial Weather Data [CWD]. 3. Weather Forecasting provides global and regional advanced scientific numerical weather and extreme weather prediction capabilities for automated, high-resolution forecast products supporting mission planning and execution with an emphasis on clouds, theater scale weather, aerosol/chemical constituents, hydrology, machine learning, and space environmental characterization. Weather Forecasting includes activities for Numerical Weather Modeling [NWM] 4. Product Tailoring Warfighter Applications [PTWA] develops and modernizes software applications that provide and enhance environmental information to support rapid warfighter decision-making. PTWA includes the program, Weather Applications Rapid Production [WARPspeed], which is a suite of software applications developed and delivered across multiple security classification levels. WARPspeed encompasses weather workflow tools and decision aids used to tailor terrestrial and space environmental information, which include both Forecaster-in-the-Loop [FITL] and automated machine-to-machine processes enhanced by AI/ML. WARPspeed leverages the WDA Inc 5 cloud computing, data processing, and CI/CD and AI/ML platforms to rapidly develop, deliver, and sustain software capabilities, whether deployed into the AF Weather Virtual Private Cloud [AFW-VPC] and to warfighter processing nodes at the edge. Activities include research and analysis to support current program planning. Management Service costs include Federally Funded Research and Development Centers [FFRDC] and Advisory and Assistance Service [A&AS]. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305111F / Weather Service Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305114F$$, $$Air Traffic Control, Approach, and Landing System (ATCALS)$$, $$rdte_af_ba7$$, $$aflcmc_hn$$, 2026, 17259000, 25910000, 15143000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305114F"}$$::jsonb, $$To support the Air Force worldwide flying mission, the Air Traffic Control and Landing System (ATCALS) program element funds research, development, and management of fielded and emerging air traffic control communications, surveillance, automation, positioning, and precision approach and landing systems. ATCALS programs are focused on development of technology and strategies to support Agile Combat Employment (ACE) adaptive basing and agile basing concepts of operation as well as modernizing airfield operations to ensure enduring, resilient, efficient, and safe air operations. ATCALS also pursues opportunities in the organization, training, and equipping of ATC associated career fields and any new civil ATCALS technologies that may have military utility. ATCALS currently includes three programs: Air Traffic Control (ATC) Future Technology (AFT), development of a Man-Portable (MP) Tactical Navigation (TACAN) Electronically Scanned Antenna (ESA), and development of a Multi-Function Tactical Radar System (MTRS). 1. AFT is a multi-project program focused on identifying and documenting capability gaps and associated future technologies in multiple areas of aircraft launch and recovery for both fixed and expeditionary operations. These gaps and technologies will be outlined in a bridging strategy, capability-based assessments, and capability roadmaps. FY26 AFT research and development programs span multiple projects that include the following: - The Small Footprint Precision Approach and Landing Capability (SF-PALC) effort aims to reduce the footprint, transport and set-up time for delivering instrument landing system capabilities in an Agile Combat Employment (ACE) Environment. This effort is developing and comparing a Lightweight Deployable Instrument Landing System (LD-ILS) and a Mode-5 (Identification Friend or Foe) capable Tactical Transponder Landing System (TTLS). -The Flight Inspection Drone project purchases two prototype systems for evaluation against Federal Aviation Administration (FAA) and Air Force flight inspection requirements. The goal is to reduce flight inspections, fuel costs, and inspection time while also reducing exposure in a contested environment. -The Tactical ATC Command and Control (C2) Operating Systems (TACOS) will automate and display sensor feeds and includes the communication radios and voice switch needed by controllers to communicate to host nations, other agencies and aircraft. As these and other technologies and architectures mature, any applicable fixed-base or deployable, ground-system upgrades will be coordinated and fielded concurrently with related manned and unmanned aircraft avionics capabilities as required. When implemented, these efforts will enable DoD aircraft to enhance safety, security, efficiency, and affordability of global flight operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0305114F / Air Traffic Control, Approach, and Landing System (ATCALS) Operational Systems Development 2. The Man Portable-Tactical Navigation (MP-TACAN) Electronically Scanned Antenna (ESA) will replace the MP-TACAN mechanical rotating antenna. It will improve system reliability and reduce system weight. The MP-TACAN provides aircraft with point-to point navigating and instrument flight approaches to operating sites/landing zones and is critical to mission success in adverse weather conditions and Global positioning System denied operations. 3. The Multi-function Tactical Radar System (MTRS) will be capable of supporting Air Traffic Control (ATC) surveillance and communication, weather alerts, small Unmanned Arial System (sUAS) detection, and air base air defense situational awareness. It replaces the unsupportable legacy (1970's-era) AN/TPN-19 and MPN-14K mobile ATC systems, the last of which will be decommissioned in 2027. FY26 request was reduced by 0.258 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, implementing the President's Department of Government Efficiency Cost Efficiency Initiatives. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY24 0.162M was expended for civilian pay expenses in this program element, and in FY25 0.000 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 52326000, 36953000, 9637000, NULL, NULL, 252, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 14689000, 27064000, 61895000, 61895000, 0, 61895000, 9835000, $$To support the Air Force worldwide flying mission, the Air Traffic Control and Landing System (ATCALS) program element funds research, development, and management of fielded and emerging air traffic control communications, surveillance, automation, positioning, and precision approach and landing systems. ATCALS programs are focused on development of technology and strategies to support Agile Combat Employment (ACE) adaptive basing and agile basing concepts of operation as well as modernizing airfield operations to ensure enduring, resilient, efficient, and safe air operations. ATCALS also pursues opportunities in the organization, training, and equipping of ATC associated career fields and any new civil ATCALS technologies that may have military utility. ATCALS currently includes three projects: Air Traffic Control (ATC) Future Technology (AFT), Multi-Function Tactical Radar System (MTRS), and Tactical ATC Operations System (TACOS). 1. AFT is a multi-project program focused on identifying and documenting capability gaps and associated future technologies in multiple areas of aircraft launch and recovery for both fixed and expeditionary operations. These gaps and technologies will be outlined in a bridging strategy, capability-based assessments, and capability roadmaps. FY 2027 AFT research and development spans multiple projects that include the following: - The Small Footprint Precision Approach and Landing Capability (SF-PALC) effort aims to reduce the footprint, transport and set-up time for delivering instrument landing system capabilities in an Agile Combat Employment (ACE) Environment. SF-PALC researches multiple technologies including a traditional instrumented landing system (ILS) approach and a non-traditional tactical transponder approach. - The Flight Inspection Drone project manages the foreign comparative test of flight inspection drones against Federal Aviation Administration (FAA) and Air Force flight inspection requirements. The goal is to reduce flight inspections, fuel costs, and inspection time while also reducing exposure in a contested environment. As these and other technologies and architectures mature, any applicable fixed-base or deployable, ground-system upgrades will be coordinated and fielded concurrently with related manned and unmanned aircraft avionics capabilities as required. When implemented, these efforts will enable Department of War (DoW) aircraft to enhance safety, security, efficiency, and affordability of global flight operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305114F / Air Traffic Control, Approach, and Landing System (ATCALS) Operational Systems Development 2. The Multifunction Tactical Radar System (MTRS) will be capable of supporting Air Traffic Control (ATC) surveillance and communication, weather alerts, Unmanned Aircraft System (UAS) detection, and air battle management command control (BMC2) situational awareness. MTRS provides mobile ATC surveillance radar capability in an Agile Combat Operations (ACE) environment to replace the the unsupportable legacy (1970's-era) AN/MPN-14K. The last AN/MPN-14K will decommission in FY 2028. MTRS Initial Operational Capability (IOC) is anticipated in FY 2030. Two refurbished Air Traffic Control Navigation, Integration, and Coordination System (ATNAVICS) along with the three Africa Command (AFRICOM) Expeditionary Scalable MCRs will provide a limited material solution until MTRS IOC. 3. The Tactical ATC Command and Control (C2) Operating Systems (TACOS) will automate, and display sensor feeds and includes the communication radios and voice switch needed by controllers to communicate to aircraft, host nations, and other agencies. TACOS will include the shelters, furniture, laptops, servers, software, power- supplies, and communications equipment needed for controllers to perform their mission in environments when existing infrastructure is damaged or does not exist. TACOS will include software interfaces with the greater Department of Air Force (DAF) Battle Network as well as appropriate C2 nodes for air battle management and counter-small UAS sensors and networks. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305116F$$, $$Aerial Targets$$, $$rdte_af_ba7$$, $$aflcmc_wa$$, 2026, 5081000, 6671000, 6085000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305116F"}$$::jsonb, $$Full-scale Aerial Targets (FSAT), Subscale Aerial Targets (SSAT), and companion Target Control Systems (TCS) assure the effectiveness and currency of warfighter weapon systems to combat real-world enemy fighters and cruise missiles. Aerial targets support adherence to Public Law Title 10, Section 2366, which requires major systems and munitions programs to conduct live fire survivability and lethality testing before full rate production. Targets are used to validate operational missile/weapon system effectiveness and fighter Operational Flight Program (OFP) updates. Targets are required for developmental/operational testing for all surface-to-air and air- to-air missiles employed by the F-22A, F-35, F-18, F-16, F-15, among other aircraft. Funding supports simulator development and improvements on the QF-16 FSAT, BQM-167A SSAT, and updates of Target Control Systems and specialized target payload subsystems for requirements such as: missile scoring, electronic attack (EA), infrared (IR) countermeasures, radar/IR signature augmentation, and chaff and flare dispensing systems. Enables analysis, development and prototyping of threat emulations/ simulations, and presentation of evolving threat scenarios and target area environments to prepare for emerging weapons development activities. Development is required to evolve aerial targets and target control capabilities to meet current and future threats. Air Force is the executive agent for full-scale aerial targets. The Aerial Targets Program leverages and implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio tradespace studies by conducting trade studies, system engineering, test activities, and protype and concept development, supporting system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Invests in analytical, information management, data management, digital environments, and networks directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY25 0.0 million was expended for civilian pay expenses in this program element, and in FY26 0.0 million is forecasted for civilian pay expenses in this program element. The FY2026 funding request is to modernize the TCS and close existing capability gaps. Modernization, will reduce future infrastructure costs by 67% and incorporate encryption requirements as mandated by DoD. This includes support for increasing simultaneous target C2, increased cybersecurity, extending the C2 range, mitigating Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305116F / Aerial Targets Operational Systems Development target C2 communication frequency encroachment, and reprogramming for use on Government-only frequencies. Additionally, the funding supports the increase of operator / participant situational awareness while expanding payload combinations, enables autonomous terrain following capabilities, and supports the control and integration of future Aerial Targets. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 1765000, 1798000, 1832000, NULL, NULL, 253, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 5870000, 5011000, 1704000, 1704000, 0, 1704000, 1869000, $$Full-scale Aerial Targets (FSAT), Subscale Aerial Targets (SSAT), and companion Target Control Systems (TCS) assure the effectiveness and currency of warfighter weapon systems to combat real-world enemy fighters and cruise missiles. Aerial targets support adherence to Public Law Title 10, Section 4172, which requires major systems and munitions programs to conduct live fire survivability and lethality testing before full rate production. Targets are used to validate operational missile/weapon system effectiveness and fighter Operational Flight Program (OFP) updates. Targets are required for developmental/operational testing for all surface-to-air and air-to- air missiles employed by the F-22A, F-35, F-18, F-16, F-15, among other aircraft. Funding supports simulator development and improvements on FSAT, BQM-167A SSAT, and updates of Target Control Systems and specialized target payload subsystems for requirements such as: missile scoring, electronic attack (EA), infrared (IR) countermeasures, radar/IR signature augmentation, and chaff and flare dispensing systems. Enables analysis, development and prototyping of threat emulations/ simulations, and presentation of evolving threat scenarios and target area environments to prepare for emerging weapons development activities. Development is required to evolve aerial targets and target control capabilities to meet current and future threats. Air Force is the executive agent for full-scale aerial targets. The Aerial Targets Program leverages and implements tenets of Open, Agile, and Digital acquisition for any new subsystem hardware or software development. Integrates the system in weapon portfolio tradespace studies by conducting trade studies, system engineering, test activities, and protype and concept development, supporting system modeling and simulation. Builds and refines a mission modeling framework by incorporating higher-fidelity weapon system designs and updates to the threat landscape to conduct ongoing assessment of weapon system performance against the authoritative threat. Invests in analytical, information management, data management, digital environments, and networks directly supporting development and sustainment of this program's capabilities, while leveraging DoD and DAF enterprise IT solutions. Leverages Digital acquisition tenets of open, agile and digital. This may include providing funds to prime contractors; program office contract support; facility, security and IT upgrades; common component development with other weapon systems to reduce redundant costs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. The FY 2027 funding request is for continued investment in critical improvements to Aerial Targets product lines, directly supporting the Department of Defense's initiative to improve live-fire testing and enhance readiness against peer-level adversaries. Specifically, these funds will support two key initiatives, (1) Establishment of Mid-Wing Pylon Capability on Air Force Sub-scale Aerial Targets and (2) Continued Modernization of the Command and Control (C2) System. Mid-wing Pylon capability is critical for emulating the characteristics of emerging threat aircraft, allowing for more accurate radar, electronic warfare, and weapon system testing. C2 modernization Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0305116F / Aerial Targets Operational Systems Development initiatives include user interface enhancements, touch screen interfaces, 3-D renderings of post-mission replay, increased situational awareness for reduced response time in simulated threat scenarios, and enhanced accident analysis capabilities, projected to reduce accidents through improved data analysis and training. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305128F$$, $$Security and Investigative Activities$$, $$rdte_af_ba7$$, $$aflcmc_hn$$, 2026, 8964000, 339000, 481000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305128F"}$$::jsonb, $$Technical Surveillance Countermeasures (TSCM) develops future technologies designed to find, fix, track, and neutralize law enforcement and counterintelligence threats to the Department of the Air Force (DAF). The technologies will enable criminal and counterintelligence investigations and operations involving high-tech crimes and cyber activities. The technologies are unique, complex, and the equipment must be continuously updated to ensure state-of-the-art capabilities are utilized to counter increasingly sophisticated threats targeting DAF equities. AFOSI also conducts a Capabilities Based Assessment (CBA) the Law Enforcement Evidence Data Repository (LEEDR) program ongoing at Fort Eisenhower, GA. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 $0.000M was expended for civilian pay expenses in this program element, and in FY2025 $0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 417000, 425000, 434000, NULL, NULL, 256, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 463000, 7855000, 9642000, 9642000, 0, 9642000, 442000, $$Technical Surveillance Countermeasures (TSCM) develops future technologies designed to find, fix, track, and neutralize law enforcement and counterintelligence threats to the Department of the Air Force (DAF). The technologies will enable criminal and counterintelligence investigations and operations involving high-tech crimes and cyber activities. The technologies are unique, complex, and the equipment must be continuously updated to ensure state-of-the-art capabilities are utilized to counter increasingly sophisticated threats targeting DAF equities. AFOSI also conducts a Capabilities Based Assessment (CBA) the Law Enforcement Evidence Data Repository (LEEDR) program ongoing at Fort Eisenhower, GA. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 $0.000M was expended for civilian pay expenses in this program element, and in FY2025 $0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305133V$$, $$Industrial Security Activities$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 0, 2056000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305133V", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305146F$$, $$Defense Joint Counterintelligence Activities$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 6524000, 6930000, 6387000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305146F"}$$::jsonb, $$Technical Surveillance Countermeasures (TSCM) develops future technologies capable of thwarting advanced hostile force and foreign intelligence technical capabilities. The technologies will provide secure environments for austere mission planning locations and theater commander centers, and will collect information for counterintelligence (CI) operations in support of DoD and AF requirements. CI Cyber activities enable the Department of the Air Force Office of Special Investigations to detect and neutralize covert activities conducted by Foreign Intelligence Entities seeking to compromise classified or sensitive information in cyberspace. The technologies provided will enhance state of the art capabilities to detect and neutralize criminal activities targeted against sensitive and classified AF and DoD information, activities, and technology. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 0.000M was expended for civilian pay expenses in this program element, and in FY2026 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305146F / Defense Joint Counterintelligence Activities Operational Systems Development$$, NULL, 2710000, 2843000, 2977000, NULL, NULL, 257, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 6387000, 6524000, 2469000, 2469000, 0, 2469000, 3119000, $$Technical Surveillance Countermeasures (TSCM) develops future technologies capable of thwarting advanced hostile force and foreign intelligence technical capabilities. The technologies will provide secure environments for austere mission planning locations and theater commander centers, and will collect information for counterintelligence (CI) operations in support of DoD and AF requirements. CI Cyber activities enable the Department of the Air Force Office of Special Investigations to detect and neutralize covert activities conducted by Foreign Intelligence Entities seeking to compromise classified or sensitive information in cyberspace. The technologies provided will enhance state of the art capabilities to detect and neutralize criminal activities targeted against sensitive and classified AF and DoD information, activities, and technology. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 0.000M was expended for civilian pay expenses in this program element, and in FY2026 0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305146F / Defense Joint Counterintelligence Activities Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305146V$$, $$Defense Joint Counterintelligence Activities$$, $$rdte_dw_ba7$$, $$dw_dcsa$$, 2026, 1800000, 2295000, 1800000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305146V", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 6788000, 6507000, 6016000, NULL, NULL, NULL, NULL, NULL, FALSE, 1800000, 1800000, 6751000, 6751000, NULL, 6751000, 6046000, $$The Defense Counterintelligence Security Agency (DCSA) is a strategic asset to the nation and our allies - continuously ensuring a trusted federal, industrial, and affiliated workforce, and enabling industry's delivery of uncompromised capabilities by leveraging advanced technologies and innovation. DCSA uniquely blends critical technology protection, trusted personnel vetting, counterintelligence, and professional education and certification to advance and preserve America's strategic edge. The programs which fall under the Defense Joint Counterintelligence Activities are the Critical Technology Protection Integration Cell (CTPIC) and Applied Research Laboratory for Intelligence and Security (ARLIS). The CTPIC is a whole-of-government engagement effort to deter, detect, and disrupt the unauthorized technology transfer activities of our adversaries. CTPIC serves as the DoW focal point for assessments, coordination, integration, and operational information sharing related to critical technology protection across all phases of research, development, and sustainment. This funding is needed for data access and analysis tools that support prioritization of limited resources and direct focused engagements addressing targeted threat information and mitigation actions. The ARLIS program management office oversees the University Affiliated Research Center (UARC) to provide strategic research and development to solve intelligence and security problems. ARLIS overlays human behavior and social science and culture and language expertise with expertise, research, and development in emerging and advanced technologies to solve increasingly technical, but human-centered intelligence and security challenges. RDT&E funding will be used for strategic research efforts that broadly benefit the Defense Security Enterprise (DSE) and develop capability and capacity at ARLIS that work sponsors can build on. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Counterintelligence and Security Agency                                Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:          PE 0305146V / Defense Joint Counterintelligence Activities Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_DCSA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305155F$$, $$Theater Nuclear Weapon Storage & Security System$$, $$rdte_af_ba7$$, $$afnwc$$, 2026, 19875000, 0, 2000000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0305155F"}$$::jsonb, $$The Theater Nuclear Weapon Storage and Security System (WS3) supports the North Atlantic Treaty Organization (NATO) Nuclear Deterrence Mission in Europe. The WS3 was designed in the 1980s and fielded in the 1990s. The WS3 Vault Modernization Program (VMP) modernizes storage vault components and will address the National Security Agency (NSA) requirement to modernize the vault unlock management subsystem using modern cryptographic technologies. Finally, the VMP will resolve vault sustainment issues caused by obsolescence. Additional detailed information is classified and can be provided at higher classification levels. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production.$$, NULL, 21504000, 0, 0, NULL, NULL, 117, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 0, 0, 24364000, 24364000, 0, 24364000, 0, $$The Weapon Storage and Security System (WS3) is a US maintained/operated system of systems that supports the nuclear mission by providing the capability to securely and safely store resources deployed in Europe. The Vault Modernization Program (VMP) ensures National Security Directive 42 (NSD-42) compliance and addresses system obsolescence issues. Detailed information is classified and can be provided. Funding is required for VMP to deliver an NSD-42 compliant encryption system necessary to secure forward deployed nuclear weapons in Europe in time to meet the required need date. A non-compliance will result in the need for US and NATO partner nations to post unplanned and unfunded security forces continuously until a compliant encryption system is delivered and installed. Detailed information is classified and can be provided. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0305155F / Theater Nuclear Weapon Storage & Security System Operational Systems Development$$, $$Budget J-Books/FY27/Remaining/FY2027_r1.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305158F$$, $$Tactical Terminal$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 1099000, 0, 501000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305158F"}$$::jsonb, $$The Tactical Terminal program provides Integrated Broadcast Service (IBS)-compatible terminals (radios) that access the IBS broadcast, providing Air Force warfighters strategic, operational, and tactical intelligence and threat warning information. The Tactical Terminal family of systems provide both airborne and ground weapon systems transmit/receive and receive-only solutions. The program also performs development, testing, and support efforts for software and hardware modifications/ enhancements to tactical terminals. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2025, $0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 0, 0, 0, NULL, NULL, 258, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 482000, 1084000, 0, 0, 0, 0, 0, $$The Tactical Terminal program provides Integrated Broadcast Service (IBS)-compatible terminals (radios) that access the IBS broadcast, providing Air Force warfighters strategic, operational, and tactical intelligence and threat warning information. The Tactical Terminal family of systems provide both airborne and ground weapon systems transmit/receive and receive-only solutions. The program also performs development, testing, and support efforts for software and hardware modifications/ enhancements to tactical terminals. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                    Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305158F / Tactical Terminal Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305172D8Z$$, $$Combined Advanced Applications$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 22548000, 47545000, 42355000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305172D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$Combined advanced applications details are classified and reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program annual report to Congress.$$, NULL, 19829000, 20282000, 20909000, NULL, NULL, 258, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 40155000, 22548000, 18912000, 18912000, NULL, 18912000, 12458000, $$Combined advanced applications details are classified and reported in accordance with Title 10, United States Code, Section 119(a)(1) in the Special Access Program annual report to Congress.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1810_L079$$, $$Navy Multiband Terminal (NMT)$$, $$proc_navy_1810_ba2$$, $$peo_c4i$$, 2026, 106583000, 68327000, 104119000, NULL, $${"page": 100, "ba_num": "02", "source": "p1_fy26", "ba_name": "Communications and electronics equipment", "line_no": "79", "service": "navy", "fy24_qty": null, "fy25_qty": null, "fy27_v25": {"ba": "02", "appr": "OPN", "title": "P-1 Line 73", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/OPN_BA{1..5-8}_Book.pdf", "fy27_base_K": 50350, "p1_line_num": 73, "fy27_total_K": 50350}, "appr_code": "1810", "appr_name": "Other Procurement, Navy", "fy26_v179": {"disc_K": 20900, "li_num": 73, "source": "p40_fy26_v179", "supp_K": 0, "source_pdf": "uploads/Budget J-Books/FY27/Navy/OPN_BA2_Book.txt"}, "fy26t_qty": null, "fy26d_cost": 106583000, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 162928000, 63433000, 50350000, 50350000, 0, 50350000, NULL, NULL, $$Budget J-Books/FY27/Navy/OPN_BA2_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305172K$$, $$Combined Advanced Applications$$, $$rdte_dw_ba6$$, $$dw_disa$$, 2026, 5447000, 11149000, 23311000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0305172K", "page_header": "Defense-Wide"}$$::jsonb, $$The DISA Compartmented Enterprise Services Office (CESO) is charged with developing, implementing, and sustaining the DoD SAP IT Enterprise called Secure Web Services (SWS). As such, CESO offers a suite of web-enabled enterprise capabilities to DoD and Intelligence Community Special Access Program (SAP) organizations that enable secure communication and collaboration across the Services, Agencies, and the Fourth Estate. The majority of our current service offerings lie within the realm of Application and Desktop services. CESO’s SAP IT Enterprise Application and Desktop Services reside in CESO’s on-prem (Multi-Tenant Virtual Environment (MTVE)) and cloud-based (CESO Cloud Infrastructure (C2I)) infrastructures. Details of Combined Advanced Applications are classified and can be provided through appropriately classified channel.$$, NULL, 5666000, 18274000, 25652000, NULL, NULL, 211, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 22831000, 5447000, 5566000, 5566000, NULL, 5566000, 47612000, $$The DISA Compartmented Enterprise Services Office (CESO) is charged with developing, implementing, and sustaining the DoW SAP IT Enterprise called Secure Web Services (SWS). As such, CESO offers a suite of web-enabled enterprise capabilities to DoW and Intelligence Community Special Access Program (SAP) organizations that enable secure communication and collaboration across the Services, Agencies, and the Fourth Estate. The majority of our current service offerings lie within the realm of Application and Desktop services. CESO’s SAP IT Enterprise Application and Desktop Services reside in CESO’s on-prem (Multi-Tenant Virtual Environment (MTVE)) and cloud-based (CESO Cloud Infrastructure (C2I)) infrastructures. Details of Combined Advanced Applications are classified and can be provided through appropriately classified channel.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305179A$$, $$Integrated Broadcast Service (IBS)$$, $$rdte_army_ba7$$, $$dw_jsf$$, 2026, 6653000, 9456000, 5701000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "original_pe": "0305179A", "page_header": "Department of the Army"}$$::jsonb, $$The Joint Program Office (JPO) for Integrated Broadcast Service (IBS) Terminals supports the Joint Services and the Special Operations Command (SOCOM). The JPO is responsible for coordinating modernization and sustainment of IBS terminals compatible with the UHF SATCOM IBS broadcasts in support of Air and Missile Defense, Long Range Precision Fires, Soldier Lethality, and Network Command, Control, Communications and Intelligence Cross Functional Teams, and Tactical Intelligence Targeting Access Node. The IBS transmits worldwide time-sensitive tactical and strategic intelligence and targeting data to all echelons of Joint Service operational users. The Joint Tactical Terminal (JTT) is the official IBS system and ensures continued IBS interoperability to a variety of tactical producers and consumers across the Joint Services. The transmit/receive-capable JTT systems currently consist of the JTT-Senior and JTT-IBS configurations. The JPO is executing updates to the JTT terminal to incorporate Mobile User Objective System (MUOS)-Wideband Code Division Multiple Access (WCDMA) elements based on modernization requirements.$$, NULL, 7046000, 7207000, 7375000, NULL, NULL, 235, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 5701000, 6653000, 6870000, 6870000, NULL, 6870000, 7449000, $$The Joint Tactical Terminal (JTT) is the official IBS system and ensures continued IBS interoperability to a variety of tactical producers and consumers across the Joint Services. The IBS transmits worldwide time-sensitive tactical and strategic intelligence and targeting data to all echelons of Joint Service operational users. The transmit/ receive-capable JTT systems currently consist of the JTT Next Generation (JTT-NG), JTT-Senior and JTT-IBS configurations. The JPO is executing updates to the JTT terminal to incorporate updated waveforms and capabilities based on modernization requirements. FY 2027 RDTE Dollars in the amount of $6.870M support the continuation of Vendor terminal software development and porting, vendor testing and evaluation, independent testing, integration, and certification in support of IBS modernization efforts.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305179F$$, $$Integrated Broadcast Service (IBS)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 19085000, 18540000, 16006000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305179F"}$$::jsonb, $$The Integrated Broadcast Service (IBS) Broadcast fulfills the warfighter's requirements for worldwide threat warning and situational awareness information with timely dissemination of Intelligence, Surveillance, and Reconnaissance (ISR) derived combat information. It also provides target tracking data to support threat avoidance, targeting, force protection, and situational awareness. This information is continually refined in near-real time by strategic, operational and tactical sensors. IBS Broadcast Baseline is comprised of the following: - IBS Over-the-Air (OTA) includes a Common Interactive Broadcast (CIB) on UHF (Ultra High Frequency) satellite channel using a Common Message Format (CMF), a Military Standard (MIL-STD) common waveform, a Tactical Data Processor (TDP) to filter and display messages and data, and CMF analysis tools and an IBS-alternate path via mission partner provided satellite communications (SATCOM). - IBS-Network Services (IBS-NS) includes two Global IBS Network Servers (GINS) and four Theater Interface Nodes (TINs) to support the geographic Combatant Commanders (CCDRs) -- Two GINS receive data from each theater and integrate this data into a worldwide picture available to all network/broadcast users. -- Four regional TINs allow local and out-of-theater users (not directly receiving IBS OTA broadcast) to still obtain access to the data disseminated over the IBS OTA broadcast. Additionally, the TIN will receive and inject data into the CIB for consumers without access to the theater CIB. This PE funds the modernization of and/or enhancements to IBS OTA and IBS NS to include performing development and testing to ensure integration with tactical terminals. FY26 funding supports: 1. IBS OTA Modernization: Integration and fielding IBS over Mobile User Objective System (MUOS) Wideband Code Division Multiple Access (WCDMA), Integration/ testing/fielding common waveform architecture, IBS-Alternative Path (IBS-A), IBS-Low Earth Orbit (IBS-L), High Frequency (HF) capability, Starshield capability, and Line of Sight (LOS) capability. In addition, funding is sent to support Joint Tactical Terminal - Next Generation (JTT-NG) to incorporate new requirements. 2. IBS OTA Baseline Enhancements: Provides Tactical Display Processor (TDP) enhancements and cryptographic updates for IBS-A and IBS-L. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0305179F / Integrated Broadcast Service (IBS) Operational Systems Development 3. IBS-NS Modernization: Replatforms the IBS-NS capability to a new operating system on modern servers and refactors software to enable Legacy IBS Network transition to a cloud architecture. 4. Test and Evaluation: Performs test and evaluation activities of the IBS OTA and IBS-NS systems/sub-system components. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 0.508M was expended for civilian pay expenses in this program element, and in FY 2025 0.000M is forecasted for civilian pay expenses in this program element.er This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 16070000, 16455000, 16848000, NULL, NULL, 259, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 15006000, 19085000, 18266000, 18266000, 0, 18266000, 17273000, $$The Integrated Broadcast Service (IBS) Broadcast fulfills the warfighter's requirements for worldwide threat warning and situational awareness information with timely dissemination of Intelligence, Surveillance, and Reconnaissance (ISR) derived combat information. It also provides target tracking data to support threat avoidance, targeting, force protection, and situational awareness. This information is continually refined in near-real time by strategic, operational and tactical sensors. IBS Broadcast Baseline is comprised of the following: - IBS Over-the-Air (OTA) includes a Common Interactive Broadcast (CIB) on UHF (Ultra High Frequency) satellite channel using a Common Message Format (CMF), a Military Standard (MIL-STD) common waveform, a Tactical Data Processor (TDP) to filter and display messages and data, and CMF analysis tools and an IBS-alternate path via mission partner provided satellite communications (SATCOM). - IBS-Network Services (IBS-NS) includes two Global IBS Network Servers (GINS) and four Theater Interface Nodes (TINs) to support the geographic Combatant Commanders (CCDRs) -- Two GINS receive data from each theater and integrate this data into a worldwide picture available to all network/broadcast users. -- Four regional TINs allow local and out-of-theater users (not directly receiving IBS OTA broadcast) to still obtain access to the data disseminated over the IBS OTA broadcast. Additionally, the TIN will receive and inject data into the CIB for consumers without access to the theater CIB. This PE funds the modernization of and/or enhancements to IBS OTA and IBS-NS to include performing development and testing to ensure integration with tactical terminals. FY27 funding supports: 1. IBS OTA Modernization: Integration and fielding IBS over Mobile User Objective System (MUOS) Wideband Code Division Multiple Access (WCDMA)(IBS-M), Integration/testing/fielding common waveform architecture, Integration and fielding of IBS-Low Earth Orbit (IBS-L), and funding is sent to support Joint Tactical Terminal - Next Generation (JTT-NG) to incorporate new requirements. In response to operational threats or events, additional or higher priority Primary, Alternate, Contingency, Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                         R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:     PE 0305179F / Integrated Broadcast Service (IBS) Operational Systems Development and Emergency (PACE) communications paths (e.g., IBS MUOS UHF Legacy Extension (IBS-MX), L-Band Tactical Satellite (LTAC), High Frequency (HF) capability, Starshield, Line of Sight (LOS), etc.) may be developed. 2. IBS OTA Baseline Enhancements: Provides Tactical receive segment (TRS), which is a Tactical Display Processor (TDP), software enhancements. 3. IBS-NS Modernization: Replatforms the IBS-NS capability to a new operating system on modern servers and refactors software to enable Legacy IBS Network transition to a cloud architecture. 4. Enterprise Services (ES): Provides Enterprise Systems Engineering, Integration, and Engineering expertise. 5. Test and Evaluation: Performs test and evaluation activities of the IBS OTA and IBS-NS systems/sub-system components. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305186D8Z$$, $$Policy R&D Programs$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 6043000, 6075000, 6220000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305186D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$The Policy R&D Program supports the interim National Defense Strategy by providing analysis to overcome military security challenges. The global security environment is dynamic and complex. Continuous research and analysis is necessary for understanding foreign military structures and capabilities, as well as for developing mid- to long-term anticipatory and strategic perspectives on security issues. These perspectives can then guide necessary changes to policies, strategies, processes, and capabilities that advance U.S. and interests. This program blends multiple research disciplines including policy, sciences, and engineering to better understand matters affecting strategy, planning, management of international alliances and partnerships, crisis preparedness and response, budgetary and operational oversight, cyber and space challenges, special operations, homeland defense, nuclear and missile defense, and other emerging threats to the national security of the US. The program also supports statutorily directed requirements related to OUSD Policy mission areas.$$, NULL, 11793000, 11990000, 12242000, NULL, NULL, 260, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 6094000, 5996000, 11740000, 11740000, 0, 11740000, 12487000, $$The Policy R&D Program supports the National Defense Strategy by providing analysis to overcome military security challenges. The global security environment is dynamic and complex. Continuous research and analysis is necessary for understanding foreign military structures and capabilities, as well as for developing mid- to long-term anticipatory and strategic perspectives on security issues. These perspectives can then guide necessary changes to policies, strategies, processes, and capabilities that advance U.S. and interests. This program blends multiple research disciplines including policy, sciences, and engineering to better understand matters affecting strategy, planning, management of international alliances and partnerships, crisis preparedness and response, budgetary and operational oversight, cyber and space challenges, special operations, homeland defense, nuclear and missile defense, and other emerging threats to the national security of the US. The program also supports statutorily directed requirements related to Office of the Under Secretary of War for Policy mission areas.$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305199D8Z$$, $$Net Centricity$$, $$rdte_dw_ba7$$, $$dw_osd$$, 2026, 37114000, 21797000, 15465000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305199D8Z", "page_header": "Defense-Wide"}$$::jsonb, $$This program supports the Department's initiatives to deter aggression, defend the homeland, and build enduring advantage by modernizing command, control, and communications (C3) capabilities. The DoD CIO provides strategic direction and oversight for C3 capabilities, including tactical communications, infrastructure, satellite communications (SATCOM), electromagnetic spectrum (EMS) management, positioning, navigation, and timing (PNT), Defense Information Systems Network infrastructure, commercial mobile devices, and emerging 5G capabilities. The C3 modernization (C3M) program provides technical analysis and systems engineering to ensure warfighters have information advantage through C3 systems and shapes the Combined Joint All Domain Command and Control (CJADC2) technology foundation. Specifically, this program enables the research, analysis, evaluation, and management of communication networks in a contested spectrum environment. This includes providing secure information access and services (e.g., cryptographic modernization) and supporting CJADC2 efforts by refining joint protocols. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:          PE 0305199D8Z / Net Centricity Operational Systems Development$$, NULL, 56254000, 56517000, 56989000, NULL, NULL, 262, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 17099000, 16872000, 55673000, 55673000, NULL, 55673000, 57428000, $$This program supports the Department's initiatives to defend the homeland and deter China by modernizing command, control, and communications (C3) capabilities. The DoW CIO provides strategic direction and oversight for C3 capabilities, including tactical communications, infrastructure, satellite communications (SATCOM), airborne intelligence surveillance and reconnaissance, electromagnetic spectrum management, positioning, navigation, and timing, Defense Information Systems Network infrastructure, commercial mobile devices, and emerging 5G capabilities. The C3 modernization program provides technical analysis and systems engineering to ensure warfighters have an information advantage through C3 systems and shapes the Combined Joint All Domain Command and Control (CJADC2) technology foundation. Specifically, this program enables the research, analysis, evaluation, and management of communication networks in a contested spectrum environment. This includes providing secure information access and services (e.g., cryptographic modernization) and supporting Combined Joint All Domain Command and Control (CJADC2) efforts by refining joint protocols. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                                  Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:            PE 0305199D8Z / Net Centricity Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305202F$$, $$Dragon U-2$$, $$rdte_af_ba7$$, $$aflcmc_hb$$, 2026, 0, 16842000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305202F"}$$::jsonb, $$The U-2S Dragon Lady platform is a high-demand/low-density aircraft equipped with modular sensor and data link systems providing flexibility and mission essential Intelligence, Surveillance, and Reconnaissance (ISR) to the Combatant Commands, Joint and Combined forces, and the Intelligence Community in peacetime and wartime. The program supports core missions such as Sensitive Reconnaissance Operations (outlined in CJCSI 3250.01) supporting the National Defense Strategy, in addition to other missions that include execution of CCMD OPLANs and CONPLANs, Humanitarian Assistance/Disaster Response (HADR), Counter Violent Extremist Organizations, and third-party treaty verification/monitoring via the OLIVE HARVEST mission. The FY 2025 budget year is the final year that the Air Force has budgeted for the operational capability of the U-2 platform. Previously programmed funds in PE 35202F have been shifted to PE 35206F to support ASARS-2C test/eval and fielding, which will enable vastly improved collection against emerging threats through the remainder of scheduled U-2 operations. This capability and any enhancements will transferable to the broader enterprise. Additionally, the U-2 program will continue to support emergent and/or experimental RDT&E efforts in support of Joint All-Domain Command and Control [JADC2] and Advanced Battle Management System [ABMS] as a platform surrogate for risk reduction in support of SECAF's Operational Imperative-2 as well as surrogate test for RCO capabilities and Electromagnetic Spectrum Operations technology development. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0305202F / Dragon U-2 Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 260, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305204N$$, $$Tactical Unmanned Aerial Vehicles$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 0, 7518000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0305204N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305205F$$, $$Endurance Unmanned Aerial Vehicles$$, $$rdte_af_ba5$$, $$dw_dote$$, 2026, 0, 30000000, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0305205F"}$$::jsonb, $$The Ultra Long-endurance Unmanned Reconnaissance Aircraft (ULTRA) is an Air Force-led technology and concept development effort to demonstrate, transition, and field an Unmanned Aerial System (UAS) that is capable of multiple-day duration flights while still being extremely affordable. ULTRA is a shift in UAS design paradigm by significantly leveraging commercial-off-the-shelf technologies to minimize expensive custom/proprietary items while at the same time simplifying maintenance and manpower costs. The payload integration for ULTRA maintains a modular and flexible architecture to allow for rapid integration of customer-driven payload options. ULTRA was initiated by the Air Force Research Lab in 2018 in response to demand signals for long-endurance ISR that maintains an affordable edge. ULTRA leverages and builds off the successes and lessons learned of several AFRL, DoD, and other partner-funded development efforts from 2015-2021, including the Long Endurance Aerial Platform UAS which transitioned in 2019 and a number of unique payload developments and integrations. These prior developments guided and informed the initial development and demonstration of ULTRA. The initial ULTRA UAS was developed in 2018 and flight-tested in 2019. In 2020 ULTRA performed limited operational test and evaluation over a six-month period, the results of which informed payload and system requirements to meet current and future needs. Future operational test and evaluation in relevant operational environments is a critical next step in developing ULTRA as an affordable ultra-long endurance ISR platform that is responsive to current and future needs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. No FY26 Funding is requested. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0305205F / Endurance Unmanned Aerial Vehicles Development & Demonstration (SDD)$$, NULL, NULL, NULL, NULL, NULL, NULL, 118, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305205N$$, $$UAS Integration & Interoperability$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 0, 12738000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0305205N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 0, 0, 0, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 9654000, 0, 0, NULL, 0, 0, $$Project CA88 is to fund the development of the next Experimental Platform for Intelligent Combat (EPIC) Design Reference Mission (DRM) to define and demonstrate mission-planned autonomous operations for Collaborative Combat Aircraft (CCA) and related unmanned systems. Identify required mission threads, autonomy behaviors, and operational workflows necessary to support government-defined combat use cases. Additionally, efforts will define integration points between autonomy software and government-owned mission planning, debrief, and test environments, including the Collaborative Mission Planning Continuum (CMPC) and associated enterprise mission systems. Identify required software, data, hardware, interface, and runtime assurance requirements and allocate responsibilities across autonomy software components, ground systems, and test infrastructure at appropriate classification levels.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305206F$$, $$Airborne Reconnaissance Systems$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 25432000, 56158000, 84363000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305206F"}$$::jsonb, $$The Airborne Reconnaissance System [ARS] Program develops and integrates next generation intelligence, surveillance, and reconnaissance [ISR] capabilities. ARS includes platform-agile sensor data processing; sensor products aiding assisted target recognition algorithms and other artificial intelligence activities [e.g. geolocation models, sensor-base exploitation tools, sensor networking capabilities]; and implementation of sensor open architecture standards. The ARS Program includes the following efforts: Agile ISR [672002], Sensors Open System Architecture [672003], Imaging and Targeting Support [674818], Sensor Development [674820], JTC/SIL MUSE [675092], and Data Compression [676025]. The ARS PE funds airborne ISR programs to include sensor hardware, data processing, architecture standards, and simulation and training environments. ARS serves as a transition partner for mid-TRL programs to mature and integrate technologies into programs of record. The ARS PE supports multiple types of requirements to mature technologies aligning to the future force design, as well as integrating new capabilities onto existing platforms to fill existing capability gaps. The ARS program invests in modernization of airborne Geospatial (GEOINT) sensor capabilities. ARS develops, matures, demonstrates, and rapidly transitions next- generation, persistent, wide-area surveillance and common imagery reconnaissance sensor capabilities including sensor data processing and sensor products to aid in rapid targeting for multiple airborne platforms. The ARS PE is integral to developing multi-domain, multi-intelligence [multi-INT] research, development, test and evaluation [RDT&E] Program of Record [PoR] efforts in support of the National Defense Strategy (NDS) and 2018 DoD Artificial Intelligence Strategy, as applied by the Air Force in the Next Generation ISR Dominance Flight Plan, and the US Air Force Intelligence, Surveillance & Reconnaissance Planning and Programming Guidance (IP2G). Specifically, Program Element 0305206F Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0305206F / Airborne Reconnaissance Systems Operational Systems Development provides authorized and appropriated funding to multi-INT RDT&E efforts for utilization on airborne platforms. This program traditionally provides a multi-INT venue for integration of technologies matured in both the Advanced Technology & Sensors [0604257F] and Airborne SIGINT Enterprise [0304260F] programs. ARS is a platform-agile suite of sensor technologies defined for the best flexibility and capability for an ever-changing scale of ISR missions. Execution of the ARS activities are founded upon three pillars: Open Standards, Artificial Intelligence [AI]/Machine Learning [ML] algorithms, and Advanced Platform-Agile Sensors. The power behind the ARS programs is an open architectural system design that enables rapid third-party software and line replicable unit insertion/replacement allowing for DevSecOps execution, onboard multi-modal and multi-INT processing real-time, sensor cross-cueing, and AI/ML application. The AI/ML algorithms will be used to enable assisted target detection and identification. ARS will anticipate and more quickly counter adversaries' future improvements in their abilities to hide from and defeat ISR sensors. The open standards pillar of next generation capabilities is supported through Sensors Open Systems Architecture [SOSA] which coordinates advanced technologies and open architecture development for multi-INT sensor modalities. The AI/ML algorithm pillar of next generation capabilities will be supported by the Agile ISR and Data Compression efforts. Detection, Removal and Characterization Operations [DRACO] supports the development of a robust image quality improvement capability for airborne synthetic aperture radar [SAR] products. Additionally, the Reduction of Data Using Compression Enhancement [RDUCE] develops data compression algorithms, addressing current and future systems' bandwidth limitations. Algorithms are multi-INT, sensor agnostic, solutions and are submitted for formal adoption by the DOD-Intelligence Community [IC] Joint Enterprise Standards Committee [JESC] GEOINT and SIGINT standards groups. The platform agile sensors pillar of next- generation capabilities will be supported by the Sensor Development effort, which includes the Advanced Synthetic Aperture Radar System [ASARS] front-end antenna array and receiver exciter advancements [ASARS-2B], and the ASARS-2C [back end] data processing efforts. ASARS-2B follow-on RDT&E extends range, enhances SAR performance and introduces maritime capability, while laying the framework for future use of open architectures. Additional efforts that support the next generation capabilities include the Multiple Unified Simulation Environment [MUSE] Joint Technology Center/Systems Integration Lab [JTC/SIL] by supporting ISR Training. The Imaging & Targeting Support (I&TS) Uncrewed Long-endurance Tactical Reconnaissance Aircraft (ULTRA) is an Air Force-led technology and concept development effort to demonstrate an Uncrewed Aerial System (UAS) that is capable of multiple-day duration flights while maintaining affordability. All efforts for this project transitioned from ARS to PE 0304784F - LE-AISR. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.236M was expended for civilian pay expenses in this program element, and in FY 2025 $0.329M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                   Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305206F / Airborne Reconnaissance Systems Operational Systems Development$$, NULL, 54523000, 70699000, 65740000, NULL, NULL, 261, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 115637000, 65432000, 34273000, 34273000, 0, 34273000, 56629000, $$The Airborne Reconnaissance System (ARS) Program develops and integrates next generation intelligence, surveillance, and reconnaissance (ISR) capabilities. ARS includes platform-agile sensor data processing, sensor products aiding Assisted Target Recognition (ATR) algorithms, other Artificial Intelligence (AI) activities [e.g. geolocation models, sensor-based exploitation tools, sensor networking capabilities], and implementation of sensor open architecture standards. The ARS Program includes the following efforts: Resolute Sentry [674818], Agile ISR (DRACO and AgilePod) [672002], SOSA [672003], Sensor Development [674820], JTC/SIL MUSE [675092], and Data Compression [676025]. The ARS PE funds airborne ISR sensor hardware, data processing, architecture standards, and simulation and training environments. It also transitions mid-tier Technology Readiness Level (TRL) technologies into programs of record (PoRs). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                             Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305206F / Airborne Reconnaissance Systems Operational Systems Development The program supports multiple types of requirements to mature technologies aligning to the future force design, as well as integrating new capabilities onto existing platforms to fill capability gaps. The ARS program invests in modernization of airborne Geospatial (GEOINT) sensor capabilities. ARS develops, matures, demonstrates, and rapidly transitions next- generation, persistent, wide-area surveillance and common imagery reconnaissance sensor capabilities including sensor data processing and sensor products to aid in rapid targeting for multiple airborne platforms. The ARS PE is integral to developing multi-domain, multi-intelligence (multi-INT) research, development, test and evaluation (RDT&E) PoR efforts in support of the National Defense Strategy (NDS); 2023 DoD Data, Analytics, and Artificial Intelligence Adoption Strategy; and the 2024 US Air Force Intelligence, Surveillance & Reconnaissance Planning and Programming Guidance (IP2G). Specifically, ARS provides authorized and appropriated funding to multi-INT RDT&E efforts for utilization on airborne platforms. This program traditionally provides a multi-INT venue for integration of technologies matured in both the Advanced Technology & Sensors [0604257F] and Airborne SIGINT Enterprise [0304260F] programs. ARS is a platform-agile suite of sensor technologies defined for the best flexibility and capability for an ever-changing scale of ISR missions. Execution of the ARS activities is founded upon three pillars: Open Standards, AI/Machine Learning (ML) algorithms, and Advanced Platform-Agile Sensors. The power behind the ARS programs is an open architectural system design that enables rapid third-party software and line replicable unit insertion/replacement allowing for DevSecOps execution, onboard multi-modal and multi-INT processing real-time, sensor cross-cueing, and AI/ML application. The AI/ML algorithms will be used to enable assisted target detection and identification. In a FY 2026 Congressional add, Rapid Targeting Support [RTS] BPAC supports Uncrewed Long-endurance Tactical Reconnaissance Aircraft (ULTRA),an Air Force- led technology and concept development effort to demonstrate an Uncrewed Aerial System (UAS) that is capable of multiple-day duration flights while maintaining affordability. Primary funding for this project transitioned from ARS to PE 0304784F - LE-AISR. In FY 2028 and beyond, the RTS BPAC will fund Resolute Sentry program. Resolute Sentry is not a new start, it is executing in PE 0604257F in FY 2026 and FY 2027 and will transition to ARS. Resolute Sentry is an AI-driven, multi-platform, sense-making tool for predictive analytics and orchestration at the tactical edge. It provides real-time, high-quality detection, identification and tracking to close kill chains and predict adversary activity. The program delivers a platform-agnostic, edge-hostable software solution to ingest and fuse multi-INT data across multiple platforms at the tactical edge. The data will then be used to generate actionable information on the highly contested environment for Blue Force commanders and national decision making. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305206F / Airborne Reconnaissance Systems Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305207F$$, $$Manned Reconnaissance Systems$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 16643000, 14330000, 16323000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305207F"}$$::jsonb, $$RC-135 operational systems development and enhancement activities support design studies, engineering analysis, non-recurring engineering and other efforts associated with the integration and modification of the RC-135 programs and their specialized mission systems, both air and ground. Associated ground systems include RIVET JOINT Ground Data Processing Systems (GDPS), Distributed Mission Shelters (DMS), Mission Crew Training Systems (MCTS), Airborne Capabilities Extension System (ACES), and the Operational Flight Trainers (OFT, a.k.a. flight deck simulators). RC-135 funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Extensive utilization of Commercial-Off-The-Shelf (COTS) based solutions allows rapid fielding of needed capabilities through upgrades and supports Diminishing Manufacturing Sources (DMS)/Vanishing Vendor Items (VVI) logistics mitigation efforts. The results of these efforts provide for preliminary assessments of technical feasibility, operability, or military utility as well as specific engineering implementations for integration into the various systems baseline configurations. These activities are managed by the 645th Aeronautical Systems Group (645 AESG). The 645 AESG (a.k.a. BIG SAFARI) manages engineering, ground and support systems modifications, integration, flight testing, product assurance, acceptance testing, logistics, and training activities. Aircraft, sensor systems, and associated ground support system engineering planned for FY 2025 budget includes developmental planning, execution and support for the RC-135V/W RIVET JOINT Baselines 13 and 14 (BL-13 and BL-14), the RC-135U COMBAT SENT Baselines 6 and 7 (BL-6 and BL-7), and the RC-135S COBRA BALL BL-7 and BL-14 configurations. The world-wide challenge of keeping pace against technologically agile targets used by both nation and non-nation- state adversaries and the rapid evolution of COTS technologies demands a responsive and adaptive acquisition strategy for fielding incremental spiral upgrades and baseline capabilities that are logistically supportable at all locations. The 645 AESG uses an incremental baseline strategy to mitigate risk, find affordable solutions and field needed capabilities on the aircraft and associated ground support and training systems. Obsolescence and DMS/VVI logistical concerns are addressed with each baseline upgrade and assessed annually as part of the fleet sustainment responsibilities. RIVET JOINT BL-14 upgrades consist of, but are not limited to, providing a continuous recording capability, High Probability of Intercept (HPOI) Receiver, Corvus Digital Receiver (CDR), Communications, Navigation, and Surveillance - Air Traffic Management (CNS-ATM) avionics upgrades such as new autopilot, automated data system- broadcast (ADS-B) and Mode 5 identify friendly or foe (IFF) systems. RIVET JOINT BL-15 upgrades consist of, but are not limited to, scalable processor improvements, Wideband Agile Receiver and Pulse Detector (WARPD), Expanded Steered Beam capability, and augmented Remote Maintenance. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                        R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                    PE 0305207F / Manned Reconnaissance Systems Operational Systems Development COMBAT SENT BL-6 and initial BL-7 developmental enhancements consist of, but are not limited to, steerable beams for the COMINT sub-system, improved High Probability of Intercept (HPOI) capability and specific emitter identification (SEI) electronic intelligence (ELINT) sub- system, Primary Sensor Measurement System (PRISMS) merge with manual precision collections, millimeter wave and low band capabilities with PRISMS, digitizing antennas, direction finding of High Frequency signals and expanded streaming audio services and 360 degree aircraft tracking system. COBRA BALL BL-14 developmental enhancements consist of, but are not limited to, software updates to the MASINT collection system (MCS), high-gain steerable- beam K-band antenna array, high-band direction finding (DF) antenna, High Probability of Intercept (HPOI), enhanced Signals of Interest identification and classification, digitized collection antenna (Cerberus), enhanced time accuracy, coherent CFCS collections, integration of specific Quick Reaction Capabilities (QRC), migration of the common RIVET JOINT hardware and software, Ground Systems Baseline upgrades add the capabilities found in the corresponding RIVET JOINT Baseline upgrades (i.e., RIVET JOINT BL-13 corresponds to Ground System BL-13, RIVET JOINT BL-14 corresponds to Ground System BL-14, RIVET JOINT BL-15 corresponds to Ground System BL-15) to the Ground Systems to ensure crews receive training on the appropriate mission system configurations. Activities also include studies and analysis to support both current program planning and execution and future program planning. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 0.00M was expended for civilian pay expenses in this program element, and in CY 0.00M is forecasted for civilian pay expenses in this program element. The FY 2024 funding request was reduced by $1.608 million to account for the availability of prior year execution balances. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0305207F / Manned Reconnaissance Systems Operational Systems Development$$, NULL, 17729000, 18064000, 18409000, NULL, NULL, 262, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 18323000, 28733000, 17114000, 17114000, 0, 17114000, 18782000, $$RC-135 operational systems development and enhancement activities support design studies, engineering analysis, non-recurring engineering and other efforts associated with the integration and modification of the RC-135 programs and their specialized mission systems, both air and ground. Associated ground systems include RIVET JOINT Ground Data Processing Systems (GDPS), Distributed Mission Shelters (DMS), Mission Crew Training Systems (MCTS), Airborne Capabilities Extension System (ACES), and the Operational Flight Trainers (OFT, a.k.a. flight deck simulators). RC-135 funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. Extensive utilization of Commercial-Off-The-Shelf (COTS) based solutions allows rapid fielding of needed capabilities through upgrades and supports Diminishing Manufacturing Sources (DMS)/Vanishing Vendor Items (VVI) logistics mitigation efforts. The results of these efforts provide for preliminary assessments of technical feasibility, operability, or military utility as well as specific engineering implementations for integration into the various systems baseline configurations. These activities are managed by the 645th Aeronautical Systems Group (645 AESG). The 645 AESG (a.k.a. BIG SAFARI) manages engineering, ground and support systems modifications, integration, flight testing, product assurance, acceptance testing, logistics, and training activities. Aircraft, sensor systems, and associated ground support system engineering planned for FY 2027 budget includes developmental planning, execution and support for the RC-135V/W RIVET JOINT Baselines 13, 14, and 15 (BL-13, BL-14, and BL-15), the RC-135U COMBAT SENT Baselines 6 and 15 (BL-6 and BL-15), and the RC-135S COBRA BALL BL-7, BL-14, and BL-15 configurations. COMBAT SENT has renumbered their baselines going forward to align with RIVET JOINT baseline numbering to take advantage of the baseline commonalities for technical manuals, training systems, contracting, and security certifications. The world-wide challenge of keeping pace against technologically agile targets used by both nation and non- nation- state adversaries and the rapid evolution of COTS technologies demands a responsive and adaptive acquisition strategy for fielding incremental spiral upgrades and baseline capabilities that are logistically supportable at all locations. The 645 AESG uses an incremental baseline strategy to mitigate risk, find affordable solutions and field needed capabilities on the aircraft and associated ground support and training systems. Obsolescence and DMS/VVI logistical concerns are addressed with each baseline upgrade and assessed annually as part of the fleet sustainment responsibilities. RIVET JOINT BL-14 upgrades consist of, but are not limited to, StarShield Beyond Line of Sight (BLoS) system, providing a continuous recording capability, High Probability of Intercept (HPOI) Receiver, Corvus Digital Receiver (CDR), Communications, Navigation, and Surveillance - Air Traffic Management (CNS-ATM) avionics upgrades such as new autopilot, automated data system- broadcast (ADS-B) and Mode 5 identify friendly or foe (IFF) systems. RIVET JOINT BL-15 upgrades consist Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305207F / Manned Reconnaissance Systems Operational Systems Development of, but are not limited to, scalable processor improvements, Wideband Agile Receiver and Pulse Detector (WARPD), Expanded Steered Beam capability, augmented Remote Maintenance, and a high-sensitivity receiver upgrade for Low Probability of Intercept (LPI) targets. COMBAT SENT BL-6 and initial BL-15 developmental enhancements consist of, but are not limited to, steerable beams for the COMINT sub-system, search-thru- jammer improvements, improved High Probability of Intercept (HPOI) capability and specific emitter identification (SEI) electronic intelligence (ELINT) sub- system, Primary Sensor Measurement System (PRISMS) merge with manual precision collections, millimeter wave and low band capabilities with PRISMS, digitizing antennas, direction finding of High Frequency signals and expanded streaming audio services and 360 degree aircraft tracking system. COBRA BALL BL-14 developmental enhancements consist of, but are not limited to, software updates to the MASINT collection system (MCS), high-gain steerable- beam K-band antenna array, high-band direction finding (DF) antenna, High Probability of Intercept (HPOI), enhanced Signals of Interest identification and classification, digitized collection antenna (Cerberus), enhanced time accuracy, coherent CFCS collections, integration of specific Quick Reaction Capabilities (QRC), migration of the common RIVET JOINT hardware and software. COBRA BALL BL-15 developmental enhancements consist of MCS algorithm updates for machine learning, MapLarge integration, and a High-band direction finding (DF) spinner. Ground Systems Baseline upgrades add the capabilities found in the corresponding RIVET JOINT Baseline upgrades (i.e., RIVET JOINT BL-13 corresponds to Ground System BL-13, RIVET JOINT BL-14 corresponds to Ground System BL-14, RIVET JOINT BL-15 corresponds to Ground System BL-15) to the Ground Systems to ensure crews receive training on the appropriate mission system configurations. Activities also include studies and analysis to support both current program planning and execution and future program planning. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 0.00M was expended for civilian pay expenses in this program element, and in CY 0.00M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0305207F / Manned Reconnaissance Systems Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305208BB$$, $$Distributed Common Ground/Surface Systems$$, $$rdte_dw_ba7$$, $$dw_socom$$, 2026, 5656000, 6214000, 5854000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0305208BB", "page_header": "Defense-Wide"}$$::jsonb, $$This Program Element is part of the Military Intelligence Program (MIP). The Distributed Common Ground/Surface System Special Operations Forces (DCGS-SOF) is part of a family of systems providing rapid fielding of Intelligence, Surveillance, and Reconnaissance (ISR) Processing, Exploitation, Dissemination (PED), and analytical capabilities at the Combatant Commands (COCOM), Component/Theater Special Operations Commands (TSOC) level and below through a combination of reach back, forward support, and collaboration. The mission tailored infrastructure interconnects the warfighters, analysts, and sensors to find and fix high value targets and provides a network-enabled, interoperable construct allowing continual, unimpeded sharing of intelligence data, information and services with SOF and between the services, national intelligence agencies, COCOMs, and multi-national partners. The DCGS-SOF connects SOF warfighters and analysts with essential intelligence information and provides situational awareness information to SOF leadership at all echelons. The two components of DCGS-SOF are Enterprise/All Source Information Fusion (ENT/ ASIF) and SOF Geospatial Intelligence Imagery Processing, Exploitation, and Dissemination (SGIP). The ENT/ASIF provides infrastructure, processing, and intelligence analytical tools for worldwide SOF intelligence information sharing via a globally connected cloud based architecture as well as a forward disconnected capability. The SGIP provides capabilities in garrison and deployed environments for the PED of crewed and uncrewed sensors.$$, NULL, NULL, NULL, NULL, NULL, NULL, 264, $$RDTE_SOCOM_PB_2026.pdf$$, $$SOCOM$$, FALSE, 5854000, 5656000, NULL, NULL, NULL, NULL, NULL, $$This Program Element is part of the Military Intelligence Program (MIP). The Distributed Common Ground/Surface System Special Operations Forces (DCGS-SOF) is part of a family of systems providing rapid fielding of Intelligence, Surveillance, and Reconnaissance (ISR) Processing, Exploitation, Dissemination (PED), and analytical capabilities at the Combatant Command (COCOM), Component/Theater Special Operations Command (TSOC) level and below through a combination of reach back, forward support, and collaboration. The mission tailored infrastructure interconnects the warfighters, analysts, and sensors to find and fix high value targets and provides a network-enabled, interoperable construct allowing continual, unimpeded sharing of intelligence data, information and services with SOF and between the services, national intelligence agencies, COCOMs, and multi-national partners. It connects SOF warfighters and analysts with essential intelligence information and provides situational awareness information to SOF leadership at all echelons. The DCGS-SOF includes two components: Enterprise/All Source Information Fusion (ENT/ASIF) and SOF Geospatial Intelligence Imagery Processing, Exploitation, and Dissemination (SGIP). The ENT/ASIF provides infrastructure, processing, and intelligence analytical tools for worldwide SOF intelligence information sharing via a globally connected cloud-based architecture as well as a forward disconnected capability. The SGIP provides capabilities in garrison and deployed environments for the PED of crewed and uncrewed sensors.$$, $$Budget J-Books/FY27/Remaining/RDTE_SOCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305208F$$, $$Distributed Common Ground/Surface Systems$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 79033000, 92354000, 86476000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305208F"}$$::jsonb, $$Air Force Distributed Common Ground System (AF DCGS) weapon system (AN/GSQ-272) is the Combat Air Force (CAF)'s primary Command and Control, Intelligence, Surveillance, and Reconnaissance (C2ISR) node providing global orchestration, sense-making, indications & warning, and dissemination of a multitude of sensor data. The AF DCGS mission is to provide Joint Task Force (JTF) Commanders, Joint and Combined Air Component Commanders (JFACC/CFACC), Combatant Commands, and other-directed organizations with global, time-sensitive Intelligence, Surveillance and Reconnaissance (ISR) data and fused multi-Intelligence (Multi-INT) products across the continuum of conflict. The AF DCGS weapon system provides capabilities required to connect, direct, and exploit sensors, as well as transform multi-source/ multi-domain data into actionable intelligence to find, fix, and track adversary forces and enable simultaneous kill chains at the speed and scale across the continuum of conflict. AF DCGS is also a major component of the DoD intelligence infrastructure and the AF's primary intelligence sense-making element and critical enabler for the Department of the Air Force (DAF) Battle Network. AF DCGS supports Combatant Commanders by leveraging its resilient, distributed cloud architecture, ensuring survivable Command and Control (C2), robust communication capabilities, and rapid sensor integration. AF DCGS is a Multi-INT, federated weapon system capable of exploiting intelligence data from manned platforms, Remotely Piloted Aircraft (RPA), non-traditional ISR platforms, national and commercial satellites, and other collection systems. AF DCGS as the primary C2ISR node has access to a multitude of sensors and data across the Intelligence Community, to include Publicly Available Information (PAI). AF DCGS Analysts leverage Artificial Intelligence (AI)/Machine Learning (ML), Automation and Augmentation (AAA) technologies to automate and focus their review/analysis of multi-source/multi-domain intelligence across the tactical/national sensor grid and within federated databases to enable target and problem centric, sensor-agnostic analysis and exploitation to address Joint operational requirements. AF DCGS provides time-dominant and tailored fused intelligence to meet Air Operations Center (AOC) and targeting mission requirements and supports sensor to shooter and the kill chain activities across the continuum of conflict. The DCGS analysts use all available data sources and emerging capabilities to enhance their understanding of intelligence/targeting problem sets and provide the required intelligence. Currently, AF DCGS is composed of eight core sites (two active duty worldwide, three active duty regional and three Air National Guard regional), six SIGINT Distributed Mission Sites (four collocated with National Mission Partner sites), three Air National Guard full-motion video sites, and four integration and test sites connected by robust, resilient communications infrastructure. AF DCGS currently supports ongoing operations from in-garrison CONUS and OCONUS-based locations. In alignment with DoD and AF direction, AF DCGS migrated to an open, resilient, distributed cloud architecture to rapidly incorporate modern technologies and tools, new/improved sensor capabilities, and GEOINT, SIGINT and multi-INT mission applications to meet emerging and urgent operational needs. Additionally, DCGS conforms with USD(I&S)'s efforts to improve data sharing through its Common Data Fabric (CDF), as well as the Space Force's efforts with its Unified Data Library (UDL). AF DCGS integrates commercial-off-the-shelf and government-off-the-shelf services and applications to fulfill operational requirements and data sharing requirements across the DoD DCGS community. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0305208F / Distributed Common Ground/Surface Systems Operational Systems Development In FY 2025, PEO C3BM approved the transition to a Software Acquisition Pathway (SWP) program, encompassing Mission Applications, Mission Data Services, and DCGS Operations Integration and Transformation, while maintaining a single ACAT III for Network Infrastructure Transformation (NIT). This step was taken to improve responsiveness and expedite minimum viable products to meet warfighter needs on software-centric capabilities. By adopting SWP, the program office can more responsively incorporate warfighter requirements, accelerate the fielding of capabilities, drive swift integration of emerging technologies, and align the agile release trains with this streamlined acquisition process. The SWP structure is scheduled to begin in FY 2026 and will be known as the AF DCGS Software Acquisition Pathway Program in budgeting documents. Efforts within this PE align with USAF investment in ABMS (0604003F), Tech Transition - Air (0604858F), and ISR Transport and Processing (0305240F), formerly Support to DCGS Enterprise, to deliver the Long Range Fires architecture for the DAF BATTLE NETWORK. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.646M was expended for civilian pay expenses in this program element, and in FY 2025 $1.141M is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 68672000, 70588000, 67858000, NULL, NULL, 263, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 99749000, 81033000, 85365000, 85365000, 0, 85365000, 69727000, $$Air Force Distributed Common Ground System (AF DCGS) weapon system (AN/GSQ-272) is the Combat Air Force (CAF)'s primary Command and Control, Intelligence, Surveillance, and Reconnaissance (C2ISR) node providing global orchestration, sense-making, tailored analysis (battlespace awareness, battlespace characterization, and targetable custody) at speed and scale to support C2-intel teaming and decision advantage across the competition continuum. The AF DCGS mission is to provide Joint Task Force (JTF) Commanders, Joint Force and Combined Force Air Component Commanders (JFACC/CFACC), Combatant Commands, and other-directed organizations with global, time-sensitive Intelligence, Surveillance and Reconnaissance (ISR) data and fused Multi-Intelligence (Multi- INT) products across the competition continuum. The AF DCGS weapon system provides capabilities required to connect, direct, and exploit sensors, as well as transform the vast array of multi-source/multi-domain data from available sensors/sources into actionable intelligence to find, fix, track and inform targeting of adversary forces and enable simultaneous kill chains. AF DCGS is also a major component of the DoD intelligence infrastructure and the AF's primary intelligence sense-making element and critical enabler for the Department of the Air Force (DAF) Battle Network. AF DCGS leveraging its robust, resilient transport and resilient, distributed architecture to ensure survivable Command and Control (C2), robust communication capabilities, rapid sensor integration, and comprehensive target and problem centric, sensor-agnostic analysis and exploitation to meet C/JFACC's operational objectives. AF DCGS is a Multi-INT, federated weapon system capable of exploiting intelligence data from manned platforms, Remotely Piloted Aircraft (RPA), non-traditional ISR platforms, national and commercial satellites, and other collection systems. AF DCGS, as the primary C2ISR node, has access to a multitude of sensors and data across the Intelligence Community, to include Publicly Available Information (PAI). AF DCGS leverages customizable Analysis and Exploitation Teams (AETs) to provide time- dominant and tailored fused intelligence to meet Air Operations Center (AOC) and targeting mission requirements and supports sensor to shooter and the kill chain activities across the competition continuum. AETs leverage Artificial Intelligence (AI)/Machine Learning (ML), Automation and Augmentation (AAA) technologies to automate and focus their review/analysis of multi-source/multi-domain intelligence across the tactical/national sensor grid and within federated databases to enable target and problem centric, sensor-agnostic analysis and exploitation to address joint operational requirements. The DCGS analysts use all available data sources and emerging capabilities to enhance their understanding of intelligence/targeting problem sets and provide the required intelligence. AF DCGS is a regionally aligned, globally networked ISR enterprise composed of eight core sites (two active duty OCONUS, three active duty CONUS and three Air National Guard CONUS), six SIGINT Distributed Mission Sites (four collocated with National Mission Partner sites), three Air National Guard Full-Motion Video (FMV) sites, and four integration and test environments connected by robust, resilient communications infrastructure. AF DCGS currently supports ongoing operations from in- garrison CONUS and OCONUS-based locations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                          Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0305208F / Distributed Common Ground/Surface Systems Operational Systems Development AF DCGS' open, resilient, distributed architecture enables the rapid incorporate modern technologies and tools, new/improved sensor capabilities, and GEOINT, SIGINT and Multi-INT mission applications to meet emerging and urgent operational needs. Additionally, DCGS conforms with USD(I&S)'s efforts to improve data sharing through its Common Data Fabric (CDF), as well as the Space Force's efforts with its Unified Data Library (UDL). AF DCGS integrates commercial-off-the-shelf and government-off-the-shelf services and applications to fulfill operational requirements and data sharing requirements across the DoD DCGS community In FY 2026, AF DCGS transitioned to one Software Acquisition Pathway (SWP) program (encompassing Mission Applications, Mission Data Services, and DCGS Operations Integration and Transformation) and maintained a single ACAT III for Network Infrastructure Transformation (NIT). Leveraging SWP for software-centric capabilities allows the program to be more responsive to warfighter requirements, streamlining acquisition processes to enable swift integration of emerging technologies and accelerated fielding of minimum viable products. Efforts within this PE align with USAF investment in Advanced Battle Management System (ABMS) (0604003F), Tech Transition - Air (0604858F), and ISR Transport and Processing (0305240F) to deliver the Long-Range Fires architecture for the DAF BATTLE NETWORK. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305208K$$, $$Distributed Common Ground/Surface Systems$$, $$rdte_dw_ba6$$, $$dw_disa$$, 2026, 2887000, 3069000, 2988000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0305208K", "page_header": "Defense-Wide"}$$::jsonb, $$The Defense Information Systems Agency (DISA) Joint Interoperability Test Command (JITC) is the sole joint interoperability certification agent for the Department of Defense (DoD). JITC provides test and evaluation (T&E) services to the Distributed Common Ground/Surface Systems (DCGS) Family of Systems (FoS), a major component of the Defense Intelligence Enterprise (DIE). The DIE enables the joint intelligence process and the planning and direction, collection, processing and exploitation, analysis and production, dissemination and integration, and evaluation and feedback of intelligence, surveillance, and reconnaissance (ISR) needed to answer priority intelligence requirements (PIRs) across military operations. Answering PIRs enables leaders to take decisive military action. DIE components are improving battlespace awareness (BA) through the modernization and evolution of how intelligence is delivered to commanders. Part of this evolution is the development of modernized DIE test, evaluation, and assessment concepts to improve senior leader Military Intelligence Program (MIP) management and investment decisions. The goal is to develop real-time, continuous, metrics collection combined with interactive health and status visualization methods to provide quality data for leadership decision making at the speed of need. Operational testing addresses critical operational issues of a system's effectiveness in combat-like environments. Additionally, operational testing provides key stakeholders and decision makers an independent evaluation of a system’s operational effectiveness, suitability, and cybersecurity posture. Interoperability testing directly contributes to the DoD’s success by ensuring that Military forces, units and/or systems, along with U.S. mission partners, can share the data, information, materiel, and services required to operate collaboratively and effectively. Decision makers must understand the capabilities and risks of new technologies and systems as they are fielded onto warfighters’ hands at an increasingly faster pace. The Under Secretary of Defense for Intelligence and Security (OUSD(I&S)) sponsored a Capabilities Based Assessment that resulted in an Initial Capability Document (ICD) and Joint Requirements Oversight Council Memorandum ICD for the DCGS Enterprise. These form the foundational evaluation framework for the DIE. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Defense Information Systems Agency                                                    Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:             PE 0305208K / Distributed Common Ground/Surface Systems RDT&E Management Support$$, NULL, 2979000, 3034000, 3075000, NULL, NULL, 213, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 2988000, 2887000, 2951000, 2951000, NULL, 2951000, 3075000, $$The Defense Information Systems Agency (DISA) Joint Interoperability Test Command (JITC) is the sole joint interoperability certification agent for the Department of War (DoW). JITC provides test and evaluation (T&E) services to the Distributed Common Ground/Surface Systems (DCGS) Family of Systems (FoS), a major component of the Defense Intelligence Enterprise (DIE). The DIE enables the joint intelligence process and the planning and direction, collection, processing and exploitation, analysis and production, dissemination and integration, and evaluation and feedback of intelligence, surveillance, and reconnaissance (ISR) needed to answer priority intelligence requirements (PIRs) across military operations. Answering PIRs enables leaders to take decisive military action. DIE components are improving battlespace awareness (BA) through the modernization and evolution of how intelligence is delivered to commanders. Part of this evolution is the development of modernized DIE test, evaluation, and assessment concepts to improve senior leader Military Intelligence Program (MIP) management and investment decisions. The goal is to develop real-time, continuous, metrics collection combined with interactive health and status visualization methods to provide quality data for leadership decision making at the speed of need. Operational testing addresses critical operational issues of a system's effectiveness in combat-like environments. Additionally, operational testing provides key stakeholders and decision makers an independent evaluation of a system’s operational effectiveness, suitability, and cybersecurity posture. Interoperability testing directly contributes to the DoW’s success by ensuring that Military forces, units and/or systems, along with U.S. mission partners, can share the data, information, materiel, and services required to operate collaboratively and effectively. Decision makers must understand the capabilities and risks of new technologies and systems as they are fielded onto warfighters’ hands at an increasingly faster pace. The Under Secretary of War for Intelligence and Security (OUSW(I&S)) sponsored a Capabilities Based Assessment that resulted in an Initial Capability Document (ICD) and Joint Requirements Oversight Council Memorandum ICD for the DCGS Enterprise. These form the foundational evaluation framework for the DIE. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 6:         PE 0305208K / Distributed Common Ground/Surface Systems RDT&E Management Support$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305208M$$, $$Distributed Common Ground/Surface Systems$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 61238000, 55392000, 45550000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 39, "original_pe": "0305208M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 2520000, 2646000, 2778000, NULL, NULL, NULL, NULL, NULL, FALSE, 45550000, 61238000, 0, 0, NULL, 0, 2917000, $$DCGS-MC is a Military Intelligence Program (MIP) program element. Distributed Common Ground System-Marine Corps (DCGS-MC) is a critical Commandant of the Marine Corps Force Design program focused on Reconnaissance/ Counter-Reconnaissance that senses and makes sense of the forward operating area and provides robust multi-intelligence processing, exploitation, and dissemination (PED) activities to include sensor fusion and correlation. As the forward sensing element of the maritime force, DCGS-MC provides the foundation for algorithmic warfare at the tactical edge pushing validated target quality information to enable global long range precision fires. DCGS-MC complies with the DCGS Enterprise interoperability and information sharing requirements necessary for PED capabilities via consolidated functional servers, workstations, cloud computing, and advanced technological processing capabilities from a contested, tactical environment to the integrated Marine Corps Intelligence, Surveillance, and Reconnaissance Enterprise (MCISRE). DCGS-MC capabilities deliver tactically focused, operational, and strategic intelligence across all echelons of the Marine Corps at the tactical edge throughout all phases of operations to provide relevant, precise battlespace awareness, and threat characterization for the Joint Task Force, Naval Force, Marine Air-Ground Task Force, and subordinate Marine units in support of Expeditionary Advanced Base Operations and Distributed Maritime Operations. Modernization efforts are focused on advanced all-domain information environment tools, and technologies that enable superior awareness of the battlespace. The capabilities reduce the logistical and cognitive burden on the individual Marine by reducing size, weight, and power and provide advanced computing capabilities at the forward edge in a contested environment against a peer adversary. Current programmatic efforts support a multi-domain sensing architecture, organic sensing, mobile battlespace awareness, and increased integration with space and cyber systems. From the MCISRE to Naval Operations Architecture, DCGS-MC provides an enduring information advantage and the rapid weaponization of data to support enhancements to the kill web by streamlining information exchanges, federating track and sensor data for rapid analysis and exploitation and increasing accessibility information across all levels of security classification. Maritime Targeting Cell-Expeditionary (MTC-X) details provided at a higher classification level. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                               Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational        PE 0305208M / Distributed Common Ground/Surface Systems Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
