INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305219A$$, $$MQ-1 Gray Eagle UAV$$, $$rdte_army_ba7$$, $$peo_aviation$$, 2026, 3444000, 6629000, 6681000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "original_pe": "0305219A", "page_header": "Department of the Army"}$$::jsonb, $$The MQ-1C Gray Eagle provides the Army with an Extended Range, Multi-Purpose (ERMP) Uncrewed Aircraft System (UAS); capable of executing reconnaissance, security, attack, and intelligence collection missions in the Range of Military Operations (ROMO). Sensors/payloads include an Electro-Optical/Infrared/Laser Designator (EO/IR/LD), Synthetic Aperture Radar/Moving Target Indicator (SAR/MTI), Signals Intelligence (SIGINT), and HELLFIRE missiles; providing a near all-weather mission capability. MQ-1C Gray Eagle is a dedicated, assured, multi-mission UAS, fielded to Active Components, Intelligence and Security Command and Army Special Operations Command in support of the commander's warfighting priorities within Multi-Domain Operations.$$, NULL, 2799000, 2839000, 2843000, NULL, NULL, 236, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, 6681000, 3444000, 2590000, 2590000, NULL, 2590000, 2871000, $$The MQ-1C Gray Eagle provides the Army with an Extended Range, Multi-Purpose (ERMP) Uncrewed Aircraft System (UAS); capable of executing reconnaissance, security, attack, and intelligence collection missions in the Range of Military Operations (ROMO). Sensors/payloads include an Electro-Optical/Infrared/Laser Designator (EO/IR/LD), Synthetic Aperture Radar/Moving Target Indicator (SAR/MTI), Signals Intelligence (SIGINT), and HELLFIRE missiles; providing a near all-weather mission capability. MQ-1C Gray Eagle is a dedicated, assured, multi-mission UAS, fielded to Active Components, Intelligence and Security Command and Army Special Operations Command in support of the commander's warfighting priorities within Multi-Domain Operations.$$, $$Budget J-Books/FY27/Army/RDTE - Vol 4 - Budget Activity 7.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305220F$$, $$RQ-4 UAV$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 1242000, 6171000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305220F"}$$::jsonb, $$The RQ-4B Global Hawk is a high-altitude, long-endurance, all-weather, day/night Intelligence, Surveillance and Reconnaissance (ISR) platform delivering Synthetic Aperture Radar (SAR)-based Ground Moving Target Indicator (GMTI) and Maritime Mode Target Indicator (MMTI)capabilities to the warfighter. To win high-end conflict, the future force design must deliver ISR capabilities and concepts of operation that can survive against peer/near-peer threats in highly contested environments. To accomplish this, in FY 2026 the USAF will focus on maximizing the Block 40's value to the DoD until divestiture. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 0.000M was expended for civilian pay expenses in this program element. In FY 2025, civilian pay expenses are 2.096M in this program element. In FY 2026, RQ-4 execution will transition to O&M, supporting sustainment profile until divestment. This program element may include necessary emergent or unanticipated Product Support Costs (PSC) and civilian pay expenses required to manage, execute, and deliver RQ-4 program for emergent or unanticipated weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0305220F / RQ-4 UAV Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 264, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 6171000, 0, 0, 0, 0, 0, 0, $$The RQ-4B Global Hawk is a high-altitude, long-endurance, all-weather, day/night Intelligence, Surveillance and Reconnaissance (ISR) platform delivering Synthetic Aperture Radar (SAR)-based Ground Moving Target Indicator (GMTI) and Maritime Mode Target Indicator (MMTI)capabilities to the warfighter. To win high-end conflict, the future force design must deliver ISR capabilities and concepts of operation that can survive against peer/near-peer threats in highly contested environments. To accomplish this, in FY 2027 the USAF will focus on maximizing the Block 40's value to the DoD until divestiture. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F” This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305220N$$, $$MQ-4C Triton$$, $$rdte_navy_ba7$$, $$peo_uw$$, 2026, 14421000, 12094000, 14402000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0305220N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 13613000, 13406000, 12635000, NULL, NULL, NULL, NULL, NULL, FALSE, 14402000, 14421000, 10515000, 10515000, NULL, 10515000, 12819000, $$The MQ-4C Triton Unmanned Air System (UAS) is a high altitude-long endurance UAS designed to provide Fleet and combatant commanders with persistent maritime Intelligence, Surveillance Reconnaissance and Targeting (ISR&T) of nearly all the world's high-density sea-lanes, littorals, and areas of national interest. The Triton air vehicle, mission control system, specialized sensors, and communications suite play a significant role in achieving the Navy's strategic vision for the 21st century. Triton provides persistent ISR&T and unparalleled situational awareness of the maritime battle space to the supported combatant commander and fleet commander. Triton provides the Warfighter with unprecedented levels of battlespace awareness to synchronize actions necessary to maintain maritime Full Spectrum Superiority. Teamed with its manned-capability counterpart, the P-8A Poseidon, Triton is a key component of the Navy's maritime domain awareness family of systems. MQ-4C Triton leverages Maritime Patrol and Reconnaissance Force manpower, training and maintenance efficiencies. Triton Early Operational Capability (EOC) was successfully deployed in 2020 to provide early fleet integration risk reduction. It successfully prepared the fleet for fielding Initial Operational Capability (IOC) and concluded in 2022. In August of 2023 Triton fielded the Increment 1 Multi-Intelligence (Multi-INT) IOC on schedule, successfully meeting the 2011 National Defense Authorization (NDAA) requirements. This enabled the Navy's Maritime Intelligence, Surveillance, Reconnaissance, and Targeting (MISR-T) transition plan and initiated EP-3 Aries sundown. The Increment 1 Multi-INT capability provides Signals Intelligence (SIGINT), Counter Electronic Attack (CEA) upgrades, and data dissemination across multiple classification domains. Project Unit 4020: MQ-4C Triton Baseline funding supported developmental efforts from the inception of the program and continues to fund air vehicle Full Scale Fatigue Testing (FSFT), Effects of Defects (EoD) test efforts and updates to fatigue and damage tolerance analyses to fully verify and validate fatigue and damage tolerance requirements of the MQ-4C Triton Performance Based System Specification (PBSS). Fatigue testing results are required to certify the airframe to its current designed service life of 51,000 flight hours/2,029 landings. The duration of fatigue testing is paced by the cycling rate limit of the test fixture/equipment for the main wing/fuselage/ Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                    Date: April 2026 Appropriation/Budget Activity                                                         R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational              PE 0305220N / MQ-4C Triton Systems Development tail test article, as well as time to perform teardown activities and inspect for cracks. Baseline funding also includes developmental efforts that improve the air vehicle reliability, availability, maintainability, and performance. JUSTIFICATION FOR BUDGET ACTIVITY: The FY 2027 funding is provided for System Demonstration Test Article (SDTA) vehicles and Fatigue Testing to support post-test teardown, inspections and reporting for portions of the full-scale test efforts. Additionally, the funding supports the execution of the Effects of Defects testing to retire limitations imposed by non-blueprint defect repairs conducted during the manufacturing process, as well as various air vehicle reliability, availability, maintainability, and performance improvements. This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305221F$$, $$Network-Centric Collaborative Targeting$$, $$rdte_af_ba7$$, $$aflcmc_hn$$, 2026, 12019000, 20696000, 8952000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305221F"}$$::jsonb, $$Network Centric Collaborative Targeting (NCCT) is the Department of the Air Force's (DAF) program of record performing platform agnostic, tactical, cooperative geo-location against time sensitive targets. At its core, NCCT is a cloud-based, Joint sensor network that integrates sensors and shooters via a multi-domain, multi- intelligence (multi-INT) AI/ML-assisted decision matrix over a survivable network to find, fix, track, and target (F2T2) threats in highly contested battlespaces. Operationally, NCCT is currently deployed on a variety of DAF aircraft, the DCGS, and other DoD assets. NCCT's utilization of intelligent sensor mesh networks, multi-INT fusion, and its cross-domain information sharing and sensor C2 are key contributions to the Sensing Grid's sensing, sense making, integration, and global orchestration thrusts. NCCT research and development funding supports development of the NCCT message set, network management systems, and technology modernization specific to network and fusion architecture design. Development funds also support software modifications required for development and integration with new and emerging platforms, and incorporation of new data fusion algorithms while satisfying DoD standards and Information Assurance requirements. FY 2026 funding will be dedicated to filling critical capability gaps in the long-range kill chain and multi-INT High Capacity F2T2EA (HCF) sense-making, as well as continued partnerships and integrations with the Joint Force. NCCT will be working closely with C3BM and will be advancing core capabilities to fulfill critical networking and fusion gaps to advance long-range kill chain operations as well as developing advanced techniques for rapid sensemaking of multi-INT HCF sensors by leveraging cross-intelligence AI/ML-assisted fusion and optimizing the network to mirror targeting priorities. NCCT will also be continuing integration efforts with the Joint Fires Network, DAF Battle Network, and the Navy through the Joint Integrated Fire Control - Electronic Warfare Multi-INT Fusion Engine (JIFC-EW). FY 2025 funding is focused on continued cloud utilization, refinement of user interface, integrations of multiple new data sources and required fusion upgrades to support them, and optimization of automation gained through synaptic intelligence-based AI/ML. FY 2024 funding was dedicated to one major capability release and two minor releases. These releases continued development of new and emerging multi-INT use cases, development to integrate additional platforms, fusion on the edge development and integration with the RC-135 fleet, and testing/deployment of Synaptic Intelligence based AI/ML platform. FY 2024 funding continued cloud development and utilization. Additional development, testing, and deployment of a new user interface was also funded. In addition, FY 2024 funded Ukrainian assistance efforts to increase efficiencies in communications and data dissemination networks. Finally, FY 2024 funding continued National to Tactical tip and cue integration, and complete airborne moving target indication (AMTI) to SIGINT data fusion algorithms, while preserving rapid software delivery based on continuous user feedback. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0305221F / Network-Centric Collaborative Targeting Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0M was expended for civilian pay expenses in this program element, and in FY 2025 $0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 9507000, 9696000, 9878000, NULL, NULL, 265, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 9952000, 12019000, 9146000, 9146000, 0, 9146000, 10078000, $$Network Centric Collaborative Targeting (NCCT) is the Department of the Air Force's (DAF) program of record performing platform agnostic, tactical, cooperative geo-location against time sensitive targets. At its core, NCCT is a cloud-based, Joint sensor network that integrates sensors and shooters via a multi-domain, multi- intelligence (multi-INT) AI/ML-assisted decision matrix over a survivable network to find, fix, track, and target (F2T2) threats in highly contested battlespaces. Operationally, NCCT is currently deployed on a variety of DAF aircraft, the DCGS, and other DoD assets. NCCT's utilization of intelligent sensor mesh networks, multi-INT fusion, and its cross-domain information sharing and sensor C2 are key contributions to the Sensing Grid's sensing, sense making, integration, and global orchestration thrusts. NCCT research and development funding supports development of the NCCT message set, network management systems, and technology modernization specific to network and fusion architecture design. Development funds also support software modifications required for development and integration with new and emerging platforms, and incorporation of new data fusion algorithms while satisfying DoD standards and Information Assurance requirements. FY 2027 funding will be dedicated to continued scaling of the long-range kill chain by leveraging multi-INT AI/ML-assisted fusion, focused integration into track custody ontologies via object-based methods, as well as tactical edge fusion and orchestration support. NCCT will be working closely with C3BM and DAF Battle Network to advance core capabilities to fulfill critical networking requirements, as well as continued partnerships and integrations with the Joint Force. FY 2026 funding is dedicated to filling critical capability gaps in the long-range kill chain and multi-INT High Capacity F2T2EA (HCF) sense-making, as well as continued partnerships and integrations with the Joint Force. NCCT is working closely with C3BM to enhance core capabilities, fulfill critical networking and fusion gaps, and advance long-range kill chain operations. NCCT is also developing advanced techniques for rapid sensemaking of multi-INT HCF sensors by leveraging cross- intelligence AI/ML-assisted fusion and optimizing the network to mirror targeting priorities. Finally, NCCT is continuing integration efforts with the Joint Fires Network, DAF Battle Network, and the Navy through the Joint Integrated Fire Control - Electronic Warfare Multi-INT Fusion Engine (JIFC-EW). FY 2025 funding was focused on continued cloud utilization, refinement of the user interface, integrations of multiple new data sources and required fusion upgrades to support them, and optimization of automation gained through synaptic intelligence-based AI/ML. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0305221F / Network-Centric Collaborative Targeting Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305232M$$, $$RQ-11 UAV$$, $$rdte_navy_ba7$$, $$mc$$, 2026, 1063000, 2107000, 2016000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 39, "original_pe": "0305232M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 4358000, 4192000, 4451000, NULL, NULL, NULL, NULL, NULL, FALSE, 2016000, 1063000, 19842000, 19842000, NULL, 19842000, 4673000, $$In support of the Drone Dominance Program, Family of Small Unmanned Aircraft Systems (FoSUAS), formerly Small Unit Remote Scouting System (SURSS), is a Commandant of the Marine Corps Force Modernization initiative. FoSUAS consists of Short Range Tactical (SRT), Medium Range Tactical (MRT), and Long Range Tactical (LRT) systems. The FoSUAS program provides weaponized and non-weaponized Small Unmanned Aircraft Systems (SUAS) for battalion/company/detachment level units with scalable airborne Reconnaissance, Surveillance, and Target Acquisition (RSTA) capabilities to aid in detecting, identifying, engaging, and/or avoiding enemy units. Although Force Modernization prioritizes LRT capabilities, the requirements for SRT and MRT systems remain to minimize operational risk and improve operational flexibility in asset allocation that maximizes economy of force across the conflict continuum. FoSUAS meets the validated operational requirements delineated in the Family of Tactical Unmanned Aircraft Systems (FoTUAS) Capability Description Document. SRT is a SUAS with a 5-10 kilometer range and endurance up to 50 minutes. SRT systems address the need for situational awareness in urban and challenging terrain environments and reduce request-to-response timeframes for RSTA coverage. MRT is a SUAS with a 10-20 kilometer range and endurance up to 4 hours. MRT provides an organic, persistent RSTA capability to company level units, Route Clearance Platoons (RCP), and Combat Logistics Patrols (CLP) to enhance force protection, detect Improvised Explosive Devices (IEDs), provide laser targeting/ marking/range finding, and communication relay. LRT is a SUAS with a 20-50 kilometer range and endurance up to 6 hours. LRT provides organic capabilities to battalion level units to satisfy Ground Combat Element RSTA needs. LRT SUAS are currently deployed to conduct multi-sensor RSTA operations for Marine Forces Special Operations Command and support Marine Corps fires and maneuver elements. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                            Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational      PE 0305232M / RQ-11 UAV Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305236F$$, $$Common Data Link Executive Agent (CDL EA)$$, $$rdte_af_ba4$$, $$dw_osd$$, 2026, 32511000, 25157000, 33349000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0305236F"}$$::jsonb, $$Common Data Link Executive Agent (CDL EA) provides the DoD standard for interoperable, multi-service, multi-agency, Intelligence, Surveillance, and Reconnaissance (ISR) datalinks for 15,000 DoD manned/unmanned airborne and ground terminals. The project advances CDL through partnership with each of the Services, NSA, JITC, FFRDCs, and Industry. As the DoD CDL EA, the Air Force is responsible for cross-service application of CDL RDT&E Military Intelligence Program (MIP) funds facilitating compliance to DoD mandates. The CDL EA develops, modifies, distributes, and maintains specifications for the CDL waveform family; ensuring design configuration control, commonality, and interoperability among ISR platforms. The CDL EA also funds and supports cross-Service teams that manage development, maturation, and migration of CDL technologies. CDL EA enables compliance with OSD mandates to effectively utilize spectrum, use approved cryptographic equipment, and provide direct support to current operations. CDL is a vital link in DoD's existing and emerging communication architectures, providing flexibility to accommodate Command and Control (C2) data and myriad types of Signals Intelligence (SIGINT), Geospatial Intelligence (GEOINT), and Full-Motion Video (FMV) data. The CDL specifications permit interoperable operations of current and future ISR assets worldwide by providing sensor data directly via point-to-point and air-to-air or compatible satellite broadcast links to ground sites, surface ships, airborne platforms, and dismounted users to support Combined Joint All-Domain Command and Control (CJADC2) warfare. The CDL EA effort advances top-line CDL capabilities while maintaining compatibility with fielded U.S. and Allied terminals CDL EA's research and development activities support a broad array of tactical (including tactical data links (TDL) and high capacity backbone (HCB)), operational, and strategic ISR users. High priority investment activities support and include: achieving higher data rates, open architecture development, multi-access and multi-node network management, cryptographic modernization, advancements needed to operate in contested environments, terminal design enhancements, and operations in other spectral bands for spectrum efficiency. Activities also include studies and analysis to support current and future requirements documentation, program planning and execution. CDL prototype terminal designs provide for future technology insertion and reduce non-recurring engineering and life-cycle costs to the user. In addition, the Cryptographic Core Modernization (CCM) thrust enables CDL to develop a miniaturized gigabit rate crypto devices capable of securing CDL data through improving Transmission Security (TRANSEC) capabilities. The miniaturized crypto device will allow faster throughput while reducing Size, Weight, and Power (SWaP) requirements. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0305236F / Common Data Link Executive Agent (CDL EA) Component Development & Prototypes (ACD&P) 0606398F. In FY 2024 0.330M was expended for civilian pay expenses in this program element, and in FY 2025 0.358M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, NULL, 27715000, 28407000, 29077000, NULL, NULL, 76, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 33349000, 32511000, 26401000, 26401000, 0, 26401000, 29807000, $$Common Data Link Executive Agent (CDL EA) provides the DoW standard for interoperable, multi-service, multi-agency, Intelligence, Surveillance, and Reconnaissance (ISR) datalinks for 15,000 DoW manned/unmanned airborne and ground terminals. The project advances CDL through partnership with each of the Services, NSA, JITC, FFRDCs, and Industry. As the DoW CDL EA, the Air Force applies CDL RDT&E Military Intelligence Program (MIP) funds, using cross-Service teams, ensuring compliance with DoW waveform mandates. The CDL EA develops, modifies, distributes, and maintains specifications for the CDL waveform family; ensuring design configuration control, commonality, and interoperability among ISR platforms. The CDL EA also funds and supports cross-Service teams that manage development, maturation, and migration of CDL technologies. CDL EA enables compliance with OSW mandates to effectively utilize spectrum, use approved cryptographic equipment, and provide direct support to current operations. CDL is a vital link in DoW's existing and emerging communication architectures, providing flexibility to accommodate Command and Control (C2) data and myriad types of Signals Intelligence (SIGINT), Geospatial Intelligence (GEOINT), and Full-Motion Video (FMV) data. The CDL specifications enable interoperable operations of current and future ISR assets worldwide by providing sensor data directly via point-to-point and networked air-to-air or compatible satellite broadcast links to ground sites, surface ships, airborne platforms, and dismounted users, supporting Combined Joint All-Domain Command and Control (CJADC2) warfare. The CDL EA effort advances top-line CDL capabilities while maintaining compatibility with fielded U.S. and Allied terminals CDL EA's research and development activities support a broad array of tactical (including tactical data links (TDL) and high capacity backbone (HCB)), operational, and strategic ISR users. High priority investment activities support and include: achieving higher data rates, open architecture development, multi-access and multi-node network management, cryptographic modernization, advancements needed to operate in contested environments, terminal design enhancements, and operations in other spectral bands for spectrum efficiency. Activities also include studies and analysis to support current and future requirements documentation, program planning and execution. CDL prototype terminal designs provide for future technology insertion and reduce non-recurring engineering and life-cycle costs to the user. In addition, the Cryptographic Core Modernization (CCM) thrust enables CDL to develop a miniaturized gigabit rate crypto devices capable of securing CDL data through improving Transmission Security (TRANSEC) capabilities. The miniaturized crypto device will allow faster throughput while reducing Size, Weight, and Power (SWaP) requirements. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0305236F / Common Data Link Executive Agent (CDL EA) Component Development & Prototypes (ACD&P) This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305238F$$, $$NATO AGS$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 816000, 2000, 865000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305238F"}$$::jsonb, $$This program funds the U.S. support to the Alliance Ground Surveillance (AGS) system, a North Atlantic Treaty Organization (NATO) program. AGS is an airborne ground surveillance capability that provides continuous, wide area surveillance in all weather conditions. It provides NATO decision makers with near real time information and situational awareness concerning friendly, neutral and opposing ground and maritime forces to support mission planning and execution, including force protection and targeting. All NATO nations have access to AGS collection data, creating opportunities for burden sharing with the processing and exploitation of Intelligence, Surveillance, and Reconnaissance (ISR) data. The AGS program includes both air and ground segments. The air segment consists of five (5) air vehicles based on unique exportable configurations of the United States Air Force Global Hawk air frame, Navy Triton command and control architecture and the U.S. Multi-Platform Radar Technology Insertion Program (MP-RTIP) radar. The U.S. integrated a new Maritime Moving Target and Inverse Synthetic Aperture Radar capability into the MP-RTIP radar for NATO AGS. The ground segment consists of fixed site and transportable/mobile ground stations for air vehicle Command and Control (C2), data exploitation and distribution. Operations and continuing In-Service Support is funded through the NATO Military Commanders' Capability Package within the NATO Security Investment Program (NSIP). This program element may include necessary civilian pay expenses required to manage, execute, and deliver NATO AGS. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 $0.0M was expended for civilian pay expenses in this program element, and in FY2026 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305238F / NATO AGS Operational Systems Development$$, NULL, 0, 0, 0, NULL, NULL, 266, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 865000, 816000, 0, 0, 0, 0, 0, $$This program funds the U.S. support to the Alliance Ground Surveillance (AGS) system, a North Atlantic Treaty Organization (NATO) program. AGS is an airborne ground surveillance capability that provides continuous, wide area surveillance in all weather conditions. It provides NATO decision makers with near real time information and situational awareness concerning friendly, neutral and opposing ground and maritime forces to support mission planning and execution, including force protection and targeting. All NATO nations have access to AGS collection data, creating opportunities for burden sharing with the processing and exploitation of Intelligence, Surveillance, and Reconnaissance (ISR) data. The AGS program includes both air and ground segments. The air segment consists of five (5) air vehicles based on unique exportable configurations of the United States Air Force Global Hawk air frame, Navy Triton command and control architecture and the U.S. Multi-Platform Radar Technology Insertion Program (MP-RTIP) radar. The U.S. integrated a new Maritime Moving Target and Inverse Synthetic Aperture Radar capability into the MP-RTIP radar for NATO AGS. The ground segment consists of fixed site and transportable/mobile ground stations for air vehicle Command and Control (C2), data exploitation and distribution. Operations and continuing In-Service Support is funded through the NATO Military Commanders' Capability Package within the NATO Security Investment Program (NSIP). This program element may include necessary civilian pay expenses required to manage, execute, and deliver NATO AGS. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2025 $0.0M was expended for civilian pay expenses in this program element, and in FY2026 $0.0M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                       Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305238F / NATO AGS Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305240F$$, $$ISR Transport and Processing$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 32578000, 33589000, 30932000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305240F"}$$::jsonb, $$This Program Element funds a DoD program for global air and space Intelligence, Surveillance and Reconnaissance (ISR) data transport/relay, imagery processing, data conditioning, and AI/ML augmentation. Serves multiple national, theater, and tactical customers with processing and transport of raw/unexploited ISR data in support of operational and intelligence functions. This PE funds the engineering development, acquisition, modernization and migration of: Communications Infrastructure, Virtual Imagery Processing Capability (VIP-C) and High-Performance Compute (HPC), and Machine Assisted GEOINT Exploitation (MAGE) tools. The Enterprise Interoperability (formerly DCGS Enterprise Interoperability) project provides support to OUSD(I&S), C3BM, and AF DCGS interoperability efforts. This includes integration with new and emerging air and space-based sensors. The Imagery Processing effort develops the Virtual Imagery Processing Capability (VIP-C) and the High Performance Compute (HPC) Environment within the Air Force ISR Transport and Processing (Formerly Support to DCGS) architecture. The VIP-C and HPC environment provides mission critical image processing capabilities to include raw data ingest, initial image formation, and data conditioning/normalization to optimize ISR data for exploitation by humans and machines, value-added algorithmic processing, and configurable analytic workflows. It also covers Machine Assisted Geospatial Intelligence (GEOINT) Exploitation (MAGE), which is a comprehensive program to employ advanced technologies, automation, and augmentation at speed and scale to close the gap between image collection and actionable intelligence. Current efforts are focused on enabling support for new and emerging air and space-based sensors and data types and developing/scaling core MAGE components. Efforts within this PE align with USAF investment in ABMS (0604003F), Tech Transition - Air (0604858F), and AF DCGS (0305208F) to deliver the Long Range Fires architecture for the DAF BATTLE NETWORK. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.881M was expended for civilian pay expenses in this program element, and in FY 2025 $1.177M is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $.259 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0305240F / ISR Transport and Processing Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 33780000, 34651000, 35571000, NULL, NULL, 267, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 33432000, 32578000, 312037000, 312037000, 0, 312037000, 36292000, $$Intelligence, Surveillance and Reconnaissance (ISR) Transport and Processing (ITP) is a DoD program for global ISR bi-directional data transport and processing. Detailed information remains classified and will be provided on a need-to-know basis. The ITP program provides global air and space Intelligence, Surveillance and Reconnaissance (ISR) data transport/relay, imagery processing, data conditioning, and AI/ML augmentation. It serves multiple national, theater, and tactical customers with processing and transport of raw/unexploited ISR data in support of operational and intelligence functions. This PE funds the engineering development, acquisition, modernization and migration of: Communications Infrastructure, Virtual Imagery Processing Capability (VIP-C) and High-Performance Compute (HPC), and Machine Assisted GEOINT Exploitation (MAGE) tools. The Enterprise Interoperability project provides support to OUSD(I&S), C3BM, and AF DCGS interoperability efforts. This includes integration with new and emerging air and space-based ISR sensors. The Imagery Processing effort develops the Virtual Imagery Processing Capability (VIP-C) and the High-Performance Compute (HPC) Environment within the Air Force ITP architecture. The VIP-C and HPC environment provides mission critical image processing capabilities to include raw data ingest, initial image formation, and data conditioning/normalization to optimize ISR data for exploitation by humans and machines, value-added algorithmic processing, and configurable analytic workflows. It also covers Machine Assisted Geospatial Intelligence (GEOINT) Exploitation (MAGE), which is a comprehensive program to employ advanced technologies, automation, and augmentation at speed and scale to close the gap between image collection and actionable intelligence. Current efforts are focused on enabling support for new and emerging air and space-based sensors and data types and developing/scaling core MAGE components. The ISR Transport effort is an upgrade of the ITP global bi-directional system. Detailed information for this particular effort remains classified and will be provided on a need-to-know basis. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305240F / ISR Transport and Processing Operational Systems Development Efforts within this PE align with USAF investment in the Advanced Battle Management System (ABMS) (0604003F), Tech Transition - Air (0604858F), and Air Force Distributed Common Ground System (AF DCGS) (0305208F) to deliver the Long-Range Fires architecture for the DAF BATTLE NETWORK. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305242M$$, $$Unmanned Aerial Systems (UAS) Payloads$$, $$rdte_navy_ba7$$, $$onr$$, 2026, 9157000, 12505000, 10917000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "mc", "page_num": 39, "original_pe": "0305242M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 18720000, 16627000, 16244000, NULL, NULL, NULL, NULL, NULL, FALSE, 10917000, 9157000, 20750000, 20750000, NULL, 20750000, 17306000, $$The Unmanned Aircraft Systems (UAS) Sensor Payload program provides the capability to develop, integrate, field, and sustain Intelligence, Surveillance, and Reconnaissance (ISR) and non-ISR payloads for the USMC Family of UAS. These payloads will alleviate Marine Corps ISR capability gaps caused by changes in mission, threats, and technologies and will increase the versatility of UAS in support of MAGTF mission accomplishment. In support of Force Design initiative, tactical UAS Reconnaissance, Survivability, and Target Acquisition (RSTA) is primarily focused on Marine Littoral Regiments (MLR) and on Marine Expeditionary Units (MEU) to enhance their ability to operate within an operating environment characterized by Great Power Competition. In support of the Commandant of the Marine Corps Planning Guidance and Force Design requirements, UAS sensor payloads provide modular, low-cost, aerial sensing technologies to achieve the Maritime Domain Awareness required by MLRs and MEUs in support of the Joint Forces Maritime Component Command (JFMCC). Within the context of Maritime Domain Operations, Marine forces executing Expeditionary Advanced Base Operations (EABO) require the organic capability to establish and maintain awareness of adversaries and potential adversary activities in communications and navigation degraded or denied environments. UAS Payloads enable sensing of threat indicators across the electromagnetic spectrum, gravimetric, chemical, nuclear, and acoustic spectrums and within the visual and physical domain and radar spectrum, with reduced signature, and minimized risk to personnel. The incorporation of advanced technology enablers such as artificial intelligence/machine learning (AI/ML) and precision geolocation provide automated recognition, identification, tracking, advanced networks, advanced communications, and cross-cueing in support of accelerated battlespace awareness and targeting. As an essential element of the kill chain, UAS payloads are critical to the JFMCC targeting process to find, fix, track, target, engage, and assess the effects of lethal and non-lethal fires. Employment of UAS payloads on platforms distributed across the MLRs and MEUs during EABO allows for greater distribution of forces while maintaining persistent awareness, enhances the security of tactical units and personnel moving across the battlespace, and enables the rapid transition between positions necessary for force survivability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                        Date: April 2026 Appropriation/Budget Activity                                               R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational    PE 0305242M / Unmanned Aerial Systems (UAS) Payloads Systems Development$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
