INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0904903D$$, $$Defense-Wide Resources$$, $$rdte_dw_ba7$$, $$dw$$, 2026, 0, 500000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 81, "original_pe": "0904903D", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305248J$$, $$Joint Staff Office of the Chief Digital and Artificial Intelligence Officer$$, $$rdte_dw_ba6$$, $$dw_cdao$$, 2026, 14500000, 0, 12700000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "dw", "page_num": 78, "original_pe": "0305248J", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 79306000, 81613000, 83143000, NULL, NULL, NULL, NULL, NULL, FALSE, 12508000, 14398000, 67007000, 67007000, NULL, 67007000, 85469000, $$Provides funds for the operation and support of activities directly related to the JS OCDAO mission to enable digital modernization efforts across the JS. This includes concept refinement, technology/system development, hardware/ software requirements, training, experimentation and other activities necessary for OCDAO to facilitate the linkages and integration of authoritative data flows between the JS, Combatant Commands (CCMDs), Services, and Office of the Secretary of War (OSW) to achieve decision advantage. In collaboration with each of the JS Directorates, the OCDAO advances data interoperability and strengthens leadership on data governance, analytics, and artificial intelligence to ensure that digital systems can fully support Combined Joint All-Domain Operations. As the JS focal point for data, analytics, and Artificial Intelligence (AI) the JS OCDAO also works closely with the Office of the Secretary of War (OSW) Chief Digital and Artificial Intelligence Officer (CDAO) to communicate and represent the JS and Chairman’s requirements necessary to develop sustained information advantage capabilities to enable senior leader decision- making and action at the speed of the problem, and inform, shape and implement emerging AI policies, including the Responsible Use of AI principles.$$, $$Budget J-Books/FY27/Remaining/RDTE_TJS_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_2035_L197$$, $$Modification Of In-Svc Equipment (OPA-3)$$, $$proc_army_2035_ba3$$, $$peo_c3t$$, 2026, 31452000, 49319000, 52487000, NULL, $${"page": 50, "ba_num": "03", "source": "p1_fy26", "ba_name": "Other support equipment", "line_no": "197", "service": "army", "fy24_qty": null, "fy25_qty": null, "appr_code": "2035", "appr_name": "Other Procurement, Army", "fy26_v178": {"note": "no_parser_pair", "source": "p40_fy26_v178"}, "fy26t_qty": null, "fy26d_cost": 31452000, "fy26r_cost": 0, "ident_code": ""}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 54852000, 43452000, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Army/Other Procurement - BA3 & 4 - Other Support Equipment & Initial Spares.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305249F$$, $$AF JWICS Enterprise$$, $$rdte_af_ba7$$, $$acc$$, 2026, 21097000, 0, 9445000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305249F"}$$::jsonb, $$The AF JWICS Enterprise PE provides funds for the modernization, development, procurement, and sustainment of the Air Forces SCI enterprise. ICAM - Identity, credentialing and Access Management (ICAM) includes the foundational identity elements that manage users, credentials, attributes, and the access risk based upon the sensitivity of the resources being protected. ICAM is foundational to Zero Trust and is not a single process or technology, but is a complex set of systems and services that operate under various policies and organizations. JTIM - Due to a database misalignment, a portion of JTIM funds have temporarily been programmed into this PE. As soon as we are capable of doing so, we intend on realigning these funds back to their original locations in the CAIS (27431F) PE. JTIM funds currently aligned in this PE still go to the intended OAC/MAJCOM (ACC) for execution and there will be no break in expenditures or capability due to this error. JTIM is a combined OUSD(I&S) and Joint Staff J2T effort to produce modern integrated cloud-based capability for the Joint Force targeting enterprise. These new capabilities will streamline the intelligence support to Services and Combatant Commands (CCMDs) into a federated intelligence-derived target production architecture. JTIM capabilities will unify the Defense Intelligence Enterprise (DIE) targeting workforce through the production management of thousands of high-value targets by providing timely and accurate aimpoints in the deployment of lethal and non-lethal effects. These capabilities will enhance the target intelligence data supporting targeteers and decision makers as well as providing multiple weaponeering solutions for each strike action along with improving the identification of critical elements needed for subsequent re-attack options. JTIM funds were incorrectly reprogrammed in FY26-30 and will be reprogrammed back to the CAIS PE (0207431F). IC-ITE - IC-ITE mission is enabling greater integration, information sharing, and safeguarding with the Intelligence Community (IC) by adopting IC standards, data, and technology frameworks, and using systems of common concerns for unmatched decision advantage. "This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 0.00M was expended for civilian pay expenses in this program element, and in CY 0.00M is forecasted for civilian pay expenses in this program element.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0305249F / AF JWICS Enterprise Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 20311000, 21268000, 23992000, NULL, NULL, 268, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 9445000, 13404000, 19324000, 19324000, 0, 19324000, 24484000, $$The AF JWICS Enterprise PE provides funds for the modernization, development, procurement, and sustainment of the Air Forces SCI enterprise. ICAM - Identity, credentialing and Access Management (ICAM) includes the foundational identity elements that manage users, credentials, attributes, and the access risk based upon the sensitivity of the resources being protected. ICAM is foundational to Zero Trust and is not a single process or technology, but is a complex set of systems and services that operate under various policies and organizations. IC-ITE - IC-ITE mission is enabling greater integration, information sharing, and safeguarding with the Intelligence Community (IC) by adopting IC standards, data, and technology frameworks, and using systems of common concerns for unmatched decision advantage. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305251N$$, $$Cyberspace Operations Forces and Force$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 0, 9033000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0305251N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$1202140F$$, $$Service Support to SPACECOM Activities$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 0, 9752000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "1202140F"}$$::jsonb, $$The Space Analysis and Application Development program integrates space based effects into Department's ‘Model of Record' for joint campaign analysis. Current modeling and simulation [M&S] models are inadequate to represent the contribution that U.S space capabilities make to the air, sea, and land fight and do not accurately portray current and future space threats. This line of effort integrates effects of space capabilities into mission and campaign-level M&S tools. Enhanced space M&S will enable the DoD to make informed decisions regarding the direction of U.S. Space Doctrine, Tactics, Techniques, Procedures, and Resource Decisions. The DoD requires the ability to conduct campaign-level analysis to quantify the holistic operational impacts of adversary space actions on military campaigns and U.S. global operations. Navigation Warfare [NAVWAR] is deliberate defensive and offensive action to assure and prevent positioning, navigation, and timing [PNT] information through coordinated employment of space, cyberspace, and electronic warfare [EW] operations. Funds are used to create and maintain NAVWAR knowledge and ensure NAVWAR superiority across the DoD. IAW the most recent Unified Command Plan, USSPACECOM is responsible for [a] [U] Advocating for requirements and capabilities supporting NAVWAR operations and joint resilient PNT for the DoD, and [b] [U] Providing contingency and operations support to CCMDs for NAVWAR and joint resilient PNT planning. USSPACECOM will research, develop, test, assess and evaluate NAVWAR options IOT advocate across Services and the other CCMDs to achieve PNT overmatch. Funds are used to create and maintain NAVWAR knowledge. NAVWAR expertise is developed in part by execution of PNT Operational Field Assessments [POFAs] that assess Red and Blue PNT-related capabilities, limitations, and vulnerabilities. GYPSY POFA's are linked to Commander USSPACECOM's Joint Exercise Program [JEP] and nested within the Chairman's Exercise Program [CEP]and Combatant Commander's [CCMD] Tier 1 exercises [PACIFIC SENTRY AND AUSTERE CHALLENGE are examples] and provide operationally realistic threat-representative, PNT-contested environments for analytical assessment of air, ground, maritime, space & cyberspace mission capability. FORTUNE POFAs are PNT capability and vulnerability assessments associate with a Service exercise or mission event. PRISM POFAs encompass all other Operations, Actions, and Activities [OAAs] and other assessments to include evaluation of rapid innovative NAVWAR capabilities and/or solutions. Assessments inform materiel and non-materiel solutions, service acquisition decisions, capability gaps, intelligence gaps and tactics, techniques and procedures [TTP] development and implementation to mitigate effects on warfighter operations in the anticipated theater NAVWAR threat environments. JNWC assesses department wide PNT posture through the PNT Biennial assessment IAW DoDI 4650.08. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 1202140F / Service Support to SPACECOM Activities Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver Space Analysis and Application Development capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2023 $0 was expended in this program element and in FY2024 $0 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, NULL, NULL, NULL, NULL, NULL, 293, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1507_L003_v25$$, $$Conventional Prompt Strike$$, $$proc_navy_1507_ba1$$, $$peo_subs$$, 2027, 0, 0, 0, NULL, $${"fy27_v25": {"ba": "01", "appr": "WPN", "note": "INSERTed v25 to pair surplus FY27 line item beyond existing placeholders.", "title": "P-1 Line 3", "applied_at": "2026-05-09", "fy27_ooc_K": 0, "source_pdf": "Budget J-Books/FY27/Navy/WPN_Book.pdf", "fy27_base_K": 0, "p1_line_num": 3, "fy27_total_K": 0}, "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, 3953637000, NULL, NULL, NULL, FALSE, 0, 0, 0, 0, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/WPN_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305282F$$, $$Joint Fires Network (JFN)$$, $$rdte_af_ba5$$, $$aflcmc_hn$$, 2026, 132420000, 0, 0, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0305282F"}$$::jsonb, NULL, NULL, 34436000, 35138000, 35842000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 313982000, 313982000, 0, 313982000, 36568000, $$In FY 2027, the Joint Fires Network (JFN) will deliver and test new software capabilities, multi-level security (MLS) capability enhancements and infrastructure deployments. JFN will deliver new command and control software capabilities and establish automated connections between JFN and service command and control systems, ISR systems and fires systems to enable collaborative planning and execution monitoring. The JFN system will integrate Generative AI models in special access facilities to enable decision superiority for fires across the joint force. Additionally, FY 2027 will see the delivery of JFN Operations Centers and nodes in both USINDOPACOM and USEUCOM. The Joint Fires Network (JFN) is a multi-domain resilient fires-informing decision network at theater strategic and operational levels that provides a persistent targeting common operating picture and mission command applications at the SAP level to enable top echelon decision makers to optimize allocation of weapons across Services and partners at speed and scale. The FY 2026 request for Joint Fires Network (JFN) includes $0 thousand of discretionary funding and $311,432 thousand of mandatory (reconciliation) funding, for a total of $311,432 thousand. The OSW-owned, DAF-led JFN Integrated Program Office oversees execution of all JFN funding. JFN PEs consist of: DAF (0305282F) CDAO (0305282D8Z), DISA (0305282K), USN (0605853N), USMC (0305282M), USA (0305282A). This program element may include necessary civilian pay expenses required to manage, execute, and deliver Joint Fires Network system capability. Note: BA justification is automatically applied. Effort is a Software Acquisition Pathway, not a Major Defense Acquisition Pathway (Milestone B not applicable). This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                              Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System           PE 0305282F / Joint Fires Network (JFN) Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305282K$$, $$Joint Fires Network$$, $$rdte_dw_ba5$$, $$dw_disa$$, 2026, 10000000, 0, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0305282K", "page_header": "Defense-Wide"}$$::jsonb, $$Supports the development of a Joint and Combined warfighting network architecture for the Joint Fires Network program that is resilient, interoperable and flexible. This development effort will ensure efficient and secure transport for Joint Fires data across the theater from the strategic to tactical level of operations in a contested disconnected, denied, intermittent and/or with limited bandwidth (DDIL) environment$$, NULL, 35000000, 0, 0, NULL, NULL, 159, $$RDTE_DISA_PB_2026.pdf$$, $$DISA$$, FALSE, 0, 10000000, 35000000, 35000000, NULL, 35000000, 0, $$Supports the development of a Joint and Combined warfighting network architecture for the Joint Fires Network program that is resilient, interoperable and flexible. This development effort will ensure efficient and secure transport for Joint Fires data across the theater from the strategic to tactical level of operations in a contested disconnected, denied, intermittent and/or with limited bandwidth (DDIL) environment. In FY 2027, the Joint Fires Network (JFN) will deliver and test new software capabilities, multi-level security (MLS) capability enhancements, and infrastructure deployments. JFN will deliver new command and control software capabilities and establish automated connections between JFN and service command and control systems, ISR systems and fires systems to enable collaborative planning and execution monitoring. The JFN system will integrate Generative AI models in special access facilities to enable decision superiority for fires across the joint force. Additionally, FY 2027 will see the delivery of JFN Operations Centers and nodes in both USINDOPACOM and USEUCOM. The Joint Fires Network (JFN) is a multi-domain resilient fires-informing decision network at theater strategic and operational levels that provides a persistent targeting common operating picture and mission command applications at the SAP level to enable top echelon decision makers to optimize allocation of weapons across Services and partners at speed and scale. The OSW-owned, DAF-led JFN Integrated Program Office oversees execution of all JFN funding. JFN PEs consist of: DAF (0305282F) CDAO (0305282D8Z), DISA (0305282K), USN (0605853N), USMC (0305282M), USA (0305282A). This program element includes necessary civilian pay expenses required to manage, execute, and deliver Joint Fires Network system capability. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Information Systems Agency                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0305282K / Joint Fires Network System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305282M$$, $$Joint Fires Network (JFN)$$, $$rdte_navy_ba5$$, $$asn_rda$$, 2026, 26420000, 0, 0, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 35, "original_pe": "0305282M", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305304D8Z$$, $$DoW Enterprise Energy Information Management (EEIM)$$, $$rdte_dw_ba5$$, $$dw$$, 2026, 6473000, 8158000, 7152000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "dw", "page_num": 75, "original_pe": "0305304D8Z", "page_header": "Defense-Wide", "fy26_v182_disc_K": 6382, "fy26_v182_supp_K": 3000, "fy26_v182_total_K": 9382, "fy26_v182_note_name": "DoW Enterprise Energy Information Management (EEIM)", "fy26_v182_source_file": "RDTE_OSW_PB_2027.txt", "fy26_v182_source_line": 36673}$$::jsonb, $$The Enterprise Energy Information Management (EEIM) supports the interim National Defense Strategy (NDS) to build a more lethal force through modernization of key capabilities, the NDS defense objective of establishing an unmatched twenty-first century National Security Innovation Base (NSIB) that effectively supports Department operations and sustains security and solvency, and the NDS strategic approach of reforming the Department’s business practices by simultaneously increasing performance and affordability while still minimizing risk. Established in FY 2013 and tasked with supporting the Department’s goals for audit readiness, energy efficiency, Real Property (RP) accountability, and to improve data quality and integration across the full spectrum of sustainment business functions. Department of Defense (DoD) Real Property Information Management (RPIM) is used to maintain accurate and accessible data for all DoD real property assets. The Enterprise Energy Information Management (EEIM) Business Process Re-engineering (BPR) activities, develop and publish data standards. Funding supports accountability requirements, such as, reconciliation of enterprise real property inventory records and development of asset management processes, business rules and associated data standards. Funding also supports fielding an enterprise Real Property Information Management platform coupled with an independent verification and validation capability, providing access to real time data through Web Services Description Language (WSDL) in support of timely, data-driven decision-making. The Real Property Information Portal also hosts a build out of data stores and portal requirements for Energy Resiliency and Conservation Investment Program (ERCIP) management as well as, the Construction Management Portal (CMP). The Clearinghouse was established under USC, Title 10, Section 183a, directing the establishment of a Military Aviation and Installation Assurance Clearinghouse for review of mission obstructions Siting Clearinghouse (…to be referred to as the "Clearinghouse"). The Clearinghouse: (a) coordinates Department of Defense (DoD) review of applications for energy projects or antenna structure projects filed with the Secretary of Transportation pursuant to section 44718 of title 49 and received by the DoD from the Secretary of Transportation; (b) provides procedures to ensure affected local military installations are consulted; (c) accelerates the development of planning tools necessary to determine the acceptability to the Department of Defense of proposals included in an application for an energy project or antenna structure project submitted pursuant to such section; (d) reviews and assesses proposed actions likely scope, duration, and level of risk of any adverse impact of such energy project or antenna structure project on military operations and readiness; and (e) identifies any feasible and affordable actions that could be taken by the Department, the developer of such energy project or antenna structure project, or others to mitigate the adverse impact and to minimize risks to national security while allowing the energy project or antenna structure project to proceed with development. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Office of the Secretary Of Defense                                             Date: June 2025 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:          PE 0305304D8Z / DoD Enterprise Energy Information Management (EEIM) System Development & Demonstration (SDD)$$, NULL, 2587000, 2585000, 2589000, NULL, NULL, 160, $$RDTE_OSD_PB_2026.pdf$$, $$OSD$$, FALSE, 6890000, 9382000, 2573000, 2573000, NULL, 2573000, 2768000, $$The Enterprise Energy Information Management (EEIM) supports the interim National Defense Strategy (NDS) to build a more lethal force through modernization of key capabilities, the NDS defense objective of establishing an unmatched twenty-first century National Security Innovation Base (NSIB) that effectively supports Department operations and sustains security and solvency, and the NDS strategic approach of reforming the Department’s business practices by simultaneously increasing performance and affordability while still minimizing risk. Established in FY 2013 and tasked with supporting the Department’s goals for audit readiness, energy efficiency, Real Property (RP) accountability, and to improve data quality and integration across the full spectrum of sustainment business functions. Department of War (DoW) Real Property Information Management (RPIM) is used to maintain accurate and accessible data for all DoW real property assets. The Enterprise Energy Information Management (EEIM) Business Process Re-engineering (BPR) activities, develop and publish data standards. Funding supports accountability requirements, such as, reconciliation of enterprise real property inventory records and development of asset management processes, business rules and associated data standards. Funding also supports fielding an enterprise Real Property Information Management platform coupled with an independent verification and validation capability, providing access to real time data through Web Services Description Language (WSDL) in support of timely, data-driven decision-making. The Real Property Information Portal also hosts a build out of data stores and portal requirements for Energy Resiliency and Conservation Investment Program (ERCIP) management as well as, the Construction Management Portal (CMP). The FY 2026 spend plan amount for DoW Enterprise Energy Information Management (EEIM) includes $6,382 thousands of discretionary and $3,000 thousand of mandatory (reconciliation) for a total of $9,382 thousands. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Office of the Secretary Of Defense                                            Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 5:         PE 0305304D8Z / DoW Enterprise Energy Information Management (EEIM) System Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/DW/RDTE_OSW_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305327N$$, $$Insider Threat$$, $$rdte_navy_ba6$$, $$asn_rda$$, 2026, 2653000, 2236000, 2920000, NULL, $${"act": "06", "ba_raw": "6.6", "source": "r1_fy26", "service": "navy", "page_num": 36, "original_pe": "0305327N", "page_header": "Department of the Navy"}$$::jsonb, $$Executive Order 13587 and the National Insider Threat Policy mandate all United States Government departments and agencies to implement insider threat programs that monitor user activity on all classified networks and provide an insider threat analytical and response capability. The Counter Insider Threat Capability (CITC) is the Department of the Navy's implementation of this requirement. CITC's mission is to prevent, deter, detect, and respond to the threat from witting and unwitting insiders. The Platform for Risk Evaluation and Engagement to Neutralize Threat (PREVENT) is the materiel solution required to support the CITC mission, and consists of two parts: (1) User Activity Monitoring (UAM), which monitors user activity on classified Navy networks, and (2) an Integrated Tool Suite (ITS), which provides the Information Technology platform for the analytic and response capabilities. The PREVENT system provides the technology required by the Navy Insider Threat Analytic Hub to comply with the National mandates and to protect Navy data, equipment, and personnel from insider threats. RDT&E,N funding is required to develop future, long-term, capability; integrate; and perform testing and evaluation of this capability.$$, NULL, 2279000, 2316000, 2359000, NULL, NULL, 204, $$RDTEN_BA6_Book.pdf$$, NULL, FALSE, 2920000, 2653000, 2214000, 2214000, NULL, 2214000, 2405000, $$Executive Order 13587 and the National Insider Threat Policy mandate all United States Government departments and agencies to implement insider threat programs that monitor user activity on all classified networks and provide an insider threat analytical and response capability. The Counter Insider Threat Capability (CITC) is the Department of the Navy's implementation of this requirement. CITC's mission is to prevent, deter, detect, and respond to the threat from witting and unwitting insiders. The Platform for Risk Evaluation and Engagement to Neutralize Threat (PREVENT) is the materiel solution required to support the CITC mission and consists of two parts: (1) User Activity Monitoring (UAM), which monitors user activity on classified Navy networks, and (2) an Integrated Tool Suite (ITS), which provides the Information Technology platform for the analytic and response capabilities. The PREVENT system provides the technology required by the Navy Insider Threat Analytic Hub to comply with the National mandates and to protect Navy data, equipment, and personnel from insider threats. RDT&E,N funding is required to develop future, long-term, capability; integrate; and perform testing and evaluation of this capability.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA6_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305421N$$, $$RQ-4 Modernization$$, $$rdte_navy_ba7$$, $$peo_uw$$, 2026, 361943000, 217978000, 444042000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0305421N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 329063000, 138367000, 132946000, NULL, NULL, NULL, NULL, NULL, FALSE, 444042000, 361943000, 344890000, 344890000, NULL, 344890000, 135383000, $$MISSION: Project Unit 2939: The MQ-4C Triton Unmanned Air System (UAS) is a high altitude-long endurance UAS designed to provide Fleet and combatant commanders with persistent maritime Intelligence, Surveillance and Reconnaissance & Targeting (ISR&T) of nearly all the world's high-density sea-lanes, littorals, and areas of national interest. The Triton air vehicle, mission control system, specialized sensors, and communications suite play a significant role in achieving the Navy's strategic vision for the 21st century. Triton provides persistent ISR&T and unparalleled situational awareness of the maritime battle space to the supported combatant commander and fleet commander. Triton provides the Warfighter with unprecedented levels of battlespace awareness to synchronize actions necessary to maintain maritime full spectrum superiority. Teamed with its manned-capability counterpart, the P-8A Poseidon, Triton is a key component of the Navy's maritime domain awareness family of systems. MQ-4C Triton leverages Maritime Patrol and Reconnaissance Force manpower, training and maintenance efficiencies. Triton Early Operational Capability (EOC) was deployed in 2020 to provide early fleet integration risk reduction. It successfully prepared the fleet for fielding Initial Operational Capability (IOC) and concluded in 2022. In July 2023, Triton fielded the Increment 1 Multi-Intelligence (Multi-INT) IOC on schedule, successfully meeting the 2011 National Defense Authorization Act (NDAA) requirements. This enabled the Navy's Maritime Intelligence, Surveillance, Reconnaissance and Targeting (MISR-T) transition plan and initiated EP-3 Aries sundown. The Increment 1 Multi-INT capability provides Signals Intelligence (SIGINT), Counter Electronic Attack (CEA) upgrades, and data dissemination across multiple classification domains. Triton initiated Increment 2 development in FY 2023. Increment 2 will provide advanced radar modes inclusive of Ground Moving Target Indicator (GMTI), enhanced Electro-Optic/Infrared (EO/IR) detection in support of Geographic Intelligence (GEOINT) for increased maritime domain awareness, High Gain Aperture (HGA) for Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Navy                                                                                 Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 1319: Research, Development, Test & Evaluation, Navy / BA 7: Operational       PE 0305421N / RQ-4 Modernization Systems Development improved SIGINT, communications, navigation, and networks resiliency in denied environments, Multi-UA Command and Control (C2) for increase on station time, and Sense and Avoid (SAA) traffic and weather capability for increased mission availability and airspace integration. Increment 2 development is also addressing required Diminishing Manufacturing Source (DMS) and cyber security updates. Triton continues to provide near worldwide coverage through a network of orbits across the globe, with sufficient air vehicles to remain airborne for 24 hours a day, 7 days a week, out to ranges of 2,000 nautical miles. Onboard sensors provide detection, classification, tracking and identification of maritime targets and include maritime radar, electro-optical/infra-red and SIGINT/systems. Additionally, the Triton communications relay capability links dispersed forces in the theater of operations and allows Triton to serve as a node in the Navy's networked strategy. Tactical-level data analysis occurs in real-time at shore-based mission control sites connected to the air vehicle via satellite communications. Further intelligence exploitation can be conducted at Fleet shore-based sites or aboard aircraft carriers and other ships. JUSTIFICATION FOR BUDGET ACTIVITY: The FY 2027 funding is provided for the incorporation of incremental capability upgrades improving mission effectiveness, execution, and survivability through incorporation of advanced radar modes inclusive of Ground Moving Target Indicator (GMTI), enhanced Electro-Optic/Infrared (EO/IR) detection in support of Geographic Intelligence (GEOINT) for increased maritime domain awareness, High Gain Aperture (HGA) for improved SIGINT, communications, navigation, and networks resiliency in denied environments, Multi-UA Command and Control (C2) for increase on station time, and Sense and Avoid (SAA) traffic and weather capability for increased mission availability and airspace integration. The FY27 budget also addresses required Diminishing Manufacturing Source (DMS) and cyber security updates. This program is funded under OPERATIONAL SYSTEMS DEVELOPMENT because it includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate funding in the current or subsequent fiscal year. Project Unit 3329: The details of program element 0305421N Project 3329 are classified and are submitted to Congress in the classified budget justification books.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305600F$$, $$International Intelligence Technology and Architectures$$, $$rdte_af_ba7$$, $$aflcmc_az$$, 2026, 18946000, 15322000, 17784000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305600F"}$$::jsonb, $$International Intelligence Technology and Architectures (IITA) oversees, manages, and provides the United States (US) component of the multi-national Battlefield Information Collection and Exploitation Systems (BICES) with a collaborative environment and intelligence sharing enterprise required for processing and disseminating critical intelligence information between and among US, North Atlantic Treaty Organization (NATO), allied and coalition forces. The US BICES program develops and tests specialized equipment to deliver a more mature, robust and dynamic suite of capabilities for intelligence information sharing across the US BICES, US BICES Extended (US BICES-X), and the Trusted Network Environment (TNE). US BICES-X is a multi-level, secure system that uses releasable elements of the Defense Intelligence Information Enterprise (DI2E) framework, and functions to support the full spectrum of intelligence operations and dissemination across Department of Defense (DoD), Combat Support Agencies (CSA), and multiple Combatant Commands (CCMD) for the Office of the Under Secretary of Defense, Intelligence and Security (OUSD(I&S)). The TNE is an Enterprise Cross Domain Solution (ECDS) that connects 65+ network, 85+ partner nations and 69+ Communities of Interest (COI) within four federated operational TNEs. US BICES/BICES-X has been designated the enduring intelligence and information sharing component to the Mission Partner Environment (MPE). Research and Development funding will: - Provide increased intelligence information sharing capabilities to US and Coalition forces utilizing the US BICES and multinational BICES networks through CENTAUR. CENTAUR provides geospatial intelligence from the Distributed Common Ground System (DGCS) Enterprise to enable Coalition partner operations on multinational BICES. -Continue developing the TNE as an ECDS that connects 65+ network, 85+ partner nations and 69+ COI within four federated operational TNE service centers and supporting all CCMDs, CSAs, and Services. - Provide increased intelligence information sharing capabilities in support of US and coalition forces utilizing the US BICES and NATO virtual networks within all theaters of operations and provide increased database information sharing. - Continue to develop the US BICES connections with bi-lateral and multi-lateral federated TNEs that make up the US BICES-X Enterprise Network in support of CCMD requirements for conventional and coalition operations. To include multi-level security intelligence bi-laterals and multi-laterals to meet Combatant Commander Integrated Priority Lists. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 0.0M was expended for civilian pay expenses in this program element and in CY 0.0M is forecasted for civilian pay expenses in this program element. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0305600F / International Intelligence Technology and Architectures Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 0, 0, 0, NULL, NULL, 269, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 17784000, 18946000, 62000000, 62000000, 0, 62000000, 0, $$International Intelligence Technology and Architectures (IITA) investment in RDT&E ceases support in development to oversee, manage, and provide the United States (US) component of the multi-national Battlefield Information Collection and Exploitation Systems (BICES) with a collaborative environment and intelligence sharing enterprise required for processing and disseminating critical intelligence information between and among US, North Atlantic Treaty Organization (NATO), allied and coalition forces. Resources in FY27 support classified activities and are provided on a higher network. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_0350_L007$$, $$Misc Equipment - Navy Reserve$$, $$proc_dw_0350_ba1$$, $$dw$$, 2026, 0, 57000000, 48450000, NULL, $${"page": 173, "ba_num": "01", "source": "p1_fy26", "ba_name": "Reserve equipment", "line_no": "7", "service": "dw", "fy24_qty": null, "fy25_qty": null, "appr_code": "0350", "appr_name": "0350", "fy26t_qty": null, "fy27_v170": {"p1_ba": "01", "disc_K": 57000, "mand_K": 0, "p1_line": "2", "applied_at": "2026-05-09 05:40:17.087309+00", "source_pdf": "FY2027_p1.txt", "p1_appropriation": "0350 National Guard and Reserve Equipment"}, "fy26d_cost": 0, "fy26r_cost": 0, "ident_code": "A"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_p1.txt$$, NULL, FALSE, NULL, 46000000, 57000000, 57000000, 0, 57000000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_p1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305601F$$, $$Mission Partner Environments$$, $$rdte_af_ba4$$, $$aflcmc$$, 2026, 14956000, 17078000, 18438000, NULL, $${"ba_raw": "6.4", "source": "af_r1_fy26", "original_pe": "0305601F"}$$::jsonb, $$Mission Partner Environment (MPE) enables secure sharing of operational information for collaboration between and among the United States (US) and mission partners to include federal, state, local, tribal agencies, allies, coalition members, host nations, other nations, US and international Non-Governmental Organizations, multinational treaty organizations, and private sector organizations. The MPE program enables the US Department of Defense (DoD) to execute its assigned missions with mission partners across all ranges and phases of military operations to enable combined command and control (C2) of coalition forces while promoting effective exchange of C2 and intelligence information to enable effective use of the US and partner nation military power. MPE improves survivability and lethality of US Forces by incorporating coalition partners and allies ability to share information in a secret and below releasable environment. DoD Directive 5101.22E, effective August 5, 2020, designated the Secretary of the Air Force as Executive Agent (EA) for the DoD MPE. The FY 2026 funding continues the development, integration, and testing of an enterprise architectural engineering solution in alignment with the federated mission networking framework to combine multiple coalition information sharing capabilities, to include modifications or modernizations necessary to absorb or incorporate legacy capabilities and capacities. MPE capabilities share information in a secret and below releasable environment. SABRE enterprise provides Combatant Commands, Services, and Agencies (CC/S/A) with a federated and more secure data-centric releasable environment for continuous global collaboration and coordination; not only with each other, but with DoD components, select allies, coalition MPs, and interagency partners to include local, state, federal, and nongovernmental organizations (NGO) This program element may include necessary civilian pay expenses required to manage, execute, and deliver capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In PY 0.00M was expended for civilian pay expenses in this program element, and in CY 0.00M is forecasted for civilian pay expenses in this program element. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 4: Advanced PE 0305601F / Mission Partner Environments Component Development & Prototypes (ACD&P)$$, NULL, 0, 0, 0, NULL, NULL, 77, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 17765000, 36755000, 0, 0, 0, 0, 0, $$Mission Partner Environment (MPE) enables secure sharing of operational information for collaboration between and among the United States (US) and mission partners to include federal, state, local, tribal agencies, allies, coalition members, host nations, other nations, US and international Non-Governmental Organizations, multinational treaty organizations, and private sector organizations. The MPE program enables the US Department of War (DoW) to execute its assigned missions with mission partners across all ranges and phases of military operations to enable combined command and control (C2) of coalition forces while promoting effective exchange of C2 and intelligence information to enable effective use of the US and partner nation military power. MPE improves survivability and lethality of US Forces by incorporating coalition partners and allies ability to share information in a secret and below releasable environment. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305601K$$, $$Mission Partner Environment$$, $$rdte_dw_ba7$$, $$dw$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 16403000, 16858000, 17164000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 15464000, 15464000, NULL, 15464000, 17507000, $$Mission Partner Environment (MPE) enables secure sharing of operational information for collaboration between and among the United States (US) and mission partners to include federal, State, local, tribal agencies, allies, coalition members, host nations, other nations, US and international Non-Governmental Organizations, multinational treaty organizations, and private sector organizations. RDT&E required to continue development, integration, and testing of capabilities to support US and mission partners.$$, $$Budget J-Books/FY27/Remaining/RDTE_DISA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305836F$$, $$C2IMERA$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 13867000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305836F"}$$::jsonb, $$This budget line funds the development of the Command and Control, Incident Management, Emergency Response Application (C2IMERA), a C2 system that enables commanders and staffs to generate and present ready forces to combatant commanders at the tactical, operational, and strategic levels. C2IMERA funds provide enhanced installation C2 that improves decision speed, quality, and lethality by incorporating direct user inputs, connecting people to information, automating daily operations, and integrating data from myriad systems into a real-time, interactive Common Operating Picture (COP) with visualized dashboards. C2IMERA enables mission-ready units of action to support Agile Combat Employment by effectively linking combat wings and base commands, enabling bases to successfully operate during competition, crisis, and conflict. C2IMERA synchronizes information across large scale exercises and operations through the implementation of a COP and tool that streamlines daily operations and reporting. C2IMERA aggregates the theater-wide critical information into strategic and operational pictures that enable Higher Headquarters (HHQ) to make real-time force decisions across the competition continuum. C2IMERA accelerates decision makers' access to C2 information by providing automated updates through the COP/email and alleviating the need for unnecessary briefings, meetings, and radio communication(s). The C2IMERA operational concept has three capability areas: • C2 collaboration across the Wing, enabling the base to operate and fight • Wing Situational Awareness, enabling the wing to integrate across operations • Wing Collaboration/reporting to HHQ (i.e., Air Operations Center (AOC), the Air Force Forces (AFFOR), Command Center etc.), enabling high-quality operational and strategic decision making Requirements also include supporting base operations, mission management and monitoring, HHQ Information Exchange Requirements (IERs), Emergency Action Messaging, Situation Report (SITREP) automation, and other key enablers supporting the operational concept. Efforts within this PE align with USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (0207410F), All Domain Common Platform (0303248F), and ABMS (0604003F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305836F / C2IMERA Operational Systems Development FY 2026 funds will continue to support Agile development and operations enabling the delivery of new advanced features to C2IMERA following the FY 2025 completion of the codebase re-architecture from a monolithic codebase to a microservices based, multi-tenant application. FY 2026 funds will integrate C2IMERA across the DAF Battle Network, expand data access through system interoperability and new systems integrations, automate data inputs and workflows, and improve coalition warfighting capabilities through expanded information availability. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funding would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, or 0605898F. Due to being a new Program Element in FY 2026, civilian pay expenses in this program element will begin in FY 2026. For reference, this program is transferring from 0305015F where in FY 2024 0.281 million was expended for civilian pay expenses, and in FY 2025 0.226 million is forecasted for civilian pay expenses. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 11620000, 11840000, 12065000, NULL, NULL, 270, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 0, 13690000, 11393000, 11393000, 0, 11393000, 12309000, $$This budget line funds the development of the Command and Control, Incident Management, Emergency Response Application (C2IMERA), a C2 system that enables commanders and staff to generate and present ready forces to combatant commanders at tactical, operational, and strategic levels. C2IMERA funds provide enhanced installation C2 that improves decision speed, quality, and lethality by incorporating direct user inputs, connecting people to information, automating daily operations, and integrating data from myriad systems into real-time, interactive Common Operating Picture (COP) with visualized dashboards. C2IMERA enables mission-ready units of action to support Agile Combat Employment by effectively linking combat wings and base commands, enabling bases to successfully operate during competition, crisis, and conflict. C2IMERA synchronizes information across large scale exercises and operations through the implementation of a COP and tool that streamlines daily operations and reporting. C2IMERA aggregates the theater-wide critical information into strategic and operational pictures that enable Higher Headquarters (HHQ) to make real-time force decisions across the competition continuum. C2IMERA accelerates decision makers' access to C2 information by providing automated updates through the COP/email and alleviating the need for unnecessary briefings, meetings, and radio communication(s). The C2IMERA operational concept has three capability areas: • C2 collaboration across the Wing, enabling the base to operate and fight • Wing Situational Awareness, enabling the wing to integrate across operations • Wing Collaboration/reporting to HHQ (i.e., Air Operations Center (AOC), the Air Force Forces (AFFOR), Command Center etc.), enabling high-quality operational and strategic decision making Requirements also include supporting base operations, mission management and monitoring, HHQ Information Exchange Requirements (IERs), Emergency Action Messaging, Situation Report (SITREP) automation, and other key enablers supporting the operational concept. Efforts within this program align with and depend upon USAF investment in Mission Planning Systems (PE 0208006F), Air Operations Center (PE 0207410F), All Domain Common Platform (0303248F), Advanced Battle Management System (ABMS) (0604003F) and Flight Ops (PE 0207461F) to deliver the Theater Air Planning System of Systems (TAP-SoS) architecture for the DAF BATTLE NETWORK. This program's efforts directly provide the development, infrastructure, and support necessary for each of these programs and TAP-SoS interdependencies, which provides the capabilities necessary for deliberate planning, dynamic mission replanning, friendly order of battle management, and mission tasking and execution. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0305836F / C2IMERA Operational Systems Development FY 2027 funds will continue to support Agile development and operations enabling the delivery of new advanced features to C2IMERA following the FY 2026 monolithic- to-microservice cloud re-architecture. FY 2027 funds will integrate C2IMERA across the DAF Battle Network, expand data access through system interoperability and new systems integrations, automate data inputs and workflows, and improve coalition warfighting capabilities through expanded information availability. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898”. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1109_L046$$, $$Cyberspace Activities$$, $$proc_mc_1109_ba4$$, $$mc$$, 2026, 14541000, 27583000, 19245000, NULL, $${"ba": "ba4", "ingest": "v17", "source": "p1_fy27", "line_no": "36", "appr_code": "1109", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "title_raw": "Unmanned Expeditionary Systems", "fy27_total_K": 1001}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 1001000, NULL, 0, 1001000, NULL, NULL, $$Budget J-Books/FY27/Navy/PMC_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1109_L048$$, $$Unmanned Expeditionary Systems Programs$$, $$proc_mc_1109_ba4$$, $$mc$$, 2026, 0, 11164000, 16305000, NULL, $${"ba": "ba4", "ingest": "v17", "source": "p1_fy27", "line_no": "37", "appr_code": "1109", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "title_raw": "Line Ident DON UAS Video 5", "fy27_total_K": 0}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 0, NULL, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/PMC_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305881F$$, $$Rapid Cyber Acquisition$$, $$rdte_af_ba7$$, $$afrl_ri$$, 2026, 0, 8482000, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305881F"}$$::jsonb, $$The Rapid Cyber Acquisition (RCA) initiative is a materiel (hardware, software, and tool development) and non-materiel (technical support) effort to enable delivery of new cyber capabilities at the pace of warfighting relevance. Combatant and Joint Force Commanders require up-to-date, tailored cyber capabilities to win in the highly- dynamic cyberspace domain. The RCA initiative expedites cyber development and modifications of USAF cyber capabilities through integration with and technical support to other Service and Government Agency activities to leverage select Air Force-developed technologies and/or operational capabilities. RCA provides for rapid development of materiel and non-materiel cyber solutions necessary to conduct rapid prototyping, integration, and transition activities of cyber capabilities. Activities include but are not limited to development of software/hardware systems, integration and transition of lab-developed cyber capabilities, developmental testing, operational evaluation, manpower, studies, analysis, pilots, demonstrations, and risk reduction efforts for emerging technologies. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000M was expended for civilian pay expenses in this program element, and in FY 2025 $0.000M is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0305881F / Rapid Cyber Acquisition Operational Systems Development$$, NULL, NULL, NULL, NULL, NULL, NULL, 271, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305903F$$, $$Mobile Command Center Systems (MC2S)$$, $$rdte_af_ba7$$, $$dw_dsca$$, 2026, 3988000, 0, 0, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305903F"}$$::jsonb, $$MC2S is a mobile platform that provides Command, Control, Communications, Computers and Intelligence (C4I) services to USNORTHCOM in support of its Defense Support to Civil Authorities (DSCA) mission. Additional details can be provided at a higher classification. Mobile Command Control Systems (MC2S) - funding enables the development of solutions for the emerging requirements necessary for continuous operations, maintenance and sustainment. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 2012000, 2011000, 2012000, NULL, NULL, 272, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 0, 3961000, 2013000, 2013000, 0, 2013000, 2012000, $$MC2S is a mobile platform that provides Command, Control, Communications, Computers and Intelligence (C4I) services to USNORTHCOM in support of its Defense Support to Civil Authorities (DSCA) mission. Additional details can be provided at a higher classification. Mobile Command Control Systems (MC2S) - funding enables the development of solutions for the emerging requirements necessary for continuous operations, maintenance and sustainment. Program RDT&E funding may be utilized to implement innovation insertion, capability insertion, software increments, spiral upgrades, modular component swaps, and other insertions consistent with Modular Open System Architecture. Program RDT&E funding may be utilized to design, develop, integrate, and test weapon system and/or component level open architectures. Program RDT&E funding may be utilized to fund the concept refinement, design, development, integration, and testing of interdependent technologies and common architectures that underpin weapon system and portfolio-wide mission outcomes. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. . This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305903F / Mobile Command Center Systems (MC2S) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0901159D8Z$$, $$Golden Dome for America (OSD)$$, $$rdte_gd_ba3$$, $$dw_osd$$, 2026, 0, 0, 0, NULL, $${"ba": "03", "line": 15, "note": "OSD generic Golden Dome line; BA-01 line also exists (O&M class), captured here is RDT&E BA-03 only", "page": 82, "unit": "K", "source": "r1_fy27", "fy26_pl": 2243200, "fy27_disc": 30971, "fy27_mand": 2792517, "fy26_total": 2243200, "fy27_total": 2823488, "appropriation": "3007D"}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 15, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$, $$GDAF$$, FALSE, 0, 2243200000, 30971000, 30971000, 0, 30971000, NULL, NULL, $$Budget J-Books/FY27/Remaining/FY2027_r1.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305913F$$, $$Persistent Surveillance$$, $$rdte_af_ba4$$, $$aflcmc$$, 2027, 0, 0, 0, NULL, $${}$$::jsonb, NULL, NULL, 29308000, 24969000, 28959000, NULL, NULL, NULL, NULL, NULL, FALSE, 0, 0, 29325000, 29325000, 0, 29325000, 29546000, $$Nuclear Detonation Detection System (NUDET Detection System (SPACE)) investment is for the development, integration, testing and fielding of disparate technologies to provide capabilities for Nuclear and Weapons of Mass Destruction (WMD) detection and enable real-time sensing, processing, and alerting capability. This effort will establish and incorporate a digital infrastructure to provide cloud-based data and platform services that will be able to ingest Artificial Intelligence/Machine Learning (ML) and automation tools to support nuclear detection reporting in support of defense of the homeland. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This effort is in Budget Activity 4, Advanced Component Development and Prototypes (ACD&P), because efforts are necessary to evaluate integrated technologies, representative modes or prototype systems in a high fidelity and realistic operating environment.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0305984F$$, $$Personnel Recovery Command & Ctrl (PRC2)$$, $$rdte_af_ba7$$, $$aflcmc$$, 2026, 2891000, 3162000, 2831000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0305984F"}$$::jsonb, $$This budget line funds the Personnel Recovery Command and Control (PRC2) program, which develops and delivers tools and services for planning, collaborating and managing search and rescue efforts, as well as disseminating related information to all personnel recovery (PR) mission coordinators across the PR network. PRC2 provides an adaptive and networked system, delivering timely situational awareness information supporting personnel accountability and recovery mission management worldwide. PRC2 delivers a globally accessible, collaborative, interoperable and integrated set of capabilities to prevent, prepare for and respond to joint/coalition military personnel recovery activities, and civilian rescue missions. The Joint Personnel Recovery (JPR) Initial Capability Document (ICD) (2012) articulates capabilities needed for PRC2. Personnel Recover Mission Manager (PRMM) 3.1 continues to develop using Agile Development, Security and Operations (DevSecOps). Annex A to the PRMM 3.1 is the requirement document for improvements until Full Operational Capability (FOC) criteria is achieved. The system collects, stores and delivers personnel/identity biometric data, emergency locator beacon registrations, Isolated Personnel (IP) reports, evasion plans of action, incident reports and other information management capabilities. The information is used for predictive, preventive and personnel vulnerability analysis and assessment in support of PR across the Department of Defense and other national and international entities. Activities also include studies and analysis to support both current program planning and execution, as well as future program planning. In FY 2026, PRMM 3.1 modifications will continue to use an Agile DevSecOps strategy to develop and test capability in two-week increments (sprints) after fielding Configuration Control Board (CCB) approval from Major Command (MAJCOM). The modifications will improve/validate IP events/alerts and enable case files for Defense Prisoner of War/Missing Personnel Office (DPMO) and Joint Personnel Recovery Agency (JPRA). PRMM 3.1 modifications will reflect the requirements and priorities identified by Air Combat Command (ACC) as the personnel recovery environment evolves to meet the needs of the warfighter and personnel recovery efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2025, 0.000 million was expended for civilian pay expenses in this program element, and in FY 2026 0.000 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0305984F / Personnel Recovery Command & Ctrl (PRC2) Operational Systems Development$$, NULL, 1846000, 1881000, 1919000, NULL, NULL, 273, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 3272000, 2851000, 1783000, 1783000, 0, 1783000, 1958000, $$This budget line funds the Personnel Recovery Command and Control (PRC2) program, which develops and delivers tools and services for planning, collaborating and managing search and rescue efforts, as well as disseminating related information to all personnel recovery (PR) mission coordinators across the PR network. PRC2 provides an adaptive and networked system, delivering timely situational awareness information supporting personnel accountability and recovery mission management worldwide. PRC2 delivers a globally accessible, collaborative, interoperable and integrated set of capabilities to prevent, prepare for and respond to joint/coalition military personnel recovery activities, and civilian rescue missions. The Joint Personnel Recovery (JPR) Initial Capability Document (ICD) (2012) articulates capabilities needed for PRC2. Personnel Recover Mission Manager (PRMM) 3.1 continues to develop using Agile Development, Security and Operations (DevSecOps). The system collects, stores and delivers personnel/identity biometric data, emergency locator beacon registrations, Isolated Personnel (IP) reports, evasion plans of action, incident reports and other information management capabilities. The information is used for predictive, preventive and personnel vulnerability analysis and assessment in support of PR across the Department of War and other national and international entities. Activities also include studies and analysis to support both current program planning and execution, as well as future program planning. In FY 2027, PRMM 3.1 modifications will continue to use an Agile DevSecOps strategy to develop and test capability in two-week increments (sprints) after fielding Configuration Control Board (CCB) approval from Major Command (MAJCOM). The modifications will improve/validate IP events/alerts and enable case files for Defense Prisoner of War/Missing Personnel Office (DPMO) and Joint Personnel Recovery Agency (JPRA). PRMM 3.1 modifications will reflect the requirements and priorities identified by Air Combat Command (ACC) as the personnel recovery environment evolves to meet the needs of the warfighter and personnel recovery efforts. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2026, 0.000 million was expended for civilian pay expenses in this program element, and in FY 2027 0.000 million is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                      Date: April 2026 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0305984F / Personnel Recovery Command & Ctrl (PRC2) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_MIBF_L001$$, $$Maritime Industrial Base Fund$$, $$proc_navy_mibf_ba1$$, $$navy$$, 2027, 0, 0, 0, NULL, $${"fy26_v180": {"note": "topline_only_PL_119_21_supp_appropriation_created_v180", "disc_K": 0, "source": "p1_master_fy26_v180", "supp_K": 4537000, "source_pdf": "FY2027_p1.txt"}}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 4537000000, 0, 0, 0, 0, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0303028A$$, $$Security and Intelligence Activities$$, $$rdte_army_ba7$$, $$hqda$$, 2026, 0, 16290000, 0, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "army", "page_num": 23, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0303028A", "page_header": "Department of the Army"}$$::jsonb, $$Funding supports the U.S. Army Intelligence and Security Command's (INSCOM) RDTE program, which provides the Army with low-density, high-demand, extremely advanced offensive cyberspace technologies designed to degrade, deny, disrupt, or destroy adversary Command, Control, Communications, Computers and Intelligence (C4I) and shape the operational warfighting environment in order to create conditions favorable to the application of other elements of national power. INSCOM conducts RDTE of offensive Cyberspace technologies in direct support of the full range of missions called for in the National Defense Strategy, Comprehensive National Cyber-Security Initiative, National Security Strategy, National Defense Guidance, National Security Presidential Directive (NSPD)-38, NSPD-54 and Homeland Security Presidential Directive (HSPD)-23. HQDA G-2 and the Intelligence and Security Command (INSCOM) Security Operations Center (ISOC) are charged with integrating, informing, and leveraging security and counterintelligence authorities in support of the Department of the Army Insider Threat Program mission to continuously deter, detect, and mitigate insider threats to Army information, networks, facilities, and personnel.$$, NULL, NULL, NULL, NULL, NULL, NULL, 229, $$RDTE - Vol 4 - Budget Activity 7.pdf$$, NULL, FALSE, NULL, 0, NULL, NULL, NULL, NULL, NULL, NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604101A$$, $$Small Unmanned Aerial Vehicle (SUAV) (6.4)$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 0, 4956000, 1800000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604101A", "page_header": "Department of the Army"}$$::jsonb, $$The Family of Small Uncrewed Aircraft systems are critical to the Army's Transformation in Contact. These systems ensure Army formations have the best existing and emerging technology at Battalion and below to allow ground-based forces to project power from land into other domains to defeat highly capable enemies, secure terrain, and consolidate gains. The Rucksack Portable Uncrewed Aircraft System (RPUAS) Family of Small Uncrewed Aircraft System (FoSUAS) requirements are transitioning to the Joint Small Uncrewed Aircraft System sUAS Capability Development Document (J-sUAS CDD) to solve current and emergent operational gaps by incorporating Modular Open Systems Approach (MOSA) including swappable payloads, advanced autonomy and software scalability. These systems provide battalion and below ground maneuver elements with critical situational awareness and enhanced force protection. The systems provide an organic and responsive reconnaissance and targeting capability with real-time Full Motion Video and sensor data. Each system will include aircraft, ground support equipment, ground control station and Uncrewed Vehicle Control (UVC) software. The Short Range Reconnaissance (SRR) provides organic maneuver platoons an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition. The system has an aircraft weight of less than 5 lbs, a range of 3-5 km, and an endurance of 30 minutes. The system includes modular payloads, obstacle avoidance, target recognition, automated following, and networked capability. Long Range Reconnaissance (LRR) System will provide organic maneuver battalions an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition (RSTA) efforts. The system will have an aircraft weight of less than 55 lbs., a range of 40-60 km and endurance of 5-10 hours. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting/designating, and kinetic architectures in a contested environment. The Joint Tactical Autonomous Aerial Resupply System (JTAARS) is an autonomous aerial cargo delivery system, organic to the maneuver commander, that provides options for rapid and agile sustainment of highly mobile tactical combat forces, operating in a widely dispersed manner in the tactical support and close areas. JTAARS enables maneuver by reducing the tactical force's dependence on ground lines of communication and sustainment, reducing threats to manned convoys and manned aerial systems, lightening Soldier load, and shrinking the supply chain. JTAARS provides a lift capability of 125 lbs. over 13 km one way (26 km round trip). Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                              Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced        PE 0604101A / Small Unmanned Aerial Vehicle (SUAV) (6.4) Component Development & Prototypes (ACD&P) FY 2026 funding to investigate GPS Denied Navigation systems, resilient APNT, advanced low probability of detect/intercept data-links for LRR, as well as, interfaces for common mission payloads (communications relay, electronic warfare payloads, and lethal munition payloads). Minimal funding for SRR to investigate SRR payload updates for SRR Next Generation.$$, NULL, NULL, NULL, NULL, NULL, NULL, 82, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 1734000, 0, NULL, NULL, NULL, NULL, NULL, $$The Family of Small Uncrewed Aircraft systems are critical to the Army's Transformation in Contact. The Joint Small Uncrewed Aircraft System sUAS Capability Development Document (J-sUAS CDD) solves current and emergent operational gaps by incorporating Modular Open Systems Approach (MOSA) including swappable payloads, advanced autonomy and software scalability. These systems provide battalion and below ground maneuver elements with critical situational awareness and enhanced force protection as well as responsive reconnaissance and targeting capability with real-time Full Motion Video and sensor data. Each system will include aircraft, ground support equipment, ground control station and Uncrewed Vehicle Control (UVC) software. The Short Range Reconnaissance (SRR) provides organic maneuver platoons an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition. The system has an aircraft weight of less than 5 lbs, a range of 3-5 km, and an endurance of 30 minutes. The system includes modular payloads, obstacle avoidance, target recognition, automated following, and networked capability. Long Range Reconnaissance (LRR) System will provide organic maneuver battalions an uncrewed air vehicle designed to support Reconnaissance, Surveillance, and Target Acquisition (RSTA) efforts. The system will have an aircraft weight of less than 55 lbs., a range of 40-60 km and endurance of 5-10 hours. System will include Assured Positioning, Navigation and Timing (APNT), Electro-Optical/Infra-Red (EO/IR), laser targeting/designating, and kinetic architectures in a contested environment. The Joint Tactical Autonomous Aerial Resupply System (JTAARS) is an autonomous aerial cargo delivery system, organic to the maneuver commander, that provides options for rapid and agile sustainment of highly mobile tactical combat forces, operating in a widely dispersed manner in the tactical support and close areas. JTAARS enables maneuver by reducing the tactical force's dependence on ground lines of communication and sustainment, reducing threats to manned convoys and manned aerial systems, lightening Soldier load, and shrinking the supply chain. JTAARS provides a lift capability of 125 lbs. over 13 km one way (26 km round trip). Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                    Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced     PE 0604101A / Small Unmanned Aerial Vehicle (SUAV) (6.4) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604103A$$, $$Electronic Warfare Planning and Management Tool (EWPMT)$$, $$rdte_army_ba4$$, $$asa_alt$$, 2026, 0, 2260000, 2004000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604103A", "page_header": "Department of the Army"}$$::jsonb, $$Adversaries are aggressively developing and fielding counter- Positioning, Navigation, and Timing (PNT) technologies that significantly reduce the Army's ability to access the electromagnetic spectrum (EMS) to conduct military operations. The Army is actively pursuing Navigation Warfare (NAVWAR) Situational Awareness (SA) capabilities to produce NAVWAR SA solutions that leverage Electromagnetic Warfare (EW) and Signal Intelligence (SIGINT) capabilities while enabling distinctly NAVWAR SA outcomes and provide soldiers with PNT overmatch by denying adversary access to PNT services. NAVWAR SA provides commanders and soldiers with indications and warnings of PNT jamming to provide immediate notification to individual PNT users that their navigation and timing may be compromised by jamming or spoofing; detect, identify, and locate sources of PNT interference; allow command and control (C2) systems to display areas affected by interference with actionable information necessary to implement measures to mitigate or eliminate the threat. NAVWAR SA will create asymmetric opportunities to degrade and defeat an adversary's capabilities by denying their use of PNT and preserve PNT overmatch for friendly forces by creating a denied, degraded and/or disrupted operating environment for adversaries while opening windows of PNT superiority for friendly forces. NAVWAR SA supports Multi-Domain Operations (MDO) as an enabler to precision fires, movement and maneuver, force tracking, and a host of data networks that tie personnel and weapon systems together into a joint or coalition force. NAVWAR SA provides globally responsive arms teams with the ability to present multiple dilemmas to the enemy, limit enemy options and exploit enemy weaknesses. NAVWAR SA directly enhances multiple warfighting functions to include fires, aviation, mission command, and electromagnetic warfare. NAVWAR SA is a system of systems approach of detecting, geolocating, and determining the impact area of Global Positioning System (GPS) in a contested environment and the effects on PNT across the battlefield. NAVWAR SA will leverage the GNSS Operational Assessment Tool (GOAT) that was developed for an urgent requirement and be integrated with the Electronic Warfare Planning and Management Tool (EWPMT) X system. Requirement Documents Include: - Abbreviated Capabilities Development Document (A-CDD) for the NAVWAR SA, Army Futures Command (AFC) validated, 22 October 2020. - A-CDD for the NAVWAR Attack, AFC validated, 09 September 2022. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                     Date: June 2025 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced     PE 0604103A / Electronic Warfare Planning and Management Tool (EWPMT) Component Development & Prototypes (ACD&P)$$, NULL, NULL, NULL, NULL, NULL, NULL, 83, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 2004000, 0, NULL, NULL, NULL, NULL, NULL, $$Adversaries are aggressively developing and fielding counter- Positioning, Navigation, and Timing (PNT) technologies that significantly reduce the Army's ability to access the electromagnetic spectrum (EMS) to conduct military operations. The Army is actively pursuing Navigation Warfare (NAVWAR) Situational Awareness (SA) capabilities to produce NAVWAR SA solutions that leverage Electromagnetic Warfare (EW) and Signal Intelligence (SIGINT) capabilities while enabling distinctly NAVWAR SA outcomes and provide soldiers with PNT overmatch by denying adversary access to PNT services. NAVWAR SA provides commanders and soldiers with indications and warnings of PNT jamming to provide immediate notification to individual PNT users that their navigation and timing may be compromised by jamming or spoofing; detect, identify, and locate sources of PNT interference; allow command and control (C2) systems to display areas affected by interference with actionable information necessary to implement measures to mitigate or eliminate the threat. NAVWAR SA will create asymmetric opportunities to degrade and defeat an adversary's capabilities by denying their use of PNT and preserve PNT overmatch for friendly forces by creating a denied, degraded and/or disrupted operating environment for adversaries while opening windows of PNT superiority for friendly forces. NAVWAR SA supports Multi-Domain Operations (MDO) as an enabler to precision fires, movement and maneuver, force tracking, and a host of data networks that tie personnel and weapon systems together into a joint or coalition force. NAVWAR SA provides globally responsive arms teams with the ability to present multiple dilemmas to the enemy, limit enemy options and exploit enemy weaknesses. NAVWAR SA directly enhances multiple warfighting functions to include fires, aviation, mission command, and electromagnetic warfare. NAVWAR SA is a system of systems approach of detecting, geolocating, and determining the impact area of Global Positioning System (GPS) in a contested environment and the effects on PNT across the battlefield. NAVWAR SA will leverage the GNSS Operational Assessment Tool (GOAT) that was developed for an urgent requirement and be integrated with the Electronic Warfare Planning and Management Tool (EWPMT) X system. Requirement Documents Include: - Abbreviated Capabilities Development Document (A-CDD) for the NAVWAR SA, Army Futures Command (AFC) validated, 22 October 2020. - A-CDD for the NAVWAR Attack, AFC validated, 09 September 2022. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                  Date: April 2026 Appropriation/Budget Activity                                             R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced     PE 0604103A / Electronic Warfare Planning and Management Tool (EWPMT) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0604113A$$, $$Future Tactical Unmanned Aircraft System (FTUAS)$$, $$rdte_army_ba4$$, $$cft_c4isr$$, 2026, 0, 67143000, 127870000, NULL, $${"act": "04", "ba_raw": "6.4", "source": "r1_fy26", "service": "army", "page_num": 14, "fy26_v180": {"note": "R1_FY26_entry_no_value_extracted_in_original_ingest", "source": "b1_null_zero_v180"}, "original_pe": "0604113A", "page_header": "Department of the Army"}$$::jsonb, $$The Future Uncrewed Aircraft System (FUAS) is a critical system in the cross-domain capabilities concept that will employ multi-domain operation (MDO) capabilities at all echelons and allow ground-based forces to project power from land into other domains to defeat highly capable enemies, secure terrain, and consolidate gains. FUAS encompasses an array of capabilities from platoon Soldiers to Division Commanders. The Army Requirements Oversight Council (AROC) approved the FUAS Initial Capabilities Document (ICD) on 6 Mar 2019. FTUAS provides the Brigade Combat Teams (BCT) with transformational capabilities. FTUAS provides the BCT commander a runway independent, expeditionary reconnaissance, surveillance, and target acquisition (RSTA) capability through vertical takeoff and landing (VTOL) and on the move (OTM) command and control. FTUAS enhances survivability in a MDO environment through assured position, navigation, and timing (APNT) solutions; Type-1 encrypted datalinks; and a modular open systems approach (MOSA) that facilitates system upgrades at the pace of technology. FTUAS mitigates operation and support costs through organic sustainment capability, specifically through Soldiers conducting field level maintenance without contractor field service representatives. Additionally, FTUAS provides enhanced transportability, rapid deployability, expeditionary maneuver, and mobility for adaptive and agile operations. The AROC validation was completed on 17 May 2024, and AROC-M was signed on 8 July 2024 approving the updated A-CDD. One FTUAS system consists of 6 air vehicles and payloads, 6 control stations, and ancillary equipment. The aircraft subsystem includes the airframe, propulsion, avionics, communications, navigation, and software systems; aircraft-specific ground support equipment including power generation, transportation, or command and control equipment. Launched Effects (LE) extends the speed, range, lethality and survivability of maneuver formations through the integration of air vehicles, mission systems, payloads, and behaviors. LE will provides Army formations with the ability to expedite and strengthening the kill web, facilitate the penetration and dis-integration the enemy's Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Army                                                                            Date: June 2025 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced      PE 0604113A / Future Tactical Unmanned Aircraft System (FTUAS) Component Development & Prototypes (ACD&P) Anti-Access Area Denial (A2AD) environment and extend the maneuver force's reach, lethality, and survivability. LE efforts are based on requirements from an AROC approved Abbreviated-Capability Development Document (A-CDD) approved 08 July 2024. Manned, optionally-manned, and uncrewed systems will penetrate defense-in-depth environments by employing LE with teaming and swarming effects to detect, decoy, jam radar and communications, conduct cyber-attack, spoof and jam Global Positioning System (GPS), and kinetic engagement. The FY 2026 cost of the Future Unmanned Aircraft System (FUAS) Air Launched Effects (ALE) Middle Tier of Acquisition effort is $60.3 million, including RDT&E and procurement of prototype units. The Department will certify FYDP funding in a future budget submission.$$, NULL, NULL, NULL, NULL, NULL, NULL, 84, $$RDTE - Vol 2 - Budget Activity 4B.pdf$$, NULL, FALSE, 127870000, 0, NULL, NULL, NULL, NULL, NULL, $$The Future Uncrewed Aircraft System (FUAS) is a critical system in the cross-domain capabilities concept that will employ multi-domain operation (MDO) capabilities at all echelons and allow ground-based forces to project power from land into other domains to defeat highly capable enemies, secure terrain, and consolidate gains. FUAS encompasses an array of capabilities from platoon Soldiers to Division Commanders. The Army Requirements Oversight Council (AROC) approved the FUAS Initial Capabilities Document (ICD) on 6 Mar 2019. FTUAS provides the Brigade Combat Teams (BCT) with transformational capabilities. FTUAS provides the BCT commander a runway independent, expeditionary reconnaissance, surveillance, and target acquisition (RSTA) capability through vertical takeoff and landing (VTOL) and on the move (OTM) command and control. FTUAS completed Rapid Prototyping in July 2025 and will not enter production. Launched Effects (LE) extends the speed, range, lethality and survivability of maneuver formations through the integration of air vehicles, mission systems, payloads, and behaviors. LE will provides Army formations with the ability to expedite and strengthening the kill web, facilitate the penetration and dis-integration the enemy's Anti-Access Area Denial (A2AD) environment and extend the maneuver force's reach, lethality, and survivability. LE efforts are based on requirements from an AROC approved Abbreviated-Capability Development Document (A-CDD) approved 08 July 2024. Manned, optionally-manned, and uncrewed systems will penetrate defense-in-depth environments by employing LE with teaming and swarming effects to detect, decoy, jam radar and communications, conduct cyber-attack, spoof and jam Global Positioning System (GPS), and kinetic engagement. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Army                                                                     Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 2040: Research, Development, Test & Evaluation, Army / BA 4: Advanced      PE 0604113A / Future Tactical Unmanned Aircraft System (FTUAS) Component Development & Prototypes (ACD&P)$$, $$Budget J-Books/FY27/Army/RDTE - Vol 2 - Budget Activity 4B.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1611_L001$$, $$COLUMBIA Class Submarine$$, $$proc_navy_1611_ba1$$, $$peo_subs$$, 2026, 3928828000, 0, 3364835000, NULL, $${"ba": "ba1", "ingest": "v18", "source": "p1_fy27", "line_no": "1", "appr_code": "1611", "fy26_v179": {"note": "appropriation_supp_concentrated_on_largest_disc_li", "disc_K": 9279594, "li_num": 1, "source": "p40_fy26_v179", "supp_K": 17930426, "source_pdf": "uploads/Budget J-Books/FY27/Navy/SCN_Book.txt", "concentrated": true}, "title_raw": "Fleet Ballistic Missile Ships COLUMBIA Class Submarine", "fy27_total_K": 10233832}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, 10744317000, 10744317000, 4584932000, NULL, 205700000, 4790632000, NULL, NULL, $$Budget J-Books/FY27/Navy/SCN_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0306250JCY$$, $$Cyber Operations Technology Support$$, $$rdte_dw_ba7$$, $$dw_cybercom$$, 2026, 903020000, 412718000, 505434000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 80, "original_pe": "0306250JCY", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 1119609000, 925319000, 1280468000, NULL, NULL, NULL, NULL, NULL, FALSE, 519937000, 473399000, 1303094000, 1303094000, NULL, 1303094000, 1331321000, $$The U.S. Cyber Command (USCYBERCOM) conducts full spectrum cyberspace operations to deter or defeat strategic threats to U.S. interests, protect critical infrastructure, and ensure mission assurance for the Department of War (DoW) information environment. These operations enable Joint Force Commanders to maintain freedom of action in cyberspace while denying adversaries the ability to exploit or disrupt U.S. networks. USCYBERCOM’s cyber operations objectives include: • Deterring adversaries by undermining confidence in the reliability and security of their systems and capabilities. • Enhancing joint operations through intelligence collection before conflict, timely tipping and cueing during conflict, and post operation assessments. • Projecting power in cyberspace to access, influence, or disrupt adversary systems, providing non kinetic options to Combatant Commanders. • Disrupting, degrading, or destroying the capabilities of malicious cyber actors that threaten U.S. national security. To achieve these objectives, USCYBERCOM—working with the Military Services and other cyber stakeholders—develops, fields, and sustains the infrastructure, architectures, tools, and enabling technologies required to support the Cyber Mission Force (CMF). These investments ensure the CMF can conduct persistent engagement, defend the DoW Information Environment, and deliver operational effects across the full spectrum of cyberspace operations. The Cyber Operations Technology Support program provides the technical foundation, mission systems, and integration activities required to maintain CMF readiness and operational effectiveness. Funding supports the development, enhancement, and sustainment of capabilities aligned with the Joint Cyber Warfighting Architecture (JCWA), ensuring the CMF can counter rapidly evolving cyber threats and deliver timely, coordinated effects in support of Joint Force objectives. Continued investment is essential to sustaining U.S. cyber superiority and enabling the Joint Force to deter, disrupt, and defeat adversary cyber operations. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 United States Cyber Command                                            Date: April 2026 Appropriation/Budget Activity                                              R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:       PE 0306250JCY / Cyber Operations Technology Support Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_CYBERCOM_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0306250M$$, $$Cyber Operations Technology Development$$, $$rdte_navy_ba5$$, $$dw_cybercom$$, 2026, 11936000, 2407000, 7581000, NULL, $${"act": "05", "ba_raw": "6.5", "source": "r1_fy26", "service": "mc", "page_num": 35, "original_pe": "0306250M", "page_header": "Department of the Navy"}$$::jsonb, $$Marine Corps Forces Cyberspace Command (MARFORCYBER) provides advanced cyber warfare capabilities in direct support of US Cyber Command (USCYBERCOM), Marine Corps Commanders, and national agencies to enable and accomplish global operations. Activities within the project deliver cyberspace superiority capabilities through the research, development, testing, evaluation, and integration of cyber technologies. The project enables Commanders to disrupt, deny, degrade, or destroy targets. Research and develop software constructed cyber weapons disrupt rising advanced peer and near-peer threats, as well as violent extremist organizations seeking to do harm to the United States. The software constructed cyber weapons are target specific and require high quality, rapid adjustments to achieve desired effects at acceptable levels of risk. The specific details and aspects of these cyber activities are held at a higher classification level. Adversarial Cyber Developmental Test and Evaluation: Provides mission based cyber risk assessment services to Marine Corps Systems Command (MCSC) programs of record (PoRs) via Marine Corps Tactical Systems Support Activity (MCTSSA). MCTSSA serves as the Cyber Developmental Test and Evaluation agent in accordance with DODI 8500.01, DODI 5000.02, and the DoD Cybersecurity Test and Evaluation Guidebook. MCTSSA conducts adversarial cyber assessments on programs of record in development and prototypes to identify and mitigate vulnerabilities early in the acquisition cycle. These cyber assessments help inform program offices on how to design cyber survivable systems. MCTSSA also develops tools and guidebooks to assist with designing cyber resilient networks and testing prototypes that will enhance the security posture of information systems. Operations and Maintenance (O&M) funding is used for sustainment costs to include, but not limited to, fielded system assessment services, administration, and equipment.$$, NULL, 8484000, 8345000, 8254000, NULL, NULL, 185, $$RDTEN_BA5_Book.pdf$$, NULL, FALSE, 7289000, 11936000, 8962000, 8962000, NULL, 8962000, 8438000, $$Marine Corps Forces Cyberspace Command (MARFORCYBER) provides advanced cyber warfare capabilities in direct support of US Cyber Command (USCYBERCOM), Marine Corps Commanders, and national agencies to enable and accomplish global operations. Activities within the project deliver cyberspace superiority capabilities through the research, development, testing, evaluation, and integration of cyber technologies. The project enables Commanders to disrupt, deny, degrade, or destroy targets. Research and develop software constructed cyber weapons disrupt rising advanced peer and near-peer threats, as well as violent extremist organizations seeking to do harm to the United States. The software constructed cyber weapons are target specific and require high quality, rapid adjustments to achieve desired effects at acceptable levels of risk. The specific details and aspects of these cyber activities are held at a higher classification level. Adversarial Cyber Developmental Test and Evaluation: Provides mission based cyber risk assessment services to Marine Corps Systems Command (MCSC) programs of record (PoRs) via Marine Corps Tactical Systems Support Activity (MCTSSA). MCTSSA serves as the Cyber Developmental Test and Evaluation agent in accordance with DoDI 8500.01, DoDI 5000.02, and the DoD Cybersecurity Test and Evaluation Guidebook. MCTSSA conducts adversarial cyber assessments on programs of record in development and prototypes to identify and mitigate vulnerabilities early in the acquisition cycle. These cyber assessments help inform program offices on how to design cyber survivable systems. MCTSSA also develops tools and guidebooks to assist with designing cyber resilient networks and testing prototypes that will enhance the security posture of information systems. Operations and Maintenance (O&M) funding is used for sustainment costs to include, but not limited to, fielded system assessment services, administration, and equipment.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA5_Book.pdf$$) ON CONFLICT DO NOTHING;
