INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1611_L040$$, $$Bulk Fuel Vessel$$, $$proc_navy_1611_ba5$$, $$msc$$, 2026, 600000000, 0, 0, NULL, $${"ba": "ba5", "ingest": "v18", "source": "p1_fy27", "line_no": "32", "appr_code": "1611", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "title_raw": "(ATS)", "fy27_total_K": 0}$$::jsonb, NULL, NULL, NULL, NULL, NULL, 2250000000, 4500000000, NULL, NULL, NULL, FALSE, 0, 0, 0, NULL, 0, 0, NULL, NULL, $$Budget J-Books/FY27/Navy/SCN_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0307577F$$, $$Intelligence Mission Data (IMD)$$, $$rdte_af_ba7$$, $$afgsc$$, 2026, 3000000, 7090000, 3658000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0307577F"}$$::jsonb, $$Intelligence Mission Data efforts in BPAC 675306 fund RDT&E to enable Advanced Non-cooperative Target Recognition [NCTR] collection, Operational Reconnaissance and traditional ELINT capabilities, advanced all-source analysis and production of IMD across EWIR, C&P, M&S, and Signatures to inform acquisition efforts, enable combat ID and ensure survivability for air superiority and global strike platforms. Support to the Acquisition Intelligence Joint Integration Cell (Acq Intel-JIC). The JIC acts as a catalyst in the digital transformation of the Acq Intel Mission area and community, conducting research and development to enable the connection of Technical Intelligence Data to Acquisition Processes by integrating data, software, technology, and approaches to support DoD Acquisition Intelligence and Acquisition programs facilitating DoD system's lethality and survivability. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY2024 0 was expended for civilian pay expenses in this program element, and in FY2025 0 is forecasted for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0307577F / Intelligence Mission Data (IMD) Operational Systems Development$$, NULL, 3394000, 3504000, 3568000, NULL, NULL, 274, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 3658000, 18000000, 3151000, 3151000, 0, 3151000, 3641000, $$Intelligence Mission Data efforts in BPAC 675306 fund RDT&E to enable Advanced Non-cooperative Target Recognition [NCTR] collection, Operational Reconnaissance and traditional ELINT capabilities, advanced all-source analysis and production of IMD across EWIR, C&P, M&S, and Signatures to inform acquisition efforts, enable combat ID and ensure survivability for air superiority and global strike platforms. Support to the Acquisition Intelligence Joint Integration Cell (Acq Intel-JIC). The JIC acts as a catalyst in the digital transformation of the Acq Intel Mission area and community, conducting research and development to enable the connection of Technical Intelligence Data to Acquisition Processes by integrating data, software, technology, and approaches to support DoD Acquisition Intelligence and Acquisition programs facilitating DoD system's lethality and survivability. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$P_1611_L049$$, $$Programs AUX (MEMO NON ADD) MSAUX (MEMO NON ADD) LHA R (MEMO NON ADD) CVN (MEMO NON ADD) SSN-774 (MEMO NON ADD) TAGOS (MEMO NON ADD)$$, $$proc_navy_1611_ba5$$, $$peo_ships$$, 2026, 1690846000, 0, 0, NULL, $${"ba": "ba5", "ingest": "v18", "source": "p1_fy27", "line_no": "39", "appr_code": "1611", "fy26_v179": {"note": "no_parser_pair", "source": "p40_fy26_v179"}, "title_raw": "Auxiliary Personnel Lighter", "fy27_total_K": 83000}$$::jsonb, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, FALSE, NULL, 0, 83000000, NULL, 0, 83000000, NULL, NULL, $$Budget J-Books/FY27/Navy/SCN_Book.txt$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0307577N$$, $$Intelligence Mission Data (IMD)$$, $$rdte_navy_ba7$$, $$asn_rda$$, 2026, 803000, 764000, 793000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "navy", "page_num": 39, "original_pe": "0307577N", "page_header": "Department of the Navy"}$$::jsonb, NULL, NULL, 810000, 824000, 840000, NULL, NULL, NULL, NULL, NULL, FALSE, 791000, 803000, 787000, 787000, NULL, 787000, 855000, $$This project addresses intelligence projects under the Navy Modeling and Simulation (M&S) Office. It supports the Intelligence community through the integration, interoperability, prioritization and trades on threat data/modeling of intelligence data being fielded throughout the Naval acquisition enterprise. Efforts will migrate and leverage previous results to conduct analysis on threat data support to ashore and afloat Naval platforms and systems across all domains, and include Space, Air Force and Army interoperability and integration considerations. These efforts will support various afloat and ashore Navy programs and systems to modernize, digitally transform and integrate intelligence information into more agile software focused environments. Efforts are focused on developing enterprise standards, methodologies, techniques, and environments to improve intelligence data impact on complex mission performance and conduct trades on threat data/modeling prioritization.$$, $$Budget J-Books/FY27/Navy/RDTEN_BA7-8_Book.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0307609V$$, $$National Industrial Security System (NISS)$$, $$rdte_dw_ba7$$, $$dw_dcsa$$, 2026, 34710000, 0, 38761000, NULL, $${"act": "07", "ba_raw": "6.7", "source": "r1_fy26", "service": "dw", "page_num": 81, "original_pe": "0307609V", "page_header": "Defense-Wide"}$$::jsonb, NULL, NULL, 22731000, 23487000, 24301000, NULL, NULL, NULL, NULL, NULL, FALSE, 37499000, 33916000, 19840000, 19840000, NULL, 19840000, 24155000, $$The Defense Counterintelligence Security Agency (DCSA) is a strategic asset to the nation and our allies - continuously ensuring a trusted federal, industrial, and affiliated workforce, and enabling industry's delivery of uncompromised capabilities by leveraging advanced technologies and innovation. DCSA uniquely blends critical technology protection, trusted personnel vetting, counterintelligence, and professional education and certification to advance and preserve America's strategic edge. The National Industrial Security System (NISS) supports the DCSA mission to oversee approximately 10,000 cleared companies, 12,677 contractor facilities, and 5,700 classified systems in the National Industrial Security Program (NISP) are properly protected. The Industrial Security (IS) Directorate uses NISS to manage and document the oversight of facilities under the NISP. NISS is also the system of record for facilities clearance (FCL) information and the official system that allows DCSA to improve assessment and mitigation of risks related to contractors under Foreign Ownership, Control, or Influence (FOCI), and the newly developed system repository for the Department of War (DOW) Contract Classification Speciation (Form DD-254). NISS has been adopted by the DoW to provide visibility and access to security related data for classified contracts, sites, and systems. NISS is being developed into a multi-level classification system to allow visibility of relevant intelligence, threats, and communications across the Non-classified Internet Protocol (IP) Router Network (NIPRNet), Secure Internet Protocol Router Network (SIPRNet), and Joint Worldwide Intelligence Communication System (JWICS). NISS will enable near-real time threat awareness and discovered non-compliance vulnerabilities once fully deployed to enhance field and headquarters communication where security oversight, counterintelligence and cyber threats need to be addressed. NISS will provide the Defense Security Enterprise (DSE) visibility to know and project risks to specific industrial sites, be able to correlate FOCI concerns for large acquisition contracts and provide a database of security in direct support of the Under Secretary of War for Research and Engineering and Under Secretary of War for Acquisition & Sustainment enterprise efforts to make more secure decisions about unclassified acquisition, research, and grants. NISS is being designed to share a common operational picture of risk, vulnerability, and threat reporting across the entire NISP including the contractor security officials to improve transparency and timely action on identified risks. Additionally, NISS will incorporate the workflows, tools and serve as the repository for “pre award” FOCI analysis, reports and documentation of ultimate beneficiary for all DoW contracts (except commercial products and services) over $5.0 million in support of Public Law 116-92, Section 847 acquisition security reform efforts outlined in the FY 2020 National Defense Authorization Act (NDAA), impacting the Defense Industrial Base (DIB) comprised of more than 100,000 companies. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Defense Counterintelligence and Security Agency                               Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 0400: Research, Development, Test & Evaluation, Defense-Wide / BA 7:         PE 0307609V / National Industrial Security System (NISS) Operational Systems Development$$, $$Budget J-Books/FY27/DW/RDTE_DCSA_PB_2027.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401119F$$, $$C-5 Airlift Squadrons (IF)$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 33713000, 25938000, 32903000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401119F"}$$::jsonb, $$The C-5M carries outsized and heavy cargo (tanks, helicopters, etc.) between main operating bases. Additionally, the aircraft is capable of carrying 73 troops and 36 standard 463-L pallets. There are 52 C-5 aircraft in the Air Force fleet. The fleet was delivered to the Air Force between 1969 and 1989. Service life was extended to at least 2040 as a result of the reliability enhancement and re-engining program (RERP) modification. Current C-5M RDT&E efforts are the C-5M Replace Multi-functional Controls and Display (RMCD) program and C-5 Modernization. RMCD is a cockpit display modification to mitigate the obsolescence of the current control and display units. The C-5 Modernization efforts help keep the aircraft viable for the Air Force by developing solutions to mitigate safety of flight concerns and by addressing other reliability/availability/maintainability issues, such as the Holistic Avionics Grounding Avoidance and Recapitalization (HAGAR), stemming from C-5 system obsolescence. Additionally, the C-5 Modernization funding line supports the warfighter directly to implement Air Force mandated operational capabilities, including but not limited to MAF Connectivity, Mobile User Objective System (MUOS) Antenna upgrade, and Second-Generation Anti-Jam Tactical UHF Radio for NATO (SATURN), which are required to keep the platform operationally relevant in a modern threat environment. Efforts will include initial capabilities studies and analysis, risk reduction efforts, and studies and analysis to address Diminishing Manufacturing Sources (DMS). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $0.957 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                      Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0401119F / C-5 Airlift Squadrons (IF) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 72819000, 96468000, 139534000, NULL, NULL, 276, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 25825000, 33320000, 76233000, 76233000, 0, 76233000, 251576000, $$The C-5M carries outsized and heavy cargo (tanks, helicopters, etc.) between main operating bases. Additionally, the aircraft is capable of carrying 73 troops and 36 standard 463-L pallets. There are 52 C-5 aircraft in the Air Force fleet. The fleet was delivered to the Air Force between 1969 and 1989. Service life was extended to at least 2040 as a result of the reliability enhancement and re-engining program (RERP) modification. C-5M RDT&E efforts are the C-5M Replace Multi-functional Controls and Display (RMCD) program and C-5 Modernization. RMCD is a modification to mitigate the obsolescence of the current control and display units. C-5 Modernization is to develop future solutions for needed upgrades to combat obsolescence, safety of flight, and reliability/availability/maintainability issues and major thrust Next-Gen Airlift (NGAL). NGAL will perform an Analysis of Alternatives (AoA) in FY 2027, informing the Capabilities Development Document (CDD) and acquisition framework. Efforts will include but not limited to initial capabilities studies and analysis, risk reduction efforts, and studies and analysis to address Diminishing Manufacturing Sources (DMS). This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0401119F / C-5 Airlift Squadrons (IF) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401130F$$, $$C-17 Aircraft (IF)$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 80924000, 2702000, 11986000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401130F"}$$::jsonb, $$The four-engine C-17 is the only aircraft capable of routine delivery of outsize cargo (tanks, helicopters, etc.) to short, austere airfields. The aircraft can carry up to 102 troops, 36-liter patients or 18 standard 463-L pallets. The C-17 can perform the entire spectrum of airlift missions and is specifically designed to operate effectively and efficiently in both strategic and theater environments. Not only can the C-17 deliver outsize cargo to austere tactical environments, but it also reduces ground time during air and land operations. Strategic Airlift provides essential flexibility when responding to contingencies on short notice anywhere in the world. It is a major element of America's national security strategy and constitutes the most responsive means of meeting mobility requirements. Specific tasks associated with the airlift mission include deployment, employment, sustaining support, retrograde, aeromedical evacuation, and combat redeployment. The C-17 will perform this airlift mission well into this century. C-17 Research, Development, Test & Evaluation (RDT&E) funding efforts include but not limited to Aircraft performance improvements, aircraft mission execution and airspace access mandates (i.e. Communications/Navigation Improvements); flight test activities and facilities; development of solutions for obsolescence and safety of flight issues; systems engineering/program support; support for avionics laboratories; software development, test and integration; block development/change management; developments of solutions for needed upgrades to combat obsolescence and safety of flight issues; and proposal preparation for new projects. Funding supports efforts that include but not limited to Flight Deck Replacement (FDR), Beyond Line of Sight (BLOS), Aircraft Connectivity, and fuel efficiency, and studies to assess survivability efforts of different defensive systems not equipped on C-17 aircraft. Funding request includes Rapid Global Mobility (RGM) platform-related rapid capability development process activities including early planning, analysis and systems engineering activities which provide linkages between operation needs, system performance requirements, technology needs and opportunities, potential lifecycle costs and enabling the technical foundation for material development. This requirement supports performance of a full financial audit as requirement by title 10 U.S.C. Chapter 9A, Sec 240-D. The FY 2026 request for C-17A Aircraft includes $76,514 thousand of discretionary and $4,410 thousand of mandatory (reconciliation) for a total of $80,924 thousand. The mandatory funds development activities for aircraft connectivity. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                       Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:               PE 0401130F / C-17 Aircraft (IF) Operational Systems Development This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. In FY 2024 $0.500 million was expended for civilian pay expenses in this program element, and in FY 2025 $1.275 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 101198000, 101246000, 103234000, NULL, NULL, 277, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 11874000, 103465000, 178130000, 178130000, 0, 178130000, 135480000, $$C-17 program performs an entire spectrum of airlift missions and is specifically designed to operate effectively and efficiently in both strategic and theater environments. Not only can the C-17 deliver outsize cargo to austere tactical environments, but it also reduces ground time during air and land operations and is the only aircraft capable of routine delivery of outsize cargo (tanks, helicopters, etc.) to short, austere airfields. The C-17 aircraft can carry up to 102 troops, 36-litter patients or 18 standard 463-L pallets. The C-17 will perform it's airlift mission well into this century. Specific tasks associated with the airlift mission include deployment, employment, sustaining support, retrograde, aeromedical evacuation, and combat redeployment. C-17 Strategic Airlift provides essential flexibility when responding to contingencies on short notice anywhere in the world and is a major element of America's national security strategy and most responsive to meet mobility requirements. C-17 program funding supports efforts to include but not limited to Aircraft performance improvements, aircraft mission execution and airspace access mandates (i.e. Communications/Navigation Improvements); flight test activities and facilities; development of solutions for obsolescence and safety of flight issues; systems engineering/program support; support for avionics laboratories; software development, test and integration; block development/change management; developments of solutions for needed upgrades to combat obsolescence and safety of flight issues; and proposal preparation for new projects; Flight Deck Replacement (FDR); Aircraft Connectivity; and, studies to assess survivability efforts of different defensive systems not equipped on C-17 aircraft. Funding request includes Rapid Global Mobility (RGM) platform-related rapid capability development process activities including early planning, analysis and systems engineering activities which provide linkages between operation needs, system performance requirements, technology needs and opportunities, potential lifecycle costs and enabling the technical foundation for material development. This requirement supports performance of a full financial audit as requirement by title 10 U.S.C. Chapter 9A, Sec 240-D. The FY 2026 spend plan amount for RDT&E includes $103,465 thousand of discretionary and $4,410 thousand of mandatory (reconciliation) for a total of $107,875 thousand. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, 0606398F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0401130F / C-17 Aircraft (IF) Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401132F$$, $$C-130J Program$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 31354000, 21469000, 63533000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401132F"}$$::jsonb, $$The C-130J is a medium-sized transport aircraft capable of performing a variety of combat delivery (tactical airlift) operations across a broad range of mission environments. The C-130J aircraft, with its extended (by 15 feet) fuselage, provides additional cargo carrying capacity for the USAF combat delivery mission compared with legacy C-130E/H and the C-130J (short). Special mission variants of the C-130J conduct airborne weather reconnaissance (WC-130J), search and rescue (HC-130J), and special operations (MC-130J and AC-130J). All aircraft variants must be capable of worldwide operations. This project provides RDT&E funding for required capabilities that are grouped as "Block" upgrades or "Capability" or "Enhancement and Deficiencies" (EnD) updates. Content/requirements for block modifications is documented in International Program Directives (IPDs) and as determined in the Cooperative Systems and Software Upgrade Requirements Management (COSSURM) prioritized requirements process. This project will integrate the common-core capabilities developed under this program into the C-130J. The development costs are being shared via a global Project Arrangement (PA) by the United States (USAF, USMC, USCG), Italy, Australia, Denmark, Canada, and Norway. The C-130J program also includes Communication Modification 1 (Comm Mod 1) and Communication Modification 2 (Comm Mod 2). This effort includes but not limited to development, integration, and test of the new radio and communication systems including but not limited to Mobile User Objective System (MUOS), Second- generation Anti-jam Tactical UHF Radio for NATO (SATURN), Joint Range Extension Application Protocols (JREAP) to modernize Military Satellite Communications, Ultra High Frequency (UHF) and High Frequency (HF) radios, special mission processing, and data link messaging. These systems will provide secure, global Line of Sight (LOS) and Beyond Line of Sight (BLOS) satellite voice and data connectivity utilizing modern satellite constellations. C-130J requirements support the performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, or 0605898F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. The FY 2026 request was reduced by $1.001 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                         Date: June 2025 Appropriation/Budget Activity                                                      R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                  PE 0401132F / C-130J Program Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 11964000, 12239000, 12469000, NULL, NULL, 278, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 34261000, 18684000, 16628000, 16628000, 0, 16628000, 12721000, $$The C-130J is a medium-sized transport aircraft capable of performing a variety of combat delivery (tactical airlift) operations across a broad range of mission environments. The C-130J aircraft, with its extended (by 15 feet) fuselage, provides additional cargo carrying capacity for the USAF combat delivery mission compared with legacy C-130E/H and the C-130J (short). Special mission variants of the C-130J conduct airborne weather reconnaissance (WC-130J), search and rescue (HC-130J), and special operations (MC-130J and AC-130J). All aircraft variants must be capable of worldwide operations. This project provides RDT&E funding for required capabilities that are grouped as "Block" upgrades or "Capability" or "Enhancement and Deficiencies" (EnD) updates. Content/requirements for block modifications is documented in International Program Directives (IPDs) and as determined in the Cooperative Systems and Software Upgrade Requirements Management (COSSURM) prioritized requirements process. This project will integrate the common-core capabilities developed under this program into the C-130J. The development costs are being shared via a global Project Arrangement (PA) by the United States (USAF, USMC, USCG), Italy, Australia, Denmark, Canada, and Norway. The C-130J program also includes Communication Modification 1 (Comm Mod 1) and Communication Modification 2 (Comm Mod 2). This effort includes but not limited to development, integration, and test of the new radio and communication systems including but not limited to Mobile User Objective System (MUOS), Second- generation Anti-jam Tactical UHF Radio for NATO (SATURN), Joint Range Extension Application Protocols (JREAP) to modernize Military Satellite Communications, Ultra High Frequency (UHF) and High Frequency (HF) radios, special mission processing, and data link messaging. These systems will provide secure, global Line of Sight (LOS) and Beyond Line of Sight (BLOS) satellite voice and data connectivity utilizing modern satellite constellations. C-130J requirements support the performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                         Date: April 2026 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0401132F / C-130J Program Operational Systems Development This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401134F$$, $$Large Aircraft IR Countermeasures (LAIRCM)$$, $$rdte_af_ba7$$, $$afrl$$, 2026, 52928000, 3909000, 7768000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401134F"}$$::jsonb, $$The Large Aircraft Infrared Countermeasures (LAIRCM) system is an evolutionary acquisition program that provides significantly improved defensive systems capability for DoD aircraft to counter the man-portable air-defense systems (MANPADS) missile threat. The system is currently installed on 54 aircraft types and over 1,200 aircraft. The current LAIRCM system configuration consists of missile warning sensors (MWS), a laser transmitter assembly, control interface unit and processors to detect, track, jam and counter incoming missiles. The number of sensors and transmitter assemblies per aircraft is determined by the size and signature of the aircraft. The system is fully autonomous following system power-up. LAIRCM requirements are documented in the multi-command Operational Requirements Document (ORD) LAIRCM ORD 314-92, validated on 03 Aug 1998. The baseline development program is complete. Follow-on efforts continue Evolving Threat Analysis in order to address and counter new and emerging threats, as well as ensure integration onto new aircraft types and existing LAIRCM platforms. Additional efforts include design changes to improve reliability, maintainability, & availability and system improvements with form, fit, function and interface compliant replacements. Current and future efforts include AFRL Threat Analysis; Modeling, Simulation and Test; Virtual System Integration Lab (SIL) Development; and Studies and Analysis. To reestablish deterrence and protect our high-value asset aircraft from enemy threats, the Department of Defense requires an adjustment to the LAIRCM portfolio to pivot and transition LAIRCM into the Large Aircraft Defensive System (LADS) program in FY 2026. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                            Date: June 2025 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0401134F / Large Aircraft IR Countermeasures (LAIRCM) Operational Systems Development The Air Force is adjusting the lines of efforts to be 1) Evolving Threat Analysis (ETA), 2) Long Range Detect, 3) Active Detection, and 4) Advanced Defeat Technologies to help restore and rebuild capability for Survivable High-Value Airborne Assets. Latent Capability Development (LCD) updates the LAIRCM system to defend against unique threats. This funding will provide a programmatic support to update the system, to include hardware, software, and firmware, to enable the system's ability to detect and defeat a distinct category of threats and update to the latest threat models. Development begins at the AFRL Dynamic Infrared Missile Evaluator (DIME) Lab before transitioning to Northrop Grumman Corporation (NGC) for inclusion into the LAIRCM software baseline. The Active Defense Sensor (ADS) will provide sensing and cueing of threats, which is anticipated to employ a version of a long-range Radio Frequency (RF) defense sensor to provide long range sensing and cueing of threats. ADS will enhance existing High Value Airborne Asset survivability to detect and employ new tactics against an expanded category of threats. Anticipated efforts include, but are not limited to: hardware and software upgrade, development, and integration; prototyping; testing of the sensor as it integrates into a modular system of systems approach to maintain defensive capability against new and emerging threats. Program support cost efforts consist of, but are not limited to, contract services and government costs. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 20000000, 15000000, 0, NULL, NULL, 279, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 7484000, 40955000, 12323000, 12323000, 0, 12323000, 0, $$The Large Aircraft Infrared Countermeasures (LAIRCM) system is an evolutionary acquisition program designed to provide significantly improved defensive systems capability for Department of War (DoW) aircraft to counter the man-portable air-defense systems (MANPADS) and other surface-to-air Infrared (IR) missile threats. It is now being upgraded with new detection capabilities to provide aircrew with awareness of laser warning, small arms fire, rocket-propelled grenades, anti-aircraft fire, and laser guided munitions, with new sensors entering production in FY 2029. The LAIRCM system configuration consists of missile warning sensors (MWS), a laser transmitter assembly, control interface unit, and processors to detect, track, jam, and counter incoming missiles. The system is currently installed on 54 aircraft types and over 1,200 aircraft. The program's baseline development is complete. However, new efforts are required to continue addressing and countering new and emerging threats. The system is fully autonomous following the system power-up. LAIRCM requirements are documented in the multi-command Operational Requirements Document (ORD) LAIRCM ORD 314-92, validated on 03 Aug 1998. The baseline development program is complete. Follow-on efforts continue Evolving Threat Analysis in order to address and counter new and emerging threats, as well as ensure integration onto new aircraft types and existing LAIRCM platforms. Additional efforts include design changes to improve reliability, maintainability, & availability and system improvements with form, fit, function and interface compliant replacements. In FY 2027, the Air Force's focus is to expand protection of large aircraft beyond the threats LAIRCM counters. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                            Date: April 2026 Appropriation/Budget Activity                                                       R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                   PE 0401134F / Large Aircraft IR Countermeasures (LAIRCM) Operational Systems Development In FY 2026, to reestablish deterrence and protect our high-value asset aircraft from enemy threats, the Department of War required an adjustment to the LAIRCM portfolio to pivot and transition LAIRCM into the Large Aircraft Survivability System (LASS) program in FY 2027. To achieve this, the Air Force adjusted the lines of effort in PE 0401134F, LAIRCM, to be 1) Evolving Threat Analysis (ETA), 2) Long Range Detect, 3) Active Detection, and 4) Advanced Defeat Technologies to help restore and rebuild capability for Survivable High-Value Airborne Assets. Latent Capability Development (LCD) is intended to update the LAIRCM system to defend against unique threats. In FY 2027, PE 0401134F, LAIRCM, Project 67A037, LCD, was transferred to PE 0401334F, Large Aircraft Survivability Systems (LASS), Project 67A038, Active Defense Sensor. This funding provides programmatic support to update the system, to include hardware, software, and firmware, to enable the system's ability to detect and defeat a distinct category of threats and update to the latest threat models. Development begins at the AFRL Dynamic Infrared Missile Evaluator (DIME) Lab before transitioning to Northrop Grumman Corporation (NGC) for inclusion into the LAIRCM software baseline. The Active Defense Sensor (ADS) provides sensing and cueing of threats, which is anticipated to employ a version of a long-range Radio Frequency (RF) defense sensor to provide long range sensing and cueing of threats. In FY 2027, efforts under PE 0401134F, Project 67A038, Active Defense Sensor, were transferred to PE 0401334F, Large Aircraft Survivability Systems (LASS), Project 67A038, Advanced Sensors. ADS will enhance existing High Value Airborne Asset (HVAA) survivability to detect and employ new tactics against an expanded category of threats. Anticipated efforts include, but are not limited to: hardware and software upgrade, development, and integration; prototyping; testing of the sensor as it integrates into a modular system of systems approach to maintain defensive capability against new and emerging threats. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0401134F / Large Aircraft IR Countermeasures (LAIRCM) Operational Systems Development$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401218F$$, $$KC-135s$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 43000000, 71854000, 9899000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401218F"}$$::jsonb, $$The C/KC-135 is the only fully operational tanker in the Air Force inventory and also the oldest fleet by average age. In FY 2024, USAF C/KC-135s offloaded 70,727,162 gallons of fuel to refuel 36,515 aircraft (9% increase from FY 2023) in support of global operations. As a cargo aircraft, the C/KC-135 can carry six (6) standard 463- L pallets. RDT&E efforts include but are not limited to Mobile User Objective System, COMM2 Crypto & Data, High Frequency Modernization, and Center Console Refresh. Modernization funding is necessary to ensure the C/KC-135 fleet continues to support global aerial refueling operations through 2050 and beyond Mobile User Objective System (MUOS) integration and test for MUOS-capable radios on Block 45 aircraft in the COMM 3 position with Beyond Line-of-Sight (BLOS) Integrated Waveform (IW) and LOS SATURN capability with HAVE QUICK II backward compatibility. The C/KC-135 fleet must comply with the National Security Agency (NSA) mandate or will lose secure communications, which significantly degrades its ability to support worldwide operations. The ARC-210 Gen 3 radios have Diminishing Manufacturing Sources and Material Shortages (DMSMS) and will become obsolete on the CEASEKEY date. Requirements include AMC's 10-050 Crypto, 15-046 MUOS, 16-053 SATURN, and 17-039 IW. This modification is part to the USAF Radio and Crypto Modernization Plan (RCMP) for crypto modernization as directed by CSAF in Nov 2022 and DoD Chief Information Officer (CIO) in 2016. Center Console Refresh (CCR) replaces the Flight Display System (FDS) and Fuel System (FS) that is facing parts obsolescence issues and will render the aircraft non mission capable. The Integrated Fuel Management Panel (IFMP) and Fuel Management Advisory Computer (FMAC) are no longer procurable with limited repair capability. The Multi-Function Displays (MFD) are out of production with a limited cache of Liquid Crystal Display (LCD) glass. The A11 card within the Control Display Unit (CDU) is obsolete and no repair capability exists at this time. Current organizational maintenance cannibalization efforts and repair contracts have extended the service life and reduced fleet impacts from original projections. High Frequency (HF) Modernization includes integration and test to replace legacy HF radio with a modernized HF radio on C/KC-135 aircraft. A modernized HF communications capability is necessary to enable future sustainability and growth to operate in satellite communications (SATCOM) denied environment while maintaining global, secure voice and data between Mobility Air Forces (MAF) aircraft and command and control (C2) agencies to exchange classified information and require AMC 18-100 Modernized HF. This modification is part of the USAF RCMP for crypto modernization as directed by CSAF in Nov 2022 and DoD CIO in 2016. COMM2 Crypto and Data: Replaces the legacy Airborne Radio Communications (ARC)-210 Generation (Gen) 3 and Very High Frequency (VHF) Data Link (VDL)-2000 systems in the Communications (COMM) 2 position. The ARC-210 Gen 3 is replaced with the ARC-210 Gen 6, providing modern cryptographic Line-of-Sight (LoS) secure voice, Second Generation Anti-jam Tactical UHF Radio for NATO (SATURN) capability, and HAVE QUICK II backward compatibility through 2040. The VDL-2000 is replaced with the VHF-4000(E), enhancing COMM 2 civil data links. After the ARC-210 Gen 3's Cryptographic Equipment Authorized for Secure Keying Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                                 Date: June 2025 Appropriation/Budget Activity                                                    R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:                PE 0401218F / KC-135s Operational Systems Development (CEASEKEY) date, continued use risks mission degradation due to unsecure voice/data communications, loss of anti-jam capabilities, and limited legacy radio maintenance support. This will jeopardize critical air refueling and communication support for global operations. MAF connectivity enables tankers to connect to the Joint fight to close kill chains and logistics chains. Possible capabilities include, but are not limited to, intelligent gateways, antennas, radios, software updates, crew displays, and multiple aperture array housings. Hybrid SATCOM capability for airborne platforms relies on the employment of multi-band, multi-orbit SATCOM terminals to switch between both Government and Commercial satellites. Hybrid SATCOM terminals will provide airborne platforms with secure tactical communications by offering switching between five to ten distinct constellations. This flexibility of connectivity provides a high resiliency against anti-SATCOM threats, including jamming. The ability to selectively move between different satellite constellations (LEO/MEO/GEO) leverages the strengths of each constellation while the ability to switch between constellations within the Ku and Ka bands offers security of communications. The WXR-701 system, a Rockwell Collins product, is experiencing insurmountable Diminishing Manufacturing Source and Material Shortages (DMSMS). Rockwell Collins has provided a discontinuing of repair letter to the supply chain regarding the WXR-701. The purpose of this 1067 is to identify a Commercial Off the Shelf (COTS) solution for replacement of the WXR-701 Color Weather Radar. Encompasses C/KC-135 Operational System Development, continued support for activities including but not limited to Survivability, Innovation, and support for demonstrations, operational assessments, exercises, test and evaluation, and airworthiness to quantify the effectiveness of temporary and permanent solutions. The FY 2026 request for KC-135 program includes $0.000 thousand of discretionary and $43,000 thousand of mandatory (reconciliation) for a total of $43,000 thousand. The mandatory funds Center Console Refresh (CCR), Hybrid SATCOM, Color Weather Radar and MAF connectivity efforts. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, $1.482 million was expended for civilian pay expenses in this program element, and in FY 2025, $1.655 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                          Date: June 2025 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0401218F / KC-135s Operational Systems Development$$, NULL, 106043000, 87791000, 0, NULL, NULL, 280, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 9678000, 0, 121742000, 121742000, 0, 121742000, 0, $$The KC-135 program supports global aerial refueling operations through 2050 and beyond. The KC-135 is the only fully operational tanker in the Air Force inventory and the oldest fleet by average age. In FY 2024, USAF C/KC-135s offloaded 70,727,162 gallons of fuel to refuel 36,515 aircraft in support of global operations. As a cargo aircraft, the C/KC-135 can carry six (6) standard 463-L pallets. RDT&E efforts include but are not limited to Mobile User Objective System, COMM2 Crypto & Data, High Frequency Modernization, and Center Console Refresh. Funding provides for C/KC-135 Operational System Development efforts include but not limited to Mobile User Objective System (MUOS) integration, Center Console Refresh (CCR), High Frequency (HF) Modernization, COMM2 Crypto and Data, Mobility Air Forces (MAF), Hybrid SATCOM, and support for demonstrations, operational assessments, exercises, test and evaluation, and airworthiness to quantify the effectiveness of temporary and permanent solutions. Mobile User Objective System (MUOS) integration and test for MUOS-capable radios on Block 45 aircraft in the COMM 3 position with Beyond Line-of-Sight (BLOS) Integrated Waveform (IW) and LOS SATURN capability with HAVE QUICK II backward compatibility. The C/KC-135 fleet must comply with the National Security Agency (NSA) mandate or will lose secure communications, which significantly degrades its ability to support worldwide operations. The ARC-210 Gen 3 radios have Diminishing Manufacturing Sources and Material Shortages (DMSMS) and will become obsolete on the Cryptographic Equipment Authorized for Secure Keying (CEASEKEY) date. Requirements include AMC's 10-050 Crypto, 15-046 MUOS, 16-053 SATURN, and 17-039 IW. This modification is part to the USAF Radio and Crypto Modernization Plan (RCMP) for crypto modernization as directed by CSAF in Nov 2022 and DoW Chief Information Officer (CIO) in 2016. Center Console Refresh (CCR) replaces the Flight Display System (FDS) and Fuel System (FS), and Flight Computer/Integrated Processing Center (IPC) that are facing parts obsolescence issues and will render the aircraft non mission capable. Additionally, the program includes the auto-throttles requirement. The Integrated Fuel Management Panel (IFMP) and Fuel Management Advisory Computer (FMAC) are no longer procurable with limited repair capability. The Multi-Function Displays (MFD) are out of production with a limited cache of Liquid Crystal Display (LCD) glass. The A11 card within the Control Display Unit (CDU) is obsolete and no repair capability exists at this time. Current organizational maintenance cannibalization efforts and repair contracts have extended the service life and reduced fleet impacts from original projections. High Frequency (HF) Modernization includes integration and test to replace legacy HF radio with a modernized HF radio on C/KC-135 aircraft. A modernized HF communications capability is necessary to enable future sustainability and growth to operate in satellite communications (SATCOM) denied environment while Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                               Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0401218F / KC-135s Operational Systems Development maintaining global, secure voice and data between Mobility Air Forces (MAF) aircraft and command and control (C2) agencies to exchange classified information and require AMC 18-100 Modernized HF. This modification is part of the USAF RCMP for crypto modernization as directed by CSAF in Nov 2022 and DoW CIO in 2016. COMM2 Crypto and Data replaces the legacy Airborne Radio Communications (ARC)-210 Generation (Gen) 3 and Very High Frequency (VHF) Data Link (VDL)-2000 systems in the Communications (COMM) 2 position. The ARC-210 Gen 3 is replaced with the ARC-210 Gen 6, providing modern cryptographic Line-of-Sight (LoS) secure voice, Second Generation Anti-jam Tactical UHF Radio for NATO (SATURN) capability, and HAVE QUICK II backward compatibility through 2040. The VDL-2000 is replaced with the VHF-4000(E), enhancing COMM 2 civil data links. After the ARC-210 Gen 3's Cryptographic Equipment Authorized for Secure Keying (CEASEKEY) date, continued use risks mission degradation due to unsecure voice/data communications, loss of anti-jam capabilities, and limited legacy radio maintenance support jeopardizes critical air refueling and communication support for global operations. COMM2 Crypto and Data enables tankers to connect to the Joint fight to close kill chains and logistics chains. Possible capabilities include, but are not limited to, intelligent gateways, antennas, radios, software updates, crew displays, and multiple aperture array housings. MAF connectivity enables tankers to connect to the Joint fight to close kill chains and logistics chains. Possible capabilities include, but are not limited to, intelligent gateways, antennas, radios, software updates, crew displays, and multiple aperture array housings. Lays functional baseline and initial EMD for MAF NEXUS towards the next program increment. Hybrid SATCOM capability for airborne platforms relies on the employment of multi-band, multi-orbit SATCOM terminals to switch between both Government and Commercial satellites. Hybrid SATCOM terminals will provide airborne platforms with secure tactical communications by offering switching between five to ten distinct constellations. This flexibility of connectivity provides a high resiliency against anti-SATCOM threats, including jamming. The ability to selectively move between different satellite constellations (LEO/MEO/HEO/GEO) leverages the strengths of each constellation while the ability to switch between constellations within the Ku and Ka bands offers security of communications. This capability also enables tankers to connect to the Joint fight to close kill chains and logistics chains. Possible capabilities include, but are not limited to, intelligent gateways, antennas, radios, software updates, crew displays, and multiple aperture array housings. The Color Weather Radar program replaces the WXR-701 system, a Rockwell Collins product, that is experiencing insurmountable Diminishing Manufacturing Source and Material Shortages (DMSMS). Rockwell Collins has provided a discontinuing of repair letter to the supply chain regarding the WXR-701. The purpose of this program is to identify a Commercial Off the Shelf (COTS) solution for replacement of the WXR-701 Color Weather Radar. The total cost of the Color Weather Radar (CWR) Middle Tier of Acquisition effort is $302 million, including RDT&E and procurement of prototype units. VLF (Very Low Frequency) - To enhance the nuclear mission survivability of the KC-135 and meet the requirements for survivable communications as outlined in CJCSI 6811.01C, our mission is to integrate a stand-alone VLF Roll-on/Roll-off (RORO) survivable communication system. Development and Test Program - Provides agile test, evaluation, and airworthiness support for rapid technology integration. This program enables operational assessments, exercises, and demonstrations of emerging capabilities to address urgent warfighter needs and modernize legacy platforms under accelerated timelines. The FY 2026 spend plan amount for RDT&E includes $0 thousand of discretionary and $43,000 thousand of mandatory (reconciliation) for a total of $43,000 thousands. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                     Date: April 2026 Appropriation/Budget Activity                                                  R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:              PE 0401218F / KC-135s Operational Systems Development This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401318F$$, $$CV-22$$, $$rdte_af_ba7$$, $$aflcmc_aa$$, 2026, 31510000, 16581000, 26249000, NULL, $${"ba_raw": "6.7", "source": "af_r1_fy26", "original_pe": "0401318F"}$$::jsonb, $$The CV-22 is the Air Force Special Operations Forces (SOF) variant of the joint multi-mission V-22 tilt rotor aircraft. The CV-22 provides long-range, high-speed infiltration, exfiltration, personnel recovery, and resupply to Special Forces teams in hostile, denied, and politically sensitive areas. The Navy is the lead service for the Joint V-22 program. The Joint Program Manager is responsible for managing all variants of the V-22. Department of the Navy (DoN) funds the development of the MV-22 and CMV-22. The Air Force funds the service common portion of the CV-22 while United States Special Operations Command (USSOCOM) funds the development and procurement of SOF peculiar systems. CV-22 RDT&E funding provides for the development, integration, and testing of service-common, mission critical aircraft modifications to improve operational effectiveness, platform survivability, and aircraft availability. Airframe Enhancements: RDT&E funds the design, development, and testing of improvements to airframe structures, aircraft electro-mechanical and hydraulic hardware, and dynamic components to counteract the effects of structural fatigue and improve the durability and readiness of V-22 aircraft. Refinement of aircraft system's components to improve longevity and/or maintainability while protecting their performance are meant to allow continued CV-22 operation as the aircraft ages. Enhanced Self-Deployment: RDT&E funding provides for the design, development, and testing of aircraft modifications to improve aircraft self-deployment capabilities (e.g. operating range, global response time) to mitigate emerging threats to the aircraft and mission accomplishment, and to identify and assess emerging air vehicle, propulsion system, avionics architecture, electronic warfare, situational awareness, and other weapon system solutions to meet CV-22 Block 20 operational requirements. CV-22 funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This funding may include emerging requirements to support Program Support Costs (PSC), Advisory and Assistant Service (A&AS), system integration lab, trainers, equipment and other government costs. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                        Date: June 2025 Appropriation/Budget Activity                                                R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:            PE 0401318F / CV-22 Operational Systems Development The FY 2026 request for CV-22 includes $653 thousand of discretionary and $30,857 thousand of mandatory (reconciliation) for a total of $31,510 thousand. The mandatory funds both airframe enhancements and enhanced self-deployment efforts. Further information for this reconciliation request is provided in Section 20007 (Air Superiority) of the Reconciliation Exhibit. The FY 2026 request was reduced by $0.655 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative." This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such program's funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024, $0.000 million was expended for civilian pay expenses in this program element, and in FY 2025 $0.000 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, NULL, 21443000, 20674000, 21066000, NULL, NULL, 281, $$FY26 Air Force Research and Development Test and Evaluation Vol IV.pdf$$, NULL, FALSE, 25549000, 31544000, 45699000, 45699000, 0, 45699000, 21493000, $$The CV-22 is the Air Force Special Operations Forces (SOF) variant of the joint multi-mission V-22 tilt rotor aircraft. The CV-22 provides long-range, high-speed infiltration, exfiltration, personnel recovery, and resupply to Special Forces teams in hostile, denied, and politically sensitive areas. The Navy is the lead service for the Joint V-22 program. The Joint Program Manager is responsible for managing all variants of the V-22. Department of the Navy (DoN) funds the development of the MV-22 and CMV-22. The Air Force funds the service common portion of the CV-22 while United States Special Operations Command (USSOCOM) funds the development and procurement of SOF peculiar systems. CV-22 RDT&E funding provides for the development, integration, and testing of service-common, mission critical aircraft modifications to improve operational effectiveness, platform survivability, and aircraft availability. Airframe Enhancements: RDT&E funds design, development, and testing of improvements to airframe structures, aircraft electro-mechanical and hydraulic hardware, and dynamic components to counteract the effects of structural fatigue and improve the durability and readiness of V-22 aircraft. Refinement of aircraft system's components to improve longevity and/or maintainability while protecting their performance are meant to allow continued CV-22 operation as the aircraft ages. Enhanced Self-Deployment: RDT&E funding provides for the design, development, and testing of aircraft modifications to improve aircraft self-deployment capabilities (e.g. operating range, global response time) to mitigate emerging threats to the aircraft and mission accomplishment, and to identify and assess emerging air vehicle, propulsion system, avionics architecture, electronic warfare, situational awareness, and other weapon system solutions to meet CV-22 capability, reliability and survivability operational requirements. CV-22 funding also supports innovation activities to include studies, analyses, requirements definition, and quick-reaction capability prototypes/demonstrations to accelerate planning for technology transition, technology insertion and future acquisition programs. This funding may include emerging requirements to support Program Support Costs (PSC), Advisory and Assistant Service (A&AS), system integration lab, trainers, equipment and other government costs. This program element included all necessary expenses required to manage, execute, and deliver weapon system capability. The use of such program funds would be in addition to the civilian pay expenses budgeted in program elements 0605829F, 0605831F, 0605833F, and 0605898F. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                        Date: April 2026 Appropriation/Budget Activity                                                 R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 7:             PE 0401318F / CV-22 Operational Systems Development This program is in Budget Activity 7, Operational System Development because this budget activity includes development efforts to upgrade systems that have been fielded or have received approval for full rate production and anticipate production funding in the current or subsequent fiscal year.$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume IV.pdf$$) ON CONFLICT DO NOTHING;
INSERT INTO public.budget_pes (id, title, appropriation_id, owning_org_id, fiscal_year, request_amount, prior_year_amount, enacted_amount, narrative_url, raw_source, description, fy27_amount, fy28_amount, fy29_amount, fy30_amount, cost_to_complete, total_cost, r1_line, source_pdf, defense_wide_org, is_priority, fy25_actual_amount, fy26_enacted_amount, fy27_request_amount, fy27_base_amount, fy27_ooc_amount, fy27_total_amount, fy31_amount, fy27_mission_description, fy27_source_pdf) VALUES ($$0401319F$$, $$VC-25B$$, $$rdte_af_ba5$$, $$aflcmc_pz$$, 2026, 602318000, 94750000, 433943000, NULL, $${"ba_raw": "6.5", "source": "af_r1_fy26", "original_pe": "0401319F"}$$::jsonb, $$The VC-25B Program, formerly known as the Presidential Aircraft Recapitalization (PAR) Program, replaces the Presidential VC-25A fleet which faces capability gaps, rising maintenance costs, and parts obsolescence as it ages beyond 30 years. The VC-25B Program delivers two new aircraft to meet the requirements for the President to execute the duties of Head of State, Chief Executive, and Commander-in-Chief. The VC-25B Program uniquely modifies two Boeing 747-8 commercial aircraft to provide the President, staff, and guests with safe and reliable air transportation with the equivalent level of communications capability and security available in the White House. The modifications to the 747-8 aircraft include an electrical power upgrade with dual Auxiliary Power Units that are usable in flight, a mission communication system, a work and rest environment, an executive interior, military avionics, a self-defense system, independent enplaning and deplaning, and independent baggage loading. No significant changes to the existing VC-25A Concept of Operations or Concept of Employment are expected. This budget provides for Post-Milestone B (MS B) design, integration, modification, product support and test of two aircraft to make them Presidential mission ready. Funds may be used to lease test equipment, as well as address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. The FY 2026 request was reduced by $1.941 million for Advisory and Assistance Services to promote efficiencies and advance the policies of the Administration in alignment with Executive Order 14222, "Implementing the President's Department of Government Efficiency Cost Efficiency Initiative.” This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605827F, 0605828F, 0605829F, 0605831F, 0605832F, 0605833F, 0605898F, and 0606398F. In FY 2024 $5.637 million was expended for civilian pay expenses in this program element, and in FY 2025 $6.652 million is forecast for civilian pay expenses in this program element. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2026 Air Force                                                                           Date: June 2025 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0401319F / VC-25B Development & Demonstration (SDD)$$, NULL, 179441000, 33476000, 34104000, NULL, NULL, 121, $$FY26 Air Force Research and Development Test and Evaluation Vol II.pdf$$, NULL, FALSE, 419617000, 594557000, 555195000, 555195000, 0, 555195000, 34794000, $$The VC-25B Program, formerly known as the Presidential Aircraft Recapitalization (PAR) Program, replaces the Presidential VC-25A fleet which faces capability gaps, rising maintenance costs, and parts obsolescence as it ages beyond 30 years. The VC-25B Program delivers two new aircraft to meet the requirements for the President to execute the duties of Head of State, Chief Executive, and Commander-in-Chief. The VC-25B Program uniquely modifies two Boeing 747-8 commercial aircraft to provide the President, staff, and guests with safe and reliable air transportation with the equivalent level of communications capability and security available in the White House. The modifications to the 747-8 aircraft include an electrical power upgrade with dual Auxiliary Power Units that are usable in flight, a mission communication system, a work and rest environment, an executive interior, military avionics, a self-defense system, independent enplaning and deplaning, and independent baggage loading. No significant changes to the existing VC-25A Concept of Operations or Concept of Employment are expected. This budget provides for Post-Milestone B (MS B) design, integration, modification, product support and test of two aircraft to make them Presidential mission ready. Funds may be used to lease VC-25B test equipment, as well as address emerging and short-notice Diminishing Manufacturing Sources and Material Shortage (DMSMS) issues. This requirement supports performance of a full financial audit as required by title 10 U.S.C. Chapter 9A, Sec 240-D. This program element may include necessary civilian pay expenses required to manage, execute, and deliver weapon system capability. The use of such programs funds would be in addition to the civilian pay expenses budgeted in program element 0605829F, 0605831F, 0605833F, and 0605898F. This program is in Budget Activity 5, System Development and Demonstration (SDD) because it has passed Milestone B approval and is conducting engineering and manufacturing development tasks aimed at meeting validated requirements prior to full rate production. Exhibit R-2, RDT&E Budget Item Justification: PB 2027 Air Force                                                                           Date: April 2026 Appropriation/Budget Activity                                                   R-1 Program Element (Number/Name) 3600: Research, Development, Test & Evaluation, Air Force / BA 5: System        PE 0401319F / VC-25B Development & Demonstration (SDD)$$, $$Budget J-Books/FY27/Air Force/FY27 Air Force Research, Development, Test & Evaluation  Volume II.pdf$$) ON CONFLICT DO NOTHING;
